{
  "name": "LogiTrack - Gestão de Entregas",
  "description": "Uma aplicação moderna para controle de logística de pacotes, monitoramento de ganhos e geração de relatórios de produtividade."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export type LogActionType = 'ENTRADA' | 'SAIDA' | 'DEVOLUCAO';

export interface LogEntry {
  id: string;
  type: LogActionType;
  timestamp: string; // ISO string
  value: number;
}

export interface DailySummary {
  date: string;
  delivered: number;
  returns: number;
  gains: number;
}

import { LogEntry } from '../types';
import { STORAGE_KEY } from '../constants';

export const storageService = {
  getLogs: (): LogEntry[] => {
    const data = localStorage.getItem(STORAGE_KEY);
    return data ? JSON.parse(data) : [];
  },

  saveLog: (entry: LogEntry) => {
    const logs = storageService.getLogs();
    const updatedLogs = [entry, ...logs];
    localStorage.setItem(STORAGE_KEY, JSON.stringify(updatedLogs));
    return updatedLogs;
  },

  clearLogs: () => {
    localStorage.removeItem(STORAGE_KEY);
  }
};

import { jsPDF } from 'jspdf';
import 'jspdf-autotable';
import { LogEntry, DailySummary } from '../types';
import { VALOR_POR_PACOTE } from '../constants';

export const generatePDF = (logs: LogEntry[], userName: string = 'Operador Logístico') => {
  const doc = new jsPDF();
  const dateStr = new Date().toLocaleDateString('pt-BR');

  // Filtering for last 7 days
  const now = new Date();
  const sevenDaysAgo = new Date();
  sevenDaysAgo.setDate(now.getDate() - 7);

  const recentLogs = logs.filter(log => new Date(log.timestamp) >= sevenDaysAgo);

  // Aggregate by day
  const dailyData: Record<string, DailySummary> = {};

  recentLogs.forEach(log => {
    const day = new Date(log.timestamp).toLocaleDateString('pt-BR');
    if (!dailyData[day]) {
      dailyData[day] = { date: day, delivered: 0, returns: 0, gains: 0 };
    }

    if (log.type === 'SAIDA') {
      dailyData[day].delivered += 1;
      dailyData[day].gains += VALOR_POR_PACOTE;
    } else if (log.type === 'DEVOLUCAO') {
      dailyData[day].returns += 1;
    }
  });

  const summaryRows = Object.values(dailyData).sort((a, b) => {
     const [dayA, monthA, yearA] = a.date.split('/').map(Number);
     const [dayB, monthB, yearB] = b.date.split('/').map(Number);
     return new Date(yearB, monthB - 1, dayB).getTime() - new Date(yearA, monthA - 1, dayA).getTime();
  });

  const totalDelivered = summaryRows.reduce((acc, curr) => acc + curr.delivered, 0);
  const totalReturns = summaryRows.reduce((acc, curr) => acc + curr.returns, 0);
  const totalGains = summaryRows.reduce((acc, curr) => acc + curr.gains, 0);

  // Header
  doc.setFontSize(20);
  doc.setTextColor(30, 41, 59);
  doc.text('Relatório de Produtividade Logística', 14, 22);

  doc.setFontSize(10);
  doc.setTextColor(100);
  doc.text(`Data de Emissão: ${dateStr}`, 14, 30);
  doc.text(`Operador: ${userName}`, 14, 35);

  // Executive Summary
  doc.setDrawColor(226, 232, 240);
  doc.setFillColor(248, 250, 252);
  doc.rect(14, 45, 182, 30, 'F');

  doc.setFontSize(11);
  doc.setTextColor(30, 41, 59);
  doc.setFont('helvetica', 'bold');
  doc.text('RESUMO EXECUTIVO (Últimos 7 dias)', 18, 52);

  doc.setFont('helvetica', 'normal');
  doc.text(`Total de Entregas: ${totalDelivered}`, 18, 62);
  doc.text(`Total de Devoluções: ${totalReturns}`, 18, 68);

  doc.setFont('helvetica', 'bold');
  doc.setTextColor(37, 99, 235);
  doc.text(`Valor Total Bruto: R$ ${totalGains.toFixed(2)}`, 130, 65);

  // Table
  const tableColumn = ["Data", "Pacotes Entregues", "Devoluções", "Ganhos do Dia (R$)"];
  const tableRows = summaryRows.map(row => [
    row.date,
    row.delivered.toString(),
    row.returns.toString(),
    `R$ ${row.gains.toFixed(2)}`
  ]);

  (doc as any).autoTable({
    head: [tableColumn],
    body: tableRows,
    startY: 85,
    theme: 'grid',
    headStyles: { fillColor: [30, 41, 59], textColor: [255, 255, 255] },
    alternateRowStyles: { fillColor: [241, 245, 249] }
  });

  // Footer
  const finalY = (doc as any).lastAutoTable.finalY + 20;
  doc.setFontSize(9);
  doc.setTextColor(148, 163, 184);
  doc.text('Documento gerado via Sistema de Gestão Logística - LogiTrack', 14, finalY);
  doc.text('Assinatura Digital Automática', 14, finalY + 5);

  doc.save(`relatorio_logistica_${dateStr.replace(/\//g, '-')}.pdf`);
};

import React, { useState } from 'react';
import { Eye, EyeOff, Package, TrendingUp, Calendar } from 'lucide-react';
import { VALOR_POR_PACOTE } from '../constants';

interface DashboardCardsProps {
  deliveredToday: number;
  deliveredWeek: number;
  deliveredYear: number;
}

const DashboardCards: React.FC<DashboardCardsProps> = ({ 
  deliveredToday, 
  deliveredWeek, 
  deliveredYear 
}) => {
  const [visible, setVisible] = useState<Record<string, boolean>>({
    today: true,
    week: true,
    year: true
  });

  const toggleVisibility = (key: string) => {
    setVisible(prev => ({ ...prev, [key]: !prev[key] }));
  };

  const formatCurrency = (count: number) => {
    return new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(count * VALOR_POR_PACOTE);
  };

  const Card = ({ title, count, icon: Icon, color, storageKey }: any) => (
    <div className="bg-white rounded-3xl p-6 shadow-sm border border-slate-100 flex flex-col justify-between transition-all hover:shadow-lg group">
      <div className="flex justify-between items-start mb-4">
        <div className={`p-3 rounded-2xl ${color} bg-opacity-10 group-hover:bg-opacity-20 transition-all`}>
          <Icon className={`w-6 h-6 ${color.replace('bg-', 'text-')}`} />
        </div>
        <button 
          onClick={() => toggleVisibility(storageKey)}
          className="text-slate-300 hover:text-slate-600 transition-colors"
        >
          {visible[storageKey] ? <Eye size={18} /> : <EyeOff size={18} />}
        </button>
      </div>

      <div>
        <p className="text-slate-500 text-sm font-medium uppercase tracking-wider">{title}</p>
        <h2 className="text-3xl font-bold text-slate-800 mt-1">
          {visible[storageKey] ? formatCurrency(count) : "••••••"}
        </h2>
        <div className="mt-3 flex items-center gap-2">
          <div className="flex items-center gap-1 text-xs font-semibold px-2 py-1 bg-slate-50 text-slate-400 rounded-full">
            <Package size={12} /> {count} entregas
          </div>
        </div>
      </div>
    </div>
  );

  return (
    <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
      <Card 
        title="Rota do Dia" 
        count={deliveredToday} 
        icon={TrendingUp} 
        color="bg-blue-500" 
        storageKey="today"
      />
      <Card 
        title="Resumo Semanal" 
        count={deliveredWeek} 
        icon={Calendar} 
        color="bg-emerald-500" 
        storageKey="week"
      />
      <Card 
        title="Total do Ano" 
        count={deliveredYear} 
        icon={Package} 
        color="bg-violet-500" 
        storageKey="year"
      />
    </div>
  );
};

export default DashboardCards;

import React from 'react';
import { ArrowDownLeft, ArrowUpRight, RotateCcw, LucideIcon } from 'lucide-react';
import { LogActionType } from '../types';

interface ActionButtonsProps {
  onAction: (type: LogActionType) => void;
}

interface ActionBtnProps {
  label: string;
  icon: LucideIcon;
  color: string;
  onClick: () => void;
  description: string;
}

const ActionBtn: React.FC<ActionBtnProps> = ({ label, icon: Icon, color, onClick, description }) => (
  <button 
    onClick={onClick}
    className={`flex flex-col items-center justify-center p-6 rounded-2xl border-2 border-transparent transition-all active:scale-95 hover:border-slate-200 ${color} group shadow-sm`}
