export default ActionButtons;

import React from 'react';
import { LogEntry } from '../types';
import { ArrowDownLeft, ArrowUpRight, RotateCcw, Clock } from 'lucide-react';

interface HistoryListProps {
  logs: LogEntry[];
}

const HistoryList: React.FC<HistoryListProps> = ({ logs }) => {
  const getIcon = (type: string) => {
    switch (type) {
      case 'ENTRADA': return <ArrowDownLeft className="text-emerald-500" size={16} />;
      case 'SAIDA': return <ArrowUpRight className="text-blue-500" size={16} />;
      case 'DEVOLUCAO': return <RotateCcw className="text-orange-500" size={16} />;
      default: return null;
    }
  };

  const getLabel = (type: string) => {
    switch (type) {
      case 'ENTRADA': return 'Entrada de Pacote';
      case 'SAIDA': return 'Entrega Concluída';
      case 'DEVOLUCAO': return 'Devolução Registrada';
      default: return type;
    }
  };

  const formatDate = (isoStr: string) => {
    const date = new Date(isoStr);
    return date.toLocaleTimeString('pt-BR', { hour: '2-digit', minute: '2-digit' });
  };

  const recentLogs = logs.slice(0, 10);

  return (
    <div className="bg-white rounded-3xl shadow-sm border border-slate-100 overflow-hidden">
      <div className="p-5 border-b border-slate-50 flex justify-between items-center">
        <h3 className="font-bold text-slate-800 flex items-center gap-2">
          <Clock size={18} className="text-slate-400" /> Histórico Recente
        </h3>
        <span className="text-xs font-medium text-slate-400">Últimas 10 ações</span>
      </div>

      {recentLogs.length === 0 ? (
        <div className="p-10 text-center text-slate-400 italic">
          Nenhuma atividade registrada hoje.
        </div>
      ) : (
        <div className="divide-y divide-slate-50">
          {recentLogs.map((log) => (
            <div key={log.id} className="p-4 flex items-center justify-between hover:bg-slate-50 transition-colors">
              <div className="flex items-center gap-4">
                <div className="p-2 bg-slate-50 rounded-lg">
                  {getIcon(log.type)}
                </div>
                <div>
                  <p className="text-sm font-semibold text-slate-700">{getLabel(log.type)}</p>
                  <p className="text-xs text-slate-400">{new Date(log.timestamp).toLocaleDateString('pt-BR')}</p>
                </div>
              </div>
              <div className="text-right">
                <p className="text-sm font-bold text-slate-800">{formatDate(log.timestamp)}</p>
                {log.type === 'SAIDA' && (
                  <p className="text-[10px] font-bold text-emerald-500">+ R$ 2,50</p>
                )}
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  );
};

export default HistoryList;

import React, { useState, useEffect, useMemo } from 'react';
import { Package, FileText, Download, LayoutDashboard, Settings } from 'lucide-react';
import DashboardCards from './components/DashboardCards';
import ActionButtons from './components/ActionButtons';
import HistoryList from './components/HistoryList';
import { LogEntry, LogActionType } from './types';
import { storageService } from './services/storageService';
import { generatePDF } from './services/pdfService';

const App: React.FC = () => {
  const [logs, setLogs] = useState<LogEntry[]>([]);
  const [showToast, setShowToast] = useState(false);
  const [toastMsg, setToastMsg] = useState('');
  const [userName, setUserName] = useState('João Entregador');

  useEffect(() => {
    const savedLogs = storageService.getLogs();
    setLogs(savedLogs);
  }, []);

  const handleAction = (type: LogActionType) => {
    const newEntry: LogEntry = {
      id: crypto.randomUUID(),
      type,
      timestamp: new Date().toISOString(),
      value: type === 'SAIDA' ? 2.50 : 0
    };

    const updated = storageService.saveLog(newEntry);
    setLogs(updated);

    // Feedback
    const messages = {
      ENTRADA: 'Entrada registrada com sucesso!',
      SAIDA: 'Entrega registrada! + R$ 2,50',
      DEVOLUCAO: 'Devolução registrada.'
    };
    setToastMsg(messages[type]);
    setShowToast(true);
    setTimeout(() => setShowToast(false), 2500);
  };

  const counts = useMemo(() => {
    const today = new Date().toDateString();

    // Start of current week (Sunday)
    const now = new Date();
    const startOfWeek = new Date(now);
    startOfWeek.setDate(now.getDate() - now.getDay());
    startOfWeek.setHours(0, 0, 0, 0);

    const startOfYear = new Date(now.getFullYear(), 0, 1);

    const filterLogs = (start: Date, end: Date = new Date()) => {
       return logs.filter(l => {
         const d = new Date(l.timestamp);
         return l.type === 'SAIDA' && d >= start && d <= end;
       }).length;
    };

    return {
      today: logs.filter(l => l.type === 'SAIDA' && new Date(l.timestamp).toDateString() === today).length,
      week: filterLogs(startOfWeek),
      year: filterLogs(startOfYear)
    };
  }, [logs]);

  return (
    <div className="min-h-screen bg-slate-50 pb-20">
      {/* Header */}
      <header className="bg-slate-900 text-white p-6 shadow-xl sticky top-0 z-10">
        <div className="max-w-5xl mx-auto flex justify-between items-center">
          <div className="flex items-center gap-3">
            <div className="bg-blue-600 p-2 rounded-xl">
              <Package size={24} className="text-white" />
            </div>
            <div>
              <h1 className="text-xl font-bold tracking-tight">LogiTrack</h1>
              <p className="text-xs text-slate-400 font-medium uppercase tracking-widest">Painel de Controle</p>
            </div>
          </div>
          <div className="flex items-center gap-4">
             <div className="hidden sm:block text-right">
                <p className="text-sm font-bold">{userName}</p>
                <p className="text-[10px] text-blue-400 uppercase font-bold tracking-wider">Status: Online</p>
             </div>
             <button 
              className="p-2 hover:bg-slate-800 rounded-lg transition-colors text-slate-400"
              title="Configurações"
             >
                <Settings size={20} />
             </button>
          </div>
        </div>
      </header>

      <main className="max-w-5xl mx-auto p-4 md:p-6 space-y-8 mt-2">
        {/* Statistics Section */}
        <section>
          <div className="flex items-center justify-between mb-4 px-1">
            <h2 className="text-slate-800 font-bold text-lg flex items-center gap-2">
              <LayoutDashboard size={20} className="text-blue-500" /> Dashboard de Ganhos
            </h2>
          </div>
          <DashboardCards 
            deliveredToday={counts.today} 
            deliveredWeek={counts.week} 
            deliveredYear={counts.year} 
          />
        </section>

        {/* Actions Section */}
        <section className="space-y-4">
          <h2 className="text-slate-800 font-bold text-lg px-1">Ações Rápidas</h2>
          <ActionButtons onAction={handleAction} />
        </section>

        {/* Reports & History */}
        <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
          <div className="lg:col-span-2">
             <HistoryList logs={logs} />
          </div>

          <div className="space-y-6">
            <div className="bg-gradient-to-br from-slate-800 to-slate-900 p-6 rounded-3xl shadow-lg text-white">
              <h3 className="font-bold text-lg mb-2 flex items-center gap-2">
                <FileText size={20} className="text-blue-400" /> Relatórios
              </h3>
              <p className="text-slate-400 text-sm mb-6">
                Gere um resumo detalhado das suas entregas e ganhos da última semana em formato PDF.
              </p>

              <div className="mb-4">
                <label className="text-xs font-bold text-slate-500 uppercase mb-1 block">Nome no Relatório</label>
                <input 
                  type="text" 
                  value={userName}
                  onChange={(e) => setUserName(e.target.value)}
                  className="w-full bg-slate-700/50 border border-slate-700 rounded-xl px-4 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-blue-500"
                  placeholder="Seu nome"
                />
              </div>

              <button 
                onClick={() => generatePDF(logs, userName)}
                className="w-full bg-blue-600 hover:bg-blue-500 transition-colors py-4 rounded-2xl flex items-center justify-center gap-2 font-bold shadow-lg shadow-blue-900/20 active:scale-95"
              >
                <Download size={20} /> Gerar Relatório Semanal
              </button>
            </div>

            <div className="bg-white p-5 rounded-3xl border border-slate-100 shadow-sm">
              <h4 className="font-bold text-slate-800 text-sm mb-3">Dica de Produtividade</h4>
              <p className="text-slate-500 text-xs leading-relaxed">
                Mantenha seu histórico atualizado em tempo real para garantir que seus ganhos semanais estejam sempre precisos no fechamento da rota.
              </p>
            </div>
          </div>
        </div>
      </main>

      {/* Toast Notification */}
      {showToast && (
        <div className="fixed bottom-8 left-1/2 -translate-x-1/2 bg-slate-900 text-white px-6 py-3 rounded-2xl shadow-2xl flex items-center gap-3 animate-bounce border border-slate-700 z-50">
          <div className="bg-blue-600 rounded-full p-1">
            <Package size={14} />
          </div>
          <span className="font-bold text-sm">{toastMsg}</span>
        </div>
      )}
    </div>
  );
};

export default App;

