              <div className="mt-4 flex items-center justify-center gap-4">
                <button 
                  onClick={() => setQuantity(q => Math.max(1, q - 1))}
                  className="w-12 h-12 rounded-2xl border-2 border-slate-100 flex items-center justify-center text-xl font-bold text-slate-600 hover:bg-slate-50 transition-colors"
                >
                  -
                </button>
                <input 
                  type="number" 
                  value={quantity}
                  onChange={(e) => setQuantity(Math.max(1, parseInt(e.target.value) || 1))}
                  className="w-24 text-center text-3xl font-black text-slate-800 focus:outline-none"
                />
                <button 
                  onClick={() => setQuantity(q => q + 1)}
                  className="w-12 h-12 rounded-2xl border-2 border-slate-100 flex items-center justify-center text-xl font-bold text-slate-600 hover:bg-slate-50 transition-colors"
                >
                  +
                </button>
