            Cancelar
          </button>
          <button 
            onClick={() => {
              onConfirm(quantity);
              onClose();
            }}
            className={`flex-1 py-4 px-6 rounded-2xl font-bold text-white flex items-center justify-center gap-2 shadow-lg transition-all active:scale-95 ${
              type === 'SAIDA' ? 'bg-blue-600 hover:bg-blue-500 shadow-blue-200' : 'bg-emerald-600 hover:bg-emerald-500 shadow-emerald-200'
            }`}
          >
            Confirmar <ChevronRight size={20} />
          </button>
        </div>
      </div>
    </div>
  );
};

