import React, { useState } from 'react';
import { Eye, EyeOff, Package, TrendingUp, Calendar } from 'lucide-react';
import { VALOR_POR_PACOTE } from '../constants';

interface DashboardCardsProps {
  deliveredToday: number;
  deliveredWeek: number;
  deliveredYear: number;
}

const DashboardCards: React.FC<DashboardCardsProps> = ({ 
  deliveredToday, 
  deliveredWeek, 
  deliveredYear 
}) => {
  const [visible, setVisible] = useState<Record<string, boolean>>({
    today: true,
    week: true,
    year: true
  });

  const toggleVisibility = (key: string) => {
    setVisible(prev => ({ ...prev, [key]: !prev[key] }));
  };

  const formatCurrency = (count: number) => {
    return new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(count * VALOR_POR_PACOTE);
  };

  const Card = ({ title, count, icon: Icon, neonClass, borderClass, textClass, storageKey }: any) => (
    <div className={`relative overflow-hidden bg-slate-900/50 backdrop-blur-md border-2 ${borderClass} rounded-[2rem] p-6 transition-all hover:-translate-y-1 hover:shadow-2xl ${neonClass} group`}>
      <div className="absolute top-0 right-0 p-4">
        <button 
          onClick={() => toggleVisibility(storageKey)}
          className="text-slate-500 hover:text-white transition-colors"
        >
          {visible[storageKey] ? <Eye size={18} /> : <EyeOff size={18} />}
        </button>
      </div>

      <div className="flex flex-col h-full justify-between gap-4">
        <div className={`w-12 h-12 rounded-xl flex items-center justify-center ${textClass} bg-white/5`}>
          <Icon size={24} />
        </div>

        <div>
          <p className="text-slate-400 text-xs font-bold uppercase tracking-[0.2em] mb-1">{title}</p>
          <h2 className="text-3xl font-game font-bold text-white tracking-tight">
            {visible[storageKey] ? formatCurrency(count) : "••••••"}
          </h2>
          <div className="flex items-center gap-2 mt-3">
            <span className={`text-[10px] font-bold px-2 py-0.5 rounded-full bg-white/5 ${textClass} border ${borderClass}`}>
              {count} PACOTES
            </span>
          </div>
        </div>
      </div>

      {/* Glow effect on hover */}
      <div className={`absolute -bottom-8 -right-8 w-24 h-24 rounded-full blur-3xl opacity-20 group-hover:opacity-40 transition-opacity ${neonClass.split(' ')[0] === 'neon-blue' ? 'bg-blue-500' : neonClass.split(' ')[0] === 'neon-emerald' ? 'bg-emerald-500' : 'bg-purple-500'}`}></div>
    </div>
  );

  return (
    <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
      <Card 
        title="Missão Diária" 
        count={deliveredToday} 
        icon={TrendingUp} 
        neonClass="neon-blue"
        borderClass="border-blue-500/20"
        textClass="text-blue-400"
        storageKey="today"
      />
      <Card 
        title="Saldo Semanal" 
        count={deliveredWeek} 
        icon={Calendar} 
        neonClass="neon-emerald"
        borderClass="border-emerald-500/20"
        textClass="text-emerald-400"
        storageKey="week"
      />
      <Card 
        title="Nível Anual" 
        count={deliveredYear} 
        icon={Package} 
        neonClass="neon-purple"
        borderClass="border-purple-500/20"
        textClass="text-purple-400"
        storageKey="year"
      />
    </div>
  );
};

