import React from 'react';
import { LogEntry } from '../types';
import { VALOR_POR_PACOTE } from '../constants';
import { Calendar, ArrowDown, ArrowUp, RotateCcw, DollarSign } from 'lucide-react';

interface DailyStatsTableProps {
  logs: LogEntry[];
}

const DailyStatsTable: React.FC<DailyStatsTableProps> = ({ logs }) => {
  const dailyGroups = logs.reduce((acc: any, log) => {
    const date = new Date(log.timestamp).toLocaleDateString('pt-BR');
    if (!acc[date]) {
      acc[date] = { date, entrada: 0, saida: 0, devolucao: 0, total: 0 };
    }
    if (log.type === 'ENTRADA') acc[date].entrada++;
    if (log.type === 'SAIDA') {
      acc[date].saida++;
      acc[date].total += VALOR_POR_PACOTE;
    }
    if (log.type === 'DEVOLUCAO') acc[date].devolucao++;
    return acc;
  }, {});

  const sortedDays = Object.values(dailyGroups).sort((a: any, b: any) => {
    const [da, ma, ya] = a.date.split('/').map(Number);
    const [db, mb, yb] = b.date.split('/').map(Number);
    return new Date(yb, mb-1, db).getTime() - new Date(ya, ma-1, da).getTime();
  });

  return (
    <div className="bg-slate-900/40 border border-slate-800 rounded-[2rem] overflow-hidden backdrop-blur-sm">
      <div className="p-6 border-b border-slate-800 flex items-center justify-between">
        <h3 className="text-white font-game text-xl font-bold flex items-center gap-2">
          <Calendar size={20} className="text-blue-400" /> Registros Detalhados
        </h3>
        <span className="text-[10px] text-slate-500 font-bold uppercase tracking-widest">Compilado Diário</span>
      </div>

      <div className="overflow-x-auto">
        <table className="w-full text-left border-collapse">
          <thead>
            <tr className="bg-white/5">
              <th className="p-4 text-xs font-bold text-slate-400 uppercase tracking-widest">Data</th>
              <th className="p-4 text-xs font-bold text-emerald-400 uppercase tracking-widest"><div className="flex items-center gap-1"><ArrowDown size={14}/> Entrada</div></th>
              <th className="p-4 text-xs font-bold text-blue-400 uppercase tracking-widest"><div className="flex items-center gap-1"><ArrowUp size={14}/> Saída</div></th>
              <th className="p-4 text-xs font-bold text-orange-400 uppercase tracking-widest"><div className="flex items-center gap-1"><RotateCcw size={14}/> Devolução</div></th>
              <th className="p-4 text-xs font-bold text-white uppercase tracking-widest text-right"><div className="flex items-center justify-end gap-1"><DollarSign size={14}/> Ganhos</div></th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-800/50">
            {sortedDays.map((day: any) => (
              <tr key={day.date} className="hover:bg-white/5 transition-colors group">
                <td className="p-4 font-game font-bold text-slate-300">{day.date}</td>
                <td className="p-4"><span className="bg-emerald-500/10 text-emerald-400 px-3 py-1 rounded-lg font-bold text-sm">{day.entrada}</span></td>
                <td className="p-4"><span className="bg-blue-500/10 text-blue-400 px-3 py-1 rounded-lg font-bold text-sm">{day.saida}</span></td>
                <td className="p-4"><span className="bg-orange-500/10 text-orange-400 px-3 py-1 rounded-lg font-bold text-sm">{day.devolucao}</span></td>
                <td className="p-4 text-right">
                  <span className="text-white font-game text-lg font-bold">
                    {new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(day.total)}
                  </span>
                </td>
              </tr>
            ))}
            {sortedDays.length === 0 && (
              <tr>
                <td colSpan={5} className="p-10 text-center text-slate-500 italic">Nenhum dado consolidado disponível.</td>
              </tr>
            )}
          </tbody>
        </table>
      </div>
    </div>
  );
};

