import React from 'react';
import { LogEntry } from '../types';
import { ArrowDownLeft, ArrowUpRight, RotateCcw, Clock } from 'lucide-react';

interface HistoryListProps {
  logs: LogEntry[];
}

const HistoryList: React.FC<HistoryListProps> = ({ logs }) => {
  const getIcon = (type: string) => {
    switch (type) {
      case 'ENTRADA': return <ArrowDownLeft className="text-emerald-400" size={16} />;
      case 'SAIDA': return <ArrowUpRight className="text-blue-400" size={16} />;
      case 'DEVOLUCAO': return <RotateCcw className="text-orange-400" size={16} />;
      default: return null;
    }
  };

  const getLabel = (type: string) => {
    switch (type) {
      case 'ENTRADA': return 'Entrada de Lote';
      case 'SAIDA': return 'Entrega Efetuada';
      case 'DEVOLUCAO': return 'Devolução Processada';
      default: return type;
    }
  };

  const formatDate = (isoStr: string) => {
    const date = new Date(isoStr);
    return date.toLocaleTimeString('pt-BR', { hour: '2-digit', minute: '2-digit' });
  };

  const recentLogs = logs.slice(0, 10);

  return (
    <div className="bg-slate-900/40 rounded-[2rem] shadow-2xl border border-white/5 overflow-hidden backdrop-blur-sm">
      <div className="p-6 border-b border-white/5 flex justify-between items-center">
        <h3 className="font-game font-bold text-white text-lg flex items-center gap-3 uppercase tracking-wider">
          <Clock size={18} className="text-slate-500" /> Log de Campo
        </h3>
        <span className="text-[10px] font-bold text-slate-600 uppercase tracking-[0.2em]">Latest Sync</span>
      </div>

      {recentLogs.length === 0 ? (
        <div className="p-10 text-center text-slate-600 italic font-game uppercase tracking-widest">
          No signals detected.
        </div>
      ) : (
        <div className="divide-y divide-white/5">
          {recentLogs.map((log) => (
            <div key={log.id} className="p-5 flex items-center justify-between hover:bg-white/5 transition-all group">
              <div className="flex items-center gap-5">
                <div className="p-3 bg-white/5 rounded-xl border border-white/5 group-hover:border-white/10 transition-all">
                  {getIcon(log.type)}
                </div>
                <div>
                  <p className="text-sm font-game font-bold text-slate-200 uppercase tracking-tight">{getLabel(log.type)}</p>
                  <p className="text-[10px] text-slate-500 font-bold uppercase tracking-widest">{new Date(log.timestamp).toLocaleDateString('pt-BR')}</p>
                </div>
              </div>
              <div className="text-right">
                <p className="text-sm font-game font-bold text-white">{formatDate(log.timestamp)}</p>
                {log.type === 'SAIDA' && (
                  <p className="text-[10px] font-black text-emerald-400 uppercase">+ R$ 2,50</p>
                )}
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  );
};

export default HistoryList;

import React, { useState } from 'react';
import { X, Package, ChevronRight } from 'lucide-react';

interface BulkActionModalProps {
  isOpen: boolean;
  onClose: () => void;
  onConfirm: (quantity: number) => void;
  title: string;
  type: 'ENTRADA' | 'SAIDA';
}

const BulkActionModal: React.FC<BulkActionModalProps> = ({ isOpen, onClose, onConfirm, title, type }) => {
  const [quantity, setQuantity] = useState<number>(1);

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/80 backdrop-blur-md">
      <div className="bg-slate-900 border border-white/10 rounded-[3rem] w-full max-w-md shadow-[0_0_50px_rgba(0,0,0,0.5)] overflow-hidden animate-in fade-in zoom-in duration-200">
        <div className="p-8 flex justify-between items-center border-b border-white/5 bg-white/5">
          <h3 className="text-2xl font-game font-black text-white uppercase tracking-tighter">{title}</h3>
          <button onClick={onClose} className="p-2 hover:bg-white/10 rounded-full text-slate-500 transition-colors">
            <X size={24} />
          </button>
        </div>

        <div className="p-10">
          <div className="flex flex-col items-center gap-8">
            <div className={`p-6 rounded-[2rem] border-2 shadow-2xl ${type === 'SAIDA' ? 'bg-blue-500/10 border-blue-500/40 text-blue-400 neon-blue' : 'bg-emerald-500/10 border-emerald-500/40 text-emerald-400 neon-emerald'}`}>
              <Package size={56} />
            </div>

            <div className="text-center w-full">
              <p className="text-slate-500 text-[10px] font-bold uppercase tracking-[0.3em] mb-4">Set Units Quantity</p>
              <div className="flex items-center justify-center gap-6">
                <button 
                  onClick={() => setQuantity(q => Math.max(1, q - 1))}
                  className="w-14 h-14 rounded-2xl border-2 border-white/10 flex items-center justify-center text-2xl font-black text-white hover:bg-white/10 transition-all active:scale-90"
                >
                  -
                </button>
                <div className="relative">
                  <input 
                    type="number" 
                    value={quantity}
                    onChange={(e) => setQuantity(Math.max(1, parseInt(e.target.value) || 1))}
                    className="w-24 bg-transparent text-center text-5xl font-game font-black text-white focus:outline-none"
                  />
                  <div className="absolute -bottom-2 left-0 right-0 h-1 bg-white/10 rounded-full overflow-hidden">
                    <div className={`h-full transition-all duration-300 ${type === 'SAIDA' ? 'bg-blue-500' : 'bg-emerald-500'}`} style={{ width: `${Math.min(quantity * 10, 100)}%` }}></div>
                  </div>
                </div>
                <button 
                  onClick={() => setQuantity(q => q + 1)}
                  className="w-14 h-14 rounded-2xl border-2 border-white/10 flex items-center justify-center text-2xl font-black text-white hover:bg-white/10 transition-all active:scale-90"
                >
                  +
                </button>
              </div>
            </div>
          </div>
        </div>

        <div className="p-8 bg-black/40 flex gap-4">
          <button 
            onClick={onClose}
            className="flex-1 py-4 px-6 rounded-2xl font-game font-bold text-slate-400 hover:text-white transition-colors uppercase tracking-widest"
          >
            Abort
          </button>
          <button 
            onClick={() => {
              onConfirm(quantity);
              onClose();
            }}
            className={`flex-1 py-4 px-6 rounded-2xl font-game font-black text-white flex items-center justify-center gap-2 shadow-2xl transition-all active:scale-95 uppercase tracking-widest ${
              type === 'SAIDA' ? 'bg-blue-600 hover:bg-blue-500 border border-blue-400/30' : 'bg-emerald-600 hover:bg-emerald-500 border border-emerald-400/30'
            }`}
          >
            Execute <ChevronRight size={20} />
          </button>
        </div>
      </div>
    </div>
  );
};

export default BulkActionModal;

import React, { useState, useEffect, useMemo } from 'react';
import { Truck, Zap, FileText, Download, LayoutDashboard, Settings, Layers, ListPlus, Send, Table as TableIcon, Package } from 'lucide-react';
import DashboardCards from './components/DashboardCards';
import ActionButtons from './components/ActionButtons';
import HistoryList from './components/HistoryList';
import DailyStatsTable from './components/DailyStatsTable';
import BulkActionModal from './components/BulkActionModal';
import { LogEntry, LogActionType } from './types';
import { storageService } from './services/storageService';
import { generatePDF } from './services/pdfService';

const App: React.FC = () => {
  const [logs, setLogs] = useState<LogEntry[]>([]);
  const [showToast, setShowToast] = useState(false);
  const [toastMsg, setToastMsg] = useState('');
  const [userName, setUserName] = useState('João Entregador');
  const [activeTab, setActiveTab] = useState<'dash' | 'stats'>('dash');

  const [bulkModal, setBulkModal] = useState<{ isOpen: boolean; type: 'ENTRADA' | 'SAIDA' }>({
    isOpen: false,
    type: 'ENTRADA'
  });

  useEffect(() => {
    const savedLogs = storageService.getLogs();
    setLogs(savedLogs);
  }, []);

  const handleAction = (type: LogActionType) => {
    const newEntry: LogEntry = {
      id: crypto.randomUUID(),
      type,
      timestamp: new Date().toISOString(),
      value: type === 'SAIDA' ? 2.50 : 0
    };

    const updated = storageService.saveLog(newEntry);
    setLogs(updated);

    const messages = {
      ENTRADA: 'Sinal de entrada captado!',
      SAIDA: 'Entrega confirmada! +R$ 2,50',
      DEVOLUCAO: 'Pacote retornado ao estoque.'
    };
    setToastMsg(messages[type]);
    setShowToast(true);
    setTimeout(() => setShowToast(false), 2500);
  };

  const handleBulkAction = (quantity: number) => {
    const type = bulkModal.type;
    const newEntries: LogEntry[] = Array.from({ length: quantity }).map(() => ({
      id: crypto.randomUUID(),
      type: type as LogActionType,
      timestamp: new Date().toISOString(),
      value: type === 'SAIDA' ? 2.50 : 0
    }));

    const updated = storageService.saveBulkLogs(newEntries);
    setLogs(updated);

    setToastMsg(`${quantity} pacotes processados no sistema!`);
    setShowToast(true);
    setTimeout(() => setShowToast(false), 3000);
  };

  const counts = useMemo(() => {
    const today = new Date().toDateString();
    const now = new Date();
    const startOfWeek = new Date(now);
    startOfWeek.setDate(now.getDate() - now.getDay());
    startOfWeek.setHours(0, 0, 0, 0);
    const startOfYear = new Date(now.getFullYear(), 0, 1);

    const filterLogs = (start: Date, end: Date = new Date()) => {
       return logs.filter(l => {
         const d = new Date(l.timestamp);
         return l.type === 'SAIDA' && d >= start && d <= end;
       }).length;
    };

    return {
      today: logs.filter(l => l.type === 'SAIDA' && new Date(l.timestamp).toDateString() === today).length,
      week: filterLogs(startOfWeek),
      year: filterLogs(startOfYear)
    };
  }, [logs]);

  return (
    <div className="min-h-screen bg-[#020617] text-slate-200 pb-20 selection:bg-blue-500/30">
      {/* HUD Header */}
      <header className="bg-slate-900/80 backdrop-blur-xl border-b border-white/5 p-6 shadow-2xl sticky top-0 z-40">
        <div className="max-w-5xl mx-auto flex justify-between items-center">
          <div className="flex items-center gap-4">
            <div className="bg-gradient-to-tr from-blue-600 to-purple-600 p-2.5 rounded-2xl shadow-lg shadow-blue-500/20 rotate-3 relative">
              <Truck size={24} className="text-white -rotate-3" />
              <Zap size={12} className="absolute -top-1 -right-1 text-yellow-400 fill-yellow-400" />
            </div>
            <div>
              <h1 className="text-2xl font-game font-black tracking-wider text-white">FLUXO LOG</h1>
              <div className="flex items-center gap-2">
                <span className="w-2 h-2 bg-emerald-500 rounded-full animate-pulse"></span>
                <p className="text-[10px] text-slate-500 font-bold uppercase tracking-widest">Sistema Ativo</p>
              </div>
            </div>
          </div>

          <div className="flex items-center gap-6">
             <div className="hidden md:flex flex-col items-end">
                <p className="text-xs font-bold text-slate-400 uppercase tracking-tighter">Operador</p>
                <p className="text-sm font-game font-bold text-blue-400">{userName}</p>
             </div>
             <button className="p-3 bg-white/5 hover:bg-white/10 rounded-2xl border border-white/5 transition-all">
                <Settings size={20} className="text-slate-400" />
             </button>
          </div>
        </div>
      </header>

      {/* Navegação */}
      <nav className="max-w-5xl mx-auto px-4 mt-8">
        <div className="bg-slate-900/50 p-1.5 rounded-[2rem] border border-white/5 inline-flex gap-2">
          <button 
            onClick={() => setActiveTab('dash')}
            className={`flex items-center gap-2 px-6 py-3 rounded-[1.5rem] font-bold text-sm transition-all ${activeTab === 'dash' ? 'bg-blue-600 text-white shadow-lg shadow-blue-600/20' : 'text-slate-400 hover:text-white hover:bg-white/5'}`}
          >
            <LayoutDashboard size={18} /> Painel Principal
          </button>
          <button 
            onClick={() => setActiveTab('stats')}
            className={`flex items-center gap-2 px-6 py-3 rounded-[1.5rem] font-bold text-sm transition-all ${activeTab === 'stats' ? 'bg-blue-600 text-white shadow-lg shadow-blue-600/20' : 'text-slate-400 hover:text-white hover:bg-white/5'}`}
          >
            <TableIcon size={18} /> Dados Diários
          </button>
        </div>
      </nav>

      <main className="max-w-5xl mx-auto p-4 md:p-6 space-y-10">
        {activeTab === 'dash' ? (
          <>
            <section className="animate-in fade-in slide-in-from-bottom-4 duration-500">
              <DashboardCards 
                deliveredToday={counts.today} 
                deliveredWeek={counts.week} 
                deliveredYear={counts.year} 
              />
            </section>

            <section className="space-y-6 animate-in fade-in slide-in-from-bottom-6 duration-700">
              <h2 className="text-slate-400 font-game font-bold text-lg uppercase tracking-widest px-1">Ações Rápidas</h2>
              <ActionButtons onAction={handleAction} />

              <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                <button 
                  onClick={() => setBulkModal({ isOpen: true, type: 'ENTRADA' })}
                  className="group relative overflow-hidden bg-slate-900/40 border border-emerald-500/20 p-5 rounded-[2rem] flex items-center justify-between transition-all hover:border-emerald-500/50 active:scale-[0.98] neon-emerald"
                >
                  <div className="flex items-center gap-4">
                    <div className="p-3 bg-emerald-600 text-white rounded-2xl group-hover:scale-110 transition-transform">
                      <ListPlus size={24} />
                    </div>
                    <div className="text-left">
                      <p className="font-game font-bold text-white text-lg">Entrada em Massa</p>
                      <p className="text-[10px] text-emerald-400 font-bold uppercase">Processar Lote Recebido</p>
                    </div>
                  </div>
                  <Layers size={20} className="text-emerald-500/30 group-hover:text-emerald-500" />
                </button>

                <button 
                  onClick={() => setBulkModal({ isOpen: true, type: 'SAIDA' })}
                  className="group relative overflow-hidden bg-slate-900/40 border border-blue-500/20 p-5 rounded-[2rem] flex items-center justify-between transition-all hover:border-blue-500/50 active:scale-[0.98] neon-blue"
                >
                  <div className="flex items-center gap-4">
                    <div className="p-3 bg-blue-600 text-white rounded-2xl group-hover:scale-110 transition-transform">
                      <Send size={24} />
                    </div>
                    <div className="text-left">
                      <p className="font-game font-bold text-white text-lg">Saída em Massa</p>
                      <p className="text-[10px] text-blue-400 font-bold uppercase">Confirmar Múltiplas Entregas</p>
                    </div>
                  </div>
                  <Layers size={20} className="text-blue-500/30 group-hover:text-blue-500" />
                </button>
              </div>
            </section>

            <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
              <div className="lg:col-span-2">
                 <HistoryList logs={logs} />
              </div>
              <div className="space-y-6">
