  useEffect(() => {
    const unsubscribe = firebaseService.subscribeToLogs((updatedLogs) => {
      setLogs(updatedLogs);
      setLoading(false);
    });

    return () => unsubscribe();
  }, []);

  const handleAction = async (type: LogActionType) => {
    const newEntry: Omit<LogEntry, 'id'> = {
      type,
      timestamp: new Date().toISOString(),
      value: type === 'SAIDA' ? 2.50 : 0
    };

    try {
      await firebaseService.saveLog(newEntry);
