      <header className="bg-slate-900/80 backdrop-blur-xl border-b border-white/5 p-6 shadow-2xl sticky top-0 z-40">
        <div className="max-w-5xl mx-auto flex justify-between items-center">
          <div className="flex items-center gap-4">
            <div className="bg-gradient-to-tr from-blue-600 to-purple-600 p-2.5 rounded-2xl shadow-lg shadow-blue-500/20 rotate-3 relative">
              <Truck size={24} className="text-white -rotate-3" />
              <Zap size={12} className="absolute -top-1 -right-1 text-yellow-400 fill-yellow-400" />
            </div>
            <div>
              <h1 className="text-2xl font-game font-black tracking-wider text-white">FLUXO LOG</h1>
              <div className="flex items-center gap-2">
                <span className="w-2 h-2 bg-emerald-500 rounded-full animate-pulse"></span>
                <p className="text-[10px] text-slate-500 font-bold uppercase tracking-widest">Sincronizado</p>
              </div>
            </div>
          </div>

          <div className="flex items-center gap-6">
             <div className="hidden md:flex flex-col items-end">
                <p className="text-xs font-bold text-slate-400 uppercase tracking-tighter">Operador</p>
