import { createClient } from "@supabase/supabase-js";

const supabaseUrl = "https://cnimxlxjtyqitcmjzszs.supabase.co";
const supabaseAnonKey = "sb_publishable_4lWugVqrA5b7Sn4VF7bV6Q_ZAb5WcqT";

export const supabase = createClient(supabaseUrl, supabaseAnonKey);

import { supabase } from "../supabaseConfig";
import { LogEntry } from "../types";

const TABLE_NAME = "logs";

export const supabaseService = {
  // Inicializa dados e escuta mudanças em tempo real
  subscribeToLogs: (callback: (logs: LogEntry[]) => void) => {
    // Busca inicial
    const fetchLogs = async () => {
      const { data, error } = await supabase
        .from(TABLE_NAME)
        .select("*")
        .order("timestamp", { ascending: false });

      if (!error && data) {
        callback(data as LogEntry[]);
      }
    };

    fetchLogs();

    // Inscrição Realtime
    const channel = supabase
      .channel("schema-db-changes")
      .on(
        "postgres_changes",
        {
          event: "*",
          schema: "public",
          table: TABLE_NAME,
        },
        () => {
          fetchLogs(); // Atualiza a lista quando houver qualquer mudança
        }
      )
      .subscribe();

    return () => {
      supabase.removeChannel(channel);
    };
  },

  // Salva um único log
  saveLog: async (entry: Omit<LogEntry, 'id'>) => {
    const { error } = await supabase
      .from(TABLE_NAME)
      .insert([entry]);

    if (error) {
      console.error("Erro Supabase:", error);
      throw error;
    }
  },

  // Salva múltiplos logs (Supabase suporta arrays nativamente)
  saveBulkLogs: async (entries: Omit<LogEntry, 'id'>[]) => {
    const { error } = await supabase
      .from(TABLE_NAME)
      .insert(entries);

    if (error) {
      console.error("Erro Bulk Supabase:", error);
      throw error;
    }
  }
};

