import { supabase } from "../supabaseConfig";
import { LogEntry } from "../types";

const TABLE_NAME = "logs";

export const supabaseService = {
  // Inicializa dados e escuta mudanças em tempo real
  subscribeToLogs: (callback: (logs: LogEntry[], error?: any) => void) => {
    // Busca inicial
    const fetchLogs = async () => {
      try {
        const { data, error } = await supabase
          .from(TABLE_NAME)
          .select("*")
          .order("timestamp", { ascending: false });

        if (error) {
          console.error("Erro ao buscar logs no Supabase:", error);
          callback([], error);
        } else {
          callback((data as LogEntry[]) || [], undefined);
        }
      } catch (err) {
        console.error("Erro crítico na conexão com Supabase:", err);
        callback([], err);
      }
    };

    fetchLogs();

    // Inscrição Realtime
    const channel = supabase
      .channel("schema-db-changes")
      .on(
        "postgres_changes",
        {
          event: "*",
          schema: "public",
          table: TABLE_NAME,
        },
        () => {
          fetchLogs();
        }
      )
      .subscribe();

    return () => {
      supabase.removeChannel(channel);
    };
  },

  saveLog: async (entry: Omit<LogEntry, 'id'>) => {
    const { error } = await supabase
      .from(TABLE_NAME)
      .insert([entry]);

    if (error) {
      console.error("Erro ao salvar log no Supabase:", error);
      throw error;
    }
  },

  saveBulkLogs: async (entries: Omit<LogEntry, 'id'>[]) => {
    const { error } = await supabase
      .from(TABLE_NAME)
      .insert(entries);

    if (error) {
      console.error("Erro ao salvar lote no Supabase:", error);
      throw error;
    }
  }
};

