    const filterLogs = (start: Date, type: LogActionType = 'SAIDA') => {
       return logs.filter(l => {
         const d = new Date(l.timestamp);
         return l.type === type && d >= start;
       }).length;
    };

    return {
      today: logs.filter(l => l.type === 'SAIDA' && new Date(l.timestamp).toDateString() === todayStr).length,
      week: filterLogs(startOfWeek),
      year: filterLogs(startOfYear)
    };
  }, [logs]);

