import React, { useState, useEffect } from 'react';
import { Truck, Zap, Mail, Lock, ArrowRight, UserPlus, LogIn, Check } from 'lucide-react';
import { supabaseService } from '../services/supabaseService';

interface LoginProps {
  onLoginSuccess: () => void;
}

const Login: React.FC<LoginProps> = ({ onLoginSuccess }) => {
  const [isSignUp, setIsSignUp] = useState(false);
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [rememberMe, setRememberMe] = useState(false);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  // Carregar e-mail salvo ao iniciar
  useEffect(() => {
    const savedEmail = localStorage.getItem('fluxolog_saved_email');
    if (savedEmail) {
      setEmail(savedEmail);
      setRememberMe(true);
    }
  }, []);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    setError(null);

    try {
      if (isSignUp) {
        await supabaseService.signUp(email, password);
        setError("Conta criada! Verifique seu e-mail ou faça login.");
        setIsSignUp(false);
      } else {
        await supabaseService.signIn(email, password);

        // Lógica de Salvar Login
        if (rememberMe) {
          localStorage.setItem('fluxolog_saved_email', email);
        } else {
          localStorage.removeItem('fluxolog_saved_email');
        }

        onLoginSuccess();
      }
    } catch (err: any) {
      setError(err.message || "Ocorreu um erro na autenticação.");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="min-h-screen bg-[#020617] flex items-center justify-center p-4 relative overflow-hidden">
      {/* Background Orbs */}
      <div className="absolute top-[-10%] left-[-10%] w-72 h-72 bg-blue-600/10 rounded-full blur-[120px]"></div>
      <div className="absolute bottom-[-10%] right-[-10%] w-72 h-72 bg-purple-600/10 rounded-full blur-[120px]"></div>

      <div className="w-full max-w-md animate-in fade-in zoom-in duration-500">
        <div className="bg-slate-900/40 backdrop-blur-2xl border border-white/5 rounded-[3rem] p-8 md:p-12 shadow-2xl relative overflow-hidden">

          <div className="flex flex-col items-center mb-10">
            <div className="bg-gradient-to-tr from-blue-600 to-purple-600 p-4 rounded-3xl shadow-xl shadow-blue-500/20 mb-6 rotate-3">
              <Truck size={40} className="text-white -rotate-3" />
            </div>
            <h1 className="text-4xl font-game font-black text-white tracking-tighter uppercase">Fluxo Log</h1>
            <p className="text-slate-500 text-[10px] font-bold uppercase tracking-[0.4em] mt-2">Sincronização de Dados</p>
          </div>

          <form onSubmit={handleSubmit} className="space-y-6">
            {error && (
              <div className="bg-red-500/10 border border-red-500/20 text-red-400 text-xs py-3 px-4 rounded-xl text-center font-bold uppercase tracking-wider">
                {error}
              </div>
            )}

            <div className="space-y-4">
              <div className="relative group">
                <div className="absolute inset-y-0 left-0 pl-4 flex items-center pointer-events-none text-slate-500 group-focus-within:text-blue-400 transition-colors">
                  <Mail size={18} />
                </div>
                <input
                  type="email"
                  required
                  value={email}
                  onChange={(e) => setEmail(e.target.value)}
                  className="block w-full pl-12 pr-4 py-4 bg-white/5 border border-white/10 rounded-2xl text-white text-sm focus:outline-none focus:ring-2 focus:ring-blue-500/50 transition-all placeholder:text-slate-600 font-medium"
                  placeholder="Seu e-mail"
                />
              </div>

              <div className="relative group">
                <div className="absolute inset-y-0 left-0 pl-4 flex items-center pointer-events-none text-slate-500 group-focus-within:text-blue-400 transition-colors">
                  <Lock size={18} />
                </div>
                <input
                  type="password"
                  required
                  value={password}
                  onChange={(e) => setPassword(e.target.value)}
                  className="block w-full pl-12 pr-4 py-4 bg-white/5 border border-white/10 rounded-2xl text-white text-sm focus:outline-none focus:ring-2 focus:ring-blue-500/50 transition-all placeholder:text-slate-600 font-medium"
                  placeholder="Sua senha"
                />
              </div>
            </div>

            {/* Checkbox Salvar Login */}
            <div className="flex items-center justify-between px-1">
              <button 
                type="button"
                onClick={() => setRememberMe(!rememberMe)}
                className="flex items-center gap-3 group cursor-pointer"
              >
                <div className={`w-6 h-6 rounded-lg border-2 transition-all flex items-center justify-center ${rememberMe ? 'bg-blue-600 border-blue-600' : 'border-white/10 bg-white/5 group-hover:border-white/20'}`}>
                  {rememberMe && <Check size={14} className="text-white" />}
                </div>
                <span className="text-xs font-bold text-slate-400 uppercase tracking-widest group-hover:text-slate-300 transition-colors">
                  Salvar meu login
                </span>
              </button>
            </div>

            <button
              type="submit"
              disabled={loading}
              className="w-full bg-blue-600 hover:bg-blue-500 disabled:bg-blue-800 disabled:opacity-50 text-white font-game font-black text-lg py-5 rounded-2xl flex items-center justify-center gap-3 shadow-xl shadow-blue-900/30 transition-all active:scale-95 uppercase tracking-widest border border-blue-400/20"
            >
              {loading ? (
                <div className="w-6 h-6 border-2 border-white/30 border-t-white rounded-full animate-spin"></div>
              ) : (
                <>
                  {isSignUp ? "Criar Conta" : "Entrar no Sistema"}
                  <ArrowRight size={20} />
                </>
              )}
            </button>
          </form>

          <div className="mt-8 text-center">
            <button
              onClick={() => setIsSignUp(!isSignUp)}
              className="text-slate-500 hover:text-blue-400 text-xs font-bold uppercase tracking-widest transition-colors flex items-center justify-center gap-2 mx-auto"
            >
              {isSignUp ? (
                <><LogIn size={14} /> Já tem conta? Entre aqui</>
              ) : (
                <><UserPlus size={14} /> Novo por aqui? Crie sua conta</>
              )}
            </button>
          </div>
        </div>

        <p className="mt-8 text-center text-[10px] text-slate-600 font-bold uppercase tracking-[0.3em]">
          &copy; 2024 FluxoLog Intelligence v2.0
        </p>
      </div>
    </div>
  );
};

export default Login;

export const VALOR_POR_PACOTE = 2.50;
export const STORAGE_KEY = 'logitrac_package_logs';
export const SUPABASE_CACHE_KEY = 'fluxolog_supabase_cache';

import React, { useState, useEffect, useMemo } from 'react';
import { Truck, Zap, FileText, Download, LayoutDashboard, Settings, Layers, ListPlus, Send, Table as TableIcon, Package, AlertTriangle, RefreshCw, LogOut } from 'lucide-react';
import DashboardCards from './components/DashboardCards';
import ActionButtons from './components/ActionButtons';
import DailyStatsTable from './components/DailyStatsTable';
import BulkActionModal from './components/BulkActionModal';
import Login from './components/Login';
import { LogEntry, LogActionType } from './types';
import { supabaseService } from './services/supabaseService';
import { generatePDF } from './services/pdfService';
import { SUPABASE_CACHE_KEY } from './constants';

const App: React.FC = () => {
  const [session, setSession] = useState<any>(null);

  // Inicializa o estado com dados do cache para carregamento instantâneo
  const [logs, setLogs] = useState<LogEntry[]>(() => {
    const cached = localStorage.getItem(SUPABASE_CACHE_KEY);
    return cached ? JSON.parse(cached) : [];
  });

  const [loading, setLoading] = useState(true);
  const [isSyncing, setIsSyncing] = useState(false);
  const [error, setError] = useState<any>(null);
  const [showToast, setShowToast] = useState(false);
  const [toastMsg, setToastMsg] = useState('');
  const [userName, setUserName] = useState('Operador Logístico');
  const [activeTab, setActiveTab] = useState<'dash' | 'stats'>('dash');

  const [bulkModal, setBulkModal] = useState<{ isOpen: boolean; type: 'ENTRADA' | 'SAIDA' }>({
    isOpen: false,
    type: 'ENTRADA'
  });

  // Verificar sessão inicial
  useEffect(() => {
    supabaseService.getSession().then(session => {
      setSession(session);
      if (!session) setLoading(false);
    });
  }, []);

  // Sincronização em Tempo Real com Supabase
  useEffect(() => {
    if (!session) return;

    setIsSyncing(true);
    const unsubscribe = supabaseService.subscribeToLogs((updatedLogs, supabaseError) => {
      if (supabaseError) {
        setError(supabaseError);
      } else {
        setLogs(updatedLogs);
        // Atualiza o cache local sempre que novos dados chegam
        localStorage.setItem(SUPABASE_CACHE_KEY, JSON.stringify(updatedLogs));
      }
      setLoading(false);
      setIsSyncing(false);
    });

    return () => unsubscribe();
  }, [session]);

  // Handler para recarregar dados quando a aba volta a ficar visível
  useEffect(() => {
    const handleVisibilityChange = () => {
      if (document.visibilityState === 'visible' && session) {
        // O subscribeToLogs já lida com o real-time, 
        // mas aqui poderíamos forçar um refetch se necessário.
        console.log('App visível, sincronizando...');
      }
    };
    document.addEventListener('visibilitychange', handleVisibilityChange);
    return () => document.removeEventListener('visibilitychange', handleVisibilityChange);
  }, [session]);

  const handleLogout = async () => {
    await supabaseService.signOut();
    localStorage.removeItem(SUPABASE_CACHE_KEY);
    setSession(null);
    setLogs([]);
  };

  const handleAction = async (type: LogActionType) => {
    const newEntry: Omit<LogEntry, 'id'> = {
      type,
      timestamp: new Date().toISOString(),
      value: type === 'SAIDA' ? 2.50 : 0
    };

    try {
      await supabaseService.saveLog(newEntry);
      const messages = {
        ENTRADA: 'Entrada registrada!',
        SAIDA: 'Entrega sincronizada! +R$ 2,50',
        DEVOLUCAO: 'Retorno salvo com sucesso.'
      };
      setToastMsg(messages[type]);
      setShowToast(true);
      setTimeout(() => setShowToast(false), 2500);
    } catch (err) {
      setToastMsg('Erro ao salvar no Supabase.');
      setShowToast(true);
    }
  };

  const handleBulkAction = async (quantity: number) => {
    const type = bulkModal.type;
    const newEntries: Omit<LogEntry, 'id'>[] = Array.from({ length: quantity }).map(() => ({
      type: type as LogActionType,
      timestamp: new Date().toISOString(),
      value: type === 'SAIDA' ? 2.50 : 0
    }));

    try {
      await supabaseService.saveBulkLogs(newEntries);
      setToastMsg(`${quantity} pacotes sincronizados!`);
      setShowToast(true);
      setTimeout(() => setShowToast(false), 3000);
    } catch (err) {
      setToastMsg('Falha na sincronização em lote.');
      setShowToast(true);
    }
  };

  const counts = useMemo(() => {
    const todayStr = new Date().toDateString();
    const now = new Date();
    const startOfWeek = new Date(now);
    startOfWeek.setDate(now.getDate() - now.getDay());
    startOfWeek.setHours(0, 0, 0, 0);
    const startOfYear = new Date(now.getFullYear(), 0, 1);

    const filterLogs = (start: Date, type: LogActionType = 'SAIDA') => {
       return logs.filter(l => {
         const d = new Date(l.timestamp);
         return l.type === type && d >= start;
       }).length;
    };

    return {
      today: logs.filter(l => l.type === 'SAIDA' && new Date(l.timestamp).toDateString() === todayStr).length,
      week: filterLogs(startOfWeek),
      year: filterLogs(startOfYear)
    };
  }, [logs]);

  // Se não estiver logado, mostra tela de Login
  if (!session && !loading) {
    return <Login onLoginSuccess={() => supabaseService.getSession().then(setSession)} />;
  }

  // Só mostra o loader de tela cheia se não houver NENHUM dado em cache
  if (loading && logs.length === 0) {
    return (
      <div className="min-h-screen bg-[#020617] flex flex-col items-center justify-center gap-6">
        <div className="relative">
          <div className="w-20 h-20 border-4 border-blue-500/20 border-t-blue-500 rounded-full animate-spin"></div>
          <Zap className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 text-blue-400 animate-pulse" />
        </div>
        <div className="text-center">
          <h2 className="text-white font-game text-2xl font-black tracking-tighter uppercase">Conectando</h2>
          <p className="text-slate-500 text-xs font-bold uppercase tracking-[0.3em] mt-2 italic">Acessando banco de dados...</p>
        </div>
      </div>
    );
  }

  if (error && logs.length === 0) {
    return (
      <div className="min-h-screen bg-[#020617] flex flex-col items-center justify-center p-6 text-center">
        <div className="bg-red-500/10 border border-red-500/30 p-8 rounded-[2.5rem] max-w-md w-full shadow-2xl">
          <AlertTriangle className="text-red-500 mx-auto mb-4" size={48} />
          <h2 className="text-white font-game text-2xl font-black mb-2 uppercase">Erro de Conexão</h2>
          <p className="text-slate-400 text-sm mb-6 font-medium">
            Não foi possível carregar os dados. Verifique a tabela logs ou sua conexão.
          </p>
          <div className="flex flex-col gap-3">
            <button 
              onClick={() => window.location.reload()}
              className="w-full bg-red-600 hover:bg-red-500 text-white font-bold py-4 rounded-2xl flex items-center justify-center gap-2 transition-all active:scale-95"
            >
              <RefreshCw size={20} /> Tentar Novamente
            </button>
            <button 
              onClick={handleLogout}
              className="w-full bg-white/5 hover:bg-white/10 text-slate-400 font-bold py-4 rounded-2xl transition-all"
            >
              Fazer Logout
            </button>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-[#020617] text-slate-200 pb-20 selection:bg-blue-500/30">
      <header className="bg-slate-900/80 backdrop-blur-xl border-b border-white/5 p-6 shadow-2xl sticky top-0 z-40">
        <div className="max-w-5xl mx-auto flex justify-between items-center">
          <div className="flex items-center gap-4">
            <div className="bg-gradient-to-tr from-blue-600 to-purple-600 p-2.5 rounded-2xl shadow-lg shadow-blue-500/20 rotate-3 relative">
              <Truck size={24} className="text-white -rotate-3" />
              <Zap size={12} className="absolute -top-1 -right-1 text-yellow-400 fill-yellow-400" />
            </div>
            <div>
              <h1 className="text-2xl font-game font-black tracking-wider text-white">FLUXO LOG</h1>
              <div className="flex items-center gap-2">
                <span className={`w-2 h-2 rounded-full ${isSyncing ? 'bg-blue-500 animate-ping' : 'bg-emerald-500 animate-pulse'}`}></span>
                <p className="text-[10px] text-slate-500 font-bold uppercase tracking-widest">
                  {isSyncing ? 'Sincronizando...' : 'Dados Sincronizados'}
                </p>
              </div>
            </div>
          </div>

          <div className="flex items-center gap-6">
             <div className="hidden md:flex flex-col items-end">
                <p className="text-xs font-bold text-slate-400 uppercase tracking-tighter">Operador</p>
                <p className="text-sm font-game font-bold text-blue-400">{session?.user?.email?.split('@')[0]}</p>
             </div>
             <button 
                onClick={handleLogout}
                className="p-3 bg-red-500/10 hover:bg-red-500/20 rounded-2xl border border-red-500/20 transition-all group"
                title="Sair do Sistema"
             >
                <LogOut size={20} className="text-red-400 group-hover:scale-110 transition-transform" />
             </button>
          </div>
        </div>
      </header>

      <nav className="max-w-5xl mx-auto px-4 mt-8">
        <div className="bg-slate-900/50 p-1.5 rounded-[2rem] border border-white/5 inline-flex gap-2">
          <button 
            onClick={() => setActiveTab('dash')}
            className={`flex items-center gap-2 px-6 py-3 rounded-[1.5rem] font-bold text-sm transition-all ${activeTab === 'dash' ? 'bg-blue-600 text-white shadow-lg shadow-blue-600/20' : 'text-slate-400 hover:text-white hover:bg-white/5'}`}
          >
            <LayoutDashboard size={18} /> Painel Principal
          </button>
          <button 
            onClick={() => setActiveTab('stats')}
            className={`flex items-center gap-2 px-6 py-3 rounded-[1.5rem] font-bold text-sm transition-all ${activeTab === 'stats' ? 'bg-blue-600 text-white shadow-lg shadow-blue-600/20' : 'text-slate-400 hover:text-white hover:bg-white/5'}`}
          >
            <TableIcon size={18} /> Dados Diários
          </button>
        </div>
      </nav>

      <main className="max-w-5xl mx-auto p-4 md:p-6 space-y-10">
        {activeTab === 'dash' ? (
          <>
            <section className="animate-in fade-in slide-in-from-bottom-4 duration-500">
              <DashboardCards 
                deliveredToday={counts.today} 
                deliveredWeek={counts.week} 
                deliveredYear={counts.year} 
              />
            </section>

            <section className="space-y-6 animate-in fade-in slide-in-from-bottom-6 duration-700">
              <h2 className="text-slate-400 font-game font-bold text-lg uppercase tracking-widest px-1">Ações Rápidas</h2>
              <ActionButtons onAction={handleAction} />

              <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                <button 
                  onClick={() => setBulkModal({ isOpen: true, type: 'ENTRADA' })}
                  className="group relative overflow-hidden bg-slate-900/40 border border-emerald-500/20 p-5 rounded-[2rem] flex items-center justify-between transition-all hover:border-emerald-500/50 active:scale-[0.98] neon-emerald"
                >
                  <div className="flex items-center gap-4">
                    <div className="p-3 bg-emerald-600 text-white rounded-2xl group-hover:scale-110 transition-transform shadow-lg shadow-emerald-500/20">
                      <ListPlus size={24} />
                    </div>
                    <div className="text-left">
                      <p className="font-game font-bold text-white text-lg">Entrada em Massa</p>
                      <p className="text-[10px] text-emerald-400 font-bold uppercase tracking-wider">Lote Supabase</p>
                    </div>
                  </div>
                  <Layers size={20} className="text-emerald-500/30 group-hover:text-emerald-500 transition-colors" />
                </button>

                <button 
                  onClick={() => setBulkModal({ isOpen: true, type: 'SAIDA' })}
                  className="group relative overflow-hidden bg-slate-900/40 border border-blue-500/20 p-5 rounded-[2rem] flex items-center justify-between transition-all hover:border-blue-500/50 active:scale-[0.98] neon-blue"
                >
                  <div className="flex items-center gap-4">
                    <div className="p-3 bg-blue-600 text-white rounded-2xl group-hover:scale-110 transition-transform shadow-lg shadow-blue-500/20">
                      <Send size={24} />
                    </div>
                    <div className="text-left">
                      <p className="font-game font-bold text-white text-lg">Saída em Massa</p>
                      <p className="text-[10px] text-blue-400 font-bold uppercase tracking-wider">Entrega em Lote</p>
                    </div>
                  </div>
                  <Layers size={20} className="text-blue-500/30 group-hover:text-blue-500 transition-colors" />
                </button>
              </div>
            </section>

            <section className="animate-in fade-in slide-in-from-bottom-8 duration-900">
              <div className="max-w-2xl mx-auto">
                <div className="bg-gradient-to-br from-slate-900 to-black p-8 rounded-[2.5rem] border border-blue-500/20 shadow-2xl relative overflow-hidden group">
                  <div className="absolute top-0 right-0 w-32 h-32 bg-blue-600/10 blur-[60px] group-hover:bg-blue-600/20 transition-all"></div>
                  <div className="flex flex-col md:flex-row md:items-center justify-between gap-6">
                    <div className="flex-1">
                      <h3 className="font-game font-bold text-2xl text-white mb-2 flex items-center gap-2 tracking-tight">
                        <FileText size={20} className="text-blue-400" /> Relatórios Supabase
                      </h3>
                      <p className="text-slate-500 text-xs mb-6 uppercase font-bold tracking-widest">Base de dados centralizada e sincronizada</p>
                      <div className="mb-2">
                        <label className="text-[10px] font-bold text-slate-500 uppercase mb-2 block tracking-widest">Responsável Logístico</label>
                        <input 
                          type="text" 
                          value={userName}
                          onChange={(e) => setUserName(e.target.value)}
                          className="w-full bg-white/5 border border-white/10 rounded-2xl px-4 py-3 text-sm focus:outline-none focus:ring-2 focus:ring-blue-500 text-white font-game"
                          placeholder="Nome do Operador"
                        />
                      </div>
                    </div>
                    <div className="md:w-64">
                      <button 
                        onClick={() => generatePDF(logs, userName)}
                        className="w-full bg-blue-600 hover:bg-blue-500 transition-all py-6 rounded-2xl flex flex-col items-center justify-center gap-2 font-bold text-white shadow-xl shadow-blue-900/20 active:scale-95 border border-blue-400/20"
                      >
                        <Download size={24} />
                        <span className="text-sm uppercase tracking-tighter">Baixar Relatório PDF</span>
                      </button>
                    </div>
                  </div>
                </div>
              </div>
            </section>
          </>
        ) : (
          <section className="animate-in fade-in zoom-in duration-300">
            <DailyStatsTable logs={logs} />
          </section>
        )}
      </main>

      <BulkActionModal 
        isOpen={bulkModal.isOpen}
        type={bulkModal.type}
        title={bulkModal.type === 'SAIDA' ? 'Sincronizar Lote Saída' : 'Sincronizar Lote Entrada'}
        onClose={() => setBulkModal({ ...bulkModal, isOpen: false })}
        onConfirm={handleBulkAction}
      />

      {showToast && (
        <div className="fixed bottom-8 left-1/2 -translate-x-1/2 bg-slate-900 text-white px-8 py-4 rounded-[1.5rem] shadow-2xl flex items-center gap-4 animate-in slide-in-from-bottom-full border border-blue-500/30 z-50">
          <div className="bg-blue-600 rounded-xl p-1.5 shadow-lg shadow-blue-500/40"><Zap size={18} /></div>
          <span className="font-game font-bold text-sm tracking-widest uppercase">{toastMsg}</span>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { Eye, EyeOff, Package, TrendingUp, Calendar, Zap } from 'lucide-react';
import { VALOR_POR_PACOTE } from '../constants';

interface DashboardCardsProps {
  deliveredToday: number;
  deliveredWeek: number;
  deliveredYear: number;
}

const DashboardCards: React.FC<DashboardCardsProps> = ({ 
  deliveredToday, 
  deliveredWeek, 
  deliveredYear 
}) => {
  const [visible, setVisible] = useState<Record<string, boolean>>({
    today: true,
    week: true,
    year: true
  });

  const toggleVisibility = (key: string) => {
    setVisible(prev => ({ ...prev, [key]: !prev[key] }));
  };

  const formatCurrency = (count: number) => {
    return new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(count * VALOR_POR_PACOTE);
  };

  return (
    <div className="relative overflow-hidden bg-slate-900/40 backdrop-blur-2xl border-2 border-blue-500/20 rounded-[3rem] p-8 md:p-10 transition-all shadow-2xl neon-blue group">
      {/* Header do Card */}
      <div className="flex flex-col md:flex-row md:items-center justify-between mb-10 gap-6">
        <div className="flex items-center gap-5">
          <div className="p-4 bg-blue-600 text-white rounded-[1.5rem] shadow-xl shadow-blue-500/30 group-hover:rotate-6 transition-transform">
            <TrendingUp size={32} />
          </div>
          <div>
            <h2 className="text-3xl font-game font-black text-white tracking-tighter uppercase">Monitoramento de Ganhos</h2>
            <p className="text-[10px] text-slate-500 font-bold uppercase tracking-[0.3em] mt-1">Sincronização de produtividade em tempo real</p>
          </div>
        </div>
        <div className="hidden md:block bg-white/5 px-4 py-2 rounded-2xl border border-white/5">
           <p className="text-[10px] font-black text-blue-400 uppercase tracking-widest flex items-center gap-2">
             <Zap size={12} className="fill-blue-400" /> Taxa Atual: R$ {VALOR_POR_PACOTE.toFixed(2)} / Pacote
           </p>
        </div>
      </div>

      {/* Grid de Valores */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-10 items-end">

        {/* Período: DIA (Destaque) */}
        <div className="relative p-6 bg-white/5 rounded-[2rem] border border-white/5 hover:border-blue-500/30 transition-all">
          <div className="absolute top-4 right-4">
            <button onClick={() => toggleVisibility('today')} className="text-slate-500 hover:text-white transition-colors">
              {visible.today ? <Eye size={18} /> : <EyeOff size={18} />}
            </button>
          </div>
          <p className="text-blue-400 text-xs font-bold uppercase tracking-widest mb-1">Rota do Dia</p>
          <p className="text-[10px] text-slate-500 font-bold uppercase mb-4">Período: Hoje</p>
          <h3 className="text-4xl font-game font-black text-white tracking-tight mb-3">
            {visible.today ? formatCurrency(deliveredToday) : "••••••"}
          </h3>
