import { jsPDF } from 'jspdf';
import autoTable from 'jspdf-autotable';
import { LogEntry, DailySummary } from '../types';
import { VALOR_POR_PACOTE } from '../constants';

export const generatePDF = (logs: LogEntry[], userName: string = 'Operador Logístico') => {
  const doc = new jsPDF();
  const dateStr = new Date().toLocaleDateString('pt-BR');
  const pageWidth = doc.internal.pageSize.getWidth();
  const pageHeight = doc.internal.pageSize.getHeight();

  // --- FUNDO DARK ---
  doc.setFillColor(2, 6, 23); // #020617
  doc.rect(0, 0, pageWidth, pageHeight, 'F');

  // --- EFEITOS DE GLOW (DECORATIVOS) ---
  doc.setGState(new (doc as any).GState({ opacity: 0.15 }));
  doc.setFillColor(37, 99, 235); // Azul
  doc.circle(0, 0, 50, 'F');
  doc.setFillColor(147, 51, 234); // Roxo
  doc.circle(pageWidth, pageHeight, 60, 'F');
  doc.setGState(new (doc as any).GState({ opacity: 1 }));

  // --- CABEÇALHO ---
  // Ícone Simulado
  doc.setFillColor(37, 99, 235);
  doc.roundedRect(14, 15, 12, 12, 3, 3, 'F');
  doc.setTextColor(255, 255, 255);
  doc.setFontSize(8);
  doc.setFont('helvetica', 'bold');
  doc.text('FL', 18, 23);

  // Título do App
  doc.setFontSize(22);
  doc.setTextColor(255, 255, 255);
  doc.text('FLUXO LOG', 32, 23);

  doc.setFontSize(9);
  doc.setTextColor(100, 116, 139); // Slate 400
  doc.text('INTELIGÊNCIA EM LOGÍSTICA', 32, 28);

  // Info Direita
  doc.setFontSize(8);
  doc.text(`EMISSÃO: ${dateStr}`, pageWidth - 14, 20, { align: 'right' });
  doc.setTextColor(37, 99, 235);
  doc.text(`OPERADOR: ${userName.toUpperCase()}`, pageWidth - 14, 25, { align: 'right' });

  // --- LINHA DIVISORA NEON ---
  doc.setDrawColor(37, 99, 235);
  doc.setLineWidth(0.5);
  doc.line(14, 35, pageWidth - 14, 35);

  // --- CÁLCULOS ---
  const now = new Date();
  const sevenDaysAgo = new Date();
  sevenDaysAgo.setDate(now.getDate() - 7);
  const recentLogs = logs.filter(log => new Date(log.timestamp) >= sevenDaysAgo);

  const dailyData: Record<string, DailySummary> = {};
  recentLogs.forEach(log => {
    const day = new Date(log.timestamp).toLocaleDateString('pt-BR');
    if (!dailyData[day]) {
      dailyData[day] = { date: day, delivered: 0, returns: 0, gains: 0 };
    }
    if (log.type === 'SAIDA') {
      dailyData[day].delivered += 1;
      dailyData[day].gains += VALOR_POR_PACOTE;
    } else if (log.type === 'DEVOLUCAO') {
      dailyData[day].returns += 1;
    }
  });

  const summaryRows = Object.values(dailyData).sort((a, b) => {
     const [da, ma, ya] = a.date.split('/').map(Number);
     const [db, mb, yb] = b.date.split('/').map(Number);
     return new Date(yb, mb-1, db).getTime() - new Date(ya, ma-1, da).getTime();
  });

  const totalDelivered = summaryRows.reduce((acc, curr) => acc + curr.delivered, 0);
  const totalGains = summaryRows.reduce((acc, curr) => acc + curr.gains, 0);

  // --- CARD DE RESUMO (ESTILO APP) ---
  doc.setFillColor(15, 23, 42); // Slate 900
  doc.setDrawColor(30, 41, 59); // Slate 800
  doc.roundedRect(14, 45, pageWidth - 28, 35, 5, 5, 'FD');

  doc.setFontSize(10);
  doc.setTextColor(148, 163, 184); // Slate 400
  doc.text('RESUMO DA PRODUTIVIDADE (ÚLTIMOS 7 DIAS)', 20, 55);

  doc.setFontSize(24);
  doc.setTextColor(255, 255, 255);
  doc.text(`R$ ${totalGains.toFixed(2)}`, 20, 72);

  doc.setFontSize(9);
  doc.setTextColor(37, 99, 235);
  doc.text(`${totalDelivered} PACOTES ENTREGUES NO PERÍODO`, 85, 72);

  // --- TABELA DE DADOS ---
  const tableColumn = ["DATA", "ENTREGAS", "DEVOLUÇÕES", "GANHOS (BRL)"];
  const tableRows = summaryRows.map(row => [
    row.date,
    row.delivered.toString(),
    row.returns.toString(),
    `R$ ${row.gains.toFixed(2)}`
  ]);

  autoTable(doc, {
    head: [tableColumn],
    body: tableRows,
    startY: 95,
    theme: 'plain',
    headStyles: { 
      fillColor: [37, 99, 235], 
      textColor: [255, 255, 255],
      fontSize: 9,
      fontStyle: 'bold',
      halign: 'center'
    },
    bodyStyles: { 
      fillColor: [2, 6, 23], 
      textColor: [203, 213, 225], // Slate 300
      fontSize: 9,
      halign: 'center'
    },
    alternateRowStyles: { 
      fillColor: [15, 23, 42] // Slate 900
    },
    columnStyles: {
      3: { fontStyle: 'bold', textColor: [255, 255, 255] }
    },
    margin: { left: 14, right: 14 }
  });

  // --- RODAPÉ ---
  const finalY = (doc as any).lastAutoTable?.finalY || 150;

  // Badge de Segurança
  doc.setFillColor(31, 41, 55);
  doc.roundedRect(14, pageHeight - 25, pageWidth - 28, 15, 3, 3, 'F');

  doc.setFontSize(7);
  doc.setTextColor(100, 116, 139);
  doc.text('DOCUMENTO GERADO VIA FLUXOLOG INTELLIGENCE SYSTEM v2.0', 20, pageHeight - 17);
  doc.setTextColor(37, 99, 235);
  doc.text('AUTENTICIDADE GARANTIDA PELA SINCRONIZAÇÃO SUPABASE', pageWidth - 20, pageHeight - 17, { align: 'right' });

  doc.save(`extrato_fluxolog_${dateStr.replace(/\//g, '-')}.pdf`);
};

import React, { useState, useEffect, useMemo } from 'react';
import { Truck, Zap, FileText, Download, LayoutDashboard, Settings, Layers, ListPlus, Send, Table as TableIcon, Package, AlertTriangle, RefreshCw, LogOut } from 'lucide-react';
import DashboardCards from './components/DashboardCards';
import ActionButtons from './components/ActionButtons';
import DailyStatsTable from './components/DailyStatsTable';
import BulkActionModal from './components/BulkActionModal';
import Login from './components/Login';
import { LogEntry, LogActionType } from './types';
import { supabaseService } from './services/supabaseService';
import { generatePDF } from './services/pdfService';
import { SUPABASE_CACHE_KEY } from './constants';

const App: React.FC = () => {
  const [session, setSession] = useState<any>(null);

  const [logs, setLogs] = useState<LogEntry[]>(() => {
    const cached = localStorage.getItem(SUPABASE_CACHE_KEY);
    return cached ? JSON.parse(cached) : [];
  });

  const [loading, setLoading] = useState(true);
  const [isSyncing, setIsSyncing] = useState(false);
  const [error, setError] = useState<any>(null);
  const [showToast, setShowToast] = useState(false);
  const [toastMsg, setToastMsg] = useState('');
  const [userName, setUserName] = useState('Operador Logístico');
  const [activeTab, setActiveTab] = useState<'dash' | 'stats'>('dash');

  const [bulkModal, setBulkModal] = useState<{ isOpen: boolean; type: 'ENTRADA' | 'SAIDA' }>({
    isOpen: false,
    type: 'ENTRADA'
  });

  useEffect(() => {
    supabaseService.getSession().then(session => {
      setSession(session);
      if (!session) setLoading(false);
    });
  }, []);

  useEffect(() => {
    if (!session) return;

    setIsSyncing(true);
    const unsubscribe = supabaseService.subscribeToLogs((updatedLogs, supabaseError) => {
      if (supabaseError) {
        setError(supabaseError);
      } else {
        setLogs(updatedLogs);
        localStorage.setItem(SUPABASE_CACHE_KEY, JSON.stringify(updatedLogs));
      }
      setLoading(false);
      setIsSyncing(false);
    });

    return () => unsubscribe();
  }, [session]);

  const handleLogout = async () => {
    await supabaseService.signOut();
    localStorage.removeItem(SUPABASE_CACHE_KEY);
    setSession(null);
    setLogs([]);
  };

  const handleAction = async (type: LogActionType) => {
    const newEntry: Omit<LogEntry, 'id'> = {
      type,
      timestamp: new Date().toISOString(),
      value: type === 'SAIDA' ? 2.50 : 0
    };

    try {
      await supabaseService.saveLog(newEntry);
      const messages = {
        ENTRADA: 'Entrada registrada!',
        SAIDA: 'Entrega salva! +R$ 2,50',
        DEVOLUCAO: 'Retorno salvo com sucesso.'
      };
      setToastMsg(messages[type]);
      setShowToast(true);
      setTimeout(() => setShowToast(false), 2500);
    } catch (err) {
      setToastMsg('Erro ao salvar no banco.');
      setShowToast(true);
    }
  };

  const handleBulkAction = async (quantity: number) => {
    const type = bulkModal.type;
    const newEntries: Omit<LogEntry, 'id'>[] = Array.from({ length: quantity }).map(() => ({
      type: type as LogActionType,
      timestamp: new Date().toISOString(),
      value: type === 'SAIDA' ? 2.50 : 0
    }));

    try {
      await supabaseService.saveBulkLogs(newEntries);
      setToastMsg(`${quantity} pacotes sincronizados!`);
      setShowToast(true);
      setTimeout(() => setShowToast(false), 3000);
    } catch (err) {
      setToastMsg('Falha na sincronização em lote.');
      setShowToast(true);
    }
  };

  const counts = useMemo(() => {
    const todayStr = new Date().toDateString();
    const now = new Date();
    const startOfWeek = new Date(now);
    startOfWeek.setDate(now.getDate() - now.getDay());
    startOfWeek.setHours(0, 0, 0, 0);
    const startOfYear = new Date(now.getFullYear(), 0, 1);

    const filterLogs = (start: Date, type: LogActionType = 'SAIDA') => {
       return logs.filter(l => {
         const d = new Date(l.timestamp);
         return l.type === type && d >= start;
       }).length;
    };

    return {
      today: logs.filter(l => l.type === 'SAIDA' && new Date(l.timestamp).toDateString() === todayStr).length,
      week: filterLogs(startOfWeek),
      year: filterLogs(startOfYear)
    };
  }, [logs]);

  if (!session && !loading) {
    return <Login onLoginSuccess={() => supabaseService.getSession().then(setSession)} />;
  }

  if (loading && logs.length === 0) {
    return (
      <div className="min-h-screen bg-[#020617] flex flex-col items-center justify-center p-6">
        <div className="relative mb-6">
          <div className="w-16 h-16 md:w-20 md:h-20 border-4 border-blue-500/20 border-t-blue-500 rounded-full animate-spin"></div>
          <Zap className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 text-blue-400 animate-pulse" size={24} />
        </div>
        <div className="text-center">
          <h2 className="text-white font-game text-xl md:text-2xl font-black uppercase tracking-tighter">Conectando</h2>
          <p className="text-slate-500 text-[10px] font-bold uppercase tracking-widest mt-2">Sincronizando Banco de Dados</p>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-[#020617] text-slate-200 pb-24 md:pb-12 selection:bg-blue-500/30">
      <header className="bg-slate-900/80 backdrop-blur-xl border-b border-white/5 p-4 md:p-6 shadow-2xl sticky top-0 z-40">
        <div className="max-w-5xl mx-auto flex justify-between items-center">
          <div className="flex items-center gap-3 md:gap-4">
            <div className="bg-gradient-to-tr from-blue-600 to-purple-600 p-2 md:p-2.5 rounded-xl md:rounded-2xl shadow-lg rotate-3">
              <Truck size={20} className="text-white -rotate-3 md:w-6 md:h-6" />
            </div>
            <div>
              <h1 className="text-lg md:text-2xl font-game font-black tracking-wider text-white">FLUXO LOG</h1>
              <div className="flex items-center gap-1.5">
                <span className={`w-1.5 h-1.5 rounded-full ${isSyncing ? 'bg-blue-500 animate-ping' : 'bg-emerald-500 animate-pulse'}`}></span>
                <p className="text-[9px] md:text-[10px] text-slate-500 font-bold uppercase tracking-widest">
                  {isSyncing ? 'Syncing' : 'Online'}
                </p>
              </div>
            </div>
          </div>

          <div className="flex items-center gap-3 md:gap-6">
             <div className="hidden sm:flex flex-col items-end">
                <p className="text-[10px] font-bold text-slate-400 uppercase tracking-tighter">Operador</p>
                <p className="text-xs md:text-sm font-game font-bold text-blue-400">{session?.user?.email?.split('@')[0]}</p>
             </div>
             <button 
                onClick={handleLogout}
                className="p-2.5 md:p-3 bg-red-500/10 hover:bg-red-500/20 rounded-xl md:rounded-2xl border border-red-500/20 transition-all group"
             >
                <LogOut size={18} className="text-red-400 group-hover:scale-110 md:w-5 md:h-5" />
             </button>
          </div>
        </div>
      </header>

      <nav className="max-w-5xl mx-auto px-4 mt-6 md:mt-8">
        <div className="bg-slate-900/50 p-1 rounded-2xl md:rounded-[2rem] border border-white/5 flex gap-1">
          <button 
            onClick={() => setActiveTab('dash')}
            className={`flex-1 flex items-center justify-center gap-2 px-4 py-3 rounded-xl md:rounded-[1.5rem] font-bold text-xs md:text-sm transition-all ${activeTab === 'dash' ? 'bg-blue-600 text-white shadow-lg' : 'text-slate-400 hover:text-white'}`}
          >
            <LayoutDashboard size={16} className="md:w-4.5 md:h-4.5" /> <span className="hidden xs:inline">Painel</span><span className="xs:hidden">Principal</span>
          </button>
          <button 
            onClick={() => setActiveTab('stats')}
            className={`flex-1 flex items-center justify-center gap-2 px-4 py-3 rounded-xl md:rounded-[1.5rem] font-bold text-xs md:text-sm transition-all ${activeTab === 'stats' ? 'bg-blue-600 text-white shadow-lg' : 'text-slate-400 hover:text-white'}`}
          >
            <TableIcon size={16} className="md:w-4.5 md:h-4.5" /> <span className="hidden xs:inline">Estatísticas</span><span className="xs:hidden">Diário</span>
          </button>
        </div>
      </nav>

      <main className="max-w-5xl mx-auto p-4 md:p-6 space-y-8 md:space-y-10">
        {activeTab === 'dash' ? (
          <>
            <section className="animate-in fade-in slide-in-from-bottom-4">
              <DashboardCards 
                deliveredToday={counts.today} 
                deliveredWeek={counts.week} 
                deliveredYear={counts.year} 
              />
            </section>

            <section className="space-y-4 md:space-y-6">
              <h2 className="text-slate-400 font-game font-bold text-sm md:text-lg uppercase tracking-widest px-1">Ações Rápidas</h2>
              <ActionButtons onAction={handleAction} />

              <div className="grid grid-cols-1 sm:grid-cols-2 gap-3 md:gap-4">
                <button 
                  onClick={() => setBulkModal({ isOpen: true, type: 'ENTRADA' })}
                  className="group bg-slate-900/40 border border-emerald-500/20 p-4 md:p-5 rounded-2xl md:rounded-[2rem] flex items-center justify-between transition-all active:scale-[0.98] neon-emerald"
