import React from 'react';
import { LogEntry } from '../types';
import { VALOR_POR_PACOTE } from '../constants';
import { Calendar, ArrowDown, ArrowUp, RotateCcw, DollarSign } from 'lucide-react';

interface DailyStatsTableProps {
  logs: LogEntry[];
}

const DailyStatsTable: React.FC<DailyStatsTableProps> = ({ logs }) => {
  const dailyGroups = logs.reduce((acc: any, log) => {
    const date = new Date(log.timestamp).toLocaleDateString('pt-BR');
    if (!acc[date]) {
      acc[date] = { date, entrada: 0, saida: 0, devolucao: 0, total: 0 };
    }
    if (log.type === 'ENTRADA') acc[date].entrada++;
    if (log.type === 'SAIDA') {
      acc[date].saida++;
      acc[date].total += VALOR_POR_PACOTE;
    }
    if (log.type === 'DEVOLUCAO') acc[date].devolucao++;
    return acc;
  }, {});

  const sortedDays = Object.values(dailyGroups).sort((a: any, b: any) => {
    const [da, ma, ya] = a.date.split('/').map(Number);
    const [db, mb, yb] = b.date.split('/').map(Number);
    return new Date(yb, mb-1, db).getTime() - new Date(ya, ma-1, da).getTime();
  });

  return (
    <div className="bg-slate-900/40 border border-slate-800 rounded-2xl md:rounded-[2rem] overflow-hidden backdrop-blur-sm">
      <div className="p-5 md:p-6 border-b border-slate-800 flex items-center justify-between">
        <h3 className="text-white font-game text-base md:text-xl font-bold flex items-center gap-2">
          <Calendar size={18} className="text-blue-400 md:w-5 md:h-5" /> Registros Diários
        </h3>
        <span className="text-[9px] md:text-[10px] text-slate-500 font-bold uppercase tracking-widest">Compilado</span>
      </div>

      <div className="overflow-x-auto scrollbar-thin">
        <table className="w-full text-left border-collapse min-w-[500px]">
          <thead>
            <tr className="bg-white/5">
              <th className="p-4 text-[10px] font-bold text-slate-400 uppercase tracking-widest">Data</th>
              <th className="p-4 text-[10px] font-bold text-emerald-400 uppercase tracking-widest">Entrada</th>
              <th className="p-4 text-[10px] font-bold text-blue-400 uppercase tracking-widest">Saída</th>
              <th className="p-4 text-[10px] font-bold text-orange-400 uppercase tracking-widest">Dev.</th>
              <th className="p-4 text-[10px] font-bold text-white uppercase tracking-widest text-right">Ganhos</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-800/50">
            {sortedDays.map((day: any) => (
              <tr key={day.date} className="hover:bg-white/5 transition-colors">
                <td className="p-4 font-game font-bold text-slate-300 text-sm">{day.date}</td>
                <td className="p-4"><span className="bg-emerald-500/10 text-emerald-400 px-2 py-0.5 rounded font-bold text-xs">{day.entrada}</span></td>
                <td className="p-4"><span className="bg-blue-500/10 text-blue-400 px-2 py-0.5 rounded font-bold text-xs">{day.saida}</span></td>
                <td className="p-4"><span className="bg-orange-500/10 text-orange-400 px-2 py-0.5 rounded font-bold text-xs">{day.devolucao}</span></td>
                <td className="p-4 text-right">
                  <span className="text-white font-game text-base font-bold">
                    {new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(day.total)}
                  </span>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
};

export default DailyStatsTable;

import React, { useState, useEffect } from 'react';
import { Truck, Zap, Mail, Lock, ArrowRight, UserPlus, LogIn, Check } from 'lucide-react';
import { supabaseService } from '../services/supabaseService';

interface LoginProps {
  onLoginSuccess: () => void;
}

const Login: React.FC<LoginProps> = ({ onLoginSuccess }) => {
  const [isSignUp, setIsSignUp] = useState(false);
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [rememberMe, setRememberMe] = useState(false);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    const savedEmail = localStorage.getItem('fluxolog_saved_email');
    if (savedEmail) {
      setEmail(savedEmail);
      setRememberMe(true);
    }
  }, []);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    setError(null);

    try {
      if (isSignUp) {
        await supabaseService.signUp(email, password);
        setError("Conta criada! Verifique seu e-mail.");
        setIsSignUp(false);
      } else {
        await supabaseService.signIn(email, password);
        if (rememberMe) {
          localStorage.setItem('fluxolog_saved_email', email);
        } else {
          localStorage.removeItem('fluxolog_saved_email');
        }
        onLoginSuccess();
      }
    } catch (err: any) {
      setError(err.message || "Erro na autenticação.");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="min-h-screen bg-[#020617] flex items-center justify-center p-4 relative overflow-hidden">
      <div className="absolute top-[-10%] left-[-10%] w-64 h-64 md:w-72 md:h-72 bg-blue-600/10 rounded-full blur-[100px] md:blur-[120px]"></div>

      <div className="w-full max-w-md animate-in fade-in zoom-in duration-500">
        <div className="bg-slate-900/40 backdrop-blur-2xl border border-white/5 rounded-[2.5rem] md:rounded-[3rem] p-6 md:p-12 shadow-2xl relative">

          <div className="flex flex-col items-center mb-8 md:mb-10">
            <div className="bg-gradient-to-tr from-blue-600 to-purple-600 p-3.5 md:p-4 rounded-2xl md:rounded-3xl shadow-xl shadow-blue-500/20 mb-5 md:mb-6 rotate-3">
              <Truck size={32} className="text-white -rotate-3 md:w-10 md:h-10" />
            </div>
            <h1 className="text-3xl md:text-4xl font-game font-black text-white tracking-tighter uppercase">Fluxo Log</h1>
            <p className="text-slate-500 text-[9px] md:text-[10px] font-bold uppercase tracking-[0.4em] mt-2">Intelligence System</p>
          </div>

          <form onSubmit={handleSubmit} className="space-y-5 md:space-y-6">
            {error && (
              <div className="bg-red-500/10 border border-red-500/20 text-red-400 text-[10px] md:text-xs py-3 px-4 rounded-xl text-center font-bold uppercase tracking-wider">
                {error}
              </div>
            )}

            <div className="space-y-3 md:space-y-4">
              <div className="relative group">
                <div className="absolute inset-y-0 left-0 pl-4 flex items-center pointer-events-none text-slate-500">
                  <Mail size={18} />
                </div>
                <input
                  type="email"
                  required
                  value={email}
                  onChange={(e) => setEmail(e.target.value)}
                  className="block w-full pl-12 pr-4 py-3.5 md:py-4 bg-white/5 border border-white/10 rounded-xl md:rounded-2xl text-white text-sm focus:outline-none focus:ring-2 focus:ring-blue-500/50"
                  placeholder="E-mail"
                />
              </div>

              <div className="relative group">
                <div className="absolute inset-y-0 left-0 pl-4 flex items-center pointer-events-none text-slate-500">
                  <Lock size={18} />
                </div>
                <input
                  type="password"
                  required
                  value={password}
                  onChange={(e) => setPassword(e.target.value)}
                  className="block w-full pl-12 pr-4 py-3.5 md:py-4 bg-white/5 border border-white/10 rounded-xl md:rounded-2xl text-white text-sm focus:outline-none focus:ring-2 focus:ring-blue-500/50"
                  placeholder="Senha"
                />
              </div>
            </div>

            <div className="flex items-center px-1">
              <button 
                type="button"
                onClick={() => setRememberMe(!rememberMe)}
                className="flex items-center gap-3 group cursor-pointer"
              >
                <div className={`w-5 h-5 md:w-6 md:h-6 rounded-lg border-2 transition-all flex items-center justify-center ${rememberMe ? 'bg-blue-600 border-blue-600' : 'border-white/10 bg-white/5'}`}>
                  {rememberMe && <Check size={12} className="text-white" />}
                </div>
                <span className="text-[10px] md:text-xs font-bold text-slate-400 uppercase tracking-widest">
                  Salvar login
                </span>
              </button>
            </div>

            <button
              type="submit"
              disabled={loading}
              className="w-full bg-blue-600 hover:bg-blue-500 disabled:opacity-50 text-white font-game font-black text-base md:text-lg py-4 md:py-5 rounded-xl md:rounded-2xl flex items-center justify-center gap-2 shadow-xl active:scale-95 uppercase tracking-widest border border-blue-400/20"
            >
              {loading ? (
                <div className="w-5 h-5 border-2 border-white/30 border-t-white rounded-full animate-spin"></div>
              ) : (
                <>{isSignUp ? "Registrar" : "Entrar"} <ArrowRight size={18} /></>
              )}
            </button>
          </form>

          <div className="mt-6 md:mt-8 text-center">
            <button
              onClick={() => setIsSignUp(!isSignUp)}
              className="text-slate-500 hover:text-blue-400 text-[10px] md:text-xs font-bold uppercase tracking-widest transition-colors flex items-center justify-center gap-2 mx-auto"
            >
              {isSignUp ? "Voltar para Login" : "Criar Nova Conta"}
            </button>
          </div>
        </div>
      </div>
    </div>
  );
};

export default Login;

import React, { useState, useEffect, useMemo } from 'react';
import { Truck, Zap, FileText, Download, LayoutDashboard, Settings, Layers, ListPlus, Send, Table as TableIcon, Package, AlertTriangle, RefreshCw, LogOut } from 'lucide-react';
import DashboardCards from './components/DashboardCards';
