import BulkActionModal from './components/BulkActionModal';
import Login from './components/Login';
import { LogEntry, LogActionType } from './types';
import { supabaseService } from './services/supabaseService';
import { generatePDF } from './services/pdfService';
import { SUPABASE_CACHE_KEY } from './constants';

const App: React.FC = () => {
  const [session, setSession] = useState<any>(null);

  const [logs, setLogs] = useState<LogEntry[]>(() => {
    const cached = localStorage.getItem(SUPABASE_CACHE_KEY);
    return cached ? JSON.parse(cached) : [];
  });

  const [loading, setLoading] = useState(true);
  const [isSyncing, setIsSyncing] = useState(false);
  const [error, setError] = useState<any>(null);
  const [showToast, setShowToast] = useState(false);
  const [toastMsg, setToastMsg] = useState('');
  const [userName, setUserName] = useState('Operador Logístico');
  const [activeTab, setActiveTab] = useState<'dash' | 'stats'>('dash');

  const [bulkModal, setBulkModal] = useState<{ isOpen: boolean; type: 'ENTRADA' | 'SAIDA' }>({
    isOpen: false,
    type: 'ENTRADA'
  });

  useEffect(() => {
    supabaseService.getSession().then(session => {
      setSession(session);
      if (!session) setLoading(false);
    });
  }, []);

  useEffect(() => {
    if (!session) return;

    setIsSyncing(true);
    const unsubscribe = supabaseService.subscribeToLogs((updatedLogs, supabaseError) => {
      if (supabaseError) {
        setError(supabaseError);
      } else {
        setLogs(updatedLogs);
        localStorage.setItem(SUPABASE_CACHE_KEY, JSON.stringify(updatedLogs));
      }
      setLoading(false);
      setIsSyncing(false);
    });

    return () => unsubscribe();
  }, [session]);

  const handleLogout = async () => {
    await supabaseService.signOut();
    localStorage.removeItem(SUPABASE_CACHE_KEY);
    setSession(null);
    setLogs([]);
  };

  const handleAction = async (type: LogActionType) => {
    const newEntry: Omit<LogEntry, 'id'> = {
      type,
      timestamp: new Date().toISOString(),
      value: type === 'SAIDA' ? 2.50 : 0
    };

    try {
      await supabaseService.saveLog(newEntry);
      const messages = {
        ENTRADA: 'Entrada registrada!',
        SAIDA: 'Entrega salva! +R$ 2,50',
        DEVOLUCAO: 'Retorno salvo com sucesso.'
      };
      setToastMsg(messages[type]);
      setShowToast(true);
      setTimeout(() => setShowToast(false), 2500);
    } catch (err) {
      setToastMsg('Erro ao salvar no banco.');
      setShowToast(true);
    }
  };

  const handleBulkAction = async (quantity: number) => {
    const type = bulkModal.type;
    const newEntries: Omit<LogEntry, 'id'>[] = Array.from({ length: quantity }).map(() => ({
      type: type as LogActionType,
      timestamp: new Date().toISOString(),
      value: type === 'SAIDA' ? 2.50 : 0
    }));

    try {
      await supabaseService.saveBulkLogs(newEntries);
      setToastMsg(`${quantity} pacotes sincronizados!`);
      setShowToast(true);
      setTimeout(() => setShowToast(false), 3000);
    } catch (err) {
      setToastMsg('Falha na sincronização em lote.');
      setShowToast(true);
    }
  };

  const counts = useMemo(() => {
    const todayStr = new Date().toDateString();
    const now = new Date();
    const startOfWeek = new Date(now);
    startOfWeek.setDate(now.getDate() - now.getDay());
    startOfWeek.setHours(0, 0, 0, 0);
    const startOfYear = new Date(now.getFullYear(), 0, 1);

    const filterLogs = (start: Date, type: LogActionType = 'SAIDA') => {
       return logs.filter(l => {
         const d = new Date(l.timestamp);
         return l.type === type && d >= start;
       }).length;
    };

    return {
      today: logs.filter(l => l.type === 'SAIDA' && new Date(l.timestamp).toDateString() === todayStr).length,
      week: filterLogs(startOfWeek),
      year: filterLogs(startOfYear)
    };
  }, [logs]);

  if (!session && !loading) {
    return <Login onLoginSuccess={() => supabaseService.getSession().then(setSession)} />;
  }

  if (loading && logs.length === 0) {
    return (
      <div className="min-h-screen bg-[#020617] flex flex-col items-center justify-center p-6">
        <div className="relative mb-6">
          <div className="w-16 h-16 md:w-20 md:h-20 border-4 border-blue-500/20 border-t-blue-500 rounded-full animate-spin"></div>
          <Zap className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 text-blue-400 animate-pulse" size={24} />
        </div>
        <div className="text-center">
          <h2 className="text-white font-game text-xl md:text-2xl font-black uppercase tracking-tighter">Conectando</h2>
          <p className="text-slate-500 text-[10px] font-bold uppercase tracking-widest mt-2">Sincronizando Banco de Dados</p>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-[#020617] text-slate-200 pb-24 md:pb-12 selection:bg-blue-500/30">
      <header className="bg-slate-900/80 backdrop-blur-xl border-b border-white/5 p-4 md:p-6 shadow-2xl sticky top-0 z-40">
        <div className="max-w-5xl mx-auto flex justify-between items-center">
          <div className="flex items-center gap-3 md:gap-4">
            <div className="bg-gradient-to-tr from-blue-600 to-purple-600 p-2 md:p-2.5 rounded-xl md:rounded-2xl shadow-lg rotate-3">
              <Truck size={20} className="text-white -rotate-3 md:w-6 md:h-6" />
            </div>
            <div>
              <h1 className="text-lg md:text-2xl font-game font-black tracking-wider text-white">FLUXO LOG</h1>
              <div className="flex items-center gap-1.5">
                <span className={`w-1.5 h-1.5 rounded-full ${isSyncing ? 'bg-blue-500 animate-ping' : 'bg-emerald-500 animate-pulse'}`}></span>
                <p className="text-[9px] md:text-[10px] text-slate-500 font-bold uppercase tracking-widest">
                  {isSyncing ? 'Syncing' : 'Online'}
                </p>
              </div>
            </div>
          </div>

          <div className="flex items-center gap-3 md:gap-6">
             <div className="hidden sm:flex flex-col items-end">
                <p className="text-[10px] font-bold text-slate-400 uppercase tracking-tighter">Operador</p>
                <p className="text-xs md:text-sm font-game font-bold text-blue-400">{session?.user?.email?.split('@')[0]}</p>
             </div>
             <button 
