import React, { useState } from 'react';
import { LogEntry } from '../types';
import { VALOR_POR_PACOTE } from '../constants';
import { Calendar, BarChart3, List } from 'lucide-react';

interface DailyStatsTableProps {
  logs: LogEntry[];
}

type ViewMode = 'daily' | 'monthly';

const DailyStatsTable: React.FC<DailyStatsTableProps> = ({ logs }) => {
  const [viewMode, setViewMode] = useState<ViewMode>('daily');

  // Lógica de Agregação Diária
  const dailyGroups = logs.reduce((acc: any, log) => {
    const date = new Date(log.timestamp).toLocaleDateString('pt-BR');
    if (!acc[date]) {
      acc[date] = { label: date, entrada: 0, saida: 0, devolucao: 0, total: 0, rawDate: new Date(log.timestamp) };
    }
    if (log.type === 'ENTRADA') acc[date].entrada++;
    if (log.type === 'SAIDA') {
      acc[date].saida++;
      acc[date].total += VALOR_POR_PACOTE;
    }
    if (log.type === 'DEVOLUCAO') acc[date].devolucao++;
    return acc;
  }, {});

  // Lógica de Agregação Mensal
  const monthlyGroups = logs.reduce((acc: any, log) => {
    const d = new Date(log.timestamp);
    const monthLabel = d.toLocaleDateString('pt-BR', { month: 'long', year: 'numeric' });
    const monthKey = `${d.getMonth()}-${d.getFullYear()}`;

    if (!acc[monthKey]) {
      acc[monthKey] = { 
        label: monthLabel.charAt(0).toUpperCase() + monthLabel.slice(1), 
        entrada: 0, 
        saida: 0, 
        devolucao: 0, 
        total: 0,
        sortKey: d.getFullYear() * 12 + d.getMonth()
      };
    }
    if (log.type === 'ENTRADA') acc[monthKey].entrada++;
    if (log.type === 'SAIDA') {
      acc[monthKey].saida++;
      acc[monthKey].total += VALOR_POR_PACOTE;
    }
    if (log.type === 'DEVOLUCAO') acc[monthKey].devolucao++;
    return acc;
  }, {});

  const displayData = viewMode === 'daily' 
    ? Object.values(dailyGroups).sort((a: any, b: any) => b.rawDate.getTime() - a.rawDate.getTime())
    : Object.values(monthlyGroups).sort((a: any, b: any) => b.sortKey - a.sortKey);

  return (
    <div className="bg-slate-900/40 border border-slate-800 rounded-2xl md:rounded-[2rem] overflow-hidden backdrop-blur-sm shadow-2xl">
      <div className="p-5 md:p-6 border-b border-slate-800 flex flex-col sm:flex-row sm:items-center justify-between gap-4">
        <div className="flex items-center gap-3">
          <div className="p-2 bg-blue-500/10 rounded-lg">
            <Calendar size={20} className="text-blue-400" />
          </div>
          <div>
            <h3 className="text-white font-game text-base md:text-xl font-bold uppercase tracking-tight">
              Análise de Fluxo
            </h3>
            <p className="text-[10px] text-slate-500 font-bold uppercase tracking-widest">Registros Sincronizados</p>
          </div>
        </div>

        {/* View Mode Selector */}
        <div className="bg-slate-950/50 p-1 rounded-xl border border-white/5 flex self-start sm:self-center">
          <button 
            onClick={() => setViewMode('daily')}
            className={`flex items-center gap-2 px-4 py-2 rounded-lg text-[10px] font-black uppercase tracking-widest transition-all ${viewMode === 'daily' ? 'bg-blue-600 text-white shadow-lg' : 'text-slate-500 hover:text-slate-300'}`}
          >
            <List size={14} /> Diário
          </button>
          <button 
            onClick={() => setViewMode('monthly')}
            className={`flex items-center gap-2 px-4 py-2 rounded-lg text-[10px] font-black uppercase tracking-widest transition-all ${viewMode === 'monthly' ? 'bg-blue-600 text-white shadow-lg' : 'text-slate-500 hover:text-slate-300'}`}
          >
            <BarChart3 size={14} /> Mensal
          </button>
        </div>
      </div>

      <div className="overflow-x-auto scrollbar-thin">
        <table className="w-full text-left border-collapse min-w-[550px]">
          <thead>
            <tr className="bg-white/2">
              <th className="p-5 text-[10px] font-bold text-slate-400 uppercase tracking-widest border-b border-slate-800">
                {viewMode === 'daily' ? 'Data' : 'Período Mensal'}
              </th>
              <th className="p-5 text-[10px] font-bold text-emerald-400 uppercase tracking-widest border-b border-slate-800 text-center">Entrada</th>
              <th className="p-5 text-[10px] font-bold text-blue-400 uppercase tracking-widest border-b border-slate-800 text-center">Saída</th>
              <th className="p-5 text-[10px] font-bold text-orange-400 uppercase tracking-widest border-b border-slate-800 text-center">Dev.</th>
              <th className="p-5 text-[10px] font-bold text-white uppercase tracking-widest border-b border-slate-800 text-right">Ganhos Totais</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-800/30">
            {displayData.map((item: any, idx: number) => (
              <tr key={idx} className="hover:bg-blue-500/[0.03] transition-colors group">
                <td className="p-5">
                   <p className={`font-game font-bold tracking-tight ${viewMode === 'daily' ? 'text-slate-300 text-sm' : 'text-blue-400 text-base'}`}>
                     {item.label}
                   </p>
                </td>
                <td className="p-5 text-center">
                  <span className="inline-block bg-emerald-500/10 text-emerald-400 px-3 py-1 rounded-full font-bold text-[11px] border border-emerald-500/10">
                    {item.entrada}
                  </span>
                </td>
                <td className="p-5 text-center">
                  <span className="inline-block bg-blue-500/10 text-blue-400 px-3 py-1 rounded-full font-bold text-[11px] border border-blue-500/10">
                    {item.saida}
                  </span>
                </td>
                <td className="p-5 text-center">
                  <span className="inline-block bg-orange-500/10 text-orange-400 px-3 py-1 rounded-full font-bold text-[11px] border border-orange-500/10">
                    {item.devolucao}
                  </span>
                </td>
                <td className="p-5 text-right">
                  <div className="flex flex-col items-end">
                    <span className="text-white font-game text-lg font-black tracking-tighter">
                      {new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(item.total)}
                    </span>
                    {viewMode === 'monthly' && (
                      <span className="text-[9px] text-slate-500 font-bold uppercase tracking-tighter">
                        Média: {new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(item.total / (item.saida || 1))} / pac
                      </span>
                    )}
                  </div>
                </td>
              </tr>
            ))}
            {displayData.length === 0 && (
              <tr>
                <td colSpan={5} className="p-20 text-center">
                  <p className="text-slate-600 font-game uppercase tracking-[0.3em] italic">Nenhum dado encontrado para processar.</p>
                </td>
              </tr>
            )}
          </tbody>
        </table>
      </div>

      {/* Footer Decorativo da Tabela */}
      <div className="p-4 bg-black/20 flex justify-center">
        <p className="text-[9px] text-slate-600 font-bold uppercase tracking-[0.5em]">Fim da Lista</p>
      </div>
    </div>
  );
};

