import React, { useState, useEffect, useMemo } from 'react';
import { Truck, Zap, FileText, Download, LayoutDashboard, Send, Table as TableIcon, ListPlus, LogOut, Layers } from 'lucide-react';
import DashboardCards from './components/DashboardCards';
import ActionButtons from './components/ActionButtons';
import DailyStatsTable from './components/DailyStatsTable';
import BulkActionModal from './components/BulkActionModal';
import Login from './components/Login';
import { LogEntry, LogActionType } from './types';
import { supabaseService } from './services/supabaseService';
import { generatePDF } from './services/pdfService';
import { SUPABASE_CACHE_KEY } from './constants';

const App: React.FC = () => {
  const [session, setSession] = useState<any>(null);
  const [logs, setLogs] = useState<LogEntry[]>(() => {
    const cached = localStorage.getItem(SUPABASE_CACHE_KEY);
    return cached ? JSON.parse(cached) : [];
  });
  const [loading, setLoading] = useState(true);
  const [isSyncing, setIsSyncing] = useState(false);
  const [showToast, setShowToast] = useState(false);
  const [toastMsg, setToastMsg] = useState('');
  const [userName, setUserName] = useState('Operador Logístico');
  const [activeTab, setActiveTab] = useState<'dash' | 'stats'>('dash');
  const [bulkModal, setBulkModal] = useState<{ isOpen: boolean; type: 'ENTRADA' | 'SAIDA' }>({
    isOpen: false,
    type: 'ENTRADA'
  });

  useEffect(() => {
    supabaseService.getSession().then(session => {
      setSession(session);
      if (!session) setLoading(false);
    });
  }, []);

  useEffect(() => {
    if (!session) return;
    setIsSyncing(true);
    const unsubscribe = supabaseService.subscribeToLogs((updatedLogs, supabaseError) => {
      if (!supabaseError) {
        setLogs(updatedLogs);
        localStorage.setItem(SUPABASE_CACHE_KEY, JSON.stringify(updatedLogs));
      }
      setLoading(false);
      setIsSyncing(false);
    });
    return () => unsubscribe();
  }, [session]);

  const handleLogout = async () => {
    await supabaseService.signOut();
    localStorage.removeItem(SUPABASE_CACHE_KEY);
    setSession(null);
    setLogs([]);
  };

  const handleAction = async (type: LogActionType) => {
    const newEntry: Omit<LogEntry, 'id'> = {
      type,
      timestamp: new Date().toISOString(),
      value: type === 'SAIDA' ? 2.50 : 0
    };
    try {
      await supabaseService.saveLog(newEntry);
      const messages = { ENTRADA: 'Entrada registrada!', SAIDA: 'Entrega salva! +R$ 2,50', DEVOLUCAO: 'Retorno registrado.' };
      setToastMsg(messages[type]);
      setShowToast(true);
      setTimeout(() => setShowToast(false), 2000);
    } catch (err) {
      setToastMsg('Erro na sincronização.');
      setShowToast(true);
    }
  };

  const handleBulkAction = async (quantity: number) => {
    const type = bulkModal.type;
    const newEntries = Array.from({ length: quantity }).map(() => ({
      type: type as LogActionType,
      timestamp: new Date().toISOString(),
      value: type === 'SAIDA' ? 2.50 : 0
    }));
    try {
      await supabaseService.saveBulkLogs(newEntries);
      setToastMsg(`${quantity} pacotes sincronizados!`);
      setShowToast(true);
      setTimeout(() => setShowToast(false), 2500);
    } catch (err) {
      setToastMsg('Falha no envio em lote.');
      setShowToast(true);
    }
  };

  const counts = useMemo(() => {
    const todayStr = new Date().toDateString();
    const now = new Date();
    const startOfWeek = new Date(now);
    startOfWeek.setDate(now.getDate() - now.getDay());
    startOfWeek.setHours(0, 0, 0, 0);
    const startOfYear = new Date(now.getFullYear(), 0, 1);
    return {
      today: logs.filter(l => l.type === 'SAIDA' && new Date(l.timestamp).toDateString() === todayStr).length,
      week: logs.filter(l => l.type === 'SAIDA' && new Date(l.timestamp) >= startOfWeek).length,
      year: logs.filter(l => l.type === 'SAIDA' && new Date(l.timestamp) >= startOfYear).length
    };
  }, [logs]);

  if (!session && !loading) return <Login onLoginSuccess={() => supabaseService.getSession().then(setSession)} />;

  if (loading && logs.length === 0) {
    return (
      <div className="min-h-screen bg-[#020617] flex flex-col items-center justify-center p-6">
        <div className="w-12 h-12 border-4 border-blue-500/20 border-t-blue-500 rounded-full animate-spin mb-4"></div>
        <p className="text-slate-500 font-game font-bold uppercase tracking-widest text-xs">Acessando Terminal...</p>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-[#020617] text-slate-200 selection:bg-blue-500/30 flex flex-col">
      {/* Header Compacto Mobile / Robusto Desktop */}
      <header className="bg-slate-900/80 backdrop-blur-xl border-b border-white/5 px-4 py-3 md:px-8 md:py-6 sticky top-0 z-40 pt-safe">
        <div className="max-w-5xl mx-auto flex justify-between items-center">
          <div className="flex items-center gap-3">
            <div className="bg-blue-600 p-2 rounded-lg shadow-lg">
              <Truck size={18} className="text-white" />
            </div>
            <div>
              <h1 className="text-sm md:text-xl font-game font-black tracking-widest text-white leading-none">FLUXOLOG</h1>
              <p className="text-[9px] text-slate-500 font-bold uppercase tracking-tighter mt-1">{isSyncing ? 'Sincronizando...' : 'Sistema Online'}</p>
            </div>
          </div>
          <button onClick={handleLogout} className="p-2 bg-red-500/10 rounded-lg border border-red-500/20 active-scale">
            <LogOut size={16} className="text-red-400" />
          </button>
        </div>
      </header>

      <main className="flex-1 max-w-5xl mx-auto w-full p-4 md:p-8 space-y-6 md:space-y-10 pb-28 md:pb-12">
        {activeTab === 'dash' ? (
          <>
            <DashboardCards {...counts} />
            <section className="space-y-4">
              <h2 className="text-slate-500 font-game font-bold text-xs uppercase tracking-widest px-1">Registros Rápidos</h2>
              <ActionButtons onAction={handleAction} />
            </section>

            <section className="grid grid-cols-1 md:grid-cols-2 gap-3">
              <button 
                onClick={() => setBulkModal({ isOpen: true, type: 'ENTRADA' })}
                className="bg-slate-900/50 border border-emerald-500/10 p-4 rounded-2xl flex items-center justify-between active-scale"
              >
                <div className="flex items-center gap-3">
                  <div className="p-2 bg-emerald-600 rounded-lg text-white shadow-lg"><ListPlus size={18} /></div>
                  <div className="text-left"><p className="font-game font-bold text-white text-sm">Entrada em Massa</p></div>
                </div>
                <Layers size={14} className="text-emerald-500/30" />
              </button>
              <button 
                onClick={() => setBulkModal({ isOpen: true, type: 'SAIDA' })}
                className="bg-slate-900/50 border border-blue-500/10 p-4 rounded-2xl flex items-center justify-between active-scale"
              >
                <div className="flex items-center gap-3">
                  <div className="p-2 bg-blue-600 rounded-lg text-white shadow-lg"><Send size={18} /></div>
                  <div className="text-left"><p className="font-game font-bold text-white text-sm">Saída em Massa</p></div>
                </div>
                <Layers size={14} className="text-blue-500/30" />
              </button>
            </section>

            <section className="bg-slate-900/50 p-6 rounded-[2rem] border border-blue-500/10 space-y-4">
              <div className="flex items-center gap-3 mb-2">
                <FileText size={18} className="text-blue-400" />
                <h3 className="font-game font-bold text-white uppercase tracking-wider text-sm">Gerar Relatório</h3>
              </div>
              <input 
                type="text" 
                value={userName}
                onChange={(e) => setUserName(e.target.value)}
                placeholder="Nome do Operador"
                className="w-full bg-black/30 border border-white/5 rounded-xl px-4 py-3 text-sm focus:outline-none focus:ring-1 focus:ring-blue-500 text-white font-game"
              />
              <button 
                onClick={() => generatePDF(logs, userName)}
                className="w-full bg-blue-600 py-4 rounded-xl flex items-center justify-center gap-2 font-bold text-white active-scale text-xs uppercase tracking-widest"
              >
                <Download size={16} /> Exportar Extrato PDF
              </button>
            </section>
          </>
        ) : (
          <DailyStatsTable logs={logs} />
        )}
      </main>

      {/* Navegação Mobile Fixa Bottom (PWA Style) */}
      <nav className="fixed bottom-0 left-0 right-0 bg-slate-950/80 backdrop-blur-2xl border-t border-white/5 md:hidden z-50 pb-safe">
        <div className="flex justify-around items-center h-16">
          <button 
            onClick={() => setActiveTab('dash')}
            className={`flex flex-col items-center gap-1 transition-colors ${activeTab === 'dash' ? 'text-blue-500' : 'text-slate-500'}`}
          >
            <LayoutDashboard size={20} />
            <span className="text-[10px] font-bold uppercase tracking-tighter">Painel</span>
          </button>
          <button 
