import { jsPDF } from 'jspdf';
import autoTable from 'jspdf-autotable';
import { LogEntry, DailySummary } from '../types';
import { VALOR_POR_PACOTE } from '../constants';

export const generatePDF = (logs: LogEntry[], userName: string = 'Operador Logístico') => {
  const doc = new jsPDF();
  const dateStr = new Date().toLocaleDateString('pt-BR');
  const pageWidth = doc.internal.pageSize.getWidth();
  const pageHeight = doc.internal.pageSize.getHeight();

  // --- FUNDO DARK ---
  doc.setFillColor(2, 6, 23); // #020617
  doc.rect(0, 0, pageWidth, pageHeight, 'F');

  // --- EFEITOS DE GLOW (DECORATIVOS) ---
  doc.setGState(new (doc as any).GState({ opacity: 0.15 }));
  doc.setFillColor(37, 99, 235); // Azul
  doc.circle(0, 0, 50, 'F');
  doc.setFillColor(147, 51, 234); // Roxo
  doc.circle(pageWidth, pageHeight, 60, 'F');
  doc.setGState(new (doc as any).GState({ opacity: 1 }));

  // --- CABEÇALHO ---
  // Ícone Simulado
  doc.setFillColor(37, 99, 235);
  doc.roundedRect(14, 15, 12, 12, 3, 3, 'F');
  doc.setTextColor(255, 255, 255);
  doc.setFontSize(8);
  doc.setFont('helvetica', 'bold');
  doc.text('LT', 18, 23);

  // Título do App
  doc.setFontSize(22);
  doc.setTextColor(255, 255, 255);
  doc.text('LOGITRACK', 32, 23);

  doc.setFontSize(9);
  doc.setTextColor(100, 116, 139); // Slate 400
  doc.text('INTELIGÊNCIA EM LOGÍSTICA', 32, 28);

  // Info Direita
  doc.setFontSize(8);
  doc.text(`EMISSÃO: ${dateStr}`, pageWidth - 14, 20, { align: 'right' });
  doc.setTextColor(37, 99, 235);
  doc.text(`OPERADOR: ${userName.toUpperCase()}`, pageWidth - 14, 25, { align: 'right' });

  // --- LINHA DIVISORA NEON ---
  doc.setDrawColor(37, 99, 235);
  doc.setLineWidth(0.5);
  doc.line(14, 35, pageWidth - 14, 35);

  // --- CÁLCULOS ---
  const now = new Date();
  const sevenDaysAgo = new Date();
  sevenDaysAgo.setDate(now.getDate() - 7);
  const recentLogs = logs.filter(log => new Date(log.timestamp) >= sevenDaysAgo);

  const dailyData: Record<string, DailySummary> = {};
  recentLogs.forEach(log => {
    const day = new Date(log.timestamp).toLocaleDateString('pt-BR');
    if (!dailyData[day]) {
      dailyData[day] = { date: day, delivered: 0, returns: 0, gains: 0 };
    }
    if (log.type === 'SAIDA') {
      dailyData[day].delivered += 1;
      dailyData[day].gains += VALOR_POR_PACOTE;
    } else if (log.type === 'DEVOLUCAO') {
      dailyData[day].returns += 1;
    }
  });

  const summaryRows = Object.values(dailyData).sort((a, b) => {
     const [da, ma, ya] = a.date.split('/').map(Number);
     const [db, mb, yb] = b.date.split('/').map(Number);
     return new Date(yb, mb-1, db).getTime() - new Date(ya, ma-1, da).getTime();
  });

  const totalDelivered = summaryRows.reduce((acc, curr) => acc + curr.delivered, 0);
  const totalGains = summaryRows.reduce((acc, curr) => acc + curr.gains, 0);

  // --- CARD DE RESUMO (ESTILO APP) ---
  doc.setFillColor(15, 23, 42); // Slate 900
  doc.setDrawColor(30, 41, 59); // Slate 800
  doc.roundedRect(14, 45, pageWidth - 28, 35, 5, 5, 'FD');

  doc.setFontSize(10);
  doc.setTextColor(148, 163, 184); // Slate 400
  doc.text('RESUMO DA PRODUTIVIDADE (ÚLTIMOS 7 DIAS)', 20, 55);

  doc.setFontSize(24);
  doc.setTextColor(255, 255, 255);
  doc.text(`R$ ${totalGains.toFixed(2)}`, 20, 72);

  doc.setFontSize(9);
  doc.setTextColor(37, 99, 235);
  doc.text(`${totalDelivered} PACOTES ENTREGUES NO PERÍODO`, 85, 72);

  // --- TABELA DE DADOS ---
  const tableColumn = ["DATA", "ENTREGAS", "DEVOLUÇÕES", "GANHOS (BRL)"];
  const tableRows = summaryRows.map(row => [
    row.date,
    row.delivered.toString(),
    row.returns.toString(),
    `R$ ${row.gains.toFixed(2)}`
  ]);

  autoTable(doc, {
    head: [tableColumn],
    body: tableRows,
    startY: 95,
    theme: 'plain',
    headStyles: { 
      fillColor: [37, 99, 235], 
      textColor: [255, 255, 255],
      fontSize: 9,
      fontStyle: 'bold',
      halign: 'center'
    },
    bodyStyles: { 
      fillColor: [2, 6, 23], 
      textColor: [203, 213, 225], // Slate 300
      fontSize: 9,
      halign: 'center'
    },
    alternateRowStyles: { 
      fillColor: [15, 23, 42] // Slate 900
    },
    columnStyles: {
      3: { fontStyle: 'bold', textColor: [255, 255, 255] }
    },
    margin: { left: 14, right: 14 }
  });

  // --- RODAPÉ ---
  const finalY = (doc as any).lastAutoTable?.finalY || 150;

  // Badge de Segurança
  doc.setFillColor(31, 41, 55);
  doc.roundedRect(14, pageHeight - 25, pageWidth - 28, 15, 3, 3, 'F');

  doc.setFontSize(7);
  doc.setTextColor(100, 116, 139);
  doc.text('DOCUMENTO GERADO VIA LOGITRACK INTELLIGENCE SYSTEM v2.0', 20, pageHeight - 17);
  doc.setTextColor(37, 99, 235);
  doc.text('AUTENTICIDADE GARANTIDA PELA SINCRONIZAÇÃO SUPABASE', pageWidth - 20, pageHeight - 17, { align: 'right' });

  doc.save(`extrato_logitrack_${dateStr.replace(/\//g, '-')}.pdf`);
};

