export const VALOR_POR_PACOTE = 2.50;
export const STORAGE_KEY = 'logcash_package_logs';
export const SUPABASE_CACHE_KEY = 'logcash_supabase_cache';

import { supabase } from "../supabaseConfig";
import { LogEntry } from "../types";

const TABLE_NAME = "logs";

export const supabaseService = {
  // --- AUTH METHODS ---
  signUp: async (email: string, pass: string) => {
    const { data, error } = await supabase.auth.signUp({ email, password: pass });
    if (error) throw error;
    return data;
  },

  signIn: async (email: string, pass: string) => {
    const { data, error } = await supabase.auth.signInWithPassword({ email, password: pass });
    if (error) throw error;
    return data;
  },

  signOut: async () => {
    const { error } = await supabase.auth.signOut();
    if (error) throw error;
  },

  getSession: async () => {
    const { data: { session } } = await supabase.auth.getSession();
    return session;
  },

  // --- LOG METHODS ---
  subscribeToLogs: (callback: (logs: LogEntry[], error?: any) => void) => {
    const fetchLogs = async () => {
      try {
        const { data, error } = await supabase
          .from(TABLE_NAME)
          .select("*")
          .order("timestamp", { ascending: false });

        if (error) {
          console.error("Erro ao buscar logs no Supabase:", error);
          callback([], error);
        } else {
          callback((data as LogEntry[]) || [], undefined);
        }
      } catch (err) {
        console.error("Erro crítico na conexão com Supabase:", err);
        callback([], err);
      }
    };

    fetchLogs();

    const channel = supabase
      .channel("schema-db-changes")
      .on(
        "postgres_changes",
        {
          event: "*",
          schema: "public",
          table: TABLE_NAME,
        },
        () => {
          fetchLogs();
        }
      )
      .subscribe();

    return () => {
      supabase.removeChannel(channel);
    };
  },

  saveLog: async (entry: Omit<LogEntry, 'id'>) => {
    const { error } = await supabase
      .from(TABLE_NAME)
      .insert([entry]);
    if (error) throw error;
  },

  saveBulkLogs: async (entries: Omit<LogEntry, 'id'>[]) => {
    const { error } = await supabase
      .from(TABLE_NAME)
      .insert(entries);
    if (error) throw error;
  },

  deleteAllLogs: async () => {
    // Nota: Em um sistema real com RLS, isso deleta apenas os registros do usuário autenticado.
    const { error } = await supabase
      .from(TABLE_NAME)
      .delete()
      .neq('id', '00000000-0000-0000-0000-000000000000'); // Deleta tudo que não tem esse ID fake
    if (error) throw error;
  }
};

