                  <button 
                    onClick={() => setConfirmReset(true)}
                    className="w-full flex items-center justify-between p-4 bg-red-500/5 border border-red-500/10 rounded-xl text-red-500 active-scale group hover:bg-red-500/10 transition-all"
                  >
                    <div className="flex items-center gap-3">
                      <Trash2 size={18} />
                      <span className="text-xs font-bold uppercase tracking-widest">Resetar Todos os Dados</span>
                    </div>
                  </button>
                ) : (
                  <div className="p-5 bg-red-500/10 border border-red-500/20 rounded-2xl space-y-4 animate-in zoom-in-95 duration-200">
                    <div className="flex items-center gap-2 text-red-400">
                      <AlertCircle size={16} />
                      <p className="text-[10px] font-black uppercase tracking-tight">Tem certeza absoluta?</p>
                    </div>
                    <p className="text-[10px] text-slate-400 font-bold uppercase leading-relaxed">Esta ação apagará permanentemente todo o histórico de entregas e ganhos desta conta.</p>
                    <div className="flex gap-2">
                      <button onClick={() => setConfirmReset(false)} className="flex-1 py-3 bg-white/5 rounded-lg text-[10px] font-bold uppercase">Cancelar</button>
                      <button onClick={handleResetData} className="flex-1 py-3 bg-red-600 text-white rounded-lg text-[10px] font-bold uppercase shadow-lg shadow-red-500/20">Sim, APAGAR</button>
                    </div>
                  </div>
                )}
              </div>
            </div>
          </div>
        </div>
      )}

      <BulkActionModal 
        isOpen={bulkModal.isOpen}
        type={bulkModal.type}
        title={bulkModal.type === 'SAIDA' ? 'Saída Lote' : 'Entrada Lote'}
        onClose={() => setBulkModal({ ...bulkModal, isOpen: false })}
        onConfirm={handleBulkAction}
      />

      {showToast && (
        <div className="fixed bottom-20 md:bottom-8 left-1/2 -translate-x-1/2 bg-emerald-600 text-white px-6 py-3 rounded-full shadow-2xl flex items-center gap-3 z-50 animate-in slide-in-from-bottom-2">
          <Zap size={14} fill="currentColor" />
          <span className="font-game font-bold text-xs uppercase tracking-widest">{toastMsg}</span>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
