import { jsPDF } from 'jspdf';
import autoTable from 'jspdf-autotable';
import { LogEntry, DailySummary } from '../types';
import { VALOR_POR_PACOTE } from '../constants';

export const generatePDF = (logs: LogEntry[], userName: string = 'Operador Logístico') => {
  const doc = new jsPDF();
  const dateStr = new Date().toLocaleDateString('pt-BR');
  const pageWidth = doc.internal.pageSize.getWidth();
  const pageHeight = doc.internal.pageSize.getHeight();

  // --- FUNDO DARK ---
  doc.setFillColor(2, 6, 23); // #020617
  doc.rect(0, 0, pageWidth, pageHeight, 'F');

  // --- EFEITOS DE GLOW (DECORATIVOS) ---
  doc.setGState(new (doc as any).GState({ opacity: 0.1 }));
  doc.setFillColor(16, 185, 129); // Esmeralda
  doc.circle(0, 0, 60, 'F');
  doc.setFillColor(5, 150, 105); 
  doc.circle(pageWidth, pageHeight, 80, 'F');
  doc.setGState(new (doc as any).GState({ opacity: 1 }));

  // --- LOGO LOGCASH (RECRIAÇÃO EM PDF) ---
  const lx = 14, ly = 12, lw = 18;

  // Círculo Externo
  doc.setDrawColor(16, 185, 129);
  doc.setLineWidth(0.8);
  doc.circle(lx + lw/2, ly + lw/2, lw/2, 'S');

  // Barras e Símbolos Internos (Simplificados)
  doc.setFillColor(30, 41, 59);
  doc.rect(lx + 5, ly + 10, 3, 5, 'F'); // Barra 1
  doc.rect(lx + 9, ly + 7, 3, 8, 'F');  // Barra 2

  doc.setTextColor(16, 185, 129);
  doc.setFontSize(10);
  doc.setFont('helvetica', 'bold');
  doc.text('$', lx + lw - 5, ly + lw - 4);

  // Seta de Crescimento
  doc.setDrawColor(16, 185, 129);
  doc.setLineWidth(0.5);
  doc.line(lx + 4, ly + 14, lx + 10, ly + 10);
  doc.line(lx + 10, ly + 10, lx + 14, ly + 6);
  // Ponta da seta
  doc.line(lx + 14, ly + 6, lx + 11, ly + 6);
  doc.line(lx + 14, ly + 6, lx + 14, ly + 9);

  // --- CABEÇALHO TEXTO ---
  doc.setFontSize(24);
  doc.setTextColor(255, 255, 255);
  doc.setFont('helvetica', 'bold');
  doc.text('LOG', 38, 23);
  doc.setTextColor(16, 185, 129);
  doc.text('CASH', 61, 23);

  doc.setFontSize(8);
  doc.setTextColor(100, 116, 139); // Slate 400
  doc.setFont('helvetica', 'normal');
  doc.text('SISTEMA DE GESTÃO DE ENTREGAS E GANHOS', 38, 28);

  // Info Direita
  doc.setFontSize(8);
  doc.setTextColor(148, 163, 184);
  doc.text(`EXTRATO EMITIDO EM: ${dateStr}`, pageWidth - 14, 20, { align: 'right' });
  doc.setTextColor(16, 185, 129);
  doc.setFont('helvetica', 'bold');
  doc.text(`OPERADOR: ${userName.toUpperCase()}`, pageWidth - 14, 25, { align: 'right' });

  // --- LINHA DIVISORA ---
  doc.setDrawColor(16, 185, 129);
  doc.setLineWidth(0.5);
  doc.line(14, 35, pageWidth - 14, 35);

  // --- CÁLCULOS ---
  const now = new Date();
  const sevenDaysAgo = new Date();
  sevenDaysAgo.setDate(now.getDate() - 7);
  const recentLogs = logs.filter(log => new Date(log.timestamp) >= sevenDaysAgo);

  const dailyData: Record<string, DailySummary> = {};
  recentLogs.forEach(log => {
    const day = new Date(log.timestamp).toLocaleDateString('pt-BR');
    if (!dailyData[day]) {
      dailyData[day] = { date: day, delivered: 0, returns: 0, gains: 0 };
    }
    if (log.type === 'SAIDA') {
      dailyData[day].delivered += 1;
      dailyData[day].gains += VALOR_POR_PACOTE;
    } else if (log.type === 'DEVOLUCAO') {
      dailyData[day].returns += 1;
    }
  });

  const summaryRows = Object.values(dailyData).sort((a, b) => {
     const [da, ma, ya] = a.date.split('/').map(Number);
     const [db, mb, yb] = b.date.split('/').map(Number);
     return new Date(yb, mb-1, db).getTime() - new Date(ya, ma-1, da).getTime();
  });

  const totalDelivered = summaryRows.reduce((acc, curr) => acc + curr.delivered, 0);
  const totalGains = summaryRows.reduce((acc, curr) => acc + curr.gains, 0);

  // --- CARD DE PERFORMANCE ---
  doc.setFillColor(15, 23, 42); // Slate 900
  doc.setDrawColor(30, 41, 59); // Slate 800
  doc.roundedRect(14, 45, pageWidth - 28, 40, 6, 6, 'FD');

  doc.setFontSize(9);
  doc.setTextColor(148, 163, 184);
  doc.text('BALANÇO DE PRODUTIVIDADE (ÚLTIMOS 7 DIAS)', 22, 55);

  doc.setFontSize(26);
  doc.setTextColor(255, 255, 255);
  doc.text(`R$ ${totalGains.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}`, 22, 74);

  doc.setFontSize(10);
  doc.setTextColor(16, 185, 129);
  doc.text(`${totalDelivered} ENTREGAS FINALIZADAS`, 22, 80);

  // Indicador visual de lucro
  doc.setFillColor(16, 185, 129);
  doc.circle(pageWidth - 30, 65, 10, 'F');
  doc.setTextColor(255, 255, 255);
  doc.setFontSize(12);
  doc.text('$', pageWidth - 31.5, 69);

  // --- TABELA DE HISTÓRICO ---
  const tableColumn = ["DATA DO FLUXO", "SAÍDAS (OK)", "RETORNOS", "TOTAL LÍQUIDO"];
  const tableRows = summaryRows.map(row => [
    row.date,
    row.delivered.toString(),
    row.returns.toString(),
    `R$ ${row.gains.toFixed(2)}`
  ]);

  autoTable(doc, {
    head: [tableColumn],
    body: tableRows,
    startY: 100,
    theme: 'plain',
    headStyles: { 
      fillColor: [16, 185, 129], 
      textColor: [255, 255, 255],
      fontSize: 9,
      fontStyle: 'bold',
      halign: 'center',
      cellPadding: 4
    },
    bodyStyles: { 
      fillColor: [2, 6, 23], 
      textColor: [203, 213, 225],
      fontSize: 9,
      halign: 'center',
      cellPadding: 4
    },
    alternateRowStyles: { 
      fillColor: [15, 23, 42]
    },
    columnStyles: {
      3: { fontStyle: 'bold', textColor: [255, 255, 255] }
    },
    margin: { left: 14, right: 14 }
  });

  // --- RODAPÉ ---
  doc.setFillColor(15, 23, 42);
  doc.rect(0, pageHeight - 20, pageWidth, 20, 'F');

  doc.setFontSize(7);
  doc.setTextColor(71, 85, 105);
  doc.text('DOCUMENTO OFICIAL GERADO PELO TERMINAL LOGCASH v3.0', 14, pageHeight - 10);
  doc.setTextColor(16, 185, 129);
  doc.setFont('helvetica', 'bold');
  doc.text('DADOS CRIPTOGRAFADOS E SINCRONIZADOS EM NUVEM', pageWidth - 14, pageHeight - 10, { align: 'right' });

  doc.save(`extrato_logcash_${dateStr.replace(/\//g, '-')}.pdf`);
};

import React, { useState, useEffect, useMemo } from 'react';
import { Truck, Zap, FileText, Download, LayoutDashboard, Send, Table as TableIcon, ListPlus, LogOut, Layers, Settings, Trash2, AlertCircle, User, Sliders, ChevronRight, X } from 'lucide-react';
import DashboardCards from './components/DashboardCards';
import ActionButtons from './components/ActionButtons';
import DailyStatsTable from './components/DailyStatsTable';
import BulkActionModal from './components/BulkActionModal';
import Login from './components/Login';
import { LogCashLogo } from './components/Logo';
import { LogEntry, LogActionType } from './types';
import { supabaseService } from './services/supabaseService';
import { generatePDF } from './services/pdfService';
import { SUPABASE_CACHE_KEY } from './constants';

const App: React.FC = () => {
  const [session, setSession] = useState<any>(null);
  const [logs, setLogs] = useState<LogEntry[]>(() => {
    const cached = localStorage.getItem(SUPABASE_CACHE_KEY);
    return cached ? JSON.parse(cached) : [];
  });
  const [loading, setLoading] = useState(true);
  const [isSyncing, setIsSyncing] = useState(false);
  const [showToast, setShowToast] = useState(false);
  const [toastMsg, setToastMsg] = useState('');
  const [userName, setUserName] = useState(() => localStorage.getItem('logcash_user_name') || 'Operador Logístico');
  const [activeTab, setActiveTab] = useState<'dash' | 'stats'>('dash');
  const [showSettings, setShowSettings] = useState(false);
  const [confirmReset, setConfirmReset] = useState(false);
  const [settingsView, setSettingsView] = useState<'menu' | 'profile' | 'danger'>('menu');

  const [bulkModal, setBulkModal] = useState<{ isOpen: boolean; type: 'ENTRADA' | 'SAIDA' }>({
    isOpen: false,
    type: 'ENTRADA'
  });

  useEffect(() => {
    supabaseService.getSession().then(session => {
      setSession(session);
      if (!session) setLoading(false);
    });
  }, []);

  useEffect(() => {
    if (!session) return;
    setIsSyncing(true);
    const unsubscribe = supabaseService.subscribeToLogs((updatedLogs, supabaseError) => {
      if (!supabaseError) {
        setLogs(updatedLogs);
        localStorage.setItem(SUPABASE_CACHE_KEY, JSON.stringify(updatedLogs));
      }
      setLoading(false);
      setIsSyncing(false);
    });
    return () => unsubscribe();
  }, [session]);

  // Persistir nome do usuário
  useEffect(() => {
    localStorage.setItem('logcash_user_name', userName);
  }, [userName]);

  const handleLogout = async () => {
    await supabaseService.signOut();
    localStorage.removeItem(SUPABASE_CACHE_KEY);
    setSession(null);
    setLogs([]);
    setShowSettings(false);
  };

  const handleAction = async (type: LogActionType) => {
    const newEntry: Omit<LogEntry, 'id'> = {
      type,
      timestamp: new Date().toISOString(),
      value: type === 'SAIDA' ? 2.50 : 0
    };
    try {
      await supabaseService.saveLog(newEntry);
      const messages = { ENTRADA: 'Entrada registrada!', SAIDA: 'Entrega salva! +R$ 2,50', DEVOLUCAO: 'Retorno registrado.' };
      setToastMsg(messages[type]);
      setShowToast(true);
      setTimeout(() => setShowToast(false), 2000);
    } catch (err) {
      setToastMsg('Erro na sincronização.');
      setShowToast(true);
    }
  };

  const handleBulkAction = async (quantity: number) => {
    const type = bulkModal.type;
    const newEntries = Array.from({ length: quantity }).map(() => ({
      type: type as LogActionType,
      timestamp: new Date().toISOString(),
      value: type === 'SAIDA' ? 2.50 : 0
    }));
    try {
      await supabaseService.saveBulkLogs(newEntries);
      setToastMsg(`${quantity} pacotes sincronizados!`);
      setShowToast(true);
      setTimeout(() => setShowToast(false), 2500);
    } catch (err) {
      setToastMsg('Falha no envio em lote.');
      setShowToast(true);
    }
  };

  const handleResetData = async () => {
    try {
      setIsSyncing(true);
      await supabaseService.deleteAllLogs();
      setToastMsg('Todos os dados foram resetados.');
      setShowToast(true);
      setConfirmReset(false);
      setShowSettings(false);
      setSettingsView('menu');
      setTimeout(() => setShowToast(false), 3000);
    } catch (err) {
      setToastMsg('Erro ao resetar dados.');
      setShowToast(true);
    } finally {
      setIsSyncing(false);
    }
  };

  const counts = useMemo(() => {
    const todayStr = new Date().toDateString();
    const now = new Date();
    const startOfWeek = new Date(now);
    startOfWeek.setDate(now.getDate() - now.getDay());
    startOfWeek.setHours(0, 0, 0, 0);
    const startOfYear = new Date(now.getFullYear(), 0, 1);
    return {
      today: logs.filter(l => l.type === 'SAIDA' && new Date(l.timestamp).toDateString() === todayStr).length,
      week: logs.filter(l => l.type === 'SAIDA' && new Date(l.timestamp) >= startOfWeek).length,
      year: logs.filter(l => l.type === 'SAIDA' && new Date(l.timestamp) >= startOfYear).length
    };
  }, [logs]);

  if (!session && !loading) return <Login onLoginSuccess={() => supabaseService.getSession().then(setSession)} />;

  if (loading && logs.length === 0) {
    return (
      <div className="min-h-screen bg-[#020617] flex flex-col items-center justify-center p-6 text-center">
        <LogCashLogo size={60} />
        <div className="w-12 h-1 border-b border-white/5 my-4"></div>
        <p className="text-slate-500 font-game font-bold uppercase tracking-[0.3em] text-[10px] animate-pulse">Iniciando LogCash...</p>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-[#020617] text-slate-200 selection:bg-emerald-500/30 flex flex-col">
      <header className="bg-slate-900/80 backdrop-blur-xl border-b border-white/5 px-4 py-3 md:px-8 md:py-4 sticky top-0 z-40 pt-safe">
        <div className="max-w-5xl mx-auto flex justify-between items-center">
          <div className="flex items-center gap-3">
            <LogCashLogo size={36} />
            <div>
              <h1 className="text-sm md:text-xl font-game font-black tracking-[0.15em] text-white leading-none">
                LOG<span className="text-emerald-400">CASH</span>
              </h1>
              <p className="text-[9px] text-slate-500 font-bold uppercase tracking-tighter mt-1">{isSyncing ? 'Sincronizando...' : 'Conectado'}</p>
            </div>
          </div>
          <div className="flex items-center gap-2">
            <button 
              onClick={() => { setShowSettings(true); setSettingsView('menu'); }} 
              className="p-2 bg-white/5 rounded-lg border border-white/10 active-scale transition-colors hover:bg-white/10 flex items-center gap-2"
            >
              <Settings size={18} className="text-slate-400" />
              <span className="hidden md:block text-[10px] font-bold text-slate-400 uppercase tracking-widest">Configurações</span>
            </button>
          </div>
        </div>
      </header>

      <main className="flex-1 max-w-5xl mx-auto w-full p-4 md:p-8 space-y-6 md:space-y-10 pb-28 md:pb-12">
        {activeTab === 'dash' ? (
          <>
            <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
              <div>
                <h2 className="text-2xl md:text-3xl font-game font-black text-white uppercase tracking-tight">Olá, {userName.split(' ')[0]}!</h2>
                <p className="text-xs text-slate-500 font-bold uppercase tracking-widest">Resumo do seu terminal logístico</p>
              </div>
            </div>

            <DashboardCards {...counts} />

            <section className="space-y-4">
              <h2 className="text-slate-500 font-game font-bold text-xs uppercase tracking-widest px-1">Registros Rápidos</h2>
              <ActionButtons onAction={handleAction} />
            </section>

            <section className="grid grid-cols-1 md:grid-cols-2 gap-3">
              <button 
                onClick={() => setBulkModal({ isOpen: true, type: 'ENTRADA' })}
                className="bg-slate-900/50 border border-emerald-500/10 p-4 rounded-2xl flex items-center justify-between active-scale hover:border-emerald-500/20 transition-all"
              >
                <div className="flex items-center gap-3">
                  <div className="p-2 bg-emerald-600 rounded-lg text-white shadow-lg"><ListPlus size={18} /></div>
                  <div className="text-left"><p className="font-game font-bold text-white text-sm">Entrada em Massa</p></div>
                </div>
                <Layers size={14} className="text-emerald-500/30" />
