import React, { useState } from 'react';
import { LogEntry } from '../types';
import { VALOR_POR_PACOTE } from '../constants';
import { Calendar, BarChart3, List, ChevronRight } from 'lucide-react';

interface DailyStatsTableProps {
  logs: LogEntry[];
}

type ViewMode = 'daily' | 'monthly';

const DailyStatsTable: React.FC<DailyStatsTableProps> = ({ logs }) => {
  const [viewMode, setViewMode] = useState<ViewMode>('daily');

  // Lógica de Agregação Diária
  const dailyGroups = logs.reduce((acc: any, log) => {
    const date = new Date(log.timestamp).toLocaleDateString('pt-BR');
    if (!acc[date]) {
      acc[date] = { label: date, entrada: 0, saida: 0, devolucao: 0, total: 0, rawDate: new Date(log.timestamp) };
    }
    if (log.type === 'ENTRADA') acc[date].entrada++;
    if (log.type === 'SAIDA') {
      acc[date].saida++;
      acc[date].total += VALOR_POR_PACOTE;
    }
    if (log.type === 'DEVOLUCAO') acc[date].devolucao++;
    return acc;
  }, {});

  // Lógica de Agregação Mensal
  const monthlyGroups = logs.reduce((acc: any, log) => {
    const d = new Date(log.timestamp);
    const monthLabel = d.toLocaleDateString('pt-BR', { month: 'long', year: 'numeric' });
    const monthKey = `${d.getMonth()}-${d.getFullYear()}`;

    if (!acc[monthKey]) {
      acc[monthKey] = { 
        label: monthLabel.charAt(0).toUpperCase() + monthLabel.slice(1), 
        entrada: 0, 
        saida: 0, 
        devolucao: 0, 
        total: 0,
        sortKey: d.getFullYear() * 12 + d.getMonth()
      };
    }
    if (log.type === 'ENTRADA') acc[monthKey].entrada++;
    if (log.type === 'SAIDA') {
      acc[monthKey].saida++;
      acc[monthKey].total += VALOR_POR_PACOTE;
    }
    if (log.type === 'DEVOLUCAO') acc[monthKey].devolucao++;
    return acc;
  }, {});

  const displayData = viewMode === 'daily' 
    ? Object.values(dailyGroups).sort((a: any, b: any) => b.rawDate.getTime() - a.rawDate.getTime())
    : Object.values(monthlyGroups).sort((a: any, b: any) => b.sortKey - a.sortKey);

  return (
    <div className="bg-slate-900/60 border border-white/5 rounded-[2.5rem] overflow-hidden backdrop-blur-xl shadow-2xl">
      {/* Header do Card */}
      <div className="p-6 md:p-8 border-b border-white/5 flex flex-col sm:flex-row sm:items-center justify-between gap-6">
        <div className="flex items-center gap-4">
          <div className="w-12 h-12 bg-emerald-500/10 rounded-2xl flex items-center justify-center border border-emerald-500/20">
            <BarChart3 size={24} className="text-emerald-400" />
          </div>
          <div>
            <h3 className="text-white font-game text-xl font-bold uppercase tracking-tight leading-none">
              Análise de Fluxo
            </h3>
            <p className="text-[10px] text-slate-500 font-bold uppercase tracking-[0.2em] mt-2">Registros de Produtividade</p>
          </div>
        </div>

        {/* View Mode Selector - Design Moderno */}
        <div className="bg-black/40 p-1.5 rounded-2xl border border-white/5 flex items-center shadow-inner">
          <button 
            onClick={() => setViewMode('daily')}
            className={`flex items-center gap-2 px-5 py-2.5 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all duration-300 ${viewMode === 'daily' ? 'bg-emerald-600 text-white shadow-lg shadow-emerald-600/20' : 'text-slate-500 hover:text-slate-300'}`}
          >
            <List size={14} /> Diário
          </button>
          <button 
            onClick={() => setViewMode('monthly')}
            className={`flex items-center gap-2 px-5 py-2.5 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all duration-300 ${viewMode === 'monthly' ? 'bg-emerald-600 text-white shadow-lg shadow-emerald-600/20' : 'text-slate-500 hover:text-slate-300'}`}
          >
            <Calendar size={14} /> Mensal
          </button>
        </div>
      </div>

