      <div className="overflow-x-auto scrollbar-thin scrollbar-thumb-white/10 scrollbar-track-transparent">
        <table className="w-full text-left border-collapse min-w-[650px]">
          <thead>
            <tr className="bg-white/[0.02]">
              <th className="px-8 py-5 text-[10px] font-black text-slate-500 uppercase tracking-[0.2em] border-b border-white/5">
                Período
              </th>
              <th className="px-6 py-5 text-[10px] font-black text-slate-500 uppercase tracking-[0.2em] border-b border-white/5 text-center">Entradas</th>
              <th className="px-6 py-5 text-[10px] font-black text-slate-500 uppercase tracking-[0.2em] border-b border-white/5 text-center">Saídas</th>
              <th className="px-6 py-5 text-[10px] font-black text-slate-500 uppercase tracking-[0.2em] border-b border-white/5 text-center">Retornos</th>
              <th className="px-8 py-5 text-[10px] font-black text-slate-500 uppercase tracking-[0.2em] border-b border-white/5 text-right">Saldo Final</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-white/5">
            {displayData.map((item: any, idx: number) => (
              <tr key={idx} className="hover:bg-white/[0.03] transition-all duration-300 group">
                <td className="px-8 py-6">
                  <div className="flex items-center gap-3">
                    <div className="w-1.5 h-1.5 rounded-full bg-emerald-500/40 group-hover:bg-emerald-500 transition-colors"></div>
                    <p className={`font-game font-bold tracking-tight ${viewMode === 'daily' ? 'text-slate-200 text-base' : 'text-emerald-400 text-lg'}`}>
                      {item.label}
                    </p>
                  </div>
                </td>
                <td className="px-6 py-6 text-center">
                  <span className="inline-flex items-center justify-center min-w-[40px] h-8 bg-emerald-500/10 text-emerald-400 rounded-lg font-bold text-xs border border-emerald-500/10 tabular-nums">
                    {item.entrada}
                  </span>
                </td>
                <td className="px-6 py-6 text-center">
                  <span className="inline-flex items-center justify-center min-w-[40px] h-8 bg-blue-500/10 text-blue-400 rounded-lg font-bold text-xs border border-blue-500/10 tabular-nums">
                    {item.saida}
                  </span>
                </td>
                <td className="px-6 py-6 text-center">
                  <span className="inline-flex items-center justify-center min-w-[40px] h-8 bg-orange-500/10 text-orange-400 rounded-lg font-bold text-xs border border-orange-500/10 tabular-nums">
                    {item.devolucao}
                  </span>
                </td>
                <td className="px-8 py-6 text-right">
                  <div className="flex flex-col items-end">
                    <span className="text-white font-game text-xl font-black tracking-tighter tabular-nums">
                      {new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(item.total)}
                    </span>
                    <div className="flex items-center gap-1.5 mt-1">
                       <div className="w-1 h-1 rounded-full bg-emerald-500"></div>
                       <span className="text-[9px] text-slate-500 font-bold uppercase tracking-widest">
                         Confirmado
                       </span>
                    </div>
                  </div>
                </td>
              </tr>
            ))}
            {displayData.length === 0 && (
              <tr>
                <td colSpan={5} className="py-24 text-center">
                  <div className="flex flex-col items-center gap-4 opacity-30">
                    <BarChart3 size={48} className="text-slate-500" />
                    <p className="text-slate-500 font-game uppercase tracking-[0.4em] text-xs font-bold">Base de dados vazia</p>
                  </div>
                </td>
              </tr>
            )}
          </tbody>
        </table>
      </div>

      {/* Rodapé Informativo */}
      <div className="p-6 bg-black/30 border-t border-white/5 flex flex-col md:flex-row items-center justify-between gap-4">
        <div className="flex items-center gap-6">
          <div className="flex items-center gap-2">
            <div className="w-2 h-2 rounded-full bg-emerald-500"></div>
            <span className="text-[9px] text-slate-400 font-bold uppercase tracking-widest">Rendimento Positivo</span>
          </div>
          <div className="flex items-center gap-2">
            <div className="w-2 h-2 rounded-full bg-blue-500"></div>
            <span className="text-[9px] text-slate-400 font-bold uppercase tracking-widest">Fluxo de Saída</span>
          </div>
