import { jsPDF } from 'jspdf';
import autoTable from 'jspdf-autotable';
import { LogEntry, DailySummary } from '../types';
import { VALOR_POR_PACOTE } from '../constants';

export const generatePDF = (logs: LogEntry[], userName: string = 'Operador Logístico') => {
  const doc = new jsPDF();
  const dateStr = new Date().toLocaleDateString('pt-BR');
  const pageWidth = doc.internal.pageSize.getWidth();
  const pageHeight = doc.internal.pageSize.getHeight();

  // --- FUNDO ---
  doc.setFillColor(252, 252, 252);
  doc.rect(0, 0, pageWidth, pageHeight, 'F');

  // --- CABEÇALHO DESIGN ---
  doc.setFillColor(15, 23, 42); // Slate 900
  doc.rect(0, 0, pageWidth, 45, 'F');

  // LOGO LOGCASH (REPRESENTAÇÃO GRÁFICA)
  doc.setDrawColor(16, 185, 129); // Emerald 500
  doc.setLineWidth(1.2);
  doc.circle(25, 22, 10, 'S');

  doc.setFillColor(16, 185, 129);
  doc.rect(21, 19, 8, 2, 'F');
  doc.rect(21, 23, 8, 2, 'F');

  doc.setFontSize(24);
  doc.setTextColor(255, 255, 255);
  doc.setFont('helvetica', 'bold');
  doc.text('LOG', 42, 25);
  doc.setTextColor(16, 185, 129);
  doc.text('CASH', 64, 25);

  doc.setFontSize(8);
  doc.setTextColor(100, 116, 139);
  doc.text('TERMINAL DE GESTÃO LOGÍSTICA INTELIGENTE', 42, 31);

  // INFO OPERADOR NO CABEÇALHO
  doc.setTextColor(255, 255, 255);
  doc.setFontSize(9);
  doc.text(`EXTRATO EMITIDO EM: ${dateStr}`, pageWidth - 20, 20, { align: 'right' });
  doc.setFontSize(10);
  doc.setFont('helvetica', 'bold');
  doc.text(`OPERADOR: ${userName.toUpperCase()}`, pageWidth - 20, 27, { align: 'right' });

  // --- CÁLCULOS ---
  const dailyData: Record<string, DailySummary> = {};
  logs.forEach(log => {
    const day = new Date(log.timestamp).toLocaleDateString('pt-BR');
    if (!dailyData[day]) {
      dailyData[day] = { date: day, delivered: 0, returns: 0, gains: 0 };
    }
    if (log.type === 'SAIDA') {
      dailyData[day].delivered += 1;
      dailyData[day].gains += VALOR_POR_PACOTE;
    } else if (log.type === 'DEVOLUCAO') {
      dailyData[day].returns += 1;
    }
  });

  const summaryRows = Object.values(dailyData).sort((a, b) => {
     const [da, ma, ya] = a.date.split('/').map(Number);
     const [db, mb, yb] = b.date.split('/').map(Number);
     return new Date(ya, ma-1, da).getTime() - new Date(yb, mb-1, db).getTime();
  });

  const totalGains = logs.filter(l => l.type === 'SAIDA').length * VALOR_POR_PACOTE;
  const totalDelivered = logs.filter(l => l.type === 'SAIDA').length;

  // --- CARD DE RESUMO ---
  doc.setFillColor(255, 255, 255);
  doc.roundedRect(14, 55, pageWidth - 28, 35, 4, 4, 'F');
  doc.setDrawColor(226, 232, 240);
  doc.roundedRect(14, 55, pageWidth - 28, 35, 4, 4, 'S');

  doc.setTextColor(100, 116, 139);
  doc.setFontSize(10);
  doc.setFont('helvetica', 'normal');
  doc.text('SALDO ACUMULADO DISPONÍVEL', 22, 68);

  doc.setTextColor(15, 23, 42);
  doc.setFontSize(22);
  doc.setFont('helvetica', 'bold');
  doc.text(`R$ ${totalGains.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}`, 22, 82);

  doc.setTextColor(16, 185, 129);
  doc.setFontSize(11);
  doc.text(`${totalDelivered} ENTREGAS FINALIZADAS`, pageWidth - 22, 82, { align: 'right' });

  // --- TABELA ---
  const tableColumn = ["DATA DO REGISTRO", "ENTREGAS (OK)", "RETORNOS", "VALOR LÍQUIDO"];
  const tableRows = summaryRows.map(row => [
    row.date,
    row.delivered.toString(),
    row.returns.toString(),
    `R$ ${row.gains.toFixed(2)}`
  ]);

  autoTable(doc, {
    head: [tableColumn],
    body: tableRows,
    startY: 100,
    theme: 'grid',
    headStyles: { 
      fillColor: [15, 23, 42], 
      textColor: [255, 255, 255],
      fontSize: 10,
      fontStyle: 'bold',
      halign: 'center',
      cellPadding: 4
    },
    bodyStyles: { 
      fontSize: 9,
      halign: 'center',
      textColor: [51, 65, 85],
      cellPadding: 4
    },
    alternateRowStyles: { 
      fillColor: [248, 250, 252]
    },
    columnStyles: {
      0: { halign: 'left' },
      3: { fontStyle: 'bold', textColor: [16, 185, 129], halign: 'right' }
    }
  });

  // --- RODAPÉ ---
  doc.setFontSize(8);
  doc.setTextColor(148, 163, 184);
  doc.text('DOCUMENTO GERADO AUTOMATICAMENTE PELO APP LOGCASH - SINCRONIZAÇÃO EM NUVEM', pageWidth / 2, pageHeight - 15, { align: 'center' });

  doc.save(`extrato_logcash_${dateStr.replace(/\//g, '-')}.pdf`);
};

