import React, { useState, useEffect, useMemo } from 'react';
import { Truck, Zap, FileText, Download, LayoutDashboard, Send, Table as TableIcon, ListPlus, LogOut, Layers, Settings, Trash2, AlertCircle, User, Sliders, ChevronRight, X, CheckCircle2, Check } from 'lucide-react';
import DashboardCards from './components/DashboardCards';
import ActionButtons from './components/ActionButtons';
import DailyStatsTable from './components/DailyStatsTable';
import BulkActionModal from './components/BulkActionModal';
import Login from './components/Login';
import { LogCashLogo } from './components/Logo';
import { LogEntry, LogActionType } from './types';
import { supabaseService } from './services/supabaseService';
import { generatePDF } from './services/pdfService';
import { SUPABASE_CACHE_KEY } from './constants';

const App: React.FC = () => {
  const [session, setSession] = useState<any>(null);
  const [logs, setLogs] = useState<LogEntry[]>(() => {
    const cached = localStorage.getItem(SUPABASE_CACHE_KEY);
    return cached ? JSON.parse(cached) : [];
  });
  const [loading, setLoading] = useState(true);
  const [isSyncing, setIsSyncing] = useState(false);
  const [showToast, setShowToast] = useState(false);
  const [toastMsg, setToastMsg] = useState('');

  // Estado para o Pop-up de Sucesso em Massa
  const [showSuccessPopup, setShowSuccessPopup] = useState(false);
  const [bulkCount, setBulkCount] = useState(0);
  const [bulkActionType, setBulkActionType] = useState<'ENTRADA' | 'SAIDA'>('ENTRADA');

  const [userName, setUserName] = useState(() => localStorage.getItem('logcash_user_name') || 'Operador Logístico');
  const [activeTab, setActiveTab] = useState<'dash' | 'stats'>('dash');
  const [showSettings, setShowSettings] = useState(false);
  const [confirmReset, setConfirmReset] = useState(false);
  const [settingsView, setSettingsView] = useState<'menu' | 'profile' | 'danger'>('menu');

  const [bulkModal, setBulkModal] = useState<{ isOpen: boolean; type: 'ENTRADA' | 'SAIDA' }>({
    isOpen: false,
    type: 'ENTRADA'
  });

  useEffect(() => {
    supabaseService.getSession().then(session => {
      setSession(session);
      if (!session) setLoading(false);
    });
  }, []);

  useEffect(() => {
    if (!session) return;
    setIsSyncing(true);
    const unsubscribe = supabaseService.subscribeToLogs((updatedLogs, supabaseError) => {
      if (!supabaseError) {
        setLogs(updatedLogs);
        localStorage.setItem(SUPABASE_CACHE_KEY, JSON.stringify(updatedLogs));
      }
      setLoading(false);
      setIsSyncing(false);
    });
    return () => unsubscribe();
  }, [session]);

  useEffect(() => {
    localStorage.setItem('logcash_user_name', userName);
  }, [userName]);

  const handleLogout = async () => {
    await supabaseService.signOut();
    localStorage.removeItem(SUPABASE_CACHE_KEY);
    setSession(null);
    setLogs([]);
    setShowSettings(false);
  };

  const handleAction = async (type: LogActionType) => {
    const newEntry: Omit<LogEntry, 'id'> = {
      type,
      timestamp: new Date().toISOString(),
      value: type === 'SAIDA' ? 2.50 : 0
    };
    try {
      await supabaseService.saveLog(newEntry);
      const messages = { ENTRADA: 'Entrada registrada!', SAIDA: 'Entrega salva! +R$ 2,50', DEVOLUCAO: 'Retorno registrado.' };
      setToastMsg(messages[type]);
      setShowToast(true);
      setTimeout(() => setShowToast(false), 2000);
    } catch (err) {
      setToastMsg('Erro na sincronização.');
      setShowToast(true);
      setTimeout(() => setShowToast(false), 2000);
    }
  };

  const handleBulkAction = async (quantity: number) => {
    const type = bulkModal.type;
    const newEntries = Array.from({ length: quantity }).map(() => ({
      type: type as LogActionType,
      timestamp: new Date().toISOString(),
      value: type === 'SAIDA' ? 2.50 : 0
    }));
    try {
      await supabaseService.saveBulkLogs(newEntries);

      // Aciona o Pop-up de Sucesso Animado
      setBulkCount(quantity);
      setBulkActionType(type as 'ENTRADA' | 'SAIDA');
      setShowSuccessPopup(true);

      // Fecha o modal e limpa após 2.5s
      setTimeout(() => {
        setShowSuccessPopup(false);
      }, 2500);

    } catch (err) {
      setToastMsg('Falha no envio em lote.');
      setShowToast(true);
      setTimeout(() => setShowToast(false), 2000);
    }
  };

  const handleResetData = async () => {
    try {
      setIsSyncing(true);
      await supabaseService.deleteAllLogs();
      setToastMsg('Dados resetados com sucesso.');
      setShowToast(true);
      setConfirmReset(false);
      setShowSettings(false);
      setSettingsView('menu');
      setTimeout(() => setShowToast(false), 3000);
    } catch (err) {
      setToastMsg('Erro ao resetar dados.');
      setShowToast(true);
    } finally {
      setIsSyncing(false);
    }
  };

  const counts = useMemo(() => {
    const todayStr = new Date().toDateString();
    const now = new Date();
    const startOfWeek = new Date(now);
    startOfWeek.setDate(now.getDate() - now.getDay());
    startOfWeek.setHours(0, 0, 0, 0);
    const startOfYear = new Date(now.getFullYear(), 0, 1);
    return {
      today: logs.filter(l => l.type === 'SAIDA' && new Date(l.timestamp).toDateString() === todayStr).length,
      week: logs.filter(l => l.type === 'SAIDA' && new Date(l.timestamp) >= startOfWeek).length,
      year: logs.filter(l => l.type === 'SAIDA' && new Date(l.timestamp) >= startOfYear).length
    };
  }, [logs]);

  if (!session && !loading) return <Login onLoginSuccess={() => supabaseService.getSession().then(setSession)} />;

  if (loading && logs.length === 0) {
    return (
      <div className="min-h-screen bg-[#020617] flex flex-col items-center justify-center p-6 text-center">
        <LogCashLogo size={60} />
        <div className="w-12 h-1 border-b border-white/5 my-4"></div>
        <p className="text-slate-500 font-game font-bold uppercase tracking-[0.3em] text-[10px] animate-pulse">Iniciando LogCash...</p>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-[#020617] text-slate-200 selection:bg-emerald-500/30 flex flex-col overflow-x-hidden relative">
      <header className="bg-slate-900/80 backdrop-blur-xl border-b border-white/5 px-4 py-2 md:px-8 md:py-4 sticky top-0 z-40 pt-safe transition-all duration-300">
        <div className="max-w-5xl mx-auto flex justify-between items-center h-12">
          <div className="flex items-center gap-2 md:gap-3">
            <LogCashLogo size={32} />
            <div>
              <h1 className="text-sm md:text-xl font-game font-black tracking-[0.1em] text-white leading-none">
                LOG<span className="text-emerald-400">CASH</span>
              </h1>
              <p className="text-[8px] md:text-[9px] text-slate-500 font-bold uppercase tracking-tighter mt-1">
                {isSyncing ? 'Sincronizando...' : 'Online'}
              </p>
            </div>
          </div>
          <button 
            onClick={() => { setShowSettings(true); setSettingsView('menu'); }} 
            className="p-2.5 bg-white/5 rounded-xl border border-white/10 active:scale-95 transition-all hover:bg-white/10 flex items-center gap-2"
          >
            <Settings size={18} className="text-slate-400" />
            <span className="hidden sm:block text-[10px] font-bold text-slate-400 uppercase tracking-widest">Ajustes</span>
          </button>
        </div>
      </header>

      <main className="flex-1 max-w-5xl mx-auto w-full p-4 md:p-8 space-y-6 md:space-y-10 pb-28 md:pb-12 transition-all">
        {activeTab === 'dash' ? (
          <div className="animate-in fade-in duration-500">
            <div className="mb-6">
              <h2 className="text-2xl md:text-4xl font-game font-black text-white uppercase tracking-tight leading-tight">
                Olá, {userName.split(' ')[0]}
              </h2>
              <p className="text-[10px] md:text-xs text-slate-500 font-bold uppercase tracking-widest mt-1">
                Acompanhe sua produtividade logística
              </p>
            </div>

            <div className="mb-8">
              <DashboardCards {...counts} />
            </div>

            <section className="space-y-4 mb-8">
              <div className="flex items-center justify-between px-1">
                <h2 className="text-slate-500 font-game font-bold text-[10px] uppercase tracking-widest">Ações Rápidas</h2>
                <div className="h-px flex-1 bg-white/5 mx-4 hidden sm:block"></div>
              </div>
              <ActionButtons onAction={handleAction} />
            </section>

            <section className="grid grid-cols-2 gap-3 mb-8">
              <button 
                onClick={() => setBulkModal({ isOpen: true, type: 'ENTRADA' })}
                className="bg-slate-900/50 border border-white/5 p-4 rounded-2xl flex flex-col items-start gap-3 active:scale-95 hover:bg-white/[0.03] transition-all"
              >
                <div className="p-2.5 bg-emerald-600/10 text-emerald-400 rounded-xl border border-emerald-500/20"><ListPlus size={20} /></div>
                <div className="text-left">
                  <p className="font-game font-bold text-white text-xs uppercase tracking-tight">Entrada Massa</p>
                  <p className="text-[8px] text-slate-500 uppercase font-bold">Lote Recebido</p>
                </div>
              </button>
              <button 
                onClick={() => setBulkModal({ isOpen: true, type: 'SAIDA' })}
                className="bg-slate-900/50 border border-white/5 p-4 rounded-2xl flex flex-col items-start gap-3 active:scale-95 hover:bg-white/[0.03] transition-all"
              >
                <div className="p-2.5 bg-blue-600/10 text-blue-400 rounded-xl border border-blue-500/20"><Send size={20} /></div>
                <div className="text-left">
                  <p className="font-game font-bold text-white text-xs uppercase tracking-tight">Saída Massa</p>
                  <p className="text-[8px] text-slate-500 uppercase font-bold">Lote Entregue</p>
                </div>
              </button>
            </section>

            <section className="bg-slate-900/50 p-5 md:p-8 rounded-[2rem] border border-white/5 relative overflow-hidden">
              <div className="flex items-center gap-3 mb-4">
                <div className="p-2 bg-emerald-500/10 rounded-lg"><FileText size={18} className="text-emerald-400" /></div>
                <h3 className="font-game font-bold text-white uppercase tracking-wider text-sm">Relatório Operacional</h3>
              </div>
              <p className="text-[9px] text-slate-500 font-bold uppercase tracking-widest mb-6">
                Exportar registro detalhado para: <span className="text-emerald-400">{userName}</span>
              </p>
              <button 
                onClick={() => generatePDF(logs, userName)}
                className="w-full bg-emerald-600 hover:bg-emerald-500 py-4 rounded-2xl flex items-center justify-center gap-3 font-game font-black text-white active:scale-95 text-xs uppercase tracking-[0.2em] transition-all shadow-lg shadow-emerald-900/20"
              >
                <Download size={18} /> Gerar PDF
              </button>
            </section>
          </div>
        ) : (
          <div className="animate-in fade-in duration-500">
             <div className="mb-6">
                <h2 className="text-2xl font-game font-black text-white uppercase tracking-tight">Estatísticas</h2>
                <p className="text-[10px] text-slate-500 font-bold uppercase tracking-widest mt-1">Histórico completo de fluxo</p>
             </div>
             <DailyStatsTable logs={logs} />
          </div>
        )}
      </main>

      <nav className="fixed bottom-0 left-0 right-0 bg-slate-950/80 backdrop-blur-2xl border-t border-white/5 md:hidden z-50 transition-transform duration-300">
        <div className="flex justify-around items-center h-16 max-w-lg mx-auto">
          <button 
            onClick={() => setActiveTab('dash')}
            className={`flex flex-col items-center justify-center w-full h-full gap-1 transition-all ${activeTab === 'dash' ? 'text-emerald-400 scale-110' : 'text-slate-600'}`}
          >
            <LayoutDashboard size={20} strokeWidth={activeTab === 'dash' ? 2.5 : 2} />
            <span className="text-[9px] font-black uppercase tracking-widest">Início</span>
          </button>
          <button 
            onClick={() => setActiveTab('stats')}
            className={`flex flex-col items-center justify-center w-full h-full gap-1 transition-all ${activeTab === 'stats' ? 'text-emerald-400 scale-110' : 'text-slate-600'}`}
          >
            <TableIcon size={20} strokeWidth={activeTab === 'stats' ? 2.5 : 2} />
            <span className="text-[9px] font-black uppercase tracking-widest">Histórico</span>
          </button>
        </div>
        <div className="h-safe bg-slate-950"></div>
      </nav>

      {/* Settings Modal */}
      {showSettings && (
        <div className="fixed inset-0 z-[100] flex items-end md:items-center justify-center bg-black/80 backdrop-blur-sm p-0 md:p-4">
          <div className="bg-slate-900 w-full max-w-lg rounded-t-[2rem] md:rounded-[2.5rem] border-t md:border border-white/10 overflow-hidden animate-in slide-in-from-bottom-full duration-400 transition-all">
            <div className="w-12 h-1 bg-white/10 rounded-full mx-auto my-3 md:hidden"></div>

            <div className="px-6 py-4 border-b border-white/5 flex justify-between items-center">
              <div className="flex items-center gap-3">
                {settingsView !== 'menu' && (
                   <button onClick={() => setSettingsView('menu')} className="p-2 hover:bg-white/5 rounded-full text-slate-500">
                     <ChevronRight size={20} className="rotate-180" />
                   </button>
                )}
                <h3 className="font-game font-bold text-white uppercase tracking-[0.1em] text-sm">
                  {settingsView === 'menu' ? 'Menu de Ajustes' : settingsView === 'profile' ? 'Editar Perfil' : 'Danger Zone'}
                </h3>
              </div>
              <button onClick={() => { setShowSettings(false); setConfirmReset(false); setSettingsView('menu'); }} className="p-2 bg-white/5 rounded-full text-slate-500 active:scale-90"><X size={20} /></button>
            </div>

            <div className="p-6 md:p-10 space-y-4">
              {settingsView === 'menu' && (
                <div className="space-y-3">
                  <button 
                    onClick={() => setSettingsView('profile')}
                    className="w-full flex items-center justify-between p-4 bg-white/5 hover:bg-white/10 border border-white/5 rounded-2xl transition-all group active:scale-[0.98]"
                  >
                    <div className="flex items-center gap-4">
                      <div className="p-2.5 bg-blue-500/10 rounded-xl text-blue-400"><User size={20} /></div>
                      <div className="text-left">
