                </div>
              )}

              {settingsView === 'profile' && (
                <div className="space-y-6 animate-in slide-in-from-right-4 duration-300">
                  <div className="space-y-4">
                    <label className="text-[9px] font-black text-slate-500 uppercase tracking-[0.3em] ml-1">Assinatura do Operador</label>
                    <div className="relative group">
                       <User className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-600 group-focus-within:text-emerald-400 transition-colors" size={18} />
                       <input 
                        type="text" 
                        value={userName}
                        onChange={(e) => setUserName(e.target.value)}
                        className="w-full bg-black/40 border border-white/10 focus:border-emerald-500/50 rounded-2xl pl-12 pr-4 py-4 text-sm font-bold text-white focus:outline-none transition-all placeholder:text-slate-700"
                        placeholder="Nome para o PDF"
                       />
                    </div>
                  </div>
                  <button onClick={() => { setShowSettings(false); setSettingsView('menu'); }} className="w-full bg-emerald-600 py-4 rounded-2xl font-game font-black text-white uppercase text-xs tracking-[0.2em] active:scale-95 shadow-lg shadow-emerald-900/20">Confirmar Alteração</button>
                </div>
              )}

              {settingsView === 'danger' && (
                <div className="space-y-6 animate-in slide-in-from-right-4 duration-300">
                  {!confirmReset ? (
                    <div className="space-y-6">
                      <div className="p-5 bg-red-500/5 border border-red-500/10 rounded-[1.5rem] flex items-start gap-4">
                         <div className="p-2.5 bg-red-500/20 rounded-xl text-red-500 mt-0.5"><AlertCircle size={22} /></div>
                         <div className="flex-1">
                            <p className="text-xs font-black text-white uppercase tracking-tight mb-1">Atenção Crítica</p>
                            <p className="text-[9px] text-slate-500 leading-relaxed font-bold uppercase tracking-widest">O reset apagará permanentemente todos os seus ganhos.</p>
                         </div>
                      </div>
                      <button onClick={() => setConfirmReset(true)} className="w-full flex items-center justify-center gap-3 p-4 bg-red-500/10 hover:bg-red-500/20 text-red-500 rounded-2xl transition-all font-game font-black uppercase text-xs tracking-widest active:scale-95">
                        <Trash2 size={18} /> Apagar Todos os Dados
                      </button>
                    </div>
                  ) : (
                    <div className="p-6 bg-red-600/10 border border-red-500/30 rounded-[2rem] space-y-6 text-center">
                      <AlertCircle size={40} className="text-red-500 mx-auto animate-bounce" />
                      <p className="text-sm font-black text-white uppercase tracking-widest">Confirma o Reset?</p>
                      <div className="flex flex-col gap-3">
                        <button onClick={handleResetData} className="w-full py-4.5 bg-red-600 text-white rounded-2xl font-game font-black text-xs uppercase tracking-[0.3em] shadow-xl shadow-red-500/20 active:scale-95">CONFIRMAR EXCLUSÃO</button>
                        <button onClick={() => setConfirmReset(false)} className="w-full py-4 text-slate-500 font-bold uppercase text-[9px] tracking-widest hover:text-white transition-colors">Voltar atrás</button>
                      </div>
                    </div>
                  )}
                </div>
              )}
            </div>
            <div className="h-safe bg-slate-900 pb-safe"></div>
          </div>
        </div>
      )}

      <BulkActionModal 
        isOpen={bulkModal.isOpen}
        type={bulkModal.type}
        title={bulkModal.type === 'SAIDA' ? 'Saída Lote' : 'Entrada Lote'}
        onClose={() => setBulkModal({ ...bulkModal, isOpen: false })}
        onConfirm={handleBulkAction}
      />

      {/* Pop-up de Sucesso Animado para Operações em Massa */}
      {showSuccessPopup && (
        <div className="fixed inset-0 z-[200] flex items-center justify-center pointer-events-none p-6">
          <div className="bg-emerald-600/95 backdrop-blur-xl border border-emerald-400/30 rounded-[2.5rem] p-8 md:p-12 shadow-[0_0_50px_rgba(16,185,129,0.4)] flex flex-col items-center text-center max-w-sm w-full animate-in zoom-in-75 slide-in-from-bottom-20 duration-500 transition-all">
            <div className="w-20 h-20 bg-white rounded-full flex items-center justify-center mb-6 shadow-2xl animate-bounce">
              <Check size={40} className="text-emerald-600" strokeWidth={4} />
            </div>
            <h4 className="text-2xl md:text-3xl font-game font-black text-white uppercase tracking-tighter leading-tight mb-2">
              Processado!
            </h4>
            <div className="w-full h-px bg-white/20 my-4"></div>
            <p className="text-emerald-50 font-game font-bold uppercase tracking-widest text-sm">
              <span className="text-3xl block mt-1">{bulkCount} Unidades</span>
              <span className="opacity-80 mt-2 block">
                {bulkActionType === 'SAIDA' ? 'Saída Concluída' : 'Entrada Concluída'}
              </span>
            </p>
          </div>
        </div>
      )}

      {/* Toast Notificação Padrão */}
      {showToast && (
        <div className="fixed bottom-20 md:bottom-8 left-4 right-4 md:left-1/2 md:-translate-x-1/2 md:w-auto bg-emerald-600 text-white px-6 py-4 rounded-2xl shadow-2xl flex items-center justify-center md:justify-start gap-3 z-[150] animate-in slide-in-from-bottom-10 fade-in duration-300">
          <CheckCircle2 size={18} className="text-white" />
          <span className="font-game font-bold text-[10px] md:text-xs uppercase tracking-[0.2em]">{toastMsg}</span>
        </div>
      )}
    </div>
  );
};

export default App;

