                    <ChevronRight size={18} className="text-slate-700" />
                  </button>

                  <button 
                    onClick={() => setSettingsView('danger')}
                    className="w-full flex items-center justify-between p-4 bg-white/5 hover:bg-white/10 border border-white/5 rounded-2xl transition-all group active:scale-[0.98]"
                  >
                    <div className="flex items-center gap-4">
                      <div className="p-2.5 bg-red-500/10 rounded-xl text-red-400"><Sliders size={20} /></div>
                      <div className="text-left">
                        <p className="text-sm font-bold text-white uppercase tracking-tight">Banco de Dados</p>
                        <p className="text-[9px] text-slate-500 font-bold uppercase tracking-widest">Reset total de registros</p>
                      </div>
                    </div>
                    <ChevronRight size={18} className="text-slate-700" />
                  </button>

                  <div className="pt-6 mt-2 border-t border-white/5">
                    <button 
                      onClick={handleLogout}
                      className="w-full flex items-center justify-center gap-3 p-4 bg-red-500/10 hover:bg-red-500/20 text-red-500 rounded-2xl transition-all font-game font-bold uppercase text-xs tracking-[0.2em] active:scale-95"
                    >
                      <LogOut size={18} /> Sair do Sistema
                    </button>
                  </div>
                </div>
              )}

              {settingsView === 'profile' && (
                <div className="space-y-6 animate-in slide-in-from-right-4 duration-300">
                  <div className="space-y-4">
                    <label className="text-[9px] font-black text-slate-500 uppercase tracking-[0.3em] ml-1">Assinatura do Operador</label>
                    <div className="relative group">
                       <User className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-600 group-focus-within:text-emerald-400 transition-colors" size={18} />
                       <input 
                        type="text" 
                        value={userName}
                        onChange={(e) => setUserName(e.target.value)}
                        className="w-full bg-black/40 border border-white/10 focus:border-emerald-500/50 rounded-2xl pl-12 pr-4 py-4 text-sm font-bold text-white focus:outline-none transition-all placeholder:text-slate-700"
