                  <button onClick={() => { setShowSettings(false); setSettingsView('menu'); }} className="w-full bg-emerald-600 py-4 rounded-2xl font-game font-black text-white uppercase text-xs tracking-[0.2em] active:scale-95 shadow-lg shadow-emerald-900/20">Confirmar Alteração</button>
                </div>
              )}

              {settingsView === 'danger' && (
                <div className="space-y-6 animate-in slide-in-from-right-4 duration-300">
                  {!confirmReset ? (
                    <div className="space-y-6">
                      <div className="p-5 bg-red-500/5 border border-red-500/10 rounded-[1.5rem] flex items-start gap-4">
                         <div className="p-2.5 bg-red-500/20 rounded-xl text-red-500 mt-0.5"><AlertCircle size={22} /></div>
                         <div className="flex-1">
                            <p className="text-xs font-black text-white uppercase tracking-tight mb-1">Atenção Crítica</p>
                            <p className="text-[9px] text-slate-500 leading-relaxed font-bold uppercase tracking-widest">O reset apagará permanentemente todos os seus ganhos.</p>
                         </div>
                      </div>
                      <button onClick={() => setConfirmReset(true)} className="w-full flex items-center justify-center gap-3 p-4 bg-red-500/10 hover:bg-red-500/20 text-red-500 rounded-2xl transition-all font-game font-black uppercase text-xs tracking-widest active:scale-95">
                        <Trash2 size={18} /> Apagar Todos os Dados
                      </button>
                    </div>
                  ) : (
                    <div className="p-6 bg-red-600/10 border border-red-500/30 rounded-[2rem] space-y-6 text-center">
                      <AlertCircle size={40} className="text-red-500 mx-auto animate-bounce" />
                      <p className="text-sm font-black text-white uppercase tracking-widest">Confirma o Reset?</p>
                      <div className="flex flex-col gap-3">
                        <button onClick={handleResetData} className="w-full py-4.5 bg-red-600 text-white rounded-2xl font-game font-black text-xs uppercase tracking-[0.3em] shadow-xl shadow-red-500/20 active:scale-95">CONFIRMAR EXCLUSÃO</button>
                        <button onClick={() => setConfirmReset(false)} className="w-full py-4 text-slate-500 font-bold uppercase text-[9px] tracking-widest hover:text-white transition-colors">Voltar atrás</button>
                      </div>
                    </div>
                  )}
                </div>
              )}
            </div>
            <div className="h-safe bg-slate-900 pb-safe"></div>
          </div>
        </div>
      )}

      {/* Modal Confirmação Recebimento Carteira */}
      {showWalletConfirm && (
        <div className="fixed inset-0 z-[110] flex items-center justify-center bg-black/90 backdrop-blur-md p-6">
          <div className="bg-slate-900 border border-white/10 rounded-[2.5rem] w-full max-w-sm overflow-hidden animate-in zoom-in-95 duration-300 shadow-2xl">
            <div className="p-8 flex flex-col items-center text-center">
              <div className="w-16 h-16 bg-emerald-500/10 rounded-full flex items-center justify-center mb-6 border border-emerald-500/20">
                <Wallet className="text-emerald-400" size={32} />
              </div>
              <h3 className="text-2xl font-game font-black text-white uppercase tracking-tighter mb-2">Confirmar Recebimento?</h3>
              <p className="text-xs text-slate-500 font-bold uppercase tracking-widest leading-relaxed mb-8">
                Você está prestes a liquidar o saldo de <span className="text-emerald-400">{new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(counts.wallet.pending)}</span>. Este valor será movido para o histórico de pagamentos.
              </p>

              <div className="w-full space-y-3">
                <button 
                  onClick={handleSettleWallet}
                  className="w-full py-4 bg-emerald-600 hover:bg-emerald-500 text-white rounded-2xl font-game font-black text-sm uppercase tracking-[0.2em] shadow-lg shadow-emerald-900/20 active:scale-95 transition-all"
                >
                  Confirmar e Sincronizar
                </button>
                <button 
                  onClick={() => setShowWalletConfirm(false)}
                  className="w-full py-4 text-slate-500 font-bold uppercase text-[10px] tracking-widest hover:text-white transition-colors"
                >
                  Cancelar
                </button>
              </div>
            </div>
          </div>
        </div>
      )}

      <BulkActionModal 
        isOpen={bulkModal.isOpen}
        type={bulkModal.type}
        title={bulkModal.type === 'SAIDA' ? 'Saída Lote' : 'Entrada Lote'}
        onClose={() => setBulkModal({ ...bulkModal, isOpen: false })}
        onConfirm={handleBulkAction}
      />

      {/* Pop-up de Sucesso Animado */}
      {showSuccessPopup && (
        <div className="fixed inset-0 z-[200] flex items-center justify-center pointer-events-none p-6">
          <div className="bg-emerald-600/95 backdrop-blur-xl border border-emerald-400/30 rounded-[2.5rem] p-8 md:p-12 shadow-[0_0_50px_rgba(16,185,129,0.4)] flex flex-col items-center text-center max-w-sm w-full animate-in zoom-in-75 slide-in-from-bottom-20 duration-500 transition-all">
            <div className="w-20 h-20 bg-white rounded-full flex items-center justify-center mb-6 shadow-2xl animate-bounce">
              <Check size={40} className="text-emerald-600" strokeWidth={4} />
            </div>
            <h4 className="text-2xl md:text-3xl font-game font-black text-white uppercase tracking-tighter leading-tight mb-2">
              {bulkActionType === 'SETTLE' ? 'Recebido!' : 'Processado!'}
            </h4>
            <div className="w-full h-px bg-white/20 my-4"></div>
            <p className="text-emerald-50 font-game font-bold uppercase tracking-widest text-sm">
              {bulkActionType === 'SETTLE' ? (
                <span className="text-3xl block mt-1">{new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(counts.wallet.pending === 0 ? counts.wallet.cumulative : counts.wallet.pending)}</span>
              ) : (
                <span className="text-3xl block mt-1">{bulkCount} Unidades</span>
              )}
              <span className="opacity-80 mt-2 block">
                {bulkActionType === 'SAIDA' ? 'Saída Concluída' : bulkActionType === 'ENTRADA' ? 'Entrada Concluída' : 'Pagamento Liquidado'}
              </span>
            </p>
          </div>
        </div>
      )}

      {/* Toast Notificação Padrão */}
      {showToast && (
        <div className="fixed bottom-20 md:bottom-8 left-4 right-4 md:left-1/2 md:-translate-x-1/2 md:w-auto bg-emerald-600 text-white px-6 py-4 rounded-2xl shadow-2xl flex items-center justify-center md:justify-start gap-3 z-[150] animate-in slide-in-from-bottom-10 fade-in duration-300">
          <CheckCircle2 size={18} className="text-white" />
          <span className="font-game font-bold text-[10px] md:text-xs uppercase tracking-[0.2em]">{toastMsg}</span>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useState, useEffect, useMemo } from 'react';
import { Truck, Zap, FileText, Download, LayoutDashboard, Send, Table as TableIcon, ListPlus, LogOut, Layers, Settings, Trash2, AlertCircle, User, Sliders, ChevronRight, X, CheckCircle2, Check, Wallet, AlertTriangle, ArrowDownLeft, ArrowUpRight, RotateCcw } from 'lucide-react';
import DashboardCards from './components/DashboardCards';
import ActionButtons from './components/ActionButtons';
import DailyStatsTable from './components/DailyStatsTable';
import BulkActionModal from './components/BulkActionModal';
import WalletCard from './components/WalletCard';
import Login from './components/Login';
import { LogCashLogo } from './components/Logo';
import { LogEntry, LogActionType } from './types';
import { supabaseService } from './services/supabaseService';
import { generatePDF } from './services/pdfService';
import { SUPABASE_CACHE_KEY, VALOR_POR_PACOTE } from './constants';

const App: React.FC = () => {
  const [session, setSession] = useState<any>(null);
  const [logs, setLogs] = useState<LogEntry[]>(() => {
    const cached = localStorage.getItem(SUPABASE_CACHE_KEY);
    return cached ? JSON.parse(cached) : [];
  });
  const [loading, setLoading] = useState(true);
  const [isSyncing, setIsSyncing] = useState(false);
  const [showToast, setShowToast] = useState(false);
  const [toastMsg, setToastMsg] = useState('');

  // Estado para o Pop-up de Sucesso (Massa, Único e Carteira)
  const [showSuccessPopup, setShowSuccessPopup] = useState(false);
  const [bulkCount, setBulkCount] = useState(0);
  const [lastSettleValue, setLastSettleValue] = useState(0);
  const [bulkActionType, setBulkActionType] = useState<'ENTRADA' | 'SAIDA' | 'DEVOLUCAO' | 'SETTLE'>('ENTRADA');

  // Estado para Confirmação de Carteira
  const [showWalletConfirm, setShowWalletConfirm] = useState(false);

  const [userName, setUserName] = useState(() => localStorage.getItem('logcash_user_name') || 'Operador Logístico');
  const [activeTab, setActiveTab] = useState<'dash' | 'stats'>('dash');
  const [showSettings, setShowSettings] = useState(false);
  const [confirmReset, setConfirmReset] = useState(false);
  const [settingsView, setSettingsView] = useState<'menu' | 'profile' | 'danger'>('menu');

  const [bulkModal, setBulkModal] = useState<{ isOpen: boolean; type: 'ENTRADA' | 'SAIDA' }>({
    isOpen: false,
    type: 'ENTRADA'
  });

  useEffect(() => {
    supabaseService.getSession().then(session => {
      setSession(session);
      if (!session) setLoading(false);
    });
  }, []);

  useEffect(() => {
    if (!session) return;
    setIsSyncing(true);
    const unsubscribe = supabaseService.subscribeToLogs((updatedLogs, supabaseError) => {
      if (!supabaseError) {
        setLogs(updatedLogs);
        localStorage.setItem(SUPABASE_CACHE_KEY, JSON.stringify(updatedLogs));
      }
      setLoading(false);
      setIsSyncing(false);
    });
    return () => unsubscribe();
  }, [session]);

  useEffect(() => {
    localStorage.setItem('logcash_user_name', userName);
  }, [userName]);

  const handleLogout = async () => {
    await supabaseService.signOut();
    localStorage.removeItem(SUPABASE_CACHE_KEY);
    setSession(null);
    setLogs([]);
    setShowSettings(false);
  };

  const handleAction = async (type: LogActionType) => {
    const newEntry: Omit<LogEntry, 'id'> = {
      type,
      timestamp: new Date().toISOString(),
      value: type === 'SAIDA' ? VALOR_POR_PACOTE : 0
    };
    try {
      await supabaseService.saveLog(newEntry);

      // Aciona o Popup de Sucesso para Ação Única
      setBulkActionType(type);
      setBulkCount(1);
      setShowSuccessPopup(true);
      setTimeout(() => setShowSuccessPopup(false), 2000);

    } catch (err) {
      setToastMsg('Erro na sincronização.');
      setShowToast(true);
      setTimeout(() => setShowToast(false), 2000);
    }
  };

  const handleBulkAction = async (quantity: number) => {
    const type = bulkModal.type;
    const newEntries = Array.from({ length: quantity }).map(() => ({
      type: type as LogActionType,
      timestamp: new Date().toISOString(),
      value: type === 'SAIDA' ? VALOR_POR_PACOTE : 0
    }));
    try {
      await supabaseService.saveBulkLogs(newEntries);
      setBulkCount(quantity);
      setBulkActionType(type as any);
      setShowSuccessPopup(true);
      setTimeout(() => { setShowSuccessPopup(false); }, 2500);
    } catch (err) {
      setToastMsg('Falha no envio em lote.');
      setShowToast(true);
      setTimeout(() => setShowToast(false), 2000);
    }
  };

  const handleSettleWallet = async () => {
    try {
      setIsSyncing(true);
      // Captura o valor pendente atual antes de liquidar
      const pendingValue = counts.wallet.pending;
      setLastSettleValue(pendingValue);

      setShowWalletConfirm(false);
      await supabaseService.markAllAsPaid();

      setBulkActionType('SETTLE');
      setShowSuccessPopup(true);
      setTimeout(() => { setShowSuccessPopup(false); }, 2500);

    } catch (err) {
      setToastMsg('Erro ao liquidar pagamentos.');
      setShowToast(true);
      setTimeout(() => setShowToast(false), 2000);
    } finally {
      setIsSyncing(false);
    }
  };

  const handleResetData = async () => {
    try {
      setIsSyncing(true);
      await supabaseService.deleteAllLogs();
      setLogs([]);
      localStorage.removeItem(SUPABASE_CACHE_KEY);
      const defaultName = 'Operador Logístico';
      setUserName(defaultName);
      localStorage.removeItem('logcash_user_name');
      setToastMsg('Sistema reiniciado com sucesso.');
      setShowToast(true);
      setConfirmReset(false);
      setShowSettings(false);
      setSettingsView('menu');
      setActiveTab('dash');
      setTimeout(() => setShowToast(false), 3000);
    } catch (err) {
      setToastMsg('Erro ao apagar dados do servidor.');
      setShowToast(true);
    } finally {
      setIsSyncing(false);
    }
  };

  const counts = useMemo(() => {
    const todayStr = new Date().toDateString();
    const now = new Date();
    const startOfWeek = new Date(now);
    startOfWeek.setDate(now.getDate() - now.getDay());
    startOfWeek.setHours(0, 0, 0, 0);
    const startOfYear = new Date(now.getFullYear(), 0, 1);

    const deliveredLogs = logs.filter(l => l.type === 'SAIDA');
    const pending = deliveredLogs.filter(l => !l.isPaid).length * VALOR_POR_PACOTE;
    const paidCurrentCycle = deliveredLogs.filter(l => l.isPaid && new Date(l.timestamp) >= startOfWeek).length * VALOR_POR_PACOTE;
    const totalCumulativePaid = deliveredLogs.filter(l => l.isPaid).length * VALOR_POR_PACOTE;

    return {
      today: logs.filter(l => l.type === 'SAIDA' && new Date(l.timestamp).toDateString() === todayStr).length,
      week: logs.filter(l => l.type === 'SAIDA' && new Date(l.timestamp) >= startOfWeek).length,
      year: logs.filter(l => l.type === 'SAIDA' && new Date(l.timestamp) >= startOfYear).length,
      wallet: {
        pending,
        paid: paidCurrentCycle,
        cumulative: totalCumulativePaid
      }
    };
  }, [logs]);

  if (!session && !loading) return <Login onLoginSuccess={() => supabaseService.getSession().then(setSession)} />;

  if (loading && logs.length === 0) {
    return (
      <div className="min-h-screen bg-[#020617] flex flex-col items-center justify-center p-6 text-center">
        <LogCashLogo size={60} />
        <div className="w-12 h-1 border-b border-white/5 my-4"></div>
        <p className="text-slate-500 font-game font-bold uppercase tracking-[0.3em] text-[10px] animate-pulse">Iniciando LogCash...</p>
      </div>
    );
  }

  const formatBRL = (val: number) => new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(val);

  return (
    <div className="min-h-screen bg-[#020617] text-slate-200 selection:bg-emerald-500/30 flex flex-col overflow-x-hidden relative">
      <header className="bg-slate-900/80 backdrop-blur-xl border-b border-white/5 px-4 py-2 md:px-8 md:py-4 sticky top-0 z-40 pt-safe transition-all duration-300">
        <div className="max-w-5xl mx-auto flex justify-between items-center h-12">
          <div className="flex items-center gap-2 md:gap-3">
            <LogCashLogo size={32} />
            <div>
              <h1 className="text-sm md:text-xl font-game font-black tracking-[0.1em] text-white leading-none">
                LOG<span className="text-emerald-400">CASH</span>
              </h1>
              <p className="text-[8px] md:text-[9px] text-slate-500 font-bold uppercase tracking-tighter mt-1">
                {isSyncing ? 'Sincronizando...' : 'Online'}
              </p>
            </div>
          </div>
          <button 
            onClick={() => { setShowSettings(true); setSettingsView('menu'); }} 
            className="p-2.5 bg-white/5 rounded-xl border border-white/10 active:scale-95 transition-all hover:bg-white/10 flex items-center gap-2"
          >
            <Settings size={18} className="text-slate-400" />
            <span className="hidden sm:block text-[10px] font-bold text-slate-400 uppercase tracking-widest">Ajustes</span>
          </button>
        </div>
      </header>

      <main className="flex-1 max-w-5xl mx-auto w-full p-4 md:p-8 space-y-6 md:space-y-10 pb-28 md:pb-12 transition-all">
        {activeTab === 'dash' ? (
          <div className="animate-in fade-in duration-500">
            <div className="mb-6">
              <h2 className="text-2xl md:text-4xl font-game font-black text-white uppercase tracking-tight leading-tight">
                Olá, {userName.split(' ')[0]}
              </h2>
              <p className="text-[10px] md:text-xs text-slate-500 font-bold uppercase tracking-widest mt-1">
                Acompanhe sua produtividade logística
              </p>
            </div>

            <div className="grid grid-cols-1 lg:grid-cols-5 gap-6 mb-8">
              <div className="lg:col-span-3">
                <DashboardCards today={counts.today} week={counts.week} year={counts.year} />
              </div>
              <div className="lg:col-span-2">
                <WalletCard 
                  pendingAmount={counts.wallet.pending} 
                  paidAmount={counts.wallet.paid} 
                  totalCumulativePaid={counts.wallet.cumulative} 
                  onSettle={() => setShowWalletConfirm(true)}
                />
              </div>
            </div>

            <section className="space-y-4 mb-8">
              <div className="flex items-center justify-between px-1">
                <h2 className="text-slate-500 font-game font-bold text-[10px] uppercase tracking-widest">Ações Rápidas</h2>
                <div className="h-px flex-1 bg-white/5 mx-4 hidden sm:block"></div>
              </div>
              <ActionButtons onAction={handleAction} />
            </section>

            <section className="grid grid-cols-2 gap-3 mb-8">
              <button 
                onClick={() => setBulkModal({ isOpen: true, type: 'ENTRADA' })}
                className="bg-slate-900/50 border border-white/5 p-4 rounded-2xl flex flex-col items-start gap-3 active:scale-95 hover:bg-white/[0.03] transition-all"
              >
                <div className="p-2.5 bg-emerald-600/10 text-emerald-400 rounded-xl border border-emerald-500/20"><ListPlus size={20} /></div>
                <div className="text-left">
                  <p className="font-game font-bold text-white text-xs uppercase tracking-tight">Entrada Massa</p>
                  <p className="text-[8px] text-slate-500 uppercase font-bold">Lote Recebido</p>
                </div>
              </button>
              <button 
                onClick={() => setBulkModal({ isOpen: true, type: 'SAIDA' })}
                className="bg-slate-900/50 border border-white/5 p-4 rounded-2xl flex flex-col items-start gap-3 active:scale-95 hover:bg-white/[0.03] transition-all"
              >
                <div className="p-2.5 bg-blue-600/10 text-blue-400 rounded-xl border border-blue-500/20"><Send size={20} /></div>
                <div className="text-left">
                  <p className="font-game font-bold text-white text-xs uppercase tracking-tight">Saída Massa</p>
                  <p className="text-[8px] text-slate-500 uppercase font-bold">Lote Entregue</p>
                </div>
              </button>
            </section>

            <section className="bg-slate-900/50 p-5 md:p-8 rounded-[2rem] border border-white/5 relative overflow-hidden">
              <div className="flex items-center gap-3 mb-4">
                <div className="p-2 bg-emerald-500/10 rounded-lg"><FileText size={18} className="text-emerald-400" /></div>
                <h3 className="font-game font-bold text-white uppercase tracking-wider text-sm">Relatório Operacional</h3>
              </div>
              <p className="text-[9px] text-slate-500 font-bold uppercase tracking-widest mb-6">
                Exportar registro detalhado para: <span className="text-emerald-400">{userName}</span>
              </p>
              <button 
                onClick={() => generatePDF(logs, userName)}
                className="w-full bg-emerald-600 hover:bg-emerald-500 py-4 rounded-2xl flex items-center justify-center gap-3 font-game font-black text-white active:scale-95 text-xs uppercase tracking-[0.2em] transition-all shadow-lg shadow-emerald-900/20"
              >
                <Download size={18} /> Gerar PDF
              </button>
            </section>
          </div>
        ) : (
          <div className="animate-in fade-in duration-500">
             <div className="mb-6">
                <h2 className="text-2xl font-game font-black text-white uppercase tracking-tight">Estatísticas</h2>
                <p className="text-[10px] text-slate-500 font-bold uppercase tracking-widest mt-1">Histórico completo de fluxo</p>
             </div>
             <DailyStatsTable logs={logs} />
          </div>
        )}
      </main>

      <nav className="fixed bottom-0 left-0 right-0 bg-slate-950/80 backdrop-blur-2xl border-t border-white/5 md:hidden z-50 transition-transform duration-300">
        <div className="flex justify-around items-center h-16 max-w-lg mx-auto">
          <button 
            onClick={() => setActiveTab('dash')}
            className={`flex flex-col items-center justify-center w-full h-full gap-1 transition-all ${activeTab === 'dash' ? 'text-emerald-400 scale-110' : 'text-slate-600'}`}
          >
            <LayoutDashboard size={20} strokeWidth={activeTab === 'dash' ? 2.5 : 2} />
            <span className="text-[9px] font-black uppercase tracking-widest">Início</span>
          </button>
          <button 
            onClick={() => setActiveTab('stats')}
            className={`flex flex-col items-center justify-center w-full h-full gap-1 transition-all ${activeTab === 'stats' ? 'text-emerald-400 scale-110' : 'text-slate-600'}`}
          >
            <TableIcon size={20} strokeWidth={activeTab === 'stats' ? 2.5 : 2} />
            <span className="text-[9px] font-black uppercase tracking-widest">Histórico</span>
          </button>
        </div>
        <div className="h-safe bg-slate-950"></div>
      </nav>

      {/* Settings Modal */}
      {showSettings && (
        <div className="fixed inset-0 z-[100] flex items-end md:items-center justify-center bg-black/80 backdrop-blur-sm p-0 md:p-4">
          <div className="bg-slate-900 w-full max-w-lg rounded-t-[2rem] md:rounded-[2.5rem] border-t md:border border-white/10 overflow-hidden animate-in slide-in-from-bottom-full duration-400 transition-all">
            <div className="w-12 h-1 bg-white/10 rounded-full mx-auto my-3 md:hidden"></div>
            <div className="px-6 py-4 border-b border-white/5 flex justify-between items-center">
              <div className="flex items-center gap-3">
                {settingsView !== 'menu' && (
                   <button onClick={() => setSettingsView('menu')} className="p-2 hover:bg-white/5 rounded-full text-slate-500"><ChevronRight size={20} className="rotate-180" /></button>
                )}
                <h3 className="font-game font-bold text-white uppercase tracking-[0.1em] text-sm">
                  {settingsView === 'menu' ? 'Menu de Ajustes' : settingsView === 'profile' ? 'Editar Perfil' : 'Danger Zone'}
                </h3>
              </div>
              <button onClick={() => { setShowSettings(false); setConfirmReset(false); setSettingsView('menu'); }} className="p-2 bg-white/5 rounded-full text-slate-500 active:scale-90"><X size={20} /></button>
            </div>
            <div className="p-6 md:p-10 space-y-4">
              {settingsView === 'menu' && (
                <div className="space-y-3">
                  <button onClick={() => setSettingsView('profile')} className="w-full flex items-center justify-between p-4 bg-white/5 hover:bg-white/10 border border-white/5 rounded-2xl transition-all group active:scale-[0.98]">
                    <div className="flex items-center gap-4">
                      <div className="p-2.5 bg-blue-500/10 rounded-xl text-blue-400"><User size={20} /></div>
                      <div className="text-left"><p className="text-sm font-bold text-white uppercase tracking-tight">Identificação</p><p className="text-[9px] text-slate-500 font-bold uppercase tracking-widest">Nome do operador logístico</p></div>
                    </div><ChevronRight size={18} className="text-slate-700" />
                  </button>
                  <button onClick={() => setSettingsView('danger')} className="w-full flex items-center justify-between p-4 bg-white/5 hover:bg-white/10 border border-white/5 rounded-2xl transition-all group active:scale-[0.98]">
                    <div className="flex items-center gap-4">
                      <div className="p-2.5 bg-red-500/10 rounded-xl text-red-400"><Sliders size={20} /></div>
                      <div className="text-left"><p className="text-sm font-bold text-white uppercase tracking-tight">Banco de Dados</p><p className="text-[9px] text-slate-500 font-bold uppercase tracking-widest">Reset total de registros</p></div>
                    </div><ChevronRight size={18} className="text-slate-700" />
                  </button>
                  <div className="pt-6 mt-2 border-t border-white/5">
                    <button onClick={handleLogout} className="w-full flex items-center justify-center gap-3 p-4 bg-red-500/10 hover:bg-red-500/20 text-red-500 rounded-2xl transition-all font-game font-bold uppercase text-xs tracking-[0.2em] active:scale-95"><LogOut size={18} /> Sair do Sistema</button>
                  </div>
                </div>
              )}
              {settingsView === 'profile' && (
                <div className="space-y-6 animate-in slide-in-from-right-4 duration-300">
                  <div className="space-y-4">
                    <label className="text-[9px] font-black text-slate-500 uppercase tracking-[0.3em] ml-1">Assinatura do Operador</label>
                    <div className="relative group">
                       <User className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-600 group-focus-within:text-emerald-400 transition-colors" size={18} />
                       <input type="text" value={userName} onChange={(e) => setUserName(e.target.value)} className="w-full bg-black/40 border border-white/10 focus:border-emerald-500/50 rounded-2xl pl-12 pr-4 py-4 text-sm font-bold text-white focus:outline-none transition-all placeholder:text-slate-700" placeholder="Nome para o PDF" />
                    </div>
                  </div>
                  <button onClick={() => { setShowSettings(false); setSettingsView('menu'); }} className="w-full bg-emerald-600 py-4 rounded-2xl font-game font-black text-white uppercase text-xs tracking-[0.2em] active:scale-95 shadow-lg shadow-emerald-900/20">Confirmar Alteração</button>
                </div>
              )}
              {settingsView === 'danger' && (
                <div className="space-y-6 animate-in slide-in-from-right-4 duration-300">
                  {!confirmReset ? (
                    <div className="space-y-6">
                      <div className="p-5 bg-red-500/5 border border-red-500/10 rounded-[1.5rem] flex items-start gap-4">
                         <div className="p-2.5 bg-red-500/20 rounded-xl text-red-500 mt-0.5"><AlertCircle size={22} /></div>
                         <div className="flex-1"><p className="text-xs font-black text-white uppercase tracking-tight mb-1">Atenção Crítica</p><p className="text-[9px] text-slate-500 leading-relaxed font-bold uppercase tracking-widest">O reset apagará permanentemente todos os seus ganhos.</p></div>
                      </div>
                      <button onClick={() => setConfirmReset(true)} className="w-full flex items-center justify-center gap-3 p-4 bg-red-500/10 hover:bg-red-500/20 text-red-500 rounded-2xl transition-all font-game font-black uppercase text-xs tracking-widest active:scale-95"><Trash2 size={18} /> Apagar Todos os Dados</button>
                    </div>
                  ) : (
                    <div className="p-6 bg-red-600/10 border border-red-500/30 rounded-[2rem] space-y-6 text-center">
                      <AlertCircle size={40} className="text-red-500 mx-auto animate-bounce" />
                      <p className="text-sm font-black text-white uppercase tracking-widest">Confirma o Reset?</p>
                      <div className="flex flex-col gap-3">
                        <button onClick={handleResetData} className="w-full py-4.5 bg-red-600 text-white rounded-2xl font-game font-black text-xs uppercase tracking-[0.3em] shadow-xl shadow-red-500/20 active:scale-95">CONFIRMAR EXCLUSÃO</button>
                        <button onClick={() => setConfirmReset(false)} className="w-full py-4 text-slate-500 font-bold uppercase text-[9px] tracking-widest hover:text-white transition-colors">Voltar atrás</button>
                      </div>
                    </div>
                  )}
                </div>
              )}
            </div>
            <div className="h-safe bg-slate-900 pb-safe"></div>
          </div>
        </div>
      )}

      {/* Modal Confirmação Recebimento Carteira */}
      {showWalletConfirm && (
        <div className="fixed inset-0 z-[110] flex items-center justify-center bg-black/90 backdrop-blur-md p-6">
          <div className="bg-slate-900 border border-white/10 rounded-[2.5rem] w-full max-w-sm overflow-hidden animate-in zoom-in-95 duration-300 shadow-2xl">
            <div className="p-8 flex flex-col items-center text-center">
              <div className="w-16 h-16 bg-emerald-500/10 rounded-full flex items-center justify-center mb-6 border border-emerald-500/20">
                <Wallet className="text-emerald-400" size={32} />
              </div>
              <h3 className="text-2xl font-game font-black text-white uppercase tracking-tighter mb-2">Confirmar Recebimento?</h3>
              <p className="text-xs text-slate-500 font-bold uppercase tracking-widest leading-relaxed mb-8">
                Você está prestes a liquidar o saldo de <span className="text-emerald-400 font-black">{formatBRL(counts.wallet.pending)}</span>. Este valor será movido para o histórico de pagamentos.
              </p>
              <div className="w-full space-y-3">
                <button onClick={handleSettleWallet} className="w-full py-4 bg-emerald-600 hover:bg-emerald-500 text-white rounded-2xl font-game font-black text-sm uppercase tracking-[0.2em] shadow-lg shadow-emerald-900/20 active:scale-95 transition-all">Confirmar e Sincronizar</button>
                <button onClick={() => setShowWalletConfirm(false)} className="w-full py-4 text-slate-500 font-bold uppercase text-[10px] tracking-widest hover:text-white transition-colors">Cancelar</button>
              </div>
            </div>
          </div>
        </div>
      )}

      <BulkActionModal isOpen={bulkModal.isOpen} type={bulkModal.type} title={bulkModal.type === 'SAIDA' ? 'Saída Lote' : 'Entrada Lote'} onClose={() => setBulkModal({ ...bulkModal, isOpen: false })} onConfirm={handleBulkAction} />

      {/* Pop-up de Sucesso Animado (Centralizado) */}
      {showSuccessPopup && (
        <div className="fixed inset-0 z-[200] flex items-center justify-center pointer-events-none p-6">
          <div className="bg-emerald-600/95 backdrop-blur-xl border border-emerald-400/30 rounded-[2.5rem] p-8 md:p-12 shadow-[0_0_50px_rgba(16,185,129,0.4)] flex flex-col items-center text-center max-w-sm w-full animate-in zoom-in-75 slide-in-from-bottom-20 duration-500 transition-all">
            <div className="w-20 h-20 bg-white rounded-full flex items-center justify-center mb-6 shadow-2xl animate-bounce">
              {bulkActionType === 'ENTRADA' && <ArrowDownLeft size={40} className="text-emerald-600" strokeWidth={3} />}
              {bulkActionType === 'SAIDA' && <ArrowUpRight size={40} className="text-emerald-600" strokeWidth={3} />}
              {bulkActionType === 'DEVOLUCAO' && <RotateCcw size={40} className="text-emerald-600" strokeWidth={3} />}
              {bulkActionType === 'SETTLE' && <Check size={40} className="text-emerald-600" strokeWidth={4} />}
            </div>

            <h4 className="text-2xl md:text-3xl font-game font-black text-white uppercase tracking-tighter leading-tight mb-2">
              {bulkActionType === 'SETTLE' ? 'Recebido!' : 'Registrado!'}
            </h4>

            <div className="w-full h-px bg-white/20 my-4"></div>

            <div className="text-emerald-50 font-game font-bold uppercase tracking-widest text-sm">
              {bulkActionType === 'SETTLE' ? (
                <span className="text-3xl block mt-1">{formatBRL(lastSettleValue)}</span>
              ) : (
                <div className="flex flex-col items-center">
                  <span className="text-3xl block mt-1">{bulkCount} {bulkCount === 1 ? 'Unidade' : 'Unidades'}</span>
                  {bulkActionType === 'SAIDA' && <span className="text-emerald-300 text-[10px] mt-2">+ {formatBRL(bulkCount * VALOR_POR_PACOTE)}</span>}
                </div>
              )}

              <span className="opacity-80 mt-2 block text-[10px]">
                {bulkActionType === 'SAIDA' ? 'Saída Concluída' : bulkActionType === 'ENTRADA' ? 'Entrada na Base' : bulkActionType === 'DEVOLUCAO' ? 'Retorno Registrado' : 'Pagamento Liquidado'}
              </span>
            </div>
          </div>
        </div>
      )}

      {/* Toast Notificação Padrão (Fallback) */}
      {showToast && (
        <div className="fixed bottom-20 md:bottom-8 left-4 right-4 md:left-1/2 md:-translate-x-1/2 md:w-auto bg-emerald-600 text-white px-6 py-4 rounded-2xl shadow-2xl flex items-center justify-center md:justify-start gap-3 z-[150] animate-in slide-in-from-bottom-10 fade-in duration-300">
          <CheckCircle2 size={18} className="text-white" />
          <span className="font-game font-bold text-[10px] md:text-xs uppercase tracking-[0.2em]">{toastMsg}</span>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useState, useEffect, useMemo } from 'react';
import { Truck, Zap, FileText, Download, LayoutDashboard, Send, Table as TableIcon, ListPlus, LogOut, Layers, Settings, Trash2, AlertCircle, User, Sliders, ChevronRight, X, CheckCircle2, Check, Wallet, AlertTriangle, ArrowDownLeft, ArrowUpRight, RotateCcw, Sparkles } from 'lucide-react';
import DashboardCards from './components/DashboardCards';
import ActionButtons from './components/ActionButtons';
import DailyStatsTable from './components/DailyStatsTable';
import BulkActionModal from './components/BulkActionModal';
import WalletCard from './components/WalletCard';
import Login from './components/Login';
import { LogCashLogo } from './components/Logo';
import { LogEntry, LogActionType } from './types';
import { supabaseService } from './services/supabaseService';
import { generatePDF } from './services/pdfService';
import { SUPABASE_CACHE_KEY, VALOR_POR_PACOTE } from './constants';

const App: React.FC = () => {
  const [session, setSession] = useState<any>(null);
  const [logs, setLogs] = useState<LogEntry[]>(() => {
    const cached = localStorage.getItem(SUPABASE_CACHE_KEY);
    return cached ? JSON.parse(cached) : [];
  });
  const [loading, setLoading] = useState(true);
  const [isSyncing, setIsSyncing] = useState(false);
  const [showToast, setShowToast] = useState(false);
  const [toastMsg, setToastMsg] = useState('');

  // Estado para o Pop-up de Sucesso Ultra-Interativo
  const [showSuccessPopup, setShowSuccessPopup] = useState(false);
  const [bulkCount, setBulkCount] = useState(0);
  const [lastSettleValue, setLastSettleValue] = useState(0);
  const [bulkActionType, setBulkActionType] = useState<'ENTRADA' | 'SAIDA' | 'DEVOLUCAO' | 'SETTLE'>('ENTRADA');

  // Estado para Confirmação de Carteira
  const [showWalletConfirm, setShowWalletConfirm] = useState(false);

  const [userName, setUserName] = useState(() => localStorage.getItem('logcash_user_name') || 'Operador Logístico');
  const [activeTab, setActiveTab] = useState<'dash' | 'stats'>('dash');
  const [showSettings, setShowSettings] = useState(false);
  const [confirmReset, setConfirmReset] = useState(false);
  const [settingsView, setSettingsView] = useState<'menu' | 'profile' | 'danger'>('menu');

  const [bulkModal, setBulkModal] = useState<{ isOpen: boolean; type: 'ENTRADA' | 'SAIDA' }>({
    isOpen: false,
    type: 'ENTRADA'
  });

  useEffect(() => {
    supabaseService.getSession().then(session => {
      setSession(session);
      if (!session) setLoading(false);
    });
  }, []);

  useEffect(() => {
    if (!session) return;
    setIsSyncing(true);
    const unsubscribe = supabaseService.subscribeToLogs((updatedLogs, supabaseError) => {
      if (!supabaseError) {
        setLogs(updatedLogs);
        localStorage.setItem(SUPABASE_CACHE_KEY, JSON.stringify(updatedLogs));
      }
      setLoading(false);
      setIsSyncing(false);
    });
    return () => unsubscribe();
  }, [session]);

  useEffect(() => {
    localStorage.setItem('logcash_user_name', userName);
  }, [userName]);

  const handleLogout = async () => {
    await supabaseService.signOut();
    localStorage.removeItem(SUPABASE_CACHE_KEY);
    setSession(null);
    setLogs([]);
    setShowSettings(false);
  };

  const handleAction = async (type: LogActionType) => {
    const newEntry: Omit<LogEntry, 'id'> = {
      type,
      timestamp: new Date().toISOString(),
      value: type === 'SAIDA' ? VALOR_POR_PACOTE : 0
    };
    try {
      await supabaseService.saveLog(newEntry);

      // Feedback Visual Interativo
      setBulkActionType(type as any);
      setBulkCount(1);
      setShowSuccessPopup(true);
      setTimeout(() => setShowSuccessPopup(false), 2200);

    } catch (err) {
      setToastMsg('Erro na sincronização.');
      setShowToast(true);
      setTimeout(() => setShowToast(false), 2000);
    }
  };

  const handleBulkAction = async (quantity: number) => {
    const type = bulkModal.type;
    const newEntries = Array.from({ length: quantity }).map(() => ({
      type: type as LogActionType,
      timestamp: new Date().toISOString(),
      value: type === 'SAIDA' ? VALOR_POR_PACOTE : 0
    }));
    try {
      await supabaseService.saveBulkLogs(newEntries);
      setBulkCount(quantity);
      setBulkActionType(type as any);
      setShowSuccessPopup(true);
      setTimeout(() => { setShowSuccessPopup(false); }, 2500);
    } catch (err) {
      setToastMsg('Falha no envio em lote.');
      setShowToast(true);
      setTimeout(() => setShowToast(false), 2000);
    }
  };

  const handleSettleWallet = async () => {
    try {
      setIsSyncing(true);
      // Salva o valor exato pendente ANTES de limpar para o popup
      const valToSettle = counts.wallet.pending;
      setLastSettleValue(valToSettle);

      setShowWalletConfirm(false);
      await supabaseService.markAllAsPaid();

      setBulkActionType('SETTLE');
      setShowSuccessPopup(true);
      setTimeout(() => { setShowSuccessPopup(false); }, 2800);

    } catch (err) {
      setToastMsg('Erro ao liquidar pagamentos.');
      setShowToast(true);
      setTimeout(() => setShowToast(false), 2000);
    } finally {
      setIsSyncing(false);
    }
  };

  const handleResetData = async () => {
    try {
      setIsSyncing(true);
      await supabaseService.deleteAllLogs();
      setLogs([]);
      localStorage.removeItem(SUPABASE_CACHE_KEY);
      const defaultName = 'Operador Logístico';
      setUserName(defaultName);
      localStorage.removeItem('logcash_user_name');
      setToastMsg('Sistema reiniciado com sucesso.');
      setShowToast(true);
      setConfirmReset(false);
      setShowSettings(false);
      setSettingsView('menu');
      setActiveTab('dash');
      setTimeout(() => setShowToast(false), 3000);
    } catch (err) {
      setToastMsg('Erro ao apagar dados do servidor.');
      setShowToast(true);
    } finally {
      setIsSyncing(false);
    }
  };

  const counts = useMemo(() => {
    const todayStr = new Date().toDateString();
    const now = new Date();
    const startOfWeek = new Date(now);
    startOfWeek.setDate(now.getDate() - now.getDay());
    startOfWeek.setHours(0, 0, 0, 0);
    const startOfYear = new Date(now.getFullYear(), 0, 1);

    const deliveredLogs = logs.filter(l => l.type === 'SAIDA');
    const pending = deliveredLogs.filter(l => !l.isPaid).length * VALOR_POR_PACOTE;
    const paidCurrentCycle = deliveredLogs.filter(l => l.isPaid && new Date(l.timestamp) >= startOfWeek).length * VALOR_POR_PACOTE;
    const totalCumulativePaid = deliveredLogs.filter(l => l.isPaid).length * VALOR_POR_PACOTE;

    return {
      today: logs.filter(l => l.type === 'SAIDA' && new Date(l.timestamp).toDateString() === todayStr).length,
      week: logs.filter(l => l.type === 'SAIDA' && new Date(l.timestamp) >= startOfWeek).length,
      year: logs.filter(l => l.type === 'SAIDA' && new Date(l.timestamp) >= startOfYear).length,
      wallet: {
        pending,
        paid: paidCurrentCycle,
        cumulative: totalCumulativePaid
      }
    };
  }, [logs]);

  if (!session && !loading) return <Login onLoginSuccess={() => supabaseService.getSession().then(setSession)} />;

  if (loading && logs.length === 0) {
    return (
      <div className="min-h-screen bg-[#020617] flex flex-col items-center justify-center p-6 text-center">
        <LogCashLogo size={60} />
        <div className="w-12 h-1 border-b border-white/5 my-4"></div>
        <p className="text-slate-500 font-game font-bold uppercase tracking-[0.3em] text-[10px] animate-pulse">Iniciando LogCash...</p>
      </div>
    );
  }

  const formatBRL = (val: number) => new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(val);

  // Cores dinâmicas para o popup
  const popupTheme = {
    ENTRADA: 'from-emerald-600/90 to-emerald-900/95 border-emerald-400/30 text-emerald-400',
    SAIDA: 'from-blue-600/90 to-blue-900/95 border-blue-400/30 text-blue-400',
    DEVOLUCAO: 'from-orange-600/90 to-orange-900/95 border-orange-400/30 text-orange-400',
    SETTLE: 'from-emerald-500/90 to-emerald-800/95 border-emerald-300/30 text-emerald-300'
  }[bulkActionType];

  return (
    <div className="min-h-screen bg-[#020617] text-slate-200 selection:bg-emerald-500/30 flex flex-col overflow-x-hidden relative">
      <header className="bg-slate-900/80 backdrop-blur-xl border-b border-white/5 px-4 py-2 md:px-8 md:py-4 sticky top-0 z-40 pt-safe transition-all duration-300">
        <div className="max-w-5xl mx-auto flex justify-between items-center h-12">
          <div className="flex items-center gap-2 md:gap-3">
            <LogCashLogo size={32} />
            <div>
              <h1 className="text-sm md:text-xl font-game font-black tracking-[0.1em] text-white leading-none">
                LOG<span className="text-emerald-400">CASH</span>
              </h1>
              <p className="text-[8px] md:text-[9px] text-slate-500 font-bold uppercase tracking-tighter mt-1">
                {isSyncing ? 'Sincronizando...' : 'Online'}
              </p>
            </div>
          </div>
          <button 
            onClick={() => { setShowSettings(true); setSettingsView('menu'); }} 
            className="p-2.5 bg-white/5 rounded-xl border border-white/10 active:scale-95 transition-all hover:bg-white/10 flex items-center gap-2"
          >
            <Settings size={18} className="text-slate-400" />
            <span className="hidden sm:block text-[10px] font-bold text-slate-400 uppercase tracking-widest">Ajustes</span>
          </button>
        </div>
      </header>

      <main className="flex-1 max-w-5xl mx-auto w-full p-4 md:p-8 space-y-6 md:space-y-10 pb-28 md:pb-12 transition-all">
        {activeTab === 'dash' ? (
          <div className="animate-in fade-in duration-500">
            <div className="mb-6">
              <h2 className="text-2xl md:text-4xl font-game font-black text-white uppercase tracking-tight leading-tight">
                Olá, {userName.split(' ')[0]}
              </h2>
              <p className="text-[10px] md:text-xs text-slate-500 font-bold uppercase tracking-widest mt-1">
                Acompanhe sua produtividade logística
              </p>
            </div>

            <div className="grid grid-cols-1 lg:grid-cols-5 gap-6 mb-8">
              <div className="lg:col-span-3">
                <DashboardCards today={counts.today} week={counts.week} year={counts.year} />
              </div>
              <div className="lg:col-span-2">
                <WalletCard 
                  pendingAmount={counts.wallet.pending} 
                  paidAmount={counts.wallet.paid} 
                  totalCumulativePaid={counts.wallet.cumulative} 
                  onSettle={() => setShowWalletConfirm(true)}
                />
              </div>
            </div>

            <section className="space-y-4 mb-8">
              <div className="flex items-center justify-between px-1">
                <h2 className="text-slate-500 font-game font-bold text-[10px] uppercase tracking-widest">Ações Rápidas</h2>
                <div className="h-px flex-1 bg-white/5 mx-4 hidden sm:block"></div>
              </div>
              <ActionButtons onAction={handleAction} />
            </section>

            <section className="grid grid-cols-2 gap-3 mb-8">
              <button 
                onClick={() => setBulkModal({ isOpen: true, type: 'ENTRADA' })}
                className="bg-slate-900/50 border border-white/5 p-4 rounded-2xl flex flex-col items-start gap-3 active:scale-95 hover:bg-white/[0.03] transition-all"
              >
                <div className="p-2.5 bg-emerald-600/10 text-emerald-400 rounded-xl border border-emerald-500/20"><ListPlus size={20} /></div>
                <div className="text-left">
                  <p className="font-game font-bold text-white text-xs uppercase tracking-tight">Entrada Massa</p>
                  <p className="text-[8px] text-slate-500 uppercase font-bold">Lote Recebido</p>
                </div>
              </button>
              <button 
                onClick={() => setBulkModal({ isOpen: true, type: 'SAIDA' })}
                className="bg-slate-900/50 border border-white/5 p-4 rounded-2xl flex flex-col items-start gap-3 active:scale-95 hover:bg-white/[0.03] transition-all"
              >
                <div className="p-2.5 bg-blue-600/10 text-blue-400 rounded-xl border border-blue-500/20"><Send size={20} /></div>
                <div className="text-left">
                  <p className="font-game font-bold text-white text-xs uppercase tracking-tight">Saída Massa</p>
                  <p className="text-[8px] text-slate-500 uppercase font-bold">Lote Entregue</p>
                </div>
              </button>
            </section>

            <section className="bg-slate-900/50 p-5 md:p-8 rounded-[2rem] border border-white/5 relative overflow-hidden">
              <div className="flex items-center gap-3 mb-4">
                <div className="p-2 bg-emerald-500/10 rounded-lg"><FileText size={18} className="text-emerald-400" /></div>
                <h3 className="font-game font-bold text-white uppercase tracking-wider text-sm">Relatório Operacional</h3>
              </div>
              <p className="text-[9px] text-slate-500 font-bold uppercase tracking-widest mb-6">
                Exportar registro detalhado para: <span className="text-emerald-400">{userName}</span>
              </p>
              <button 
                onClick={() => generatePDF(logs, userName)}
                className="w-full bg-emerald-600 hover:bg-emerald-500 py-4 rounded-2xl flex items-center justify-center gap-3 font-game font-black text-white active:scale-95 text-xs uppercase tracking-[0.2em] transition-all shadow-lg shadow-emerald-900/20"
              >
                <Download size={18} /> Gerar PDF
              </button>
            </section>
          </div>
        ) : (
          <div className="animate-in fade-in duration-500">
             <div className="mb-6">
                <h2 className="text-2xl font-game font-black text-white uppercase tracking-tight">Estatísticas</h2>
                <p className="text-[10px] text-slate-500 font-bold uppercase tracking-widest mt-1">Histórico completo de fluxo</p>
             </div>
             <DailyStatsTable logs={logs} />
          </div>
        )}
      </main>

      {/* Navegação Mobile */}
      <nav className="fixed bottom-0 left-0 right-0 bg-slate-950/80 backdrop-blur-2xl border-t border-white/5 md:hidden z-50 transition-transform duration-300">
        <div className="flex justify-around items-center h-16 max-w-lg mx-auto">
          <button onClick={() => setActiveTab('dash')} className={`flex flex-col items-center justify-center w-full h-full gap-1 transition-all ${activeTab === 'dash' ? 'text-emerald-400 scale-110' : 'text-slate-600'}`}>
            <LayoutDashboard size={20} strokeWidth={activeTab === 'dash' ? 2.5 : 2} /><span className="text-[9px] font-black uppercase tracking-widest">Início</span>
          </button>
          <button onClick={() => setActiveTab('stats')} className={`flex flex-col items-center justify-center w-full h-full gap-1 transition-all ${activeTab === 'stats' ? 'text-emerald-400 scale-110' : 'text-slate-600'}`}>
            <TableIcon size={20} strokeWidth={activeTab === 'stats' ? 2.5 : 2} /><span className="text-[9px] font-black uppercase tracking-widest">Histórico</span>
          </button>
        </div>
        <div className="h-safe bg-slate-950"></div>
      </nav>

      {/* Modal Confirmação Recebimento Carteira */}
      {showWalletConfirm && (
        <div className="fixed inset-0 z-[110] flex items-center justify-center bg-black/90 backdrop-blur-md p-6">
          <div className="bg-slate-900 border border-white/10 rounded-[2.5rem] w-full max-w-sm overflow-hidden animate-in zoom-in-95 duration-300 shadow-2xl">
            <div className="p-8 flex flex-col items-center text-center">
              <div className="w-16 h-16 bg-emerald-500/10 rounded-full flex items-center justify-center mb-6 border border-emerald-500/20"><Wallet className="text-emerald-400" size={32} /></div>
              <h3 className="text-2xl font-game font-black text-white uppercase tracking-tighter mb-2">Confirmar Recebimento?</h3>
              <p className="text-xs text-slate-500 font-bold uppercase tracking-widest leading-relaxed mb-8">
                Você está prestes a liquidar o saldo de <span className="text-emerald-400 font-black">{formatBRL(counts.wallet.pending)}</span>. Este valor será movido para o histórico de pagamentos.
              </p>
              <div className="w-full space-y-3">
                <button onClick={handleSettleWallet} className="w-full py-4 bg-emerald-600 hover:bg-emerald-500 text-white rounded-2xl font-game font-black text-sm uppercase tracking-[0.2em] shadow-lg shadow-emerald-900/20 active:scale-95 transition-all">Confirmar e Sincronizar</button>
                <button onClick={() => setShowWalletConfirm(false)} className="w-full py-4 text-slate-500 font-bold uppercase text-[10px] tracking-widest hover:text-white transition-colors">Cancelar</button>
              </div>
            </div>
          </div>
        </div>
      )}

      {/* POPUP DE SUCESSO ULTRA-INTERATIVO */}
      {showSuccessPopup && (
        <div className="fixed inset-0 z-[300] flex items-center justify-center p-6 bg-black/60 backdrop-blur-sm pointer-events-none">
          <div className={`w-full max-w-sm bg-gradient-to-b ${popupTheme} border rounded-[3rem] p-10 flex flex-col items-center text-center shadow-[0_0_80px_rgba(0,0,0,0.5)] animate-pop-burst`}>

            {/* Ícone com Pulsação */}
            <div className="relative mb-8">
              <div className="ring-pulse w-24 h-24 text-white/40"></div>
              <div className="w-24 h-24 bg-white/10 backdrop-blur-md border border-white/20 rounded-full flex items-center justify-center animate-float-bounce shadow-2xl">
                {bulkActionType === 'ENTRADA' && <ArrowDownLeft size={44} className="text-white" strokeWidth={3} />}
                {bulkActionType === 'SAIDA' && <ArrowUpRight size={44} className="text-white" strokeWidth={3} />}
                {bulkActionType === 'DEVOLUCAO' && <RotateCcw size={44} className="text-white" strokeWidth={3} />}
                {bulkActionType === 'SETTLE' && <Sparkles size={44} className="text-yellow-400" strokeWidth={3} />}
              </div>
            </div>

            <h4 className="text-3xl md:text-4xl font-game font-black text-white uppercase tracking-tighter leading-none mb-2 drop-shadow-lg">
              {bulkActionType === 'SETTLE' ? 'RECEBIDO!' : 'SUCESSO!'}
            </h4>

            <div className="w-full h-px bg-white/10 my-4"></div>

            <div className="space-y-1">
              {bulkActionType === 'SETTLE' ? (
                <div className="animate-shine px-6 py-2 bg-white/5 rounded-2xl border border-white/10">
                  <span className="text-4xl md:text-5xl font-game font-black text-white tracking-tighter block">
                    {formatBRL(lastSettleValue)}
                  </span>
                </div>
              ) : (
                <div className="flex flex-col items-center">
                   <div className="px-5 py-1.5 bg-white/5 rounded-xl border border-white/5 mb-3">
                      <span className="text-2xl md:text-3xl font-game font-black text-white tracking-widest">
                        {bulkCount} {bulkCount === 1 ? 'UNIDADE' : 'UNIDADES'}
                      </span>
                   </div>
                   {bulkActionType === 'SAIDA' && (
                     <div className="flex items-center gap-2 text-emerald-300 font-game font-black text-xl tracking-widest animate-pulse">
                        <Check size={20} strokeWidth={4} />
                        +{formatBRL(bulkCount * VALOR_POR_PACOTE)}
                     </div>
                   )}
                </div>
              )}

              <p className="text-[10px] md:text-xs text-white/50 font-game font-bold uppercase tracking-[0.4em] pt-4">
                {bulkActionType === 'SAIDA' ? 'ENTREGA CONFIRMADA' : 
                 bulkActionType === 'ENTRADA' ? 'ENTRADA NA BASE' : 
                 bulkActionType === 'DEVOLUCAO' ? 'RETORNO REGISTRADO' : 
                 'CARTEIRA SINCRONIZADA'}
              </p>
            </div>
          </div>
        </div>
      )}

      {/* Settings Modal (Omitido por brevidade mas funcional no app completo) */}
      {showSettings && (
        <div className="fixed inset-0 z-[100] flex items-end md:items-center justify-center bg-black/80 backdrop-blur-sm p-0 md:p-4">
          <div className="bg-slate-900 w-full max-w-lg rounded-t-[2rem] md:rounded-[2.5rem] border-t md:border border-white/10 overflow-hidden animate-in slide-in-from-bottom-full duration-400">
             {/* Conteúdo de Ajustes igual ao anterior */}
             <div className="px-6 py-4 border-b border-white/5 flex justify-between items-center">
              <h3 className="font-game font-bold text-white uppercase tracking-[0.1em] text-sm">Menu de Ajustes</h3>
              <button onClick={() => setShowSettings(false)} className="p-2 bg-white/5 rounded-full text-slate-500"><X size={20} /></button>
             </div>
             <div className="p-10">
                {confirmReset ? (
                   <div className="text-center space-y-6">
                      <AlertCircle size={48} className="text-red-500 mx-auto" />
                      <p className="font-game font-bold text-white uppercase tracking-widest">Confirmar Reset Total?</p>
                      <button onClick={handleResetData} className="w-full py-4 bg-red-600 text-white rounded-2xl font-game font-black uppercase tracking-widest">APAGAR TUDO</button>
                      <button onClick={() => setConfirmReset(false)} className="text-slate-500 uppercase text-[10px] font-bold">Cancelar</button>
                   </div>
                ) : (
                  <button onClick={() => setConfirmReset(true)} className="w-full p-6 bg-red-500/10 border border-red-500/20 text-red-500 rounded-3xl flex items-center justify-between font-game font-bold uppercase tracking-widest">
                    Apagar Dados <Trash2 size={20} />
                  </button>
                )}
             </div>
          </div>
        </div>
      )}

      <BulkActionModal isOpen={bulkModal.isOpen} type={bulkModal.type} title={bulkModal.type === 'SAIDA' ? 'Saída Lote' : 'Entrada Lote'} onClose={() => setBulkModal({ ...bulkModal, isOpen: false })} onConfirm={handleBulkAction} />
    </div>
  );
};

export default App;

import React, { useState, useEffect, useMemo } from 'react';
import { Truck, Zap, FileText, Download, LayoutDashboard, Send, Table as TableIcon, ListPlus, LogOut, Layers, Settings, Trash2, AlertCircle, User, Sliders, ChevronRight, X, CheckCircle2, Check, Wallet, AlertTriangle, ArrowDownLeft, ArrowUpRight, RotateCcw, Sparkles } from 'lucide-react';
import DashboardCards from './components/DashboardCards';
import ActionButtons from './components/ActionButtons';
import DailyStatsTable from './components/DailyStatsTable';
import BulkActionModal from './components/BulkActionModal';
import WalletCard from './components/WalletCard';
import Login from './components/Login';
import { LogCashLogo } from './components/Logo';
import { LogEntry, LogActionType } from './types';
import { supabaseService } from './services/supabaseService';
import { generatePDF } from './services/pdfService';
import { SUPABASE_CACHE_KEY, VALOR_POR_PACOTE } from './constants';

const App: React.FC = () => {
  const [session, setSession] = useState<any>(null);
  const [logs, setLogs] = useState<LogEntry[]>(() => {
    const cached = localStorage.getItem(SUPABASE_CACHE_KEY);
    return cached ? JSON.parse(cached) : [];
  });
  const [loading, setLoading] = useState(true);
  const [isSyncing, setIsSyncing] = useState(false);
  const [showToast, setShowToast] = useState(false);
  const [toastMsg, setToastMsg] = useState('');

  // Estado para o Pop-up de Sucesso Hyper-Interativo
  const [showSuccessPopup, setShowSuccessPopup] = useState(false);
  const [bulkCount, setBulkCount] = useState(0);
  const [lastSettleValue, setLastSettleValue] = useState(0);
  const [bulkActionType, setBulkActionType] = useState<'ENTRADA' | 'SAIDA' | 'DEVOLUCAO' | 'SETTLE'>('ENTRADA');

  // Estado para Confirmação de Carteira
  const [showWalletConfirm, setShowWalletConfirm] = useState(false);

  const [userName, setUserName] = useState(() => localStorage.getItem('logcash_user_name') || 'Operador Logístico');
  const [activeTab, setActiveTab] = useState<'dash' | 'stats'>('dash');
  const [showSettings, setShowSettings] = useState(false);
  const [confirmReset, setConfirmReset] = useState(false);
  const [settingsView, setSettingsView] = useState<'menu' | 'profile' | 'danger'>('menu');

  const [bulkModal, setBulkModal] = useState<{ isOpen: boolean; type: 'ENTRADA' | 'SAIDA' }>({
    isOpen: false,
    type: 'ENTRADA'
  });

  useEffect(() => {
    supabaseService.getSession().then(session => {
      setSession(session);
      if (!session) setLoading(false);
    });
  }, []);

  useEffect(() => {
    if (!session) return;
    setIsSyncing(true);
    const unsubscribe = supabaseService.subscribeToLogs((updatedLogs, supabaseError) => {
      if (!supabaseError) {
        setLogs(updatedLogs);
        localStorage.setItem(SUPABASE_CACHE_KEY, JSON.stringify(updatedLogs));
      }
      setLoading(false);
      setIsSyncing(false);
    });
    return () => unsubscribe();
  }, [session]);

  useEffect(() => {
    localStorage.setItem('logcash_user_name', userName);
  }, [userName]);

  const handleLogout = async () => {
    await supabaseService.signOut();
    localStorage.removeItem(SUPABASE_CACHE_KEY);
    setSession(null);
    setLogs([]);
    setShowSettings(false);
  };

  const handleAction = async (type: LogActionType) => {
    const newEntry: Omit<LogEntry, 'id'> = {
      type,
      timestamp: new Date().toISOString(),
      value: type === 'SAIDA' ? VALOR_POR_PACOTE : 0
    };
    try {
      await supabaseService.saveLog(newEntry);

      setBulkActionType(type as any);
      setBulkCount(1);
      setShowSuccessPopup(true);
      setTimeout(() => setShowSuccessPopup(false), 2200);

    } catch (err) {
      setToastMsg('Erro na sincronização.');
      setShowToast(true);
      setTimeout(() => setShowToast(false), 2000);
    }
  };

  const handleBulkAction = async (quantity: number) => {
    const type = bulkModal.type;
    const newEntries = Array.from({ length: quantity }).map(() => ({
      type: type as LogActionType,
      timestamp: new Date().toISOString(),
      value: type === 'SAIDA' ? VALOR_POR_PACOTE : 0
    }));
    try {
      await supabaseService.saveBulkLogs(newEntries);
      setBulkCount(quantity);
      setBulkActionType(type as any);
      setShowSuccessPopup(true);
      setTimeout(() => { setShowSuccessPopup(false); }, 2200);
    } catch (err) {
      setToastMsg('Falha no envio em lote.');
      setShowToast(true);
      setTimeout(() => setShowToast(false), 2000);
    }
  };

  const handleSettleWallet = async () => {
    try {
      setIsSyncing(true);
      const valToSettle = counts.wallet.pending;
      setLastSettleValue(valToSettle);

      setShowWalletConfirm(false);
      await supabaseService.markAllAsPaid();

      setBulkActionType('SETTLE');
      setShowSuccessPopup(true);
      setTimeout(() => { setShowSuccessPopup(false); }, 2200);

    } catch (err) {
      setToastMsg('Erro ao liquidar pagamentos.');
      setShowToast(true);
      setTimeout(() => setShowToast(false), 2000);
    } finally {
      setIsSyncing(false);
    }
  };

  const handleResetData = async () => {
    try {
      setIsSyncing(true);
      await supabaseService.deleteAllLogs();
      setLogs([]);
      localStorage.removeItem(SUPABASE_CACHE_KEY);
      setUserName('Operador Logístico');
      localStorage.removeItem('logcash_user_name');
      setToastMsg('Sistema reiniciado.');
      setShowToast(true);
      setConfirmReset(false);
      setShowSettings(false);
      setTimeout(() => setShowToast(false), 2000);
    } catch (err) {
      setToastMsg('Erro ao apagar dados.');
      setShowToast(true);
    } finally {
      setIsSyncing(false);
    }
  };

  const counts = useMemo(() => {
    const todayStr = new Date().toDateString();
    const now = new Date();
    const startOfWeek = new Date(now);
    startOfWeek.setDate(now.getDate() - now.getDay());
    startOfWeek.setHours(0, 0, 0, 0);
    const startOfYear = new Date(now.getFullYear(), 0, 1);

    const deliveredLogs = logs.filter(l => l.type === 'SAIDA');
    const pending = deliveredLogs.filter(l => !l.isPaid).length * VALOR_POR_PACOTE;
    const paidCurrentCycle = deliveredLogs.filter(l => l.isPaid && new Date(l.timestamp) >= startOfWeek).length * VALOR_POR_PACOTE;
    const totalCumulativePaid = deliveredLogs.filter(l => l.isPaid).length * VALOR_POR_PACOTE;

    return {
      today: logs.filter(l => l.type === 'SAIDA' && new Date(l.timestamp).toDateString() === todayStr).length,
      week: logs.filter(l => l.type === 'SAIDA' && new Date(l.timestamp) >= startOfWeek).length,
      year: logs.filter(l => l.type === 'SAIDA' && new Date(l.timestamp) >= startOfYear).length,
      wallet: {
        pending,
        paid: paidCurrentCycle,
        cumulative: totalCumulativePaid
      }
    };
  }, [logs]);

  if (!session && !loading) return <Login onLoginSuccess={() => supabaseService.getSession().then(setSession)} />;

  if (loading && logs.length === 0) {
    return (
      <div className="min-h-screen bg-[#020617] flex flex-col items-center justify-center p-6 text-center">
        <LogCashLogo size={60} />
        <p className="text-slate-500 font-game font-bold uppercase tracking-[0.3em] text-[10px] animate-pulse mt-4">Iniciando...</p>
      </div>
    );
  }

  const formatBRL = (val: number) => new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(val);

  const popupTheme = {
    ENTRADA: { bg: 'from-emerald-600 to-emerald-900', border: 'border-emerald-400/40', text: 'text-emerald-400', glow: 'text-emerald-500' },
    SAIDA: { bg: 'from-blue-600 to-blue-900', border: 'border-blue-400/40', text: 'text-blue-400', glow: 'text-blue-500' },
    DEVOLUCAO: { bg: 'from-orange-600 to-orange-900', border: 'border-orange-400/40', text: 'text-orange-400', glow: 'text-orange-500' },
    SETTLE: { bg: 'from-indigo-600 to-indigo-900', border: 'border-indigo-400/40', text: 'text-indigo-400', glow: 'text-indigo-500' }
  }[bulkActionType];

  return (
    <div className="min-h-screen bg-[#020617] text-slate-200 selection:bg-emerald-500/30 flex flex-col overflow-x-hidden relative">
      <header className="bg-slate-900/80 backdrop-blur-xl border-b border-white/5 px-4 md:px-8 sticky top-0 z-40 pt-safe transition-all h-20">
        <div className="max-w-5xl mx-auto flex justify-between items-center h-full">
          <div className="flex items-center gap-3">
            <LogCashLogo size={36} />
            <div>
              <h1 className="text-xl font-game font-black tracking-[0.1em] text-white leading-none">LOG<span className="text-emerald-400">CASH</span></h1>
              <p className="text-[8px] text-slate-500 font-bold uppercase tracking-widest mt-1">{isSyncing ? 'Sincronizando...' : 'Sistema Online'}</p>
            </div>
          </div>

          <div className="flex items-center gap-2">
            <button 
              onClick={() => { setShowSettings(true); setSettingsView('menu'); }} 
              className="p-2.5 bg-white/5 rounded-2xl border border-white/10 active:scale-95 transition-all hover:bg-white/10 flex items-center gap-2"
            >
              <Settings size={18} className="text-slate-400" />
              <span className="hidden sm:block text-[10px] font-black text-slate-400 uppercase tracking-widest">Ajustes</span>
            </button>
            <button 
              onClick={handleLogout}
              className="p-2.5 bg-red-500/10 rounded-2xl border border-red-500/20 active:scale-95 transition-all hover:bg-red-500/20 text-red-500 flex items-center gap-2"
            >
              <LogOut size={18} />
              <span className="hidden sm:block text-[10px] font-black uppercase tracking-widest">Sair</span>
            </button>
          </div>
        </div>
      </header>

      <main className="flex-1 max-w-5xl mx-auto w-full p-4 md:p-8 space-y-8 pb-28 md:pb-12 transition-all">
        {activeTab === 'dash' ? (
          <div className="animate-in fade-in duration-500">
            <div className="mb-8">
              <h2 className="text-3xl md:text-5xl font-game font-black text-white uppercase tracking-tight leading-tight">Olá, {userName.split(' ')[0]}</h2>
              <p className="text-[10px] md:text-xs text-slate-500 font-bold uppercase tracking-[0.4em] mt-2">Relatórios em tempo real</p>
            </div>

            <div className="grid grid-cols-1 lg:grid-cols-5 gap-6 mb-10">
              <div className="lg:col-span-3"><DashboardCards today={counts.today} week={counts.week} year={counts.year} /></div>
              <div className="lg:col-span-2">
                <WalletCard 
                  pendingAmount={counts.wallet.pending} 
                  paidAmount={counts.wallet.paid} 
                  totalCumulativePaid={counts.wallet.cumulative} 
                  onSettle={() => setShowWalletConfirm(true)}
                />
              </div>
            </div>

            <section className="space-y-4 mb-10">
              <div className="flex items-center justify-between px-1">
                <h2 className="text-slate-500 font-game font-bold text-[10px] uppercase tracking-[0.5em]">Ações de Registro</h2>
                <div className="h-px flex-1 bg-white/5 mx-4 hidden sm:block"></div>
              </div>
              <ActionButtons onAction={handleAction} />
            </section>

            <section className="grid grid-cols-2 gap-4 mb-10">
              <button onClick={() => setBulkModal({ isOpen: true, type: 'ENTRADA' })} className="bg-slate-900/40 border border-white/5 p-6 rounded-3xl flex flex-col items-start gap-4 active:scale-95 hover:bg-white/[0.03] transition-all">
                <div className="p-3 bg-emerald-600/10 text-emerald-400 rounded-2xl border border-emerald-500/20"><ListPlus size={24} /></div>
                <div className="text-left"><p className="font-game font-black text-white text-sm uppercase tracking-widest">Lote Entrada</p><p className="text-[8px] text-slate-500 uppercase font-bold mt-1">Check-in Massivo</p></div>
              </button>
              <button onClick={() => setBulkModal({ isOpen: true, type: 'SAIDA' })} className="bg-slate-900/40 border border-white/5 p-6 rounded-3xl flex flex-col items-start gap-4 active:scale-95 hover:bg-white/[0.03] transition-all">
                <div className="p-3 bg-blue-600/10 text-blue-400 rounded-2xl border border-blue-500/20"><Send size={24} /></div>
                <div className="text-left"><p className="font-game font-black text-white text-sm uppercase tracking-widest">Lote Saída</p><p className="text-[8px] text-slate-500 uppercase font-bold mt-1">Entrega Massiva</p></div>
              </button>
            </section>

            <section className="bg-slate-900/50 p-6 md:p-10 rounded-[3rem] border border-white/5 relative overflow-hidden group">
              <div className="flex items-center gap-4 mb-6">
                <div className="p-3 bg-emerald-500/10 rounded-2xl"><FileText size={24} className="text-emerald-400" /></div>
                <h3 className="font-game font-black text-white uppercase tracking-[0.2em] text-base">Exportar Base de Dados</h3>
              </div>
              <button 
                onClick={() => generatePDF(logs, userName)}
                className="w-full bg-emerald-600 hover:bg-emerald-500 py-5 rounded-[1.5rem] flex items-center justify-center gap-3 font-game font-black text-white active:scale-95 text-xs uppercase tracking-[0.4em] transition-all shadow-2xl shadow-emerald-900/30"
              >
                <Download size={22} /> Gerar PDF Detalhado
              </button>
            </section>
          </div>
        ) : (
          <div className="animate-in fade-in duration-500"><DailyStatsTable logs={logs} /></div>
        )}
      </main>

      <nav className="fixed bottom-0 left-0 right-0 glass-card border-t border-white/10 md:hidden z-50">
        <div className="flex justify-around items-center h-20 max-w-lg mx-auto">
          <button onClick={() => setActiveTab('dash')} className={`flex flex-col items-center justify-center w-full h-full gap-1 transition-all ${activeTab === 'dash' ? 'text-emerald-400 scale-110' : 'text-slate-600'}`}>
            <LayoutDashboard size={24} strokeWidth={activeTab === 'dash' ? 2.5 : 2} /><span className="text-[9px] font-black uppercase tracking-[0.2em]">Home</span>
          </button>
          <button onClick={() => setActiveTab('stats')} className={`flex flex-col items-center justify-center w-full h-full gap-1 transition-all ${activeTab === 'stats' ? 'text-emerald-400 scale-110' : 'text-slate-600'}`}>
            <TableIcon size={24} strokeWidth={activeTab === 'stats' ? 2.5 : 2} /><span className="text-[9px] font-black uppercase tracking-[0.2em]">Histórico</span>
          </button>
        </div>
        <div className="h-safe bg-slate-950"></div>
      </nav>

      {/* POPUP SUCESSO HYPER-INTERATIVO */}
      {showSuccessPopup && (
        <div className="fixed inset-0 z-[500] flex items-center justify-center p-6 pointer-events-none overflow-hidden">
          <div className={`w-full max-w-sm bg-gradient-to-b ${popupTheme.bg} ${popupTheme.border} border-2 rounded-[3.5rem] p-12 flex flex-col items-center text-center shadow-[0_0_100px_rgba(0,0,0,0.8)] animate-spring-in relative`}>

            {/* Elementos de Brilho Orbitais */}
            <div className="absolute inset-0 flex items-center justify-center pointer-events-none animate-orbit">
               <Sparkles size={120} className={`${popupTheme.text} opacity-20`} strokeWidth={0.5} />
            </div>

            <div className={`w-28 h-28 bg-white/10 backdrop-blur-xl border border-white/20 rounded-full flex items-center justify-center mb-8 pulse-glow ${popupTheme.glow}`}>
              {bulkActionType === 'ENTRADA' && <ArrowDownLeft size={50} className="text-white" strokeWidth={3} />}
              {bulkActionType === 'SAIDA' && <ArrowUpRight size={50} className="text-white" strokeWidth={3} />}
              {bulkActionType === 'DEVOLUCAO' && <RotateCcw size={50} className="text-white" strokeWidth={3} />}
              {bulkActionType === 'SETTLE' && <Check size={60} className="text-white" strokeWidth={4} />}
            </div>

            <h4 className="text-3xl md:text-4xl font-game font-black text-white uppercase tracking-tighter leading-none mb-3 drop-shadow-2xl">
              {bulkActionType === 'SETTLE' ? 'RECEBIDO!' : 'CONCLUÍDO!'}
            </h4>

            <div className="w-full h-px bg-white/20 my-6"></div>

            <div className="space-y-2">
              {bulkActionType === 'SETTLE' ? (
                <div className="px-8 py-3 bg-white/10 rounded-3xl border border-white/20 shadow-inner">
                  <span className="text-4xl md:text-5xl font-game font-black text-white tracking-tighter block">{formatBRL(lastSettleValue)}</span>
                </div>
              ) : (
                <div className="flex flex-col items-center">
                   <div className="px-6 py-2 bg-white/10 rounded-2xl border border-white/20 mb-4">
                      <span className="text-3xl font-game font-black text-white tracking-widest uppercase">{bulkCount} Unid.</span>
                   </div>
                   {bulkActionType === 'SAIDA' && (
                     <p className="text-emerald-300 font-game font-black text-2xl tracking-widest flex items-center gap-2 drop-shadow-md">
                        <Zap size={20} fill="currentColor" /> +{formatBRL(bulkCount * VALOR_POR_PACOTE)}
                     </p>
                   )}
                </div>
              )}

              <p className="text-[10px] text-white/60 font-game font-bold uppercase tracking-[0.5em] pt-6 opacity-80">
                Sincronização em nuvem ok
              </p>
            </div>

            {/* Barra de Timer Rodapé */}
            <div className="absolute bottom-6 left-12 right-12 h-1 bg-white/10 rounded-full overflow-hidden">
               <div className="h-full bg-white/60 animate-timer"></div>
            </div>
          </div>
        </div>
      )}

      {/* Modal Ajustes */}
      {showSettings && (
        <div className="fixed inset-0 z-[100] flex items-end md:items-center justify-center bg-black/90 backdrop-blur-md p-0 md:p-4">
          <div className="bg-slate-900 w-full max-w-lg rounded-t-[3rem] md:rounded-[3rem] border-t md:border border-white/10 overflow-hidden animate-in slide-in-from-bottom-full duration-500">
             <div className="px-8 py-6 border-b border-white/5 flex justify-between items-center">
              <h3 className="font-game font-black text-white uppercase tracking-[0.2em] text-sm">Painel de Controle</h3>
              <button onClick={() => { setShowSettings(false); setConfirmReset(false); }} className="p-3 bg-white/5 rounded-full text-slate-500"><X size={20} /></button>
             </div>
             <div className="p-8 md:p-12 space-y-6">
                {confirmReset ? (
                   <div className="text-center space-y-8 animate-in zoom-in-95">
                      <div className="w-20 h-20 bg-red-500/10 rounded-full flex items-center justify-center mx-auto border border-red-500/20 text-red-500"><AlertCircle size={40} /></div>
                      <div className="space-y-2">
                        <p className="font-game font-black text-white uppercase tracking-widest text-lg">Reset Absoluto?</p>
                        <p className="text-[10px] text-slate-500 uppercase font-bold tracking-widest">Essa ação não pode ser desfeita.</p>
                      </div>
                      <div className="flex flex-col gap-4">
                        <button onClick={handleResetData} className="w-full py-5 bg-red-600 hover:bg-red-500 text-white rounded-2xl font-game font-black uppercase tracking-[0.3em] shadow-2xl shadow-red-900/40">Limpar Tudo</button>
                        <button onClick={() => setConfirmReset(false)} className="text-slate-500 uppercase text-[10px] font-black hover:text-white transition-colors">Voltar</button>
                      </div>
                   </div>
                ) : (
                  <div className="space-y-4">
                    <div className="space-y-4 mb-8">
                       <label className="text-[10px] font-black text-slate-600 uppercase tracking-[0.4em] ml-1">Assinatura no Relatório</label>
                       <input 
                        type="text" 
                        value={userName} 
                        onChange={(e) => setUserName(e.target.value)} 
                        className="w-full bg-black/40 border border-white/10 focus:border-emerald-500/50 rounded-2xl p-5 text-sm font-bold text-white focus:outline-none transition-all" 
                       />
                    </div>
                    <button onClick={() => setConfirmReset(true)} className="w-full p-6 bg-red-500/5 border border-red-500/10 text-red-500 rounded-3xl flex items-center justify-between font-game font-black uppercase tracking-widest text-xs active:scale-95 transition-all">
                      Zona de Perigo <Trash2 size={20} />
                    </button>
                  </div>
                )}
             </div>
             <div className="h-safe bg-slate-900 pb-safe"></div>
          </div>
        </div>
      )}

      {/* Modal Confirmação Carteira */}
      {showWalletConfirm && (
        <div className="fixed inset-0 z-[110] flex items-center justify-center bg-black/95 backdrop-blur-xl p-6">
          <div className="bg-slate-900 border border-white/10 rounded-[3rem] w-full max-w-sm overflow-hidden animate-in zoom-in-95 duration-400">
            <div className="p-10 flex flex-col items-center text-center">
              <div className="w-20 h-20 bg-emerald-500/10 rounded-full flex items-center justify-center mb-8 border border-emerald-500/20"><Wallet className="text-emerald-400" size={36} /></div>
              <h3 className="text-3xl font-game font-black text-white uppercase tracking-tighter mb-3 leading-none">Confirmar Saldo?</h3>
              <p className="text-[10px] text-slate-500 font-bold uppercase tracking-widest leading-relaxed mb-10">
                Sincronizar <span className="text-emerald-400 font-black">{formatBRL(counts.wallet.pending)}</span> para o histórico de pagamentos?
              </p>
              <div className="w-full space-y-4">
                <button onClick={handleSettleWallet} className="w-full py-5 bg-emerald-600 hover:bg-emerald-500 text-white rounded-2xl font-game font-black text-sm uppercase tracking-[0.3em] active:scale-95 transition-all shadow-2xl shadow-emerald-900/40">Liquidar Agora</button>
                <button onClick={() => setShowWalletConfirm(false)} className="text-slate-500 font-bold uppercase text-[10px] tracking-widest hover:text-white transition-colors">Fechar</button>
              </div>
            </div>
          </div>
        </div>
      )}

      <BulkActionModal isOpen={bulkModal.isOpen} type={bulkModal.type} title={bulkModal.type === 'SAIDA' ? 'Saída Lote' : 'Entrada Lote'} onClose={() => setBulkModal({ ...bulkModal, isOpen: false })} onConfirm={handleBulkAction} />
    </div>
  );
};

export default App;

import React, { useState, useEffect, useMemo } from 'react';
import { Truck, Zap, FileText, Download, LayoutDashboard, Send, Table as TableIcon, ListPlus, LogOut, Layers, Settings, Trash2, AlertCircle, User, Sliders, ChevronRight, X, CheckCircle2, Check, Wallet, AlertTriangle, ArrowDownLeft, ArrowUpRight, RotateCcw, Sparkles } from 'lucide-react';
import DashboardCards from './components/DashboardCards';
import ActionButtons from './components/ActionButtons';
import DailyStatsTable from './components/DailyStatsTable';
import BulkActionModal from './components/BulkActionModal';
import WalletCard from './components/WalletCard';
import Login from './components/Login';
import { LogCashLogo } from './components/Logo';
import { LogEntry, LogActionType } from './types';
import { supabaseService } from './services/supabaseService';
import { generatePDF } from './services/pdfService';
import { SUPABASE_CACHE_KEY, VALOR_POR_PACOTE } from './constants';

const App: React.FC = () => {
  const [session, setSession] = useState<any>(null);
  const [logs, setLogs] = useState<LogEntry[]>(() => {
    const cached = localStorage.getItem(SUPABASE_CACHE_KEY);
    return cached ? JSON.parse(cached) : [];
  });
  const [loading, setLoading] = useState(true);
  const [isSyncing, setIsSyncing] = useState(false);
  const [showToast, setShowToast] = useState(false);
  const [toastMsg, setToastMsg] = useState('');

  // Estado para o Pop-up de Sucesso Hyper-Interativo
  const [showSuccessPopup, setShowSuccessPopup] = useState(false);
  const [bulkCount, setBulkCount] = useState(0);
  const [lastSettleValue, setLastSettleValue] = useState(0);
  const [bulkActionType, setBulkActionType] = useState<'ENTRADA' | 'SAIDA' | 'DEVOLUCAO' | 'SETTLE'>('ENTRADA');

  // Estado para Confirmação de Carteira
  const [showWalletConfirm, setShowWalletConfirm] = useState(false);

  const [userName, setUserName] = useState(() => localStorage.getItem('logcash_user_name') || 'Operador Logístico');
  const [activeTab, setActiveTab] = useState<'dash' | 'stats'>('dash');
  const [showSettings, setShowSettings] = useState(false);
  const [confirmReset, setConfirmReset] = useState(false);
  const [settingsView, setSettingsView] = useState<'menu' | 'profile' | 'danger'>('menu');

  const [bulkModal, setBulkModal] = useState<{ isOpen: boolean; type: 'ENTRADA' | 'SAIDA' }>({
    isOpen: false,
    type: 'ENTRADA'
  });

  useEffect(() => {
    supabaseService.getSession().then(session => {
      setSession(session);
      if (!session) setLoading(false);
    });
  }, []);

  useEffect(() => {
    if (!session) return;
    setIsSyncing(true);
    const unsubscribe = supabaseService.subscribeToLogs((updatedLogs, supabaseError) => {
      if (!supabaseError) {
        setLogs(updatedLogs);
        localStorage.setItem(SUPABASE_CACHE_KEY, JSON.stringify(updatedLogs));
      }
      setLoading(false);
      setIsSyncing(false);
    });
    return () => unsubscribe();
  }, [session]);

  useEffect(() => {
    localStorage.setItem('logcash_user_name', userName);
  }, [userName]);

  const handleLogout = async () => {
    await supabaseService.signOut();
    localStorage.removeItem(SUPABASE_CACHE_KEY);
    setSession(null);
    setLogs([]);
    setShowSettings(false);
  };

  const handleAction = async (type: LogActionType) => {
    const newEntry: Omit<LogEntry, 'id'> = {
      type,
      timestamp: new Date().toISOString(),
      value: type === 'SAIDA' ? VALOR_POR_PACOTE : 0
    };
    try {
      await supabaseService.saveLog(newEntry);

      setBulkActionType(type as any);
      setBulkCount(1);
      setShowSuccessPopup(true);
      setTimeout(() => setShowSuccessPopup(false), 2200);

    } catch (err) {
      setToastMsg('Erro na sincronização.');
      setShowToast(true);
      setTimeout(() => setShowToast(false), 2000);
    }
  };

  const handleBulkAction = async (quantity: number) => {
    const type = bulkModal.type;
    const newEntries = Array.from({ length: quantity }).map(() => ({
      type: type as LogActionType,
      timestamp: new Date().toISOString(),
      value: type === 'SAIDA' ? VALOR_POR_PACOTE : 0
    }));
    try {
      await supabaseService.saveBulkLogs(newEntries);
      setBulkCount(quantity);
      setBulkActionType(type as any);
      setShowSuccessPopup(true);
      setTimeout(() => { setShowSuccessPopup(false); }, 2200);
    } catch (err) {
      setToastMsg('Falha no envio em lote.');
      setShowToast(true);
      setTimeout(() => setShowToast(false), 2000);
    }
  };

  const handleSettleWallet = async () => {
    try {
      setIsSyncing(true);
      // Capturamos o valor ANTES da liquidação para exibir no popup
      const valToSettle = counts.wallet.pending;
      setLastSettleValue(valToSettle);

      setShowWalletConfirm(false);
      await supabaseService.markAllAsPaid();

      // Feedback Visual
      setBulkActionType('SETTLE');
      setShowSuccessPopup(true);
      setTimeout(() => { setShowSuccessPopup(false); }, 2200);

    } catch (err) {
      setToastMsg('Erro ao liquidar pagamentos.');
      setShowToast(true);
      setTimeout(() => setShowToast(false), 2000);
    } finally {
      setIsSyncing(false);
    }
  };

  const handleResetData = async () => {
    try {
      setIsSyncing(true);
      await supabaseService.deleteAllLogs();
      setLogs([]);
      localStorage.removeItem(SUPABASE_CACHE_KEY);
      setUserName('Operador Logístico');
      localStorage.removeItem('logcash_user_name');
      setToastMsg('Sistema reiniciado.');
      setShowToast(true);
      setConfirmReset(false);
      setShowSettings(false);
      setTimeout(() => setShowToast(false), 2000);
    } catch (err) {
      setToastMsg('Erro ao apagar dados.');
      setShowToast(true);
    } finally {
      setIsSyncing(false);
    }
  };

  const counts = useMemo(() => {
    const todayStr = new Date().toDateString();
    const now = new Date();
    const startOfWeek = new Date(now);
    startOfWeek.setDate(now.getDate() - now.getDay());
    startOfWeek.setHours(0, 0, 0, 0);
    const startOfYear = new Date(now.getFullYear(), 0, 1);

    const deliveredLogs = logs.filter(l => l.type === 'SAIDA');
    const pending = deliveredLogs.filter(l => !l.isPaid).length * VALOR_POR_PACOTE;
    const paidCurrentCycle = deliveredLogs.filter(l => l.isPaid && new Date(l.timestamp) >= startOfWeek).length * VALOR_POR_PACOTE;
    const totalCumulativePaid = deliveredLogs.filter(l => l.isPaid).length * VALOR_POR_PACOTE;

    return {
      today: logs.filter(l => l.type === 'SAIDA' && new Date(l.timestamp).toDateString() === todayStr).length,
      week: logs.filter(l => l.type === 'SAIDA' && new Date(l.timestamp) >= startOfWeek).length,
      year: logs.filter(l => l.type === 'SAIDA' && new Date(l.timestamp) >= startOfYear).length,
      wallet: {
        pending,
        paid: paidCurrentCycle,
        cumulative: totalCumulativePaid
      }
    };
  }, [logs]);

  if (!session && !loading) return <Login onLoginSuccess={() => supabaseService.getSession().then(setSession)} />;

  if (loading && logs.length === 0) {
    return (
      <div className="min-h-screen bg-[#020617] flex flex-col items-center justify-center p-6 text-center">
        <LogCashLogo size={60} />
        <p className="text-slate-500 font-game font-bold uppercase tracking-[0.3em] text-[10px] animate-pulse mt-4">Sincronizando Terminal...</p>
      </div>
    );
  }

  const formatBRL = (val: number) => new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(val);

  const popupTheme = {
    ENTRADA: { bg: 'from-emerald-600 to-emerald-900', border: 'border-emerald-400/40', text: 'text-emerald-400', glow: 'text-emerald-500' },
    SAIDA: { bg: 'from-blue-600 to-blue-900', border: 'border-blue-400/40', text: 'text-blue-400', glow: 'text-blue-500' },
    DEVOLUCAO: { bg: 'from-orange-600 to-orange-900', border: 'border-orange-400/40', text: 'text-orange-400', glow: 'text-orange-500' },
    SETTLE: { bg: 'from-indigo-600 to-indigo-900', border: 'border-indigo-400/40', text: 'text-indigo-400', glow: 'text-indigo-500' }
  }[bulkActionType];

  return (
    <div className="min-h-screen bg-[#020617] text-slate-200 selection:bg-emerald-500/30 flex flex-col overflow-x-hidden relative">
      <header className="bg-slate-900/80 backdrop-blur-xl border-b border-white/5 px-4 md:px-8 sticky top-0 z-40 pt-safe transition-all h-20">
        <div className="max-w-5xl mx-auto flex justify-between items-center h-full">
          <div className="flex items-center gap-3">
            <LogCashLogo size={36} />
            <div>
              <h1 className="text-xl font-game font-black tracking-[0.1em] text-white leading-none">LOG<span className="text-emerald-400">CASH</span></h1>
              <p className="text-[8px] text-slate-500 font-bold uppercase tracking-widest mt-1">{isSyncing ? 'Atualizando...' : 'Online'}</p>
            </div>
          </div>

          <div className="flex items-center gap-2">
            <button 
              onClick={() => { setShowSettings(true); setSettingsView('menu'); }} 
              className="p-3 bg-white/5 rounded-2xl border border-white/10 active:scale-95 transition-all hover:bg-white/10 flex items-center gap-2"
            >
              <Settings size={20} className="text-slate-400" />
              <span className="hidden sm:block text-[10px] font-black text-slate-400 uppercase tracking-widest">Painel</span>
            </button>
          </div>
        </div>
      </header>

      <main className="flex-1 max-w-5xl mx-auto w-full p-4 md:p-8 space-y-8 pb-28 md:pb-12 transition-all">
        {activeTab === 'dash' ? (
          <div className="animate-in fade-in duration-500">
            <div className="mb-8">
              <h2 className="text-3xl md:text-5xl font-game font-black text-white uppercase tracking-tight leading-tight">Olá, {userName.split(' ')[0]}</h2>
              <p className="text-[10px] md:text-xs text-slate-500 font-bold uppercase tracking-[0.4em] mt-2">Seu desempenho logístico hoje</p>
            </div>

            <div className="grid grid-cols-1 lg:grid-cols-5 gap-6 mb-10">
              <div className="lg:col-span-3">
                <DashboardCards today={counts.today} week={counts.week} year={counts.year} />
              </div>
              <div className="lg:col-span-2">
                <WalletCard 
                  pendingAmount={counts.wallet.pending} 
                  paidAmount={counts.wallet.paid} 
                  totalCumulativePaid={counts.wallet.cumulative} 
                  onSettle={() => setShowWalletConfirm(true)}
                />
              </div>
            </div>

            <section className="space-y-4 mb-10">
              <div className="flex items-center justify-between px-1">
                <h2 className="text-slate-500 font-game font-bold text-[10px] uppercase tracking-[0.5em]">Ações Rápidas</h2>
                <div className="h-px flex-1 bg-white/5 mx-4 hidden sm:block"></div>
              </div>
              <ActionButtons onAction={handleAction} />
            </section>

            <section className="grid grid-cols-2 gap-4 mb-10">
              <button onClick={() => setBulkModal({ isOpen: true, type: 'ENTRADA' })} className="bg-slate-900/40 border border-white/5 p-6 rounded-3xl flex flex-col items-start gap-4 active:scale-95 hover:bg-white/[0.03] transition-all">
                <div className="p-3 bg-emerald-600/10 text-emerald-400 rounded-2xl border border-emerald-500/20"><ListPlus size={24} /></div>
                <div className="text-left"><p className="font-game font-black text-white text-sm uppercase tracking-widest">Lote Entrada</p><p className="text-[8px] text-slate-500 uppercase font-bold mt-1">Check-in</p></div>
              </button>
              <button onClick={() => setBulkModal({ isOpen: true, type: 'SAIDA' })} className="bg-slate-900/40 border border-white/5 p-6 rounded-3xl flex flex-col items-start gap-4 active:scale-95 hover:bg-white/[0.03] transition-all">
                <div className="p-3 bg-blue-600/10 text-blue-400 rounded-2xl border border-blue-500/20"><Send size={24} /></div>
                <div className="text-left"><p className="font-game font-black text-white text-sm uppercase tracking-widest">Lote Saída</p><p className="text-[8px] text-slate-500 uppercase font-bold mt-1">Entrega</p></div>
              </button>
            </section>

            <section className="bg-slate-900/50 p-6 md:p-10 rounded-[3rem] border border-white/5 relative overflow-hidden group">
              <div className="flex items-center gap-4 mb-6">
                <div className="p-3 bg-emerald-500/10 rounded-2xl"><FileText size={24} className="text-emerald-400" /></div>
                <h3 className="font-game font-black text-white uppercase tracking-[0.2em] text-base">Exportar Extrato</h3>
              </div>
              <button 
                onClick={() => generatePDF(logs, userName)}
                className="w-full bg-emerald-600 hover:bg-emerald-500 py-5 rounded-[1.5rem] flex items-center justify-center gap-3 font-game font-black text-white active:scale-95 text-xs uppercase tracking-[0.4em] transition-all shadow-2xl shadow-emerald-900/30"
              >
                <Download size={22} /> Gerar PDF
              </button>
            </section>
          </div>
        ) : (
          <div className="animate-in fade-in duration-500">
            <div className="mb-6 flex items-center justify-between">
              <h2 className="text-2xl font-game font-black text-white uppercase tracking-tight">Estatísticas de Fluxo</h2>
            </div>
            <DailyStatsTable logs={logs} />
          </div>
        )}
      </main>

      <nav className="fixed bottom-0 left-0 right-0 glass-card border-t border-white/10 md:hidden z-50">
        <div className="flex justify-around items-center h-20 max-w-lg mx-auto">
          <button onClick={() => setActiveTab('dash')} className={`flex flex-col items-center justify-center w-full h-full gap-1 transition-all ${activeTab === 'dash' ? 'text-emerald-400 scale-110' : 'text-slate-600'}`}>
            <LayoutDashboard size={24} strokeWidth={activeTab === 'dash' ? 2.5 : 2} /><span className="text-[9px] font-black uppercase tracking-[0.2em]">Home</span>
          </button>
          <button onClick={() => setActiveTab('stats')} className={`flex flex-col items-center justify-center w-full h-full gap-1 transition-all ${activeTab === 'stats' ? 'text-emerald-400 scale-110' : 'text-slate-600'}`}>
            <TableIcon size={24} strokeWidth={activeTab === 'stats' ? 2.5 : 2} /><span className="text-[9px] font-black uppercase tracking-[0.2em]">Registros</span>
          </button>
        </div>
        <div className="h-safe bg-slate-950"></div>
      </nav>

      {/* POPUP SUCESSO HYPER-INTERATIVO */}
      {showSuccessPopup && (
        <div className="fixed inset-0 z-[500] flex items-center justify-center p-6 pointer-events-none overflow-hidden">
          <div className={`w-full max-w-sm bg-gradient-to-b ${popupTheme.bg} ${popupTheme.border} border-2 rounded-[3.5rem] p-12 flex flex-col items-center text-center shadow-[0_0_120px_rgba(0,0,0,0.9)] animate-spring-in relative`}>

            {/* Elementos de Brilho Orbitais */}
            <div className="absolute inset-0 flex items-center justify-center pointer-events-none animate-orbit">
               <Sparkles size={140} className={`${popupTheme.text} opacity-25`} strokeWidth={0.5} />
            </div>

            <div className={`w-28 h-28 bg-white/10 backdrop-blur-xl border border-white/20 rounded-full flex items-center justify-center mb-8 pulse-glow ${popupTheme.glow}`}>
              {bulkActionType === 'ENTRADA' && <ArrowDownLeft size={50} className="text-white" strokeWidth={3} />}
              {bulkActionType === 'SAIDA' && <ArrowUpRight size={50} className="text-white" strokeWidth={3} />}
              {bulkActionType === 'DEVOLUCAO' && <RotateCcw size={50} className="text-white" strokeWidth={3} />}
              {bulkActionType === 'SETTLE' && <Check size={60} className="text-white" strokeWidth={4} />}
            </div>

            <h4 className="text-3xl md:text-4xl font-game font-black text-white uppercase tracking-tighter leading-none mb-3 drop-shadow-2xl">
              {bulkActionType === 'SETTLE' ? 'PAGAMENTO OK!' : 'REGISTRADO!'}
            </h4>

            <div className="w-full h-px bg-white/20 my-6"></div>

            <div className="space-y-2">
              {bulkActionType === 'SETTLE' ? (
                <div className="px-8 py-3 bg-white/10 rounded-3xl border border-white/20 shadow-inner">
                  <span className="text-4xl md:text-5xl font-game font-black text-white tracking-tighter block">{formatBRL(lastSettleValue)}</span>
                </div>
              ) : (
                <div className="flex flex-col items-center">
                   <div className="px-6 py-2 bg-white/10 rounded-2xl border border-white/20 mb-4">
                      <span className="text-3xl font-game font-black text-white tracking-widest uppercase">{bulkCount} {bulkCount === 1 ? 'Item' : 'Itens'}</span>
                   </div>
                   {bulkActionType === 'SAIDA' && (
                     <p className="text-emerald-300 font-game font-black text-2xl tracking-widest flex items-center gap-2 drop-shadow-md">
                        <Zap size={20} fill="currentColor" /> +{formatBRL(bulkCount * VALOR_POR_PACOTE)}
                     </p>
                   )}
                </div>
              )}

              <p className="text-[10px] text-white/60 font-game font-bold uppercase tracking-[0.5em] pt-6 opacity-80">
                Sincronizado com Sucesso
              </p>
            </div>

            {/* Barra de Timer Rodapé */}
            <div className="absolute bottom-6 left-12 right-12 h-1 bg-white/10 rounded-full overflow-hidden">
               <div className="h-full bg-white/80 animate-timer"></div>
            </div>
          </div>
        </div>
      )}

      {/* Modal Ajustes com Botão de Sair */}
      {showSettings && (
        <div className="fixed inset-0 z-[100] flex items-end md:items-center justify-center bg-black/90 backdrop-blur-md p-0 md:p-4">
          <div className="bg-slate-900 w-full max-w-lg rounded-t-[3rem] md:rounded-[3rem] border-t md:border border-white/10 overflow-hidden animate-in slide-in-from-bottom-full duration-500">
             <div className="px-8 py-6 border-b border-white/5 flex justify-between items-center">
              <h3 className="font-game font-black text-white uppercase tracking-[0.2em] text-sm">Configurações do Terminal</h3>
              <button onClick={() => { setShowSettings(false); setConfirmReset(false); }} className="p-3 bg-white/5 rounded-full text-slate-500"><X size={20} /></button>
             </div>
             <div className="p-8 md:p-12 space-y-8">
                {confirmReset ? (
                   <div className="text-center space-y-8 animate-in zoom-in-95">
                      <div className="w-20 h-20 bg-red-500/10 rounded-full flex items-center justify-center mx-auto border border-red-500/20 text-red-500"><AlertCircle size={40} /></div>
                      <div className="space-y-2">
                        <p className="font-game font-black text-white uppercase tracking-widest text-lg">Reset Total?</p>
                        <p className="text-[10px] text-slate-500 uppercase font-bold tracking-widest">Todos os dados serão apagados permanentemente.</p>
                      </div>
                      <div className="flex flex-col gap-4">
                        <button onClick={handleResetData} className="w-full py-5 bg-red-600 hover:bg-red-500 text-white rounded-2xl font-game font-black uppercase tracking-[0.3em] shadow-2xl shadow-red-900/40">Confirmar Limpeza</button>
                        <button onClick={() => setConfirmReset(false)} className="text-slate-500 uppercase text-[10px] font-black hover:text-white transition-colors">Voltar</button>
                      </div>
                   </div>
                ) : (
                  <div className="space-y-6">
                    <div className="space-y-4">
                       <label className="text-[10px] font-black text-slate-600 uppercase tracking-[0.4em] ml-1">Assinatura do Operador</label>
                       <div className="relative group">
                        <User className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-600 group-focus-within:text-emerald-400 transition-colors" size={18} />
                        <input 
                          type="text" 
                          value={userName} 
                          onChange={(e) => setUserName(e.target.value)} 
                          className="w-full bg-black/40 border border-white/10 focus:border-emerald-500/50 rounded-2xl pl-12 pr-4 py-5 text-sm font-bold text-white focus:outline-none transition-all" 
                        />
                       </div>
                    </div>

                    <div className="pt-4 space-y-3">
                      <button 
                        onClick={handleLogout}
                        className="w-full p-6 bg-slate-800/50 border border-white/5 text-white rounded-3xl flex items-center justify-between font-game font-black uppercase tracking-widest text-xs active:scale-95 transition-all hover:bg-red-500/10 hover:text-red-400 hover:border-red-500/20"
                      >
                        Encerrar Sessão (Sair) <LogOut size={20} />
                      </button>

                      <button onClick={() => setConfirmReset(true)} className="w-full p-6 bg-red-500/5 border border-red-500/10 text-red-500 rounded-3xl flex items-center justify-between font-game font-black uppercase tracking-widest text-xs active:scale-95 transition-all">
                        Resetar Banco de Dados <Trash2 size={20} />
                      </button>
                    </div>
                  </div>
                )}
             </div>
             <div className="h-safe bg-slate-900 pb-safe"></div>
          </div>
        </div>
      )}

      {/* Modal Confirmação Carteira */}
      {showWalletConfirm && (
        <div className="fixed inset-0 z-[110] flex items-center justify-center bg-black/95 backdrop-blur-xl p-6">
          <div className="bg-slate-900 border border-white/10 rounded-[3rem] w-full max-w-sm overflow-hidden animate-in zoom-in-95 duration-400">
            <div className="p-10 flex flex-col items-center text-center">
              <div className="w-20 h-20 bg-emerald-500/10 rounded-full flex items-center justify-center mb-8 border border-emerald-500/20"><Wallet className="text-emerald-400" size={36} /></div>
              <h3 className="text-3xl font-game font-black text-white uppercase tracking-tighter mb-3 leading-none">Confirmar Recebimento?</h3>
              <p className="text-[10px] text-slate-500 font-bold uppercase tracking-widest leading-relaxed mb-10">
                Você receberá o saldo de <span className="text-emerald-400 font-black">{formatBRL(counts.wallet.pending)}</span>.
              </p>
              <div className="w-full space-y-4">
                <button onClick={handleSettleWallet} className="w-full py-5 bg-emerald-600 hover:bg-emerald-500 text-white rounded-2xl font-game font-black text-sm uppercase tracking-[0.3em] active:scale-95 transition-all shadow-2xl shadow-emerald-900/40">Receber e Sincronizar</button>
                <button onClick={() => setShowWalletConfirm(false)} className="text-slate-500 font-bold uppercase text-[10px] tracking-widest hover:text-white transition-colors">Cancelar</button>
              </div>
            </div>
          </div>
        </div>
      )}

      <BulkActionModal isOpen={bulkModal.isOpen} type={bulkModal.type} title={bulkModal.type === 'SAIDA' ? 'Saída Lote' : 'Entrada Lote'} onClose={() => setBulkModal({ ...bulkModal, isOpen: false })} onConfirm={handleBulkAction} />
    </div>
  );
};

export default App;

import React, { useState, useEffect, useMemo } from 'react';
import { Truck, Zap, FileText, Download, LayoutDashboard, Send, Table as TableIcon, ListPlus, LogOut, Layers, Settings, Trash2, AlertCircle, User, Sliders, ChevronRight, X, CheckCircle2, Check, Wallet, AlertTriangle, ArrowDownLeft, ArrowUpRight, RotateCcw, Sparkles } from 'lucide-react';
import DashboardCards from './components/DashboardCards';
import ActionButtons from './components/ActionButtons';
import DailyStatsTable from './components/DailyStatsTable';
import BulkActionModal from './components/BulkActionModal';
import WalletCard from './components/WalletCard';
import Login from './components/Login';
import { LogCashLogo } from './components/Logo';
import { LogEntry, LogActionType } from './types';
import { supabaseService } from './services/supabaseService';
import { generatePDF } from './services/pdfService';
import { SUPABASE_CACHE_KEY, VALOR_POR_PACOTE } from './constants';

const App: React.FC = () => {
  const [session, setSession] = useState<any>(null);
  const [logs, setLogs] = useState<LogEntry[]>(() => {
    const cached = localStorage.getItem(SUPABASE_CACHE_KEY);
    return cached ? JSON.parse(cached) : [];
  });
  const [loading, setLoading] = useState(true);
  const [isSyncing, setIsSyncing] = useState(false);
  const [showToast, setShowToast] = useState(false);
  const [toastMsg, setToastMsg] = useState('');

  // Estado para o Pop-up de Sucesso Hyper-Interativo
  const [showSuccessPopup, setShowSuccessPopup] = useState(false);
  const [bulkCount, setBulkCount] = useState(0);
  const [lastSettleValue, setLastSettleValue] = useState(0);
  const [bulkActionType, setBulkActionType] = useState<'ENTRADA' | 'SAIDA' | 'DEVOLUCAO' | 'SETTLE'>('ENTRADA');

  // Estado para Confirmação de Carteira
  const [showWalletConfirm, setShowWalletConfirm] = useState(false);

  const [userName, setUserName] = useState(() => localStorage.getItem('logcash_user_name') || 'Operador Logístico');
  const [activeTab, setActiveTab] = useState<'dash' | 'stats'>('dash');
  const [showSettings, setShowSettings] = useState(false);
  const [confirmReset, setConfirmReset] = useState(false);
  const [settingsView, setSettingsView] = useState<'menu' | 'profile' | 'danger'>('menu');

  const [bulkModal, setBulkModal] = useState<{ isOpen: boolean; type: 'ENTRADA' | 'SAIDA' }>({
    isOpen: false,
    type: 'ENTRADA'
  });

  useEffect(() => {
    supabaseService.getSession().then(session => {
      setSession(session);
      if (!session) setLoading(false);
    });
  }, []);

  useEffect(() => {
    if (!session) return;
    setIsSyncing(true);
    const unsubscribe = supabaseService.subscribeToLogs((updatedLogs, supabaseError) => {
      if (!supabaseError) {
        setLogs(updatedLogs);
        localStorage.setItem(SUPABASE_CACHE_KEY, JSON.stringify(updatedLogs));
      }
      setLoading(false);
      setIsSyncing(false);
    });
    return () => unsubscribe();
  }, [session]);

  useEffect(() => {
    localStorage.setItem('logcash_user_name', userName);
  }, [userName]);

  const handleLogout = async () => {
    await supabaseService.signOut();
    localStorage.removeItem(SUPABASE_CACHE_KEY);
    setSession(null);
    setLogs([]);
    setShowSettings(false);
  };

  const handleAction = async (type: LogActionType) => {
    const newEntry: Omit<LogEntry, 'id'> = {
      type,
      timestamp: new Date().toISOString(),
      value: type === 'SAIDA' ? VALOR_POR_PACOTE : 0
    };
    try {
      await supabaseService.saveLog(newEntry);

      setBulkActionType(type as any);
      setBulkCount(1);
      setShowSuccessPopup(true);
      setTimeout(() => setShowSuccessPopup(false), 2200);

    } catch (err) {
      setToastMsg('Erro na sincronização.');
      setShowToast(true);
      setTimeout(() => setShowToast(false), 2000);
    }
  };

  const handleBulkAction = async (quantity: number) => {
    const type = bulkModal.type;
    const newEntries = Array.from({ length: quantity }).map(() => ({
      type: type as LogActionType,
      timestamp: new Date().toISOString(),
      value: type === 'SAIDA' ? VALOR_POR_PACOTE : 0
    }));
    try {
      await supabaseService.saveBulkLogs(newEntries);
      setBulkCount(quantity);
      setBulkActionType(type as any);
      setShowSuccessPopup(true);
      setTimeout(() => { setShowSuccessPopup(false); }, 2200);
    } catch (err) {
      setToastMsg('Falha no envio em lote.');
      setShowToast(true);
      setTimeout(() => setShowToast(false), 2000);
    }
  };

  const handleSettleWallet = async () => {
    try {
      setIsSyncing(true);

      // Capturamos o valor ANTES da liquidação no banco
      const currentPending = counts.wallet.pending;
      setLastSettleValue(currentPending);

      setShowWalletConfirm(false);
      await supabaseService.markAllAsPaid();

      // Feedback Visual
      setBulkActionType('SETTLE');
      setShowSuccessPopup(true);
      setTimeout(() => { setShowSuccessPopup(false); }, 2200);

    } catch (err) {
      setToastMsg('Erro ao liquidar pagamentos.');
      setShowToast(true);
      setTimeout(() => setShowToast(false), 2000);
    } finally {
      setIsSyncing(false);
    }
  };

  const handleResetData = async () => {
    try {
      setIsSyncing(true);
      await supabaseService.deleteAllLogs();
      setLogs([]);
      localStorage.removeItem(SUPABASE_CACHE_KEY);
      setUserName('Operador Logístico');
      localStorage.removeItem('logcash_user_name');
      setToastMsg('Sistema reiniciado.');
      setShowToast(true);
      setConfirmReset(false);
      setShowSettings(false);
      setTimeout(() => setShowToast(false), 2000);
    } catch (err) {
      setToastMsg('Erro ao apagar dados.');
      setShowToast(true);
    } finally {
      setIsSyncing(false);
    }
  };

  const counts = useMemo(() => {
    const todayStr = new Date().toDateString();
    const now = new Date();
    const startOfWeek = new Date(now);
    startOfWeek.setDate(now.getDate() - now.getDay());
    startOfWeek.setHours(0, 0, 0, 0);
    const startOfYear = new Date(now.getFullYear(), 0, 1);

    const deliveredLogs = logs.filter(l => l.type === 'SAIDA');
    const pending = deliveredLogs.filter(l => !l.isPaid).length * VALOR_POR_PACOTE;
    const paidCurrentCycle = deliveredLogs.filter(l => l.isPaid && new Date(l.timestamp) >= startOfWeek).length * VALOR_POR_PACOTE;
    const totalCumulativePaid = deliveredLogs.filter(l => l.isPaid).length * VALOR_POR_PACOTE;

    return {
      today: logs.filter(l => l.type === 'SAIDA' && new Date(l.timestamp).toDateString() === todayStr).length,
      week: logs.filter(l => l.type === 'SAIDA' && new Date(l.timestamp) >= startOfWeek).length,
      year: logs.filter(l => l.type === 'SAIDA' && new Date(l.timestamp) >= startOfYear).length,
      wallet: {
        pending,
        paid: paidCurrentCycle,
        cumulative: totalCumulativePaid
      }
    };
  }, [logs]);

  if (!session && !loading) return <Login onLoginSuccess={() => supabaseService.getSession().then(setSession)} />;

  if (loading && logs.length === 0) {
    return (
      <div className="min-h-screen bg-[#020617] flex flex-col items-center justify-center p-6 text-center">
        <LogCashLogo size={60} />
        <p className="text-slate-500 font-game font-bold uppercase tracking-[0.3em] text-[10px] animate-pulse mt-4">Sincronizando Terminal...</p>
      </div>
    );
  }

  const formatBRL = (val: number) => new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(val);

  const popupTheme = {
    ENTRADA: { bg: 'from-emerald-600 to-emerald-900', border: 'border-emerald-400/40', text: 'text-emerald-400', pulse: 'border-emerald-500/50' },
    SAIDA: { bg: 'from-blue-600 to-blue-900', border: 'border-blue-400/40', text: 'text-blue-400', pulse: 'border-blue-500/50' },
    DEVOLUCAO: { bg: 'from-orange-600 to-orange-900', border: 'border-orange-400/40', text: 'text-orange-400', pulse: 'border-orange-500/50' },
    SETTLE: { bg: 'from-emerald-500 to-emerald-800', border: 'border-emerald-300/40', text: 'text-emerald-300', pulse: 'border-emerald-400/50' }
  }[bulkActionType];

  return (
    <div className="min-h-screen bg-[#020617] text-slate-200 selection:bg-emerald-500/30 flex flex-col overflow-x-hidden relative">
      <header className="bg-slate-900/80 backdrop-blur-xl border-b border-white/5 px-4 md:px-8 sticky top-0 z-40 pt-safe transition-all h-20">
        <div className="max-w-5xl mx-auto flex justify-between items-center h-full">
          <div className="flex items-center gap-3">
            <LogCashLogo size={36} />
            <div>
              <h1 className="text-xl font-game font-black tracking-[0.1em] text-white leading-none">LOG<span className="text-emerald-400">CASH</span></h1>
              <p className="text-[8px] text-slate-500 font-bold uppercase tracking-widest mt-1">{isSyncing ? 'Atualizando...' : 'Online'}</p>
            </div>
          </div>

          <div className="flex items-center gap-2">
            <button 
              onClick={() => { setShowSettings(true); setSettingsView('menu'); }} 
              className="p-3 bg-white/5 rounded-2xl border border-white/10 active:scale-95 transition-all hover:bg-white/10 flex items-center gap-2"
            >
              <Settings size={20} className="text-slate-400" />
              <span className="hidden sm:block text-[10px] font-black text-slate-400 uppercase tracking-widest">Painel</span>
            </button>
            <button 
              onClick={handleLogout}
              className="p-3 bg-red-500/10 rounded-2xl border border-red-500/20 active:scale-95 transition-all hover:bg-red-500/20 text-red-500"
            >
              <LogOut size={20} />
            </button>
          </div>
        </div>
      </header>

      <main className="flex-1 max-w-5xl mx-auto w-full p-4 md:p-8 space-y-8 pb-28 md:pb-12 transition-all">
        {activeTab === 'dash' ? (
          <div className="animate-in fade-in duration-500">
            <div className="mb-8">
              <h2 className="text-3xl md:text-5xl font-game font-black text-white uppercase tracking-tight leading-tight">Olá, {userName.split(' ')[0]}</h2>
              <p className="text-[10px] md:text-xs text-slate-500 font-bold uppercase tracking-[0.4em] mt-2">Gestão Logística Inteligente</p>
            </div>

            <div className="grid grid-cols-1 lg:grid-cols-5 gap-6 mb-10">
              <div className="lg:col-span-3">
                <DashboardCards today={counts.today} week={counts.week} year={counts.year} />
              </div>
              <div className="lg:col-span-2">
                <WalletCard 
                  pendingAmount={counts.wallet.pending} 
                  paidAmount={counts.wallet.paid} 
                  totalCumulativePaid={counts.wallet.cumulative} 
                  onSettle={() => setShowWalletConfirm(true)}
                />
              </div>
            </div>

            <section className="space-y-4 mb-10">
              <div className="flex items-center justify-between px-1">
                <h2 className="text-slate-500 font-game font-bold text-[10px] uppercase tracking-[0.5em]">Ações Rápidas</h2>
                <div className="h-px flex-1 bg-white/5 mx-4 hidden sm:block"></div>
              </div>
              <ActionButtons onAction={handleAction} />
            </section>

            <section className="grid grid-cols-2 gap-4 mb-10">
              <button onClick={() => setBulkModal({ isOpen: true, type: 'ENTRADA' })} className="bg-slate-900/40 border border-white/5 p-6 rounded-3xl flex flex-col items-start gap-4 active:scale-95 hover:bg-white/[0.03] transition-all">
                <div className="p-3 bg-emerald-600/10 text-emerald-400 rounded-2xl border border-emerald-500/20"><ListPlus size={24} /></div>
                <div className="text-left"><p className="font-game font-black text-white text-sm uppercase tracking-widest">Lote Entrada</p><p className="text-[8px] text-slate-500 uppercase font-bold mt-1">Check-in</p></div>
              </button>
              <button onClick={() => setBulkModal({ isOpen: true, type: 'SAIDA' })} className="bg-slate-900/40 border border-white/5 p-6 rounded-3xl flex flex-col items-start gap-4 active:scale-95 hover:bg-white/[0.03] transition-all">
                <div className="p-3 bg-blue-600/10 text-blue-400 rounded-2xl border border-blue-500/20"><Send size={24} /></div>
                <div className="text-left"><p className="font-game font-black text-white text-sm uppercase tracking-widest">Lote Saída</p><p className="text-[8px] text-slate-500 uppercase font-bold mt-1">Entrega</p></div>
              </button>
            </section>

            <section className="bg-slate-900/50 p-6 md:p-10 rounded-[3rem] border border-white/5 relative overflow-hidden group">
              <div className="flex items-center gap-4 mb-6">
                <div className="p-3 bg-emerald-500/10 rounded-2xl"><FileText size={24} className="text-emerald-400" /></div>
                <h3 className="font-game font-black text-white uppercase tracking-[0.2em] text-base">Exportar Extrato</h3>
              </div>
              <button 
                onClick={() => generatePDF(logs, userName)}
                className="w-full bg-emerald-600 hover:bg-emerald-500 py-5 rounded-[1.5rem] flex items-center justify-center gap-3 font-game font-black text-white active:scale-95 text-xs uppercase tracking-[0.4em] transition-all shadow-2xl shadow-emerald-900/30"
              >
                <Download size={22} /> Gerar PDF Detalhado
              </button>
            </section>
          </div>
        ) : (
          <div className="animate-in fade-in duration-500">
            <DailyStatsTable logs={logs} />
          </div>
        )}
      </main>

      <nav className="fixed bottom-0 left-0 right-0 glass-card border-t border-white/10 md:hidden z-50">
        <div className="flex justify-around items-center h-20 max-w-lg mx-auto">
          <button onClick={() => setActiveTab('dash')} className={`flex flex-col items-center justify-center w-full h-full gap-1 transition-all ${activeTab === 'dash' ? 'text-emerald-400 scale-110' : 'text-slate-600'}`}>
            <LayoutDashboard size={24} strokeWidth={activeTab === 'dash' ? 2.5 : 2} /><span className="text-[9px] font-black uppercase tracking-[0.2em]">Home</span>
          </button>
          <button onClick={() => setActiveTab('stats')} className={`flex flex-col items-center justify-center w-full h-full gap-1 transition-all ${activeTab === 'stats' ? 'text-emerald-400 scale-110' : 'text-slate-600'}`}>
            <TableIcon size={24} strokeWidth={activeTab === 'stats' ? 2.5 : 2} /><span className="text-[9px] font-black uppercase tracking-[0.2em]">Fluxo</span>
          </button>
        </div>
        <div className="h-safe bg-slate-950"></div>
      </nav>

      {/* POPUP SUCESSO HYPER-INTERATIVO (Impacto e Brilho) */}
      {showSuccessPopup && (
        <div className="fixed inset-0 z-[500] flex items-center justify-center p-6 pointer-events-none overflow-hidden bg-black/40 backdrop-blur-sm">
          <div className={`w-full max-w-sm glass-deep bg-gradient-to-b ${popupTheme.bg} ${popupTheme.border} border-2 rounded-[3.5rem] p-12 flex flex-col items-center text-center shadow-[0_0_120px_rgba(0,0,0,0.8)] animate-pop-burst relative`}>

            {/* Elementos de Brilho Orbitais */}
            <div className="absolute inset-0 flex items-center justify-center pointer-events-none overflow-hidden rounded-[3.5rem]">
               <Sparkles size={160} className={`${popupTheme.text} opacity-20`} strokeWidth={0.5} />
            </div>

            {/* Ícone Principal com Anel de Pulsação */}
            <div className="relative mb-10">
              <div className={`absolute -inset-4 border-2 ${popupTheme.pulse} rounded-full animate-ring-pulse`}></div>
              <div className={`w-28 h-28 bg-white/10 backdrop-blur-xl border border-white/20 rounded-full flex items-center justify-center shadow-[0_0_40px_rgba(255,255,255,0.1)] animate-float-bounce`}>
                {bulkActionType === 'ENTRADA' && <ArrowDownLeft size={50} className="text-white" strokeWidth={3} />}
                {bulkActionType === 'SAIDA' && <ArrowUpRight size={50} className="text-white" strokeWidth={3} />}
                {bulkActionType === 'DEVOLUCAO' && <RotateCcw size={50} className="text-white" strokeWidth={3} />}
                {bulkActionType === 'SETTLE' && <Check size={60} className="text-white" strokeWidth={4} />}
              </div>
            </div>

            <h4 className="text-3xl md:text-4xl font-game font-black text-white uppercase tracking-tighter leading-none mb-3 drop-shadow-2xl">
              {bulkActionType === 'SETTLE' ? 'RECEBIDO!' : 'CONFIRMADO!'}
            </h4>

            <div className="w-full h-px bg-white/20 my-6"></div>

            <div className="space-y-3">
              {bulkActionType === 'SETTLE' ? (
                <div className="px-8 py-3 bg-white/10 rounded-3xl border border-white/20 shadow-inner shine-container">
                  <div className="shine-overlay"></div>
                  <span className="text-4xl md:text-5xl font-game font-black text-white tracking-tighter block drop-shadow-lg">
                    {formatBRL(lastSettleValue)}
                  </span>
                </div>
              ) : (
                <div className="flex flex-col items-center">
                   <div className="px-6 py-2 bg-white/10 rounded-2xl border border-white/20 mb-4 shine-container">
                      <div className="shine-overlay"></div>
                      <span className="text-3xl font-game font-black text-white tracking-widest uppercase">
                        {bulkCount} {bulkCount === 1 ? 'Item' : 'Itens'}
                      </span>
                   </div>
                   {bulkActionType === 'SAIDA' && (
                     <div className="flex items-center gap-2 text-emerald-300 font-game font-black text-3xl tracking-widest drop-shadow-[0_0_10px_rgba(16,185,129,0.5)]">
                        <Check size={26} strokeWidth={4} />
                        +{formatBRL(bulkCount * VALOR_POR_PACOTE)}
                     </div>
                   )}
                </div>
              )}

              <p className="text-[10px] text-white/50 font-game font-bold uppercase tracking-[0.5em] pt-6 opacity-70">
                Sincronização Cloud Terminal Ok
              </p>
            </div>

            {/* Barra de Timer Rodapé */}
            <div className="absolute bottom-6 left-12 right-12 h-1 bg-white/10 rounded-full overflow-hidden">
               <div className="h-full bg-white/60 animate-timer"></div>
            </div>
          </div>
        </div>
      )}

      {/* Modal Ajustes */}
      {showSettings && (
        <div className="fixed inset-0 z-[100] flex items-end md:items-center justify-center bg-black/90 backdrop-blur-md p-0 md:p-4">
          <div className="bg-slate-900 w-full max-w-lg rounded-t-[3rem] md:rounded-[3rem] border-t md:border border-white/10 overflow-hidden animate-in slide-in-from-bottom-full duration-500">
             <div className="px-8 py-6 border-b border-white/5 flex justify-between items-center">
              <h3 className="font-game font-black text-white uppercase tracking-[0.2em] text-sm">Painel do Operador</h3>
              <button onClick={() => { setShowSettings(false); setConfirmReset(false); }} className="p-3 bg-white/5 rounded-full text-slate-500"><X size={20} /></button>
             </div>
             <div className="p-8 md:p-12 space-y-8">
                {confirmReset ? (
                   <div className="text-center space-y-8 animate-in zoom-in-95">
                      <div className="w-20 h-20 bg-red-500/10 rounded-full flex items-center justify-center mx-auto border border-red-500/20 text-red-500"><AlertCircle size={40} /></div>
                      <p className="font-game font-black text-white uppercase tracking-widest text-lg">Reset Total do Banco?</p>
                      <div className="flex flex-col gap-4">
                        <button onClick={handleResetData} className="w-full py-5 bg-red-600 hover:bg-red-500 text-white rounded-2xl font-game font-black uppercase tracking-[0.3em] shadow-2xl shadow-red-900/40">Limpar Registros</button>
                        <button onClick={() => setConfirmReset(false)} className="text-slate-500 uppercase text-[10px] font-black hover:text-white transition-colors">Cancelar</button>
                      </div>
                   </div>
                ) : (
                  <div className="space-y-6">
                    <div className="space-y-4">
                       <label className="text-[10px] font-black text-slate-600 uppercase tracking-[0.4em] ml-1">Assinatura no PDF</label>
                       <div className="relative group">
                        <User className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-600 group-focus-within:text-emerald-400 transition-colors" size={18} />
                        <input 
                          type="text" 
                          value={userName} 
                          onChange={(e) => setUserName(e.target.value)} 
                          className="w-full bg-black/40 border border-white/10 focus:border-emerald-500/50 rounded-2xl pl-12 pr-4 py-5 text-sm font-bold text-white focus:outline-none transition-all" 
                        />
                       </div>
                    </div>
                    <button onClick={() => setConfirmReset(true)} className="w-full p-6 bg-red-500/5 border border-red-500/10 text-red-500 rounded-3xl flex items-center justify-between font-game font-black uppercase tracking-widest text-xs active:scale-95 transition-all">
                      Zona de Perigo <Trash2 size={20} />
                    </button>
                  </div>
                )}
             </div>
             <div className="h-safe bg-slate-900 pb-safe"></div>
          </div>
        </div>
      )}

      {/* Modal Confirmação Carteira */}
      {showWalletConfirm && (
        <div className="fixed inset-0 z-[110] flex items-center justify-center bg-black/95 backdrop-blur-xl p-6">
          <div className="bg-slate-900 border border-white/10 rounded-[3rem] w-full max-w-sm overflow-hidden animate-in zoom-in-95 duration-400">
            <div className="p-10 flex flex-col items-center text-center">
              <div className="w-20 h-20 bg-emerald-500/10 rounded-full flex items-center justify-center mb-8 border border-emerald-500/20"><Wallet className="text-emerald-400" size={36} /></div>
              <h3 className="text-3xl font-game font-black text-white uppercase tracking-tighter mb-3 leading-none">Confirmar Pagamento?</h3>
              <p className="text-[10px] text-slate-500 font-bold uppercase tracking-widest leading-relaxed mb-10">
                Você liquidará <span className="text-emerald-400 font-black">{formatBRL(counts.wallet.pending)}</span> do saldo pendente.
              </p>
              <div className="w-full space-y-4">
                <button onClick={handleSettleWallet} className="w-full py-5 bg-emerald-600 hover:bg-emerald-500 text-white rounded-2xl font-game font-black text-sm uppercase tracking-[0.3em] active:scale-95 transition-all shadow-2xl shadow-emerald-900/40">Confirmar Recebimento</button>
                <button onClick={() => setShowWalletConfirm(false)} className="text-slate-500 font-bold uppercase text-[10px] tracking-widest hover:text-white transition-colors">Voltar</button>
              </div>
            </div>
          </div>
        </div>
      )}

      <BulkActionModal isOpen={bulkModal.isOpen} type={bulkModal.type} title={bulkModal.type === 'SAIDA' ? 'Saída Lote' : 'Entrada Lote'} onClose={() => setBulkModal({ ...bulkModal, isOpen: false })} onConfirm={handleBulkAction} />
    </div>
  );
};

export default App;

import React, { useState, useEffect, useMemo } from 'react';
import { Truck, Zap, FileText, Download, LayoutDashboard, Send, Table as TableIcon, ListPlus, LogOut, Layers, Settings, Trash2, AlertCircle, User, Sliders, ChevronRight, X, CheckCircle2, Check, Wallet, AlertTriangle, ArrowDownLeft, ArrowUpRight, RotateCcw, Sparkles } from 'lucide-react';
import DashboardCards from './components/DashboardCards';
import ActionButtons from './components/ActionButtons';
import DailyStatsTable from './components/DailyStatsTable';
import BulkActionModal from './components/BulkActionModal';
import WalletCard from './components/WalletCard';
import Login from './components/Login';
import { LogCashLogo } from './components/Logo';
import { LogEntry, LogActionType } from './types';
import { supabaseService } from './services/supabaseService';
import { generatePDF } from './services/pdfService';
import { SUPABASE_CACHE_KEY, VALOR_POR_PACOTE } from './constants';

const App: React.FC = () => {
  const [session, setSession] = useState<any>(null);
  const [logs, setLogs] = useState<LogEntry[]>(() => {
    const cached = localStorage.getItem(SUPABASE_CACHE_KEY);
    return cached ? JSON.parse(cached) : [];
  });
  const [loading, setLoading] = useState(true);
  const [isSyncing, setIsSyncing] = useState(false);
  const [showToast, setShowToast] = useState(false);
  const [toastMsg, setToastMsg] = useState('');

  // Estado para o Pop-up de Sucesso Gamificado
  const [showSuccessPopup, setShowSuccessPopup] = useState(false);
  const [bulkCount, setBulkCount] = useState(0);
  const [lastSettleValue, setLastSettleValue] = useState(0);
  const [bulkActionType, setBulkActionType] = useState<'ENTRADA' | 'SAIDA' | 'DEVOLUCAO' | 'SETTLE'>('ENTRADA');

  // Estado para Confirmação de Carteira
  const [showWalletConfirm, setShowWalletConfirm] = useState(false);

  const [userName, setUserName] = useState(() => localStorage.getItem('logcash_user_name') || 'Operador Logístico');
  const [activeTab, setActiveTab] = useState<'dash' | 'stats'>('dash');
  const [showSettings, setShowSettings] = useState(false);
  const [confirmReset, setConfirmReset] = useState(false);
  const [settingsView, setSettingsView] = useState<'menu' | 'profile' | 'danger'>('menu');

  const [bulkModal, setBulkModal] = useState<{ isOpen: boolean; type: 'ENTRADA' | 'SAIDA' }>({
    isOpen: false,
    type: 'ENTRADA'
  });

  useEffect(() => {
    supabaseService.getSession().then(session => {
      setSession(session);
      if (!session) setLoading(false);
    });
  }, []);

  useEffect(() => {
    if (!session) return;
    setIsSyncing(true);
    const unsubscribe = supabaseService.subscribeToLogs((updatedLogs, supabaseError) => {
      if (!supabaseError) {
        setLogs(updatedLogs);
        localStorage.setItem(SUPABASE_CACHE_KEY, JSON.stringify(updatedLogs));
      }
      setLoading(false);
      setIsSyncing(false);
    });
    return () => unsubscribe();
  }, [session]);

  useEffect(() => {
    localStorage.setItem('logcash_user_name', userName);
  }, [userName]);

  const handleLogout = async () => {
    await supabaseService.signOut();
    localStorage.removeItem(SUPABASE_CACHE_KEY);
    setSession(null);
    setLogs([]);
    setShowSettings(false);
  };

  const handleAction = async (type: LogActionType) => {
    const newEntry: Omit<LogEntry, 'id'> = {
      type,
      timestamp: new Date().toISOString(),
      value: type === 'SAIDA' ? VALOR_POR_PACOTE : 0
    };
    try {
      await supabaseService.saveLog(newEntry);

      setBulkActionType(type as any);
      setBulkCount(1);
      setShowSuccessPopup(true);
      setTimeout(() => setShowSuccessPopup(false), 2400);

    } catch (err) {
      setToastMsg('Erro na sincronização.');
      setShowToast(true);
      setTimeout(() => setShowToast(false), 2000);
    }
  };

  const handleBulkAction = async (quantity: number) => {
    const type = bulkModal.type;
    const newEntries = Array.from({ length: quantity }).map(() => ({
      type: type as LogActionType,
      timestamp: new Date().toISOString(),
      value: type === 'SAIDA' ? VALOR_POR_PACOTE : 0
    }));
    try {
      await supabaseService.saveBulkLogs(newEntries);
      setBulkCount(quantity);
      setBulkActionType(type as any);
      setShowSuccessPopup(true);
      setTimeout(() => { setShowSuccessPopup(false); }, 2400);
    } catch (err) {
      setToastMsg('Falha no envio em lote.');
      setShowToast(true);
      setTimeout(() => setShowToast(false), 2000);
    }
  };

  const handleSettleWallet = async () => {
    // FIX: Captura o valor ANTES da mutação para garantir exibição correta no popup
    const currentPending = counts.wallet.pending;
    setLastSettleValue(currentPending);

    try {
      setIsSyncing(true);
      setShowWalletConfirm(false);
      await supabaseService.markAllAsPaid();

      // Feedback Visual Impactante
      setBulkActionType('SETTLE');
      setShowSuccessPopup(true);
      setTimeout(() => { setShowSuccessPopup(false); }, 2800);

    } catch (err) {
      setToastMsg('Erro ao liquidar pagamentos.');
      setShowToast(true);
      setTimeout(() => setShowToast(false), 2000);
    } finally {
      setIsSyncing(false);
    }
  };

  const handleResetData = async () => {
    try {
      setIsSyncing(true);
      await supabaseService.deleteAllLogs();
      setLogs([]);
      localStorage.removeItem(SUPABASE_CACHE_KEY);
      setUserName('Operador Logístico');
      localStorage.removeItem('logcash_user_name');
      setToastMsg('Sistema reiniciado.');
      setShowToast(true);
      setConfirmReset(false);
      setShowSettings(false);
      setTimeout(() => setShowToast(false), 2000);
    } catch (err) {
      setToastMsg('Erro ao apagar dados.');
      setShowToast(true);
    } finally {
      setIsSyncing(false);
    }
  };

  const counts = useMemo(() => {
    const todayStr = new Date().toDateString();
    const now = new Date();
    const startOfWeek = new Date(now);
    startOfWeek.setDate(now.getDate() - now.getDay());
    startOfWeek.setHours(0, 0, 0, 0);
    const startOfYear = new Date(now.getFullYear(), 0, 1);

    const deliveredLogs = logs.filter(l => l.type === 'SAIDA');
    const pending = deliveredLogs.filter(l => !l.isPaid).length * VALOR_POR_PACOTE;
    const paidCurrentCycle = deliveredLogs.filter(l => l.isPaid && new Date(l.timestamp) >= startOfWeek).length * VALOR_POR_PACOTE;
    const totalCumulativePaid = deliveredLogs.filter(l => l.isPaid).length * VALOR_POR_PACOTE;

    return {
      today: logs.filter(l => l.type === 'SAIDA' && new Date(l.timestamp).toDateString() === todayStr).length,
      week: logs.filter(l => l.type === 'SAIDA' && new Date(l.timestamp) >= startOfWeek).length,
      year: logs.filter(l => l.type === 'SAIDA' && new Date(l.timestamp) >= startOfYear).length,
      wallet: {
        pending,
        paid: paidCurrentCycle,
        cumulative: totalCumulativePaid
      }
    };
  }, [logs]);

  if (!session && !loading) return <Login onLoginSuccess={() => supabaseService.getSession().then(setSession)} />;

  if (loading && logs.length === 0) {
    return (
      <div className="min-h-screen bg-[#020617] flex flex-col items-center justify-center p-6 text-center">
        <LogCashLogo size={60} />
        <p className="text-slate-500 font-game font-bold uppercase tracking-[0.3em] text-[10px] animate-pulse mt-4">Sincronizando Sistema...</p>
      </div>
    );
  }

  const formatBRL = (val: number) => new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(val);

  // Mapeamento de Cores e Temas do Popup
  const popupTheme = {
    ENTRADA: { bg: 'from-emerald-600 to-emerald-950', border: 'border-emerald-400/40', text: 'text-emerald-400', ring: 'border-emerald-500' },
    SAIDA: { bg: 'from-blue-600 to-blue-950', border: 'border-blue-400/40', text: 'text-blue-400', ring: 'border-blue-500' },
    DEVOLUCAO: { bg: 'from-orange-600 to-orange-950', border: 'border-orange-400/40', text: 'text-orange-400', ring: 'border-orange-500' },
    SETTLE: { bg: 'from-indigo-600 to-indigo-950', border: 'border-indigo-400/40', text: 'text-indigo-400', ring: 'border-emerald-400' }
  }[bulkActionType];

  return (
    <div className="min-h-screen bg-[#020617] text-slate-200 selection:bg-emerald-500/30 flex flex-col overflow-x-hidden relative">
      <header className="bg-slate-900/80 backdrop-blur-xl border-b border-white/5 px-4 md:px-8 sticky top-0 z-40 pt-safe transition-all h-20">
        <div className="max-w-5xl mx-auto flex justify-between items-center h-full">
          <div className="flex items-center gap-3">
            <LogCashLogo size={36} />
            <div>
              <h1 className="text-xl font-game font-black tracking-[0.1em] text-white leading-none">LOG<span className="text-emerald-400">CASH</span></h1>
              <p className="text-[8px] text-slate-500 font-bold uppercase tracking-widest mt-1">{isSyncing ? 'Sincronizando...' : 'Conectado'}</p>
            </div>
          </div>

          <div className="flex items-center gap-2">
            <button 
              onClick={() => { setShowSettings(true); setSettingsView('menu'); }} 
              className="p-3 bg-white/5 rounded-2xl border border-white/10 active:scale-95 transition-all hover:bg-white/10 flex items-center gap-2"
            >
              <Settings size={20} className="text-slate-400" />
              <span className="hidden sm:block text-[10px] font-black text-slate-400 uppercase tracking-widest">Ajustes</span>
            </button>
          </div>
        </div>
      </header>

      <main className="flex-1 max-w-5xl mx-auto w-full p-4 md:p-8 space-y-8 pb-28 md:pb-12 transition-all">
        {activeTab === 'dash' ? (
          <div className="animate-in fade-in duration-500">
            <div className="mb-8">
              <h2 className="text-3xl md:text-5xl font-game font-black text-white uppercase tracking-tight leading-tight">Olá, {userName.split(' ')[0]}</h2>
              <p className="text-[10px] md:text-xs text-slate-500 font-bold uppercase tracking-[0.4em] mt-2">Visão Geral da Operação</p>
            </div>

            <div className="grid grid-cols-1 lg:grid-cols-5 gap-6 mb-10">
              <div className="lg:col-span-3">
                <DashboardCards today={counts.today} week={counts.week} year={counts.year} />
              </div>
              <div className="lg:col-span-2">
                <WalletCard 
                  pendingAmount={counts.wallet.pending} 
                  paidAmount={counts.wallet.paid} 
                  totalCumulativePaid={counts.wallet.cumulative} 
                  onSettle={() => setShowWalletConfirm(true)}
                />
              </div>
            </div>

            <section className="space-y-4 mb-10">
              <ActionButtons onAction={handleAction} />
            </section>

            <section className="grid grid-cols-2 gap-4 mb-10">
              <button onClick={() => setBulkModal({ isOpen: true, type: 'ENTRADA' })} className="bg-slate-900/40 border border-white/5 p-6 rounded-3xl flex flex-col items-start gap-4 active:scale-95 hover:bg-white/[0.03] transition-all">
                <div className="p-3 bg-emerald-600/10 text-emerald-400 rounded-2xl border border-emerald-500/20"><ListPlus size={24} /></div>
                <div className="text-left"><p className="font-game font-black text-white text-sm uppercase tracking-widest">Lote Entrada</p><p className="text-[8px] text-slate-500 uppercase font-bold mt-1">Check-in Base</p></div>
              </button>
              <button onClick={() => setBulkModal({ isOpen: true, type: 'SAIDA' })} className="bg-slate-900/40 border border-white/5 p-6 rounded-3xl flex flex-col items-start gap-4 active:scale-95 hover:bg-white/[0.03] transition-all">
                <div className="p-3 bg-blue-600/10 text-blue-400 rounded-2xl border border-blue-500/20"><Send size={24} /></div>
                <div className="text-left"><p className="font-game font-black text-white text-sm uppercase tracking-widest">Lote Saída</p><p className="text-[8px] text-slate-500 uppercase font-bold mt-1">Entrega Final</p></div>
              </button>
            </section>

            <section className="bg-slate-900/50 p-6 md:p-10 rounded-[3rem] border border-white/5 relative overflow-hidden group">
              <div className="flex items-center gap-4 mb-6">
                <div className="p-3 bg-emerald-500/10 rounded-2xl"><FileText size={24} className="text-emerald-400" /></div>
                <h3 className="font-game font-black text-white uppercase tracking-[0.2em] text-base">Relatório de Rendimentos</h3>
              </div>
              <button 
                onClick={() => generatePDF(logs, userName)}
                className="w-full bg-emerald-600 hover:bg-emerald-500 py-5 rounded-[1.5rem] flex items-center justify-center gap-3 font-game font-black text-white active:scale-95 text-xs uppercase tracking-[0.4em] transition-all shadow-2xl shadow-emerald-900/30"
              >
                <Download size={22} /> Exportar PDF Completo
              </button>
            </section>
          </div>
        ) : (
          <div className="animate-in fade-in duration-500">
            <DailyStatsTable logs={logs} />
          </div>
        )}
      </main>

      <nav className="fixed bottom-0 left-0 right-0 glass-card border-t border-white/10 md:hidden z-50">
        <div className="flex justify-around items-center h-20 max-w-lg mx-auto">
          <button onClick={() => setActiveTab('dash')} className={`flex flex-col items-center justify-center w-full h-full gap-1 transition-all ${activeTab === 'dash' ? 'text-emerald-400 scale-110' : 'text-slate-600'}`}>
            <LayoutDashboard size={24} strokeWidth={activeTab === 'dash' ? 2.5 : 2} /><span className="text-[9px] font-black uppercase tracking-[0.2em]">Dash</span>
          </button>
          <button onClick={() => setActiveTab('stats')} className={`flex flex-col items-center justify-center w-full h-full gap-1 transition-all ${activeTab === 'stats' ? 'text-emerald-400 scale-110' : 'text-slate-600'}`}>
            <TableIcon size={24} strokeWidth={activeTab === 'stats' ? 2.5 : 2} /><span className="text-[9px] font-black uppercase tracking-[0.2em]">Fluxo</span>
          </button>
        </div>
        <div className="h-safe bg-slate-950"></div>
      </nav>

      {/* POPUP SUCESSO HYPER-INTERATIVO (Impacto e Brilho) */}
      {showSuccessPopup && (
        <div className="fixed inset-0 z-[500] flex items-center justify-center p-6 pointer-events-none overflow-hidden bg-black/60 backdrop-blur-sm">
          <div className={`w-full max-w-sm glass-deep bg-gradient-to-b ${popupTheme.bg} ${popupTheme.border} border-2 rounded-[3.5rem] p-12 flex flex-col items-center text-center animate-pop-burst relative`}>

            {/* Brilho de Fundo Dinâmico */}
            <div className="absolute inset-0 flex items-center justify-center pointer-events-none opacity-40">
               <Sparkles size={180} className={`${popupTheme.text} animate-pulse`} strokeWidth={0.5} />
            </div>

            {/* Ícone Principal com Anel de Pulsação */}
            <div className="relative mb-10 z-10 flex items-center justify-center">
              <div className={`absolute w-32 h-32 border-4 ${popupTheme.ring} rounded-full animate-ring-pulse`}></div>
