import React, { useState, useEffect, useMemo } from 'react';
import { Truck, Zap, FileText, Download, LayoutDashboard, Send, Table as TableIcon, ListPlus, LogOut, Layers, Settings, Trash2, AlertCircle, User, Sliders, ChevronRight, X, CheckCircle2, Check, Wallet, AlertTriangle, ArrowDownLeft, ArrowUpRight, RotateCcw, Sparkles, Package } from 'lucide-react';
import DashboardCards from './components/DashboardCards';
import ActionButtons from './components/ActionButtons';
import DailyStatsTable from './components/DailyStatsTable';
import BulkActionModal from './components/BulkActionModal';
import WalletCard from './components/WalletCard';
import Login from './components/Login';
import { LogCashLogo } from './components/Logo';
import { LogEntry, LogActionType } from './types';
import { supabaseService } from './services/supabaseService';
import { generatePDF } from './services/pdfService';
import { SUPABASE_CACHE_KEY, VALOR_POR_PACOTE } from './constants';

const App: React.FC = () => {
  const [session, setSession] = useState<any>(null);
  const [logs, setLogs] = useState<LogEntry[]>(() => {
    const cached = localStorage.getItem(SUPABASE_CACHE_KEY);
    return cached ? JSON.parse(cached) : [];
  });
  const [loading, setLoading] = useState(true);
  const [isSyncing, setIsSyncing] = useState(false);
  const [showToast, setShowToast] = useState(false);
  const [toastMsg, setToastMsg] = useState('');

  // Estado para o Pop-up de Sucesso Gamificado
  const [showSuccessPopup, setShowSuccessPopup] = useState(false);
  const [bulkCount, setBulkCount] = useState(0);
  const [lastSettleValue, setLastSettleValue] = useState(0);
  const [bulkActionType, setBulkActionType] = useState<'ENTRADA' | 'SAIDA' | 'DEVOLUCAO' | 'SETTLE'>('ENTRADA');

  // Estado para Confirmação de Ação Manual
  const [actionToConfirm, setActionToConfirm] = useState<LogActionType | null>(null);

  // Estado para Confirmação de Carteira
  const [showWalletConfirm, setShowWalletConfirm] = useState(false);

  const [userName, setUserName] = useState(() => localStorage.getItem('logcash_user_name') || 'Operador Logístico');
  const [activeTab, setActiveTab] = useState<'dash' | 'stats'>('dash');
  const [showSettings, setShowSettings] = useState(false);
  const [confirmReset, setConfirmReset] = useState(false);
  const [settingsView, setSettingsView] = useState<'menu' | 'profile' | 'danger'>('menu');

  const [bulkModal, setBulkModal] = useState<{ isOpen: boolean; type: 'ENTRADA' | 'SAIDA' }>({
    isOpen: false,
    type: 'ENTRADA'
  });

  useEffect(() => {
    supabaseService.getSession().then(session => {
      setSession(session);
      if (!session) setLoading(false);
    });
  }, []);

  useEffect(() => {
    if (!session) return;
    setIsSyncing(true);
    const unsubscribe = supabaseService.subscribeToLogs((updatedLogs, supabaseError) => {
      if (!supabaseError) {
        setLogs(updatedLogs);
        localStorage.setItem(SUPABASE_CACHE_KEY, JSON.stringify(updatedLogs));
      }
      setLoading(false);
      setIsSyncing(false);
    });
    return () => unsubscribe();
  }, [session]);

  useEffect(() => {
    localStorage.setItem('logcash_user_name', userName);
  }, [userName]);

  const handleLogout = async () => {
    await supabaseService.signOut();
    localStorage.removeItem(SUPABASE_CACHE_KEY);
    setSession(null);
    setLogs([]);
    setShowSettings(false);
  };

  const executeAction = async (type: LogActionType) => {
    const newEntry: Omit<LogEntry, 'id'> = {
      type,
      timestamp: new Date().toISOString(),
      value: type === 'SAIDA' ? VALOR_POR_PACOTE : 0
    };
    try {
      await supabaseService.saveLog(newEntry);

      setBulkActionType(type as any);
      setBulkCount(1);
      setShowSuccessPopup(true);
      setActionToConfirm(null); // Fecha o modal de confirmação
      setTimeout(() => setShowSuccessPopup(false), 2400);

    } catch (err) {
      setToastMsg('Erro na sincronização.');
      setShowToast(true);
      setTimeout(() => setShowToast(false), 2000);
    }
  };

  const handleBulkAction = async (quantity: number) => {
    const type = bulkModal.type;
    const newEntries = Array.from({ length: quantity }).map(() => ({
      type: type as LogActionType,
      timestamp: new Date().toISOString(),
      value: type === 'SAIDA' ? VALOR_POR_PACOTE : 0
    }));
    try {
      await supabaseService.saveBulkLogs(newEntries);
      setBulkCount(quantity);
      setBulkActionType(type as any);
      setShowSuccessPopup(true);
      setTimeout(() => { setShowSuccessPopup(false); }, 2400);
    } catch (err) {
      setToastMsg('Falha no envio em lote.');
      setShowToast(true);
      setTimeout(() => setShowToast(false), 2000);
    }
  };

  const handleSettleWallet = async () => {
    const currentPending = counts.wallet.pending;
    setLastSettleValue(currentPending);

    try {
      setIsSyncing(true);
      setShowWalletConfirm(false);
      await supabaseService.markAllAsPaid();

      setBulkActionType('SETTLE');
      setShowSuccessPopup(true);
      setTimeout(() => { setShowSuccessPopup(false); }, 2800);

    } catch (err) {
      setToastMsg('Erro ao liquidar pagamentos.');
      setShowToast(true);
      setTimeout(() => setShowToast(false), 2000);
    } finally {
      setIsSyncing(false);
    }
  };

  const handleResetData = async () => {
    try {
      setIsSyncing(true);
      await supabaseService.deleteAllLogs();
      setLogs([]);
      localStorage.removeItem(SUPABASE_CACHE_KEY);
      setUserName('Operador Logístico');
      localStorage.removeItem('logcash_user_name');
      setToastMsg('Sistema reiniciado.');
      setShowToast(true);
      setConfirmReset(false);
      setShowSettings(false);
      setTimeout(() => setShowToast(false), 2000);
    } catch (err) {
      setToastMsg('Erro ao apagar dados.');
      setShowToast(true);
    } finally {
      setIsSyncing(false);
    }
  };

  const counts = useMemo(() => {
    const todayStr = new Date().toDateString();
    const now = new Date();
    const startOfWeek = new Date(now);
    startOfWeek.setDate(now.getDate() - now.getDay());
    startOfWeek.setHours(0, 0, 0, 0);
    const startOfYear = new Date(now.getFullYear(), 0, 1);

    const deliveredLogs = logs.filter(l => l.type === 'SAIDA');
    const pending = deliveredLogs.filter(l => !l.isPaid).length * VALOR_POR_PACOTE;
    const paidCurrentCycle = deliveredLogs.filter(l => l.isPaid && new Date(l.timestamp) >= startOfWeek).length * VALOR_POR_PACOTE;
    const totalCumulativePaid = deliveredLogs.filter(l => l.isPaid).length * VALOR_POR_PACOTE;

    return {
      today: logs.filter(l => l.type === 'SAIDA' && new Date(l.timestamp).toDateString() === todayStr).length,
      week: logs.filter(l => l.type === 'SAIDA' && new Date(l.timestamp) >= startOfWeek).length,
      year: logs.filter(l => l.type === 'SAIDA' && new Date(l.timestamp) >= startOfYear).length,
      wallet: {
        pending,
        paid: paidCurrentCycle,
        cumulative: totalCumulativePaid
      }
    };
  }, [logs]);

  if (!session && !loading) return <Login onLoginSuccess={() => supabaseService.getSession().then(setSession)} />;

  if (loading && logs.length === 0) {
    return (
      <div className="min-h-screen bg-[#020617] flex flex-col items-center justify-center p-6 text-center">
        <LogCashLogo size={60} />
        <p className="text-slate-500 font-game font-bold uppercase tracking-[0.3em] text-[10px] animate-pulse mt-4">Sincronizando Sistema...</p>
      </div>
    );
  }

  const formatBRL = (val: number) => new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(val);

  const popupTheme = {
    ENTRADA: { bg: 'from-emerald-600 to-emerald-950', border: 'border-emerald-400/40', text: 'text-emerald-400', ring: 'border-emerald-500', label: 'Entrada' },
    SAIDA: { bg: 'from-blue-600 to-blue-950', border: 'border-blue-400/40', text: 'text-blue-400', ring: 'border-blue-500', label: 'Saída' },
    DEVOLUCAO: { bg: 'from-orange-600 to-orange-950', border: 'border-orange-400/40', text: 'text-orange-400', ring: 'border-orange-500', label: 'Retorno' },
    SETTLE: { bg: 'from-indigo-600 to-indigo-950', border: 'border-indigo-400/40', text: 'text-indigo-400', ring: 'border-emerald-400', label: 'Recebido' }
  }[bulkActionType];

  return (
    <div className="min-h-screen bg-[#020617] text-slate-200 selection:bg-emerald-500/30 flex flex-col overflow-x-hidden relative">
      <header className="bg-slate-900/80 backdrop-blur-xl border-b border-white/5 px-4 md:px-8 sticky top-0 z-40 pt-safe transition-all h-20">
        <div className="max-w-5xl mx-auto flex justify-between items-center h-full">
          <div className="flex items-center gap-3">
            <LogCashLogo size={36} />
            <div>
              <h1 className="text-xl font-game font-black tracking-[0.1em] text-white leading-none">LOG<span className="text-emerald-400">CASH</span></h1>
              <p className="text-[8px] text-slate-500 font-bold uppercase tracking-widest mt-1">{isSyncing ? 'Sincronizando...' : 'Conectado'}</p>
            </div>
          </div>

          <div className="flex items-center gap-2">
            <button 
              onClick={() => { setShowSettings(true); setSettingsView('menu'); }} 
              className="p-3 bg-white/5 rounded-2xl border border-white/10 active:scale-95 transition-all hover:bg-white/10 flex items-center gap-2"
            >
              <Settings size={20} className="text-slate-400" />
              <span className="hidden sm:block text-[10px] font-black text-slate-400 uppercase tracking-widest">Painel</span>
            </button>
          </div>
        </div>
      </header>

      <main className="flex-1 max-w-5xl mx-auto w-full p-4 md:p-8 space-y-8 pb-28 md:pb-12 transition-all">
        {activeTab === 'dash' ? (
          <div className="animate-in fade-in duration-500">
            <div className="mb-8">
              <h2 className="text-3xl md:text-5xl font-game font-black text-white uppercase tracking-tight leading-tight">Olá, {userName.split(' ')[0]}</h2>
              <p className="text-[10px] md:text-xs text-slate-500 font-bold uppercase tracking-[0.4em] mt-2">Visão Geral da Operação</p>
            </div>

            <div className="grid grid-cols-1 lg:grid-cols-5 gap-6 mb-10">
              <div className="lg:col-span-3">
                <DashboardCards today={counts.today} week={counts.week} year={counts.year} />
              </div>
              <div className="lg:col-span-2">
                <WalletCard 
                  pendingAmount={counts.wallet.pending} 
                  paidAmount={counts.wallet.paid} 
                  totalCumulativePaid={counts.wallet.cumulative} 
