      </main>

      <nav className="fixed bottom-0 left-0 right-0 glass-card border-t border-white/10 md:hidden z-50">
        <div className="flex justify-around items-center h-20 max-w-lg mx-auto">
          <button onClick={() => setActiveTab('dash')} className={`flex flex-col items-center justify-center w-full h-full gap-1 transition-all ${activeTab === 'dash' ? 'text-emerald-400 scale-110' : 'text-slate-600'}`}>
            <LayoutDashboard size={24} strokeWidth={activeTab === 'dash' ? 2.5 : 2} /><span className="text-[9px] font-black uppercase tracking-[0.2em]">Dash</span>
          </button>
          <button onClick={() => setActiveTab('stats')} className={`flex flex-col items-center justify-center w-full h-full gap-1 transition-all ${activeTab === 'stats' ? 'text-emerald-400 scale-110' : 'text-slate-600'}`}>
