              actionToConfirm === 'ENTRADA' ? 'text-emerald-400' : 
              actionToConfirm === 'SAIDA' ? 'text-blue-400' : 'text-orange-400'
            }`}>
              {actionToConfirm === 'ENTRADA' && <ArrowDownLeft size={48} strokeWidth={3} />}
              {actionToConfirm === 'SAIDA' && <ArrowUpRight size={48} strokeWidth={3} />}
              {actionToConfirm === 'DEVOLUCAO' && <RotateCcw size={48} strokeWidth={3} />}
