                className={`w-full py-5 rounded-2xl font-game font-black text-sm uppercase tracking-[0.3em] shadow-2xl transition-all active:scale-95 text-white ${
                  actionToConfirm === 'ENTRADA' ? 'bg-emerald-600 shadow-emerald-900/30' : 
