            </div>
          </div>
        </div>
      )}

      {/* POPUP SUCESSO HYPER-INTERATIVO (Resultado Final) */}
      {showSuccessPopup && (
        <div className="fixed inset-0 z-[700] flex items-center justify-center p-6 pointer-events-none overflow-hidden bg-black/40 backdrop-blur-sm">
          <div className={`w-full max-w-sm glass-deep bg-gradient-to-b ${popupTheme.bg} ${popupTheme.border} border-2 rounded-[3.5rem] p-12 flex flex-col items-center text-center animate-pop-burst relative`}>

            <div className="absolute inset-0 flex items-center justify-center pointer-events-none opacity-40">
               <Sparkles size={180} className={`${popupTheme.text} animate-pulse`} strokeWidth={0.5} />
            </div>

            <div className="relative mb-10 z-10 flex items-center justify-center">
              <div className={`absolute w-32 h-32 border-4 ${popupTheme.ring} rounded-full animate-ring-pulse`}></div>
              <div className={`w-28 h-28 bg-white/10 backdrop-blur-2xl border border-white/25 rounded-full flex items-center justify-center shadow-2xl animate-float-bounce`}>
                {bulkActionType === 'ENTRADA' && <ArrowDownLeft size={50} className="text-white" strokeWidth={3} />}
                {bulkActionType === 'SAIDA' && <ArrowUpRight size={50} className="text-white" strokeWidth={3} />}
                {bulkActionType === 'DEVOLUCAO' && <RotateCcw size={50} className="text-white" strokeWidth={3} />}
                {bulkActionType === 'SETTLE' && <Check size={64} className="text-white" strokeWidth={4} />}
              </div>
            </div>

            <h4 className="text-3xl md:text-4xl font-game font-black text-white uppercase tracking-tighter leading-none mb-4 drop-shadow-2xl z-10">
              {popupTheme.label.toUpperCase()} OK!
            </h4>

            <div className="w-full h-px bg-white/20 mb-8 z-10"></div>

            <div className="space-y-4 z-10 w-full">
              {bulkActionType === 'SETTLE' ? (
                <div className="px-8 py-4 bg-white/5 rounded-3xl border border-white/10 shadow-inner shine-container overflow-hidden">
                  <div className="shine-overlay"></div>
                  <span className="text-4xl md:text-5xl font-game font-black text-white tracking-tighter block drop-shadow-lg">
                    {formatBRL(lastSettleValue)}
                  </span>
                </div>
              ) : (
                <div className="flex flex-col items-center">
                   <div className="px-8 py-3 bg-white/5 rounded-2xl border border-white/10 mb-5 shine-container overflow-hidden">
                      <div className="shine-overlay"></div>
                      <span className="text-3xl font-game font-black text-white tracking-widest uppercase">
                        {bulkCount} {bulkCount === 1 ? 'UNIDADE' : 'UNIDADES'}
                      </span>
                   </div>
                   {bulkActionType === 'SAIDA' && (
                     <div className="flex items-center gap-2 text-emerald-400 font-game font-black text-4xl tracking-widest drop-shadow-[0_0_15px_rgba(52,211,153,0.6)]">
                        <Zap size={28} fill="currentColor" />
                        +{formatBRL(bulkCount * VALOR_POR_PACOTE)}
                     </div>
                   )}
                </div>
              )}

              <p className="text-[10px] text-white/50 font-game font-bold uppercase tracking-[0.6em] pt-6 opacity-80 leading-relaxed">
                Operação Concluída com Sucesso
              </p>
            </div>

            <div className="absolute bottom-6 left-16 right-16 h-1 bg-white/10 rounded-full overflow-hidden">
               <div className="h-full bg-white/60 animate-timer"></div>
            </div>
          </div>
        </div>
      )}

      {/* Modal Ajustes */}
      {showSettings && (
        <div className="fixed inset-0 z-[100] flex items-end md:items-center justify-center bg-black/90 backdrop-blur-md p-0 md:p-4">
          <div className="bg-slate-900 w-full max-w-lg rounded-t-[3rem] md:rounded-[3rem] border-t md:border border-white/10 overflow-hidden animate-in slide-in-from-bottom-full duration-500">
             <div className="px-8 py-6 border-b border-white/5 flex justify-between items-center">
              <h3 className="font-game font-black text-white uppercase tracking-[0.2em] text-sm">Painel de Ajustes</h3>
              <button onClick={() => { setShowSettings(false); setConfirmReset(false); }} className="p-3 bg-white/5 rounded-full text-slate-500"><X size={20} /></button>
             </div>
             <div className="p-8 md:p-12 space-y-8">
                {confirmReset ? (
                   <div className="text-center space-y-8 animate-in zoom-in-95">
                      <div className="w-20 h-20 bg-red-500/10 rounded-full flex items-center justify-center mx-auto border border-red-500/20 text-red-500"><AlertCircle size={40} /></div>
                      <p className="font-game font-black text-white uppercase tracking-widest text-lg">Resetar Terminal?</p>
                      <div className="flex flex-col gap-4">
                        <button onClick={handleResetData} className="w-full py-5 bg-red-600 hover:bg-red-500 text-white rounded-2xl font-game font-black uppercase tracking-[0.3em] shadow-2xl shadow-red-900/40 transition-all">Apagar Tudo</button>
                        <button onClick={() => setConfirmReset(false)} className="text-slate-500 uppercase text-[10px] font-black hover:text-white transition-colors">Voltar</button>
                      </div>
                   </div>
                ) : (
                  <div className="space-y-6">
                    <div className="space-y-4">
                       <label className="text-[10px] font-black text-slate-600 uppercase tracking-[0.4em] ml-1">Assinatura Logística</label>
                       <div className="relative group">
                        <User className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-600 group-focus-within:text-emerald-400 transition-colors" size={18} />
                        <input 
                          type="text" 
                          value={userName} 
                          onChange={(e) => setUserName(e.target.value)} 
                          className="w-full bg-black/40 border border-white/10 focus:border-emerald-500/50 rounded-2xl pl-12 pr-4 py-5 text-sm font-bold text-white focus:outline-none transition-all" 
                        />
                       </div>
                    </div>

                    <div className="pt-4 flex flex-col gap-3">
                      <button 
                        onClick={handleLogout}
                        className="w-full p-6 bg-slate-800/50 border border-white/5 text-slate-400 rounded-3xl flex items-center justify-between font-game font-black uppercase tracking-widest text-xs active:scale-95 transition-all hover:bg-red-500/10 hover:text-red-500"
                      >
                        Encerrar Sessão <LogOut size={20} />
                      </button>

                      <button onClick={() => setConfirmReset(true)} className="w-full p-6 bg-red-500/5 border border-red-500/10 text-red-500 rounded-3xl flex items-center justify-between font-game font-black uppercase tracking-widest text-xs active:scale-95 transition-all">
                        Limpar Banco <Trash2 size={20} />
                      </button>
                    </div>
                  </div>
                )}
             </div>
             <div className="h-safe bg-slate-900 pb-safe"></div>
          </div>
        </div>
      )}

      {/* Modal Confirmação Carteira */}
      {showWalletConfirm && (
        <div className="fixed inset-0 z-[110] flex items-center justify-center bg-black/95 backdrop-blur-xl p-6">
          <div className="bg-slate-900 border border-white/10 rounded-[3rem] w-full max-w-sm overflow-hidden animate-in zoom-in-95 duration-400">
            <div className="p-10 flex flex-col items-center text-center">
              <div className="w-20 h-20 bg-emerald-500/10 rounded-full flex items-center justify-center mb-8 border border-emerald-500/20 shadow-[0_0_30px_rgba(16,185,129,0.2)]">
                <Wallet className="text-emerald-400" size={36} />
              </div>
              <h3 className="text-3xl font-game font-black text-white uppercase tracking-tighter mb-3 leading-none">Confirmar Saldo?</h3>
              <p className="text-[10px] text-slate-500 font-bold uppercase tracking-widest leading-relaxed mb-10">
                Você liquidará o valor de <span className="text-emerald-400 font-black">{formatBRL(counts.wallet.pending)}</span> pendentes.
              </p>
              <div className="w-full space-y-4">
                <button onClick={handleSettleWallet} className="w-full py-5 bg-emerald-600 hover:bg-emerald-500 text-white rounded-2xl font-game font-black text-sm uppercase tracking-[0.3em] active:scale-95 transition-all shadow-2xl shadow-emerald-900/40">Confirmar Recebimento</button>
                <button onClick={() => setShowWalletConfirm(false)} className="text-slate-500 font-bold uppercase text-[10px] tracking-widest hover:text-white transition-colors">Voltar</button>
              </div>
            </div>
          </div>
        </div>
      )}

      <BulkActionModal isOpen={bulkModal.isOpen} type={bulkModal.type} title={bulkModal.type === 'SAIDA' ? 'Saída em Massa' : 'Entrada em Massa'} onClose={() => setBulkModal({ ...bulkModal, isOpen: false })} onConfirm={handleBulkAction} />
    </div>
  );
};

export default App;

import React, { useState, useEffect, useMemo } from 'react';
import { Truck, Zap, FileText, Download, LayoutDashboard, Send, Table as TableIcon, ListPlus, LogOut, Layers, Settings, Trash2, AlertCircle, User, Sliders, ChevronRight, X, CheckCircle2, Check, Wallet, AlertTriangle, ArrowDownLeft, ArrowUpRight, RotateCcw, Sparkles, Package } from 'lucide-react';
import DashboardCards from './components/DashboardCards';
import ActionButtons from './components/ActionButtons';
import DailyStatsTable from './components/DailyStatsTable';
import BulkActionModal from './components/BulkActionModal';
import WalletCard from './components/WalletCard';
import Login from './components/Login';
import { LogCashLogo } from './components/Logo';
import { LogEntry, LogActionType } from './types';
import { supabaseService } from './services/supabaseService';
import { generatePDF } from './services/pdfService';
import { SUPABASE_CACHE_KEY, VALOR_POR_PACOTE } from './constants';

const App: React.FC = () => {
  const [session, setSession] = useState<any>(null);
  const [logs, setLogs] = useState<LogEntry[]>(() => {
    const cached = localStorage.getItem(SUPABASE_CACHE_KEY);
    return cached ? JSON.parse(cached) : [];
  });
  const [loading, setLoading] = useState(true);
  const [isSyncing, setIsSyncing] = useState(false);
  const [showToast, setShowToast] = useState(false);
  const [toastMsg, setToastMsg] = useState('');

  // Estado para o Pop-up de Sucesso Gamificado
  const [showSuccessPopup, setShowSuccessPopup] = useState(false);
  const [bulkCount, setBulkCount] = useState(0);
  const [lastSettleValue, setLastSettleValue] = useState(0);
  const [bulkActionType, setBulkActionType] = useState<'ENTRADA' | 'SAIDA' | 'DEVOLUCAO' | 'SETTLE'>('ENTRADA');

  // Estado para Confirmação de Ação Manual
  const [actionToConfirm, setActionToConfirm] = useState<LogActionType | null>(null);
  const [isExecuting, setIsExecuting] = useState(false);

  // Estado para Confirmação de Carteira
  const [showWalletConfirm, setShowWalletConfirm] = useState(false);

  const [userName, setUserName] = useState(() => localStorage.getItem('logcash_user_name') || 'Operador Logístico');
  const [activeTab, setActiveTab] = useState<'dash' | 'stats'>('dash');
  const [showSettings, setShowSettings] = useState(false);
  const [confirmReset, setConfirmReset] = useState(false);
  const [settingsView, setSettingsView] = useState<'menu' | 'profile' | 'danger'>('menu');

  const [bulkModal, setBulkModal] = useState<{ isOpen: boolean; type: 'ENTRADA' | 'SAIDA' }>({
    isOpen: false,
    type: 'ENTRADA'
  });

  useEffect(() => {
    supabaseService.getSession().then(session => {
      setSession(session);
      if (!session) setLoading(false);
    });
  }, []);

  useEffect(() => {
    if (!session) return;
    setIsSyncing(true);
    const unsubscribe = supabaseService.subscribeToLogs((updatedLogs, supabaseError) => {
      if (!supabaseError) {
        setLogs(updatedLogs);
        localStorage.setItem(SUPABASE_CACHE_KEY, JSON.stringify(updatedLogs));
      }
      setLoading(false);
      setIsSyncing(false);
    });
    return () => unsubscribe();
  }, [session]);

  useEffect(() => {
    localStorage.setItem('logcash_user_name', userName);
  }, [userName]);

  const handleLogout = async () => {
    await supabaseService.signOut();
    localStorage.removeItem(SUPABASE_CACHE_KEY);
    setSession(null);
    setLogs([]);
    setShowSettings(false);
  };

  const executeAction = async (type: LogActionType) => {
    if (isExecuting) return;
    setIsExecuting(true);

    const newEntry: Omit<LogEntry, 'id'> = {
      type,
      timestamp: new Date().toISOString(),
      value: type === 'SAIDA' ? VALOR_POR_PACOTE : 0
    };

    try {
      await supabaseService.saveLog(newEntry);

      setBulkActionType(type as any);
      setBulkCount(1);

      // Transição suave para o popup de sucesso
      setActionToConfirm(null);
      setTimeout(() => {
        setShowSuccessPopup(true);
        setTimeout(() => setShowSuccessPopup(false), 2400);
      }, 50);

    } catch (err) {
      setToastMsg('Erro na sincronização Cloud.');
      setShowToast(true);
      setTimeout(() => setShowToast(false), 2000);
    } finally {
      setIsExecuting(false);
    }
  };

  const handleBulkAction = async (quantity: number) => {
    const type = bulkModal.type;
    const newEntries = Array.from({ length: quantity }).map(() => ({
      type: type as LogActionType,
      timestamp: new Date().toISOString(),
      value: type === 'SAIDA' ? VALOR_POR_PACOTE : 0
    }));
    try {
      await supabaseService.saveBulkLogs(newEntries);
      setBulkCount(quantity);
      setBulkActionType(type as any);
      setShowSuccessPopup(true);
      setTimeout(() => { setShowSuccessPopup(false); }, 2400);
    } catch (err) {
      setToastMsg('Falha no envio em lote.');
      setShowToast(true);
      setTimeout(() => setShowToast(false), 2000);
    }
  };

  const handleSettleWallet = async () => {
    const currentPending = counts.wallet.pending;
    setLastSettleValue(currentPending);

    try {
      setIsSyncing(true);
      setShowWalletConfirm(false);
      await supabaseService.markAllAsPaid();

      setBulkActionType('SETTLE');
      setShowSuccessPopup(true);
      setTimeout(() => { setShowSuccessPopup(false); }, 2800);

    } catch (err) {
      setToastMsg('Erro ao liquidar pagamentos.');
      setShowToast(true);
      setTimeout(() => setShowToast(false), 2000);
    } finally {
      setIsSyncing(false);
    }
  };

  const handleResetData = async () => {
    try {
      setIsSyncing(true);
      await supabaseService.deleteAllLogs();
      setLogs([]);
      localStorage.removeItem(SUPABASE_CACHE_KEY);
      setUserName('Operador Logístico');
      localStorage.removeItem('logcash_user_name');
      setToastMsg('Sistema reiniciado.');
      setShowToast(true);
      setConfirmReset(false);
      setShowSettings(false);
      setTimeout(() => setShowToast(false), 2000);
    } catch (err) {
      setToastMsg('Erro ao apagar dados.');
      setShowToast(true);
    } finally {
      setIsSyncing(false);
    }
  };

  const counts = useMemo(() => {
    const todayStr = new Date().toDateString();
    const now = new Date();
    const startOfWeek = new Date(now);
    startOfWeek.setDate(now.getDate() - now.getDay());
    startOfWeek.setHours(0, 0, 0, 0);
    const startOfYear = new Date(now.getFullYear(), 0, 1);

    const deliveredLogs = logs.filter(l => l.type === 'SAIDA');
    const pending = deliveredLogs.filter(l => !l.isPaid).length * VALOR_POR_PACOTE;
    const paidCurrentCycle = deliveredLogs.filter(l => l.isPaid && new Date(l.timestamp) >= startOfWeek).length * VALOR_POR_PACOTE;
    const totalCumulativePaid = deliveredLogs.filter(l => l.isPaid).length * VALOR_POR_PACOTE;

    return {
      today: logs.filter(l => l.type === 'SAIDA' && new Date(l.timestamp).toDateString() === todayStr).length,
      week: logs.filter(l => l.type === 'SAIDA' && new Date(l.timestamp) >= startOfWeek).length,
      year: logs.filter(l => l.type === 'SAIDA' && new Date(l.timestamp) >= startOfYear).length,
      wallet: {
        pending,
        paid: paidCurrentCycle,
        cumulative: totalCumulativePaid
      }
    };
  }, [logs]);

  if (!session && !loading) return <Login onLoginSuccess={() => supabaseService.getSession().then(setSession)} />;

  if (loading && logs.length === 0) {
    return (
      <div className="min-h-screen bg-[#020617] flex flex-col items-center justify-center p-6 text-center">
        <LogCashLogo size={60} />
        <p className="text-slate-500 font-game font-bold uppercase tracking-[0.3em] text-[10px] animate-pulse mt-4">Conectando ao Terminal...</p>
      </div>
    );
  }

  const formatBRL = (val: number) => new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(val);

  const popupTheme = {
    ENTRADA: { bg: 'from-emerald-600 to-emerald-950', border: 'border-emerald-400/40', text: 'text-emerald-400', ring: 'border-emerald-500', label: 'Entrada' },
    SAIDA: { bg: 'from-blue-600 to-blue-950', border: 'border-blue-400/40', text: 'text-blue-400', ring: 'border-blue-500', label: 'Saída' },
    DEVOLUCAO: { bg: 'from-orange-600 to-orange-950', border: 'border-orange-400/40', text: 'text-orange-400', ring: 'border-orange-500', label: 'Retorno' },
    SETTLE: { bg: 'from-indigo-600 to-indigo-950', border: 'border-indigo-400/40', text: 'text-indigo-400', ring: 'border-emerald-400', label: 'Recebido' }
  }[bulkActionType];

  return (
    <div className="min-h-screen bg-[#020617] text-slate-200 selection:bg-emerald-500/30 flex flex-col overflow-x-hidden relative">
      <header className="bg-slate-900/80 backdrop-blur-xl border-b border-white/5 px-4 md:px-8 sticky top-0 z-40 pt-safe transition-all h-20">
        <div className="max-w-5xl mx-auto flex justify-between items-center h-full">
          <div className="flex items-center gap-3">
            <LogCashLogo size={36} />
            <div>
              <h1 className="text-xl font-game font-black tracking-[0.1em] text-white leading-none">LOG<span className="text-emerald-400">CASH</span></h1>
              <p className="text-[8px] text-slate-500 font-bold uppercase tracking-widest mt-1">{isSyncing ? 'Sincronizando...' : 'Online'}</p>
            </div>
          </div>

          <div className="flex items-center gap-2">
            <button 
              onClick={() => { setShowSettings(true); setSettingsView('menu'); }} 
              className="p-3 bg-white/5 rounded-2xl border border-white/10 active:scale-95 transition-all hover:bg-white/10 flex items-center gap-2"
            >
              <Settings size={20} className="text-slate-400" />
              <span className="hidden sm:block text-[10px] font-black text-slate-400 uppercase tracking-widest">Painel</span>
            </button>
          </div>
        </div>
      </header>

      <main className="flex-1 max-w-5xl mx-auto w-full p-4 md:p-8 space-y-8 pb-28 md:pb-12 transition-all">
        {activeTab === 'dash' ? (
          <div className="animate-in fade-in duration-500">
            <div className="mb-8">
              <h2 className="text-3xl md:text-5xl font-game font-black text-white uppercase tracking-tight leading-tight">Olá, {userName.split(' ')[0]}</h2>
              <p className="text-[10px] md:text-xs text-slate-500 font-bold uppercase tracking-[0.4em] mt-2">Visão Geral da Operação</p>
            </div>

            <div className="grid grid-cols-1 lg:grid-cols-5 gap-6 mb-10">
              <div className="lg:col-span-3">
                <DashboardCards today={counts.today} week={counts.week} year={counts.year} />
              </div>
              <div className="lg:col-span-2">
                <WalletCard 
                  pendingAmount={counts.wallet.pending} 
                  paidAmount={counts.wallet.paid} 
                  totalCumulativePaid={counts.wallet.cumulative} 
                  onSettle={() => setShowWalletConfirm(true)}
                />
              </div>
            </div>

            <section className="space-y-4 mb-10">
              <div className="flex items-center justify-between px-1">
                <h2 className="text-slate-500 font-game font-bold text-[10px] uppercase tracking-[0.5em]">Lançamento de Pacotes</h2>
                <div className="h-px flex-1 bg-white/5 mx-4 hidden sm:block"></div>
              </div>
              <ActionButtons onAction={(type) => setActionToConfirm(type)} />
            </section>

            <section className="grid grid-cols-2 gap-4 mb-10">
              <button onClick={() => setBulkModal({ isOpen: true, type: 'ENTRADA' })} className="bg-slate-900/40 border border-white/5 p-6 rounded-3xl flex flex-col items-start gap-4 active:scale-95 hover:bg-white/[0.03] transition-all">
                <div className="p-3 bg-emerald-600/10 text-emerald-400 rounded-2xl border border-emerald-500/20"><ListPlus size={24} /></div>
                <div className="text-left"><p className="font-game font-black text-white text-sm uppercase tracking-widest">Lote Entrada</p><p className="text-[8px] text-slate-500 uppercase font-bold mt-1">Check-in Base</p></div>
              </button>
              <button onClick={() => setBulkModal({ isOpen: true, type: 'SAIDA' })} className="bg-slate-900/40 border border-white/5 p-6 rounded-3xl flex flex-col items-start gap-4 active:scale-95 hover:bg-white/[0.03] transition-all">
                <div className="p-3 bg-blue-600/10 text-blue-400 rounded-2xl border border-blue-500/20"><Send size={24} /></div>
                <div className="text-left"><p className="font-game font-black text-white text-sm uppercase tracking-widest">Lote Saída</p><p className="text-[8px] text-slate-500 uppercase font-bold mt-1">Entrega Final</p></div>
              </button>
            </section>

            <section className="bg-slate-900/50 p-6 md:p-10 rounded-[3rem] border border-white/5 relative overflow-hidden group text-center">
              <div className="flex flex-col items-center gap-4 mb-6">
                <div className="p-4 bg-emerald-500/10 rounded-full border border-emerald-500/20"><FileText size={32} className="text-emerald-400" /></div>
                <h3 className="font-game font-black text-white uppercase tracking-[0.2em] text-lg">Exportar Extrato Detalhado</h3>
              </div>
              <button 
                onClick={() => generatePDF(logs, userName)}
                className="w-full bg-emerald-600 hover:bg-emerald-500 py-5 rounded-[1.5rem] flex items-center justify-center gap-3 font-game font-black text-white active:scale-95 text-xs uppercase tracking-[0.4em] transition-all shadow-2xl shadow-emerald-900/30 border border-emerald-400/20"
              >
                <Download size={22} /> Gerar PDF Completo
              </button>
            </section>
          </div>
        ) : (
          <div className="animate-in fade-in duration-500">
            <DailyStatsTable logs={logs} />
          </div>
        )}
      </main>

      <nav className="fixed bottom-0 left-0 right-0 glass-card border-t border-white/10 md:hidden z-50">
        <div className="flex justify-around items-center h-20 max-w-lg mx-auto">
          <button onClick={() => setActiveTab('dash')} className={`flex flex-col items-center justify-center w-full h-full gap-1 transition-all ${activeTab === 'dash' ? 'text-emerald-400 scale-110' : 'text-slate-600'}`}>
            <LayoutDashboard size={24} strokeWidth={activeTab === 'dash' ? 2.5 : 2} /><span className="text-[9px] font-black uppercase tracking-[0.2em]">Dash</span>
          </button>
          <button onClick={() => setActiveTab('stats')} className={`flex flex-col items-center justify-center w-full h-full gap-1 transition-all ${activeTab === 'stats' ? 'text-emerald-400 scale-110' : 'text-slate-600'}`}>
            <TableIcon size={24} strokeWidth={activeTab === 'stats' ? 2.5 : 2} /><span className="text-[9px] font-black uppercase tracking-[0.2em]">Fluxo</span>
          </button>
        </div>
        <div className="h-safe bg-slate-950"></div>
      </nav>

      {/* POPUP DE CONFIRMAÇÃO DE AÇÃO (Impacto e Brilho) */}
      {actionToConfirm && (
        <div className="fixed inset-0 z-[600] flex items-center justify-center p-6 bg-black/95 backdrop-blur-xl">
          <div className="w-full max-w-sm glass-deep rounded-[3.5rem] p-10 border border-white/20 animate-pop-burst text-center relative overflow-hidden">
            <div className="absolute top-0 inset-x-0 h-1.5 bg-gradient-to-r from-transparent via-white/20 to-transparent"></div>

            <div className={`w-24 h-24 mx-auto bg-white/5 rounded-3xl flex items-center justify-center mb-8 border border-white/10 animate-float-bounce ${
              actionToConfirm === 'ENTRADA' ? 'text-emerald-400 shadow-[0_0_40px_rgba(52,211,153,0.15)]' : 
              actionToConfirm === 'SAIDA' ? 'text-blue-400 shadow-[0_0_40px_rgba(59,130,246,0.15)]' : 'text-orange-400 shadow-[0_0_40px_rgba(249,115,22,0.15)]'
            }`}>
              {actionToConfirm === 'ENTRADA' && <ArrowDownLeft size={48} strokeWidth={3} />}
              {actionToConfirm === 'SAIDA' && <ArrowUpRight size={48} strokeWidth={3} />}
              {actionToConfirm === 'DEVOLUCAO' && <RotateCcw size={48} strokeWidth={3} />}
            </div>

            <h3 className="text-3xl font-game font-black text-white uppercase tracking-tighter mb-4 leading-none">
              Confirmar {actionToConfirm === 'ENTRADA' ? 'Entrada' : actionToConfirm === 'SAIDA' ? 'Saída' : 'Retorno'}?
            </h3>

            <p className="text-[10px] text-slate-500 font-bold uppercase tracking-[0.4em] mb-10 leading-relaxed px-4 opacity-80">
              Registrar Unidade Logística
            </p>

            <div className="space-y-4">
              <button 
                disabled={isExecuting}
                onClick={() => executeAction(actionToConfirm)}
                className={`w-full py-5 rounded-2xl font-game font-black text-sm uppercase tracking-[0.4em] shadow-2xl transition-all active:scale-95 text-white btn-confirm-impact flex items-center justify-center gap-3 shine-container overflow-hidden ${
                  actionToConfirm === 'ENTRADA' ? 'bg-emerald-600 shadow-emerald-900/40' : 
                  actionToConfirm === 'SAIDA' ? 'bg-blue-600 shadow-blue-900/40' : 'bg-orange-600 shadow-orange-900/40'
                }`}
              >
                <div className="shine-overlay"></div>
                {isExecuting ? <div className="w-5 h-5 border-2 border-white/30 border-t-white rounded-full animate-spin"></div> : 'Confirmar Registro'}
              </button>
              <button 
                disabled={isExecuting}
                onClick={() => setActionToConfirm(null)}
                className="w-full py-4 bg-white/5 hover:bg-white/10 text-slate-500 font-bold uppercase text-[10px] tracking-widest rounded-xl transition-all disabled:opacity-30"
              >
                Cancelar Ação
              </button>
            </div>
          </div>
        </div>
      )}

      {/* POPUP SUCESSO HYPER-INTERATIVO (Resultado Final) */}
      {showSuccessPopup && (
        <div className="fixed inset-0 z-[700] flex items-center justify-center p-6 pointer-events-none overflow-hidden bg-black/50 backdrop-blur-sm">
          <div className={`w-full max-w-sm glass-deep bg-gradient-to-b ${popupTheme.bg} ${popupTheme.border} border-2 rounded-[3.5rem] p-12 flex flex-col items-center text-center animate-pop-burst relative`}>

            <div className="absolute inset-0 flex items-center justify-center pointer-events-none opacity-50">
               <Sparkles size={180} className={`${popupTheme.text} animate-pulse`} strokeWidth={0.5} />
            </div>

            <div className="relative mb-10 z-10 flex items-center justify-center">
              <div className={`absolute w-32 h-32 border-4 ${popupTheme.ring} rounded-full animate-ring-pulse`}></div>
              <div className={`w-28 h-28 bg-white/10 backdrop-blur-3xl border border-white/30 rounded-full flex items-center justify-center shadow-2xl animate-float-bounce`}>
                {bulkActionType === 'ENTRADA' && <ArrowDownLeft size={50} className="text-white" strokeWidth={3} />}
                {bulkActionType === 'SAIDA' && <ArrowUpRight size={50} className="text-white" strokeWidth={3} />}
                {bulkActionType === 'DEVOLUCAO' && <RotateCcw size={50} className="text-white" strokeWidth={3} />}
                {bulkActionType === 'SETTLE' && <Check size={64} className="text-white" strokeWidth={4} />}
              </div>
            </div>

            <h4 className="text-3xl md:text-4xl font-game font-black text-white uppercase tracking-tighter leading-none mb-4 drop-shadow-2xl z-10">
              {popupTheme.label.toUpperCase()} REGISTRADO!
            </h4>

            <div className="w-full h-px bg-white/20 mb-8 z-10"></div>

            <div className="space-y-4 z-10 w-full">
              {bulkActionType === 'SETTLE' ? (
                <div className="px-8 py-4 bg-white/10 rounded-3xl border border-white/20 shadow-inner shine-container overflow-hidden">
                  <div className="shine-overlay"></div>
                  <span className="text-4xl md:text-5xl font-game font-black text-white tracking-tighter block drop-shadow-lg">
                    {formatBRL(lastSettleValue)}
                  </span>
                </div>
              ) : (
                <div className="flex flex-col items-center">
                   <div className="px-8 py-3 bg-white/10 rounded-2xl border border-white/20 mb-5 shine-container overflow-hidden">
                      <div className="shine-overlay"></div>
                      <span className="text-3xl font-game font-black text-white tracking-widest uppercase">
                        {bulkCount} {bulkCount === 1 ? 'UNIDADE' : 'UNIDADES'}
                      </span>
                   </div>
                   {bulkActionType === 'SAIDA' && (
                     <div className="flex items-center gap-2 text-emerald-400 font-game font-black text-4xl tracking-widest drop-shadow-[0_0_20px_rgba(52,211,153,0.7)]">
                        <Zap size={28} fill="currentColor" />
                        +{formatBRL(bulkCount * VALOR_POR_PACOTE)}
                     </div>
                   )}
                </div>
              )}

              <p className="text-[10px] text-white/60 font-game font-bold uppercase tracking-[0.7em] pt-6 opacity-90 leading-relaxed">
                Sincronização Cloud Completa
              </p>
            </div>

            <div className="absolute bottom-6 left-16 right-16 h-1 bg-white/20 rounded-full overflow-hidden">
               <div className="h-full bg-white animate-timer"></div>
            </div>
          </div>
        </div>
      )}

      {/* Modal Ajustes */}
      {showSettings && (
        <div className="fixed inset-0 z-[100] flex items-end md:items-center justify-center bg-black/90 backdrop-blur-md p-0 md:p-4">
          <div className="bg-slate-900 w-full max-w-lg rounded-t-[3rem] md:rounded-[3rem] border-t md:border border-white/10 overflow-hidden animate-in slide-in-from-bottom-full duration-500">
             <div className="px-8 py-6 border-b border-white/5 flex justify-between items-center">
              <h3 className="font-game font-black text-white uppercase tracking-[0.2em] text-sm">Painel de Ajustes</h3>
              <button onClick={() => { setShowSettings(false); setConfirmReset(false); }} className="p-3 bg-white/5 rounded-full text-slate-500"><X size={20} /></button>
             </div>
             <div className="p-8 md:p-12 space-y-8">
                {confirmReset ? (
                   <div className="text-center space-y-8 animate-in zoom-in-95">
                      <div className="w-20 h-20 bg-red-500/10 rounded-full flex items-center justify-center mx-auto border border-red-500/20 text-red-500"><AlertCircle size={40} /></div>
                      <p className="font-game font-black text-white uppercase tracking-widest text-lg">Resetar Terminal?</p>
                      <div className="flex flex-col gap-4">
                        <button onClick={handleResetData} className="w-full py-5 bg-red-600 hover:bg-red-500 text-white rounded-2xl font-game font-black uppercase tracking-[0.3em] shadow-2xl shadow-red-900/40 transition-all">Apagar Tudo</button>
                        <button onClick={() => setConfirmReset(false)} className="text-slate-500 uppercase text-[10px] font-black hover:text-white transition-colors">Voltar</button>
                      </div>
                   </div>
                ) : (
                  <div className="space-y-6">
                    <div className="space-y-4">
                       <label className="text-[10px] font-black text-slate-600 uppercase tracking-[0.4em] ml-1">Assinatura Logística</label>
                       <div className="relative group">
                        <User className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-600 group-focus-within:text-emerald-400 transition-colors" size={18} />
                        <input 
                          type="text" 
                          value={userName} 
                          onChange={(e) => setUserName(e.target.value)} 
                          className="w-full bg-black/40 border border-white/10 focus:border-emerald-500/50 rounded-2xl pl-12 pr-4 py-5 text-sm font-bold text-white focus:outline-none transition-all" 
                        />
                       </div>
                    </div>

                    <div className="pt-4 flex flex-col gap-3">
                      <button 
                        onClick={handleLogout}
                        className="w-full p-6 bg-slate-800/50 border border-white/5 text-slate-400 rounded-3xl flex items-center justify-between font-game font-black uppercase tracking-widest text-xs active:scale-95 transition-all hover:bg-red-500/10 hover:text-red-500"
                      >
                        Encerrar Sessão <LogOut size={20} />
                      </button>

                      <button onClick={() => setConfirmReset(true)} className="w-full p-6 bg-red-500/5 border border-red-500/10 text-red-500 rounded-3xl flex items-center justify-between font-game font-black uppercase tracking-widest text-xs active:scale-95 transition-all">
                        Limpar Banco <Trash2 size={20} />
                      </button>
                    </div>
                  </div>
                )}
             </div>
             <div className="h-safe bg-slate-900 pb-safe"></div>
          </div>
        </div>
      )}

      {/* Modal Confirmação Carteira */}
      {showWalletConfirm && (
        <div className="fixed inset-0 z-[110] flex items-center justify-center bg-black/95 backdrop-blur-xl p-6">
          <div className="bg-slate-900 border border-white/10 rounded-[3rem] w-full max-w-sm overflow-hidden animate-in zoom-in-95 duration-400">
            <div className="p-10 flex flex-col items-center text-center">
              <div className="w-20 h-20 bg-emerald-500/10 rounded-full flex items-center justify-center mb-8 border border-emerald-500/20 shadow-[0_0_30px_rgba(16,185,129,0.2)]">
                <Wallet className="text-emerald-400" size={36} />
              </div>
              <h3 className="text-3xl font-game font-black text-white uppercase tracking-tighter mb-3 leading-none">Confirmar Saldo?</h3>
              <p className="text-[10px] text-slate-500 font-bold uppercase tracking-widest leading-relaxed mb-10">
                Você liquidará o valor de <span className="text-emerald-400 font-black">{formatBRL(counts.wallet.pending)}</span> pendentes.
              </p>
              <div className="w-full space-y-4">
                <button onClick={handleSettleWallet} className="w-full py-5 bg-emerald-600 hover:bg-emerald-500 text-white rounded-2xl font-game font-black text-sm uppercase tracking-[0.3em] active:scale-95 transition-all shadow-2xl shadow-emerald-900/40">Liquidat Agora</button>
                <button onClick={() => setShowWalletConfirm(false)} className="text-slate-500 font-bold uppercase text-[10px] tracking-widest hover:text-white transition-colors">Voltar</button>
              </div>
            </div>
          </div>
        </div>
      )}

      <BulkActionModal isOpen={bulkModal.isOpen} type={bulkModal.type} title={bulkModal.type === 'SAIDA' ? 'Saída em Massa' : 'Entrada em Massa'} onClose={() => setBulkModal({ ...bulkModal, isOpen: false })} onConfirm={handleBulkAction} />
    </div>
  );
};

export default App;

import React, { useState, useEffect, useMemo } from 'react';
import { Truck, Zap, FileText, Download, LayoutDashboard, Send, Table as TableIcon, ListPlus, LogOut, Layers, Settings, Trash2, AlertCircle, User, Sliders, ChevronRight, X, CheckCircle2, Check, Wallet, AlertTriangle, ArrowDownLeft, ArrowUpRight, RotateCcw, Sparkles, Package } from 'lucide-react';
import DashboardCards from './components/DashboardCards';
import ActionButtons from './components/ActionButtons';
import DailyStatsTable from './components/DailyStatsTable';
import BulkActionModal from './components/BulkActionModal';
import WalletCard from './components/WalletCard';
import Login from './components/Login';
import { LogCashLogo } from './components/Logo';
import { LogEntry, LogActionType } from './types';
import { supabaseService } from './services/supabaseService';
import { generatePDF } from './services/pdfService';
import { SUPABASE_CACHE_KEY, VALOR_POR_PACOTE } from './constants';

const App: React.FC = () => {
  const [session, setSession] = useState<any>(null);
  const [logs, setLogs] = useState<LogEntry[]>(() => {
    const cached = localStorage.getItem(SUPABASE_CACHE_KEY);
    return cached ? JSON.parse(cached) : [];
  });
  const [loading, setLoading] = useState(true);
  const [isSyncing, setIsSyncing] = useState(false);
  const [showToast, setShowToast] = useState(false);
  const [toastMsg, setToastMsg] = useState('');

  // Estado para o Pop-up de Sucesso Gamificado
  const [showSuccessPopup, setShowSuccessPopup] = useState(false);
  const [isClosingSuccess, setIsClosingSuccess] = useState(false);
  const [bulkCount, setBulkCount] = useState(0);
  const [lastSettleValue, setLastSettleValue] = useState(0);
  const [bulkActionType, setBulkActionType] = useState<'ENTRADA' | 'SAIDA' | 'DEVOLUCAO' | 'SETTLE'>('ENTRADA');

  // Estado para Confirmação de Ação Manual
  const [actionToConfirm, setActionToConfirm] = useState<LogActionType | null>(null);
  const [isExecuting, setIsExecuting] = useState(false);

  // Estado para Confirmação de Carteira
  const [showWalletConfirm, setShowWalletConfirm] = useState(false);

  const [userName, setUserName] = useState(() => localStorage.getItem('logcash_user_name') || 'Operador Logístico');
  const [activeTab, setActiveTab] = useState<'dash' | 'stats'>('dash');
  const [showSettings, setShowSettings] = useState(false);
  const [confirmReset, setConfirmReset] = useState(false);
  const [settingsView, setSettingsView] = useState<'menu' | 'profile' | 'danger'>('menu');

  const [bulkModal, setBulkModal] = useState<{ isOpen: boolean; type: 'ENTRADA' | 'SAIDA' }>({
    isOpen: false,
    type: 'ENTRADA'
  });

  useEffect(() => {
    supabaseService.getSession().then(session => {
      setSession(session);
      if (!session) setLoading(false);
    });
  }, []);

  useEffect(() => {
    if (!session) return;
    setIsSyncing(true);
    const unsubscribe = supabaseService.subscribeToLogs((updatedLogs, supabaseError) => {
      if (!supabaseError) {
        setLogs(updatedLogs);
        localStorage.setItem(SUPABASE_CACHE_KEY, JSON.stringify(updatedLogs));
      }
      setLoading(false);
      setIsSyncing(false);
    });
    return () => unsubscribe();
  }, [session]);

  useEffect(() => {
    localStorage.setItem('logcash_user_name', userName);
  }, [userName]);

  const handleLogout = async () => {
    await supabaseService.signOut();
    localStorage.removeItem(SUPABASE_CACHE_KEY);
    setSession(null);
    setLogs([]);
    setShowSettings(false);
  };

  const closeSuccessPopup = () => {
    if (isClosingSuccess) return;
    setIsClosingSuccess(true);
    setTimeout(() => {
      setShowSuccessPopup(false);
      setIsClosingSuccess(false);
    }, 400); // Duração da animação pop-minimize
  };

  const executeAction = async (type: LogActionType) => {
    if (isExecuting) return;
    setIsExecuting(true);

    const newEntry: Omit<LogEntry, 'id'> = {
      type,
      timestamp: new Date().toISOString(),
      value: type === 'SAIDA' ? VALOR_POR_PACOTE : 0
    };

    try {
      await supabaseService.saveLog(newEntry);

      setBulkActionType(type as any);
      setBulkCount(1);

      // Transição suave para o popup de sucesso
      setActionToConfirm(null);
      setTimeout(() => {
        setShowSuccessPopup(true);
        // Autoclose (minimizar) após 2.2 segundos
        setTimeout(closeSuccessPopup, 2200);
      }, 50);

    } catch (err) {
      setToastMsg('Erro na sincronização Cloud.');
      setShowToast(true);
      setTimeout(() => setShowToast(false), 2000);
    } finally {
      setIsExecuting(false);
    }
  };

  const handleBulkAction = async (quantity: number) => {
    const type = bulkModal.type;
    const newEntries = Array.from({ length: quantity }).map(() => ({
      type: type as LogActionType,
      timestamp: new Date().toISOString(),
      value: type === 'SAIDA' ? VALOR_POR_PACOTE : 0
    }));
    try {
      await supabaseService.saveBulkLogs(newEntries);
      setBulkCount(quantity);
      setBulkActionType(type as any);
      setShowSuccessPopup(true);
      setTimeout(closeSuccessPopup, 2200);
    } catch (err) {
      setToastMsg('Falha no envio em lote.');
      setShowToast(true);
      setTimeout(() => setShowToast(false), 2000);
    }
  };

  const handleSettleWallet = async () => {
    const currentPending = counts.wallet.pending;
    setLastSettleValue(currentPending);

    try {
      setIsSyncing(true);
      setShowWalletConfirm(false);
      await supabaseService.markAllAsPaid();

      setBulkActionType('SETTLE');
      setShowSuccessPopup(true);
      setTimeout(closeSuccessPopup, 2600);

    } catch (err) {
      setToastMsg('Erro ao liquidar pagamentos.');
      setShowToast(true);
      setTimeout(() => setShowToast(false), 2000);
    } finally {
      setIsSyncing(false);
    }
  };

  const handleResetData = async () => {
    try {
      setIsSyncing(true);
      await supabaseService.deleteAllLogs();
      setLogs([]);
      localStorage.removeItem(SUPABASE_CACHE_KEY);
      setUserName('Operador Logístico');
      localStorage.removeItem('logcash_user_name');
      setToastMsg('Sistema reiniciado.');
      setShowToast(true);
      setConfirmReset(false);
      setShowSettings(false);
      setTimeout(() => setShowToast(false), 2000);
    } catch (err) {
      setToastMsg('Erro ao apagar dados.');
      setShowToast(true);
    } finally {
      setIsSyncing(false);
    }
  };

  const counts = useMemo(() => {
    const todayStr = new Date().toDateString();
    const now = new Date();
    const startOfWeek = new Date(now);
    startOfWeek.setDate(now.getDate() - now.getDay());
    startOfWeek.setHours(0, 0, 0, 0);
    const startOfYear = new Date(now.getFullYear(), 0, 1);

    const deliveredLogs = logs.filter(l => l.type === 'SAIDA');
    const pending = deliveredLogs.filter(l => !l.isPaid).length * VALOR_POR_PACOTE;
    const paidCurrentCycle = deliveredLogs.filter(l => l.isPaid && new Date(l.timestamp) >= startOfWeek).length * VALOR_POR_PACOTE;
    const totalCumulativePaid = deliveredLogs.filter(l => l.isPaid).length * VALOR_POR_PACOTE;

    return {
      today: logs.filter(l => l.type === 'SAIDA' && new Date(l.timestamp).toDateString() === todayStr).length,
      week: logs.filter(l => l.type === 'SAIDA' && new Date(l.timestamp) >= startOfWeek).length,
      year: logs.filter(l => l.type === 'SAIDA' && new Date(l.timestamp) >= startOfYear).length,
      wallet: {
        pending,
        paid: paidCurrentCycle,
        cumulative: totalCumulativePaid
      }
    };
  }, [logs]);

  if (!session && !loading) return <Login onLoginSuccess={() => supabaseService.getSession().then(setSession)} />;

  if (loading && logs.length === 0) {
    return (
      <div className="min-h-screen bg-[#020617] flex flex-col items-center justify-center p-6 text-center">
        <LogCashLogo size={60} />
        <p className="text-slate-500 font-game font-bold uppercase tracking-[0.3em] text-[10px] animate-pulse mt-4">Conectando ao Terminal...</p>
      </div>
    );
  }

  const formatBRL = (val: number) => new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(val);

  const popupTheme = {
    ENTRADA: { bg: 'from-emerald-600 to-emerald-950', border: 'border-emerald-400/40', text: 'text-emerald-400', ring: 'border-emerald-500', label: 'Entrada' },
    SAIDA: { bg: 'from-blue-600 to-blue-950', border: 'border-blue-400/40', text: 'text-blue-400', ring: 'border-blue-500', label: 'Saída' },
    DEVOLUCAO: { bg: 'from-orange-600 to-orange-950', border: 'border-orange-400/40', text: 'text-orange-400', ring: 'border-orange-500', label: 'Retorno' },
    SETTLE: { bg: 'from-indigo-600 to-indigo-950', border: 'border-indigo-400/40', text: 'text-indigo-400', ring: 'border-emerald-400', label: 'Recebido' }
  }[bulkActionType];

  return (
    <div className="min-h-screen bg-[#020617] text-slate-200 selection:bg-emerald-500/30 flex flex-col overflow-x-hidden relative">
      <header className="bg-slate-900/80 backdrop-blur-xl border-b border-white/5 px-4 md:px-8 sticky top-0 z-40 pt-safe transition-all h-20">
        <div className="max-w-5xl mx-auto flex justify-between items-center h-full">
          <div className="flex items-center gap-3">
            <LogCashLogo size={36} />
            <div>
              <h1 className="text-xl font-game font-black tracking-[0.1em] text-white leading-none">LOG<span className="text-emerald-400">CASH</span></h1>
              <p className="text-[8px] text-slate-500 font-bold uppercase tracking-widest mt-1">{isSyncing ? 'Sincronizando...' : 'Online'}</p>
            </div>
          </div>

          <div className="flex items-center gap-2">
            <button 
              onClick={() => { setShowSettings(true); setSettingsView('menu'); }} 
              className="p-3 bg-white/5 rounded-2xl border border-white/10 active:scale-95 transition-all hover:bg-white/10 flex items-center gap-2"
            >
              <Settings size={20} className="text-slate-400" />
              <span className="hidden sm:block text-[10px] font-black text-slate-400 uppercase tracking-widest">Painel</span>
            </button>
          </div>
        </div>
      </header>

      <main className="flex-1 max-w-5xl mx-auto w-full p-4 md:p-8 space-y-8 pb-28 md:pb-12 transition-all">
        {activeTab === 'dash' ? (
          <div className="animate-in fade-in duration-500">
            <div className="mb-8">
              <h2 className="text-3xl md:text-5xl font-game font-black text-white uppercase tracking-tight leading-tight">Olá, {userName.split(' ')[0]}</h2>
              <p className="text-[10px] md:text-xs text-slate-500 font-bold uppercase tracking-[0.4em] mt-2">Visão Geral da Operação</p>
            </div>

            <div className="grid grid-cols-1 lg:grid-cols-5 gap-6 mb-10">
              <div className="lg:col-span-3">
                <DashboardCards today={counts.today} week={counts.week} year={counts.year} />
              </div>
              <div className="lg:col-span-2">
                <WalletCard 
                  pendingAmount={counts.wallet.pending} 
                  paidAmount={counts.wallet.paid} 
                  totalCumulativePaid={counts.wallet.cumulative} 
                  onSettle={() => setShowWalletConfirm(true)}
                />
              </div>
            </div>

            <section className="space-y-4 mb-10">
              <div className="flex items-center justify-between px-1">
                <h2 className="text-slate-500 font-game font-bold text-[10px] uppercase tracking-[0.5em]">Lançamento de Pacotes</h2>
                <div className="h-px flex-1 bg-white/5 mx-4 hidden sm:block"></div>
              </div>
              <ActionButtons onAction={(type) => setActionToConfirm(type)} />
            </section>

            <section className="grid grid-cols-2 gap-4 mb-10">
              <button onClick={() => setBulkModal({ isOpen: true, type: 'ENTRADA' })} className="bg-slate-900/40 border border-white/5 p-6 rounded-3xl flex flex-col items-start gap-4 active:scale-95 hover:bg-white/[0.03] transition-all">
                <div className="p-3 bg-emerald-600/10 text-emerald-400 rounded-2xl border border-emerald-500/20"><ListPlus size={24} /></div>
                <div className="text-left"><p className="font-game font-black text-white text-sm uppercase tracking-widest">Lote Entrada</p><p className="text-[8px] text-slate-500 uppercase font-bold mt-1">Check-in Base</p></div>
              </button>
              <button onClick={() => setBulkModal({ isOpen: true, type: 'SAIDA' })} className="bg-slate-900/40 border border-white/5 p-6 rounded-3xl flex flex-col items-start gap-4 active:scale-95 hover:bg-white/[0.03] transition-all">
                <div className="p-3 bg-blue-600/10 text-blue-400 rounded-2xl border border-blue-500/20"><Send size={24} /></div>
                <div className="text-left"><p className="font-game font-black text-white text-sm uppercase tracking-widest">Lote Saída</p><p className="text-[8px] text-slate-500 uppercase font-bold mt-1">Entrega Final</p></div>
              </button>
            </section>

            <section className="bg-slate-900/50 p-6 md:p-10 rounded-[3rem] border border-white/5 relative overflow-hidden group text-center">
              <div className="flex flex-col items-center gap-4 mb-6">
                <div className="p-4 bg-emerald-500/10 rounded-full border border-emerald-500/20"><FileText size={32} className="text-emerald-400" /></div>
                <h3 className="font-game font-black text-white uppercase tracking-[0.2em] text-lg">Exportar Extrato Detalhado</h3>
              </div>
              <button 
                onClick={() => generatePDF(logs, userName)}
                className="w-full bg-emerald-600 hover:bg-emerald-500 py-5 rounded-[1.5rem] flex items-center justify-center gap-3 font-game font-black text-white active:scale-95 text-xs uppercase tracking-[0.4em] transition-all shadow-2xl shadow-emerald-900/30 border border-emerald-400/20"
              >
                <Download size={22} /> Gerar PDF Completo
              </button>
            </section>
          </div>
        ) : (
          <div className="animate-in fade-in duration-500">
            <DailyStatsTable logs={logs} />
          </div>
        )}
      </main>

      <nav className="fixed bottom-0 left-0 right-0 glass-card border-t border-white/10 md:hidden z-50">
        <div className="flex justify-around items-center h-20 max-w-lg mx-auto">
          <button onClick={() => setActiveTab('dash')} className={`flex flex-col items-center justify-center w-full h-full gap-1 transition-all ${activeTab === 'dash' ? 'text-emerald-400 scale-110' : 'text-slate-600'}`}>
            <LayoutDashboard size={24} strokeWidth={activeTab === 'dash' ? 2.5 : 2} /><span className="text-[9px] font-black uppercase tracking-[0.2em]">Dash</span>
          </button>
          <button onClick={() => setActiveTab('stats')} className={`flex flex-col items-center justify-center w-full h-full gap-1 transition-all ${activeTab === 'stats' ? 'text-emerald-400 scale-110' : 'text-slate-600'}`}>
            <TableIcon size={24} strokeWidth={activeTab === 'stats' ? 2.5 : 2} /><span className="text-[9px] font-black uppercase tracking-[0.2em]">Fluxo</span>
          </button>
        </div>
        <div className="h-safe bg-slate-950"></div>
      </nav>

      {/* POPUP DE CONFIRMAÇÃO DE AÇÃO (Impacto e Brilho) */}
      {actionToConfirm && (
        <div className="fixed inset-0 z-[600] flex items-center justify-center p-6 bg-black/95 backdrop-blur-xl">
          <div className="w-full max-w-sm glass-deep rounded-[3.5rem] p-10 border border-white/20 animate-pop-burst text-center relative overflow-hidden">
            <div className="absolute top-0 inset-x-0 h-1.5 bg-gradient-to-r from-transparent via-white/20 to-transparent"></div>

            <div className={`w-24 h-24 mx-auto bg-white/5 rounded-3xl flex items-center justify-center mb-8 border border-white/10 animate-float-bounce ${
              actionToConfirm === 'ENTRADA' ? 'text-emerald-400 shadow-[0_0_40px_rgba(52,211,153,0.15)]' : 
              actionToConfirm === 'SAIDA' ? 'text-blue-400 shadow-[0_0_40px_rgba(59,130,246,0.15)]' : 'text-orange-400 shadow-[0_0_40px_rgba(249,115,22,0.15)]'
            }`}>
              {actionToConfirm === 'ENTRADA' && <ArrowDownLeft size={48} strokeWidth={3} />}
              {actionToConfirm === 'SAIDA' && <ArrowUpRight size={48} strokeWidth={3} />}
              {actionToConfirm === 'DEVOLUCAO' && <RotateCcw size={48} strokeWidth={3} />}
            </div>

            <h3 className="text-3xl font-game font-black text-white uppercase tracking-tighter mb-4 leading-none">
              Confirmar {actionToConfirm === 'ENTRADA' ? 'Entrada' : actionToConfirm === 'SAIDA' ? 'Saída' : 'Retorno'}?
            </h3>

            <p className="text-[10px] text-slate-500 font-bold uppercase tracking-[0.4em] mb-10 leading-relaxed px-4 opacity-80">
              Registrar Unidade Logística
            </p>

            <div className="space-y-4">
              <button 
                disabled={isExecuting}
                onClick={() => executeAction(actionToConfirm)}
                className={`w-full py-5 rounded-2xl font-game font-black text-sm uppercase tracking-[0.4em] shadow-2xl transition-all active:scale-95 text-white btn-confirm-impact flex items-center justify-center gap-3 shine-container overflow-hidden ${
                  actionToConfirm === 'ENTRADA' ? 'bg-emerald-600 shadow-emerald-900/40' : 
                  actionToConfirm === 'SAIDA' ? 'bg-blue-600 shadow-blue-900/40' : 'bg-orange-600 shadow-orange-900/40'
                }`}
              >
                <div className="shine-overlay"></div>
                {isExecuting ? <div className="w-5 h-5 border-2 border-white/30 border-t-white rounded-full animate-spin"></div> : 'Confirmar Registro'}
              </button>
              <button 
                disabled={isExecuting}
                onClick={() => setActionToConfirm(null)}
                className="w-full py-4 bg-white/5 hover:bg-white/10 text-slate-500 font-bold uppercase text-[10px] tracking-widest rounded-xl transition-all disabled:opacity-30"
              >
                Cancelar Ação
              </button>
            </div>
          </div>
        </div>
      )}

      {/* POPUP SUCESSO HYPER-INTERATIVO (Resultado Final) */}
      {showSuccessPopup && (
        <div 
          onClick={closeSuccessPopup}
          className="fixed inset-0 z-[700] flex items-center justify-center p-6 cursor-pointer overflow-hidden bg-black/50 backdrop-blur-sm"
        >
          <div className={`w-full max-w-sm glass-deep bg-gradient-to-b ${popupTheme.bg} ${popupTheme.border} border-2 rounded-[3.5rem] p-12 flex flex-col items-center text-center ${isClosingSuccess ? 'animate-pop-minimize' : 'animate-pop-burst'} relative transition-all`}>

            <div className="absolute inset-0 flex items-center justify-center pointer-events-none opacity-50">
               <Sparkles size={180} className={`${popupTheme.text} animate-pulse`} strokeWidth={0.5} />
            </div>

            <div className="relative mb-10 z-10 flex items-center justify-center">
              <div className={`absolute w-32 h-32 border-4 ${popupTheme.ring} rounded-full animate-ring-pulse`}></div>
              <div className={`w-28 h-28 bg-white/10 backdrop-blur-3xl border border-white/30 rounded-full flex items-center justify-center shadow-2xl animate-float-bounce`}>
                {bulkActionType === 'ENTRADA' && <ArrowDownLeft size={50} className="text-white" strokeWidth={3} />}
                {bulkActionType === 'SAIDA' && <ArrowUpRight size={50} className="text-white" strokeWidth={3} />}
                {bulkActionType === 'DEVOLUCAO' && <RotateCcw size={50} className="text-white" strokeWidth={3} />}
                {bulkActionType === 'SETTLE' && <Check size={64} className="text-white" strokeWidth={4} />}
              </div>
            </div>

            <h4 className="text-3xl md:text-4xl font-game font-black text-white uppercase tracking-tighter leading-none mb-4 drop-shadow-2xl z-10">
              {popupTheme.label.toUpperCase()} REGISTRADO!
            </h4>

            <div className="w-full h-px bg-white/20 mb-8 z-10"></div>

            <div className="space-y-4 z-10 w-full">
              {bulkActionType === 'SETTLE' ? (
                <div className="px-8 py-4 bg-white/10 rounded-3xl border border-white/20 shadow-inner shine-container overflow-hidden">
                  <div className="shine-overlay"></div>
                  <span className="text-4xl md:text-5xl font-game font-black text-white tracking-tighter block drop-shadow-lg">
                    {formatBRL(lastSettleValue)}
                  </span>
                </div>
              ) : (
                <div className="flex flex-col items-center">
                   <div className="px-8 py-3 bg-white/10 rounded-2xl border border-white/20 mb-5 shine-container overflow-hidden">
                      <div className="shine-overlay"></div>
                      <span className="text-3xl font-game font-black text-white tracking-widest uppercase">
                        {bulkCount} {bulkCount === 1 ? 'UNIDADE' : 'UNIDADES'}
                      </span>
                   </div>
                   {bulkActionType === 'SAIDA' && (
                     <div className="flex items-center gap-2 text-emerald-400 font-game font-black text-4xl tracking-widest drop-shadow-[0_0_20px_rgba(52,211,153,0.7)]">
                        <Zap size={28} fill="currentColor" />
                        +{formatBRL(bulkCount * VALOR_POR_PACOTE)}
                     </div>
                   )}
                </div>
              )}

              <p className="text-[10px] text-white/60 font-game font-bold uppercase tracking-[0.7em] pt-6 opacity-90 leading-relaxed">
                Toque para Minimizar
              </p>
            </div>

            <div className="absolute bottom-6 left-16 right-16 h-1 bg-white/20 rounded-full overflow-hidden">
               <div className="h-full bg-white animate-timer"></div>
            </div>
          </div>
        </div>
      )}

      {/* Modal Ajustes */}
      {showSettings && (
        <div className="fixed inset-0 z-[100] flex items-end md:items-center justify-center bg-black/90 backdrop-blur-md p-0 md:p-4">
          <div className="bg-slate-900 w-full max-w-lg rounded-t-[3rem] md:rounded-[3rem] border-t md:border border-white/10 overflow-hidden animate-in slide-in-from-bottom-full duration-500">
             <div className="px-8 py-6 border-b border-white/5 flex justify-between items-center">
              <h3 className="font-game font-black text-white uppercase tracking-[0.2em] text-sm">Painel de Ajustes</h3>
              <button onClick={() => { setShowSettings(false); setConfirmReset(false); }} className="p-3 bg-white/5 rounded-full text-slate-500"><X size={20} /></button>
             </div>
             <div className="p-8 md:p-12 space-y-8">
                {confirmReset ? (
                   <div className="text-center space-y-8 animate-in zoom-in-95">
                      <div className="w-20 h-20 bg-red-500/10 rounded-full flex items-center justify-center mx-auto border border-red-500/20 text-red-500"><AlertCircle size={40} /></div>
                      <p className="font-game font-black text-white uppercase tracking-widest text-lg">Resetar Terminal?</p>
                      <div className="flex flex-col gap-4">
                        <button onClick={handleResetData} className="w-full py-5 bg-red-600 hover:bg-red-500 text-white rounded-2xl font-game font-black uppercase tracking-[0.3em] shadow-2xl shadow-red-900/40 transition-all">Apagar Tudo</button>
                        <button onClick={() => setConfirmReset(false)} className="text-slate-500 uppercase text-[10px] font-black hover:text-white transition-colors">Voltar</button>
                      </div>
                   </div>
                ) : (
                  <div className="space-y-6">
                    <div className="space-y-4">
                       <label className="text-[10px] font-black text-slate-600 uppercase tracking-[0.4em] ml-1">Assinatura Logística</label>
                       <div className="relative group">
                        <User className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-600 group-focus-within:text-emerald-400 transition-colors" size={18} />
                        <input 
                          type="text" 
                          value={userName} 
                          onChange={(e) => setUserName(e.target.value)} 
                          className="w-full bg-black/40 border border-white/10 focus:border-emerald-500/50 rounded-2xl pl-12 pr-4 py-5 text-sm font-bold text-white focus:outline-none transition-all" 
                        />
                       </div>
                    </div>

                    <div className="pt-4 flex flex-col gap-3">
                      <button 
                        onClick={handleLogout}
                        className="w-full p-6 bg-slate-800/50 border border-white/5 text-slate-400 rounded-3xl flex items-center justify-between font-game font-black uppercase tracking-widest text-xs active:scale-95 transition-all hover:bg-red-500/10 hover:text-red-500"
                      >
                        Encerrar Sessão <LogOut size={20} />
                      </button>

                      <button onClick={() => setConfirmReset(true)} className="w-full p-6 bg-red-500/5 border border-red-500/10 text-red-500 rounded-3xl flex items-center justify-between font-game font-black uppercase tracking-widest text-xs active:scale-95 transition-all">
                        Limpar Banco <Trash2 size={20} />
                      </button>
                    </div>
                  </div>
                )}
             </div>
             <div className="h-safe bg-slate-900 pb-safe"></div>
          </div>
        </div>
      )}

      {/* Modal Confirmação Carteira */}
      {showWalletConfirm && (
        <div className="fixed inset-0 z-[110] flex items-center justify-center bg-black/95 backdrop-blur-xl p-6">
          <div className="bg-slate-900 border border-white/10 rounded-[3rem] w-full max-w-sm overflow-hidden animate-in zoom-in-95 duration-400">
            <div className="p-10 flex flex-col items-center text-center">
              <div className="w-20 h-20 bg-emerald-500/10 rounded-full flex items-center justify-center mb-8 border border-emerald-500/20 shadow-[0_0_30px_rgba(16,185,129,0.2)]">
                <Wallet className="text-emerald-400" size={36} />
              </div>
              <h3 className="text-3xl font-game font-black text-white uppercase tracking-tighter mb-3 leading-none">Confirmar Saldo?</h3>
              <p className="text-[10px] text-slate-500 font-bold uppercase tracking-widest leading-relaxed mb-10">
                Você liquidará o valor de <span className="text-emerald-400 font-black">{formatBRL(counts.wallet.pending)}</span> pendentes.
              </p>
              <div className="w-full space-y-4">
                <button onClick={handleSettleWallet} className="w-full py-5 bg-emerald-600 hover:bg-emerald-500 text-white rounded-2xl font-game font-black text-sm uppercase tracking-[0.3em] active:scale-95 transition-all shadow-2xl shadow-emerald-900/40">Confirmar Recebimento</button>
                <button onClick={() => setShowWalletConfirm(false)} className="text-slate-500 font-bold uppercase text-[10px] tracking-widest hover:text-white transition-colors">Voltar</button>
              </div>
            </div>
          </div>
        </div>
      )}

      <BulkActionModal isOpen={bulkModal.isOpen} type={bulkModal.type} title={bulkModal.type === 'SAIDA' ? 'Saída em Massa' : 'Entrada em Massa'} onClose={() => setBulkModal({ ...bulkModal, isOpen: false })} onConfirm={handleBulkAction} />
    </div>
  );
};

export default App;

import React, { useState, useEffect, useMemo } from 'react';
import { Truck, Zap, FileText, Download, LayoutDashboard, Send, Table as TableIcon, ListPlus, LogOut, Layers, Settings, Trash2, AlertCircle, User, Sliders, ChevronRight, X, CheckCircle2, Check, Wallet, AlertTriangle, ArrowDownLeft, ArrowUpRight, RotateCcw, Sparkles, Package } from 'lucide-react';
import DashboardCards from './components/DashboardCards';
import ActionButtons from './components/ActionButtons';
import DailyStatsTable from './components/DailyStatsTable';
import BulkActionModal from './components/BulkActionModal';
import WalletCard from './components/WalletCard';
import Login from './components/Login';
import { LogCashLogo } from './components/Logo';
import { LogEntry, LogActionType } from './types';
import { supabaseService } from './services/supabaseService';
import { generatePDF } from './services/pdfService';
import { SUPABASE_CACHE_KEY, VALOR_POR_PACOTE } from './constants';

const App: React.FC = () => {
  const [session, setSession] = useState<any>(null);
  const [logs, setLogs] = useState<LogEntry[]>(() => {
    const cached = localStorage.getItem(SUPABASE_CACHE_KEY);
    return cached ? JSON.parse(cached) : [];
  });
  const [loading, setLoading] = useState(true);
  const [isSyncing, setIsSyncing] = useState(false);
  const [showToast, setShowToast] = useState(false);
  const [toastMsg, setToastMsg] = useState('');

  // Estado para o Pop-up de Sucesso Gamificado
  const [showSuccessPopup, setShowSuccessPopup] = useState(false);
  const [isClosingSuccess, setIsClosingSuccess] = useState(false);
  const [bulkCount, setBulkCount] = useState(0);
  const [lastSettleValue, setLastSettleValue] = useState(0);
  const [bulkActionType, setBulkActionType] = useState<'ENTRADA' | 'SAIDA' | 'DEVOLUCAO' | 'SETTLE'>('ENTRADA');

  // Estado para Confirmação de Ação Manual (Single)
  const [actionToConfirm, setActionToConfirm] = useState<LogActionType | null>(null);

  // Estado para Confirmação de Ação em Lote (Bulk)
  const [bulkActionPending, setBulkActionPending] = useState<{ type: 'ENTRADA' | 'SAIDA'; quantity: number } | null>(null);

  const [isExecuting, setIsExecuting] = useState(false);

  // Estado para Confirmação de Carteira
  const [showWalletConfirm, setShowWalletConfirm] = useState(false);

  const [userName, setUserName] = useState(() => localStorage.getItem('logcash_user_name') || 'Operador Logístico');
  const [activeTab, setActiveTab] = useState<'dash' | 'stats'>('dash');
  const [showSettings, setShowSettings] = useState(false);
  const [confirmReset, setConfirmReset] = useState(false);
  const [settingsView, setSettingsView] = useState<'menu' | 'profile' | 'danger'>('menu');

  const [bulkModal, setBulkModal] = useState<{ isOpen: boolean; type: 'ENTRADA' | 'SAIDA' }>({
    isOpen: false,
    type: 'ENTRADA'
  });

  useEffect(() => {
    supabaseService.getSession().then(session => {
      setSession(session);
      if (!session) setLoading(false);
    });
  }, []);

  useEffect(() => {
    if (!session) return;
    setIsSyncing(true);
    const unsubscribe = supabaseService.subscribeToLogs((updatedLogs, supabaseError) => {
      if (!supabaseError) {
        setLogs(updatedLogs);
        localStorage.setItem(SUPABASE_CACHE_KEY, JSON.stringify(updatedLogs));
      }
      setLoading(false);
      setIsSyncing(false);
    });
    return () => unsubscribe();
  }, [session]);

  useEffect(() => {
    localStorage.setItem('logcash_user_name', userName);
  }, [userName]);

  const handleLogout = async () => {
    await supabaseService.signOut();
    localStorage.removeItem(SUPABASE_CACHE_KEY);
    setSession(null);
    setLogs([]);
    setShowSettings(false);
  };

  const closeSuccessPopup = () => {
    if (isClosingSuccess) return;
    setIsClosingSuccess(true);
    setTimeout(() => {
      setShowSuccessPopup(false);
      setIsClosingSuccess(false);
    }, 400); // Duração da animação pop-minimize
  };

  const executeAction = async (type: LogActionType) => {
    if (isExecuting) return;
    setIsExecuting(true);

    const newEntry: Omit<LogEntry, 'id'> = {
      type,
      timestamp: new Date().toISOString(),
      value: type === 'SAIDA' ? VALOR_POR_PACOTE : 0
    };

    try {
      await supabaseService.saveLog(newEntry);

      setBulkActionType(type as any);
      setBulkCount(1);

      // Transição suave para o popup de sucesso
      setActionToConfirm(null);
      setTimeout(() => {
        setShowSuccessPopup(true);
        // Autoclose (minimizar) após 2.2 segundos
        setTimeout(closeSuccessPopup, 2200);
      }, 50);

    } catch (err) {
      setToastMsg('Erro na sincronização Cloud.');
      setShowToast(true);
      setTimeout(() => setShowToast(false), 2000);
    } finally {
      setIsExecuting(false);
    }
  };

  const handlePrepareBulk = (quantity: number) => {
    setBulkActionPending({ type: bulkModal.type, quantity });
    setBulkModal({ ...bulkModal, isOpen: false });
  };

  const executeBulkAction = async () => {
    if (!bulkActionPending || isExecuting) return;
    setIsExecuting(true);

    const { type, quantity } = bulkActionPending;
    const newEntries = Array.from({ length: quantity }).map(() => ({
      type: type as LogActionType,
      timestamp: new Date().toISOString(),
      value: type === 'SAIDA' ? VALOR_POR_PACOTE : 0
    }));

    try {
      await supabaseService.saveBulkLogs(newEntries);
      setBulkCount(quantity);
      setBulkActionType(type as any);

      setBulkActionPending(null);
      setTimeout(() => {
        setShowSuccessPopup(true);
        setTimeout(closeSuccessPopup, 2200);
      }, 50);
    } catch (err) {
      setToastMsg('Falha no envio em lote.');
      setShowToast(true);
      setTimeout(() => setShowToast(false), 2000);
    } finally {
      setIsExecuting(false);
    }
  };

  const handleSettleWallet = async () => {
    const currentPending = counts.wallet.pending;
    setLastSettleValue(currentPending);

    try {
      setIsSyncing(true);
      setShowWalletConfirm(false);
      await supabaseService.markAllAsPaid();

      setBulkActionType('SETTLE');
      setShowSuccessPopup(true);
      setTimeout(closeSuccessPopup, 2600);

    } catch (err) {
      setToastMsg('Erro ao liquidar pagamentos.');
      setShowToast(true);
      setTimeout(() => setShowToast(false), 2000);
    } finally {
      setIsSyncing(false);
    }
  };

  const handleResetData = async () => {
    try {
      setIsSyncing(true);
      await supabaseService.deleteAllLogs();
      setLogs([]);
      localStorage.removeItem(SUPABASE_CACHE_KEY);
      setUserName('Operador Logístico');
      localStorage.removeItem('logcash_user_name');
      setToastMsg('Sistema reiniciado.');
      setShowToast(true);
      setConfirmReset(false);
      setShowSettings(false);
      setTimeout(() => setShowToast(false), 2000);
    } catch (err) {
      setToastMsg('Erro ao apagar dados.');
      setShowToast(true);
    } finally {
      setIsSyncing(false);
    }
  };

  const counts = useMemo(() => {
    const todayStr = new Date().toDateString();
    const now = new Date();
    const startOfWeek = new Date(now);
    startOfWeek.setDate(now.getDate() - now.getDay());
    startOfWeek.setHours(0, 0, 0, 0);
    const startOfYear = new Date(now.getFullYear(), 0, 1);

    const deliveredLogs = logs.filter(l => l.type === 'SAIDA');
    const pending = deliveredLogs.filter(l => !l.isPaid).length * VALOR_POR_PACOTE;
    const paidCurrentCycle = deliveredLogs.filter(l => l.isPaid && new Date(l.timestamp) >= startOfWeek).length * VALOR_POR_PACOTE;
    const totalCumulativePaid = deliveredLogs.filter(l => l.isPaid).length * VALOR_POR_PACOTE;

    return {
      today: logs.filter(l => l.type === 'SAIDA' && new Date(l.timestamp).toDateString() === todayStr).length,
      week: logs.filter(l => l.type === 'SAIDA' && new Date(l.timestamp) >= startOfWeek).length,
      year: logs.filter(l => l.type === 'SAIDA' && new Date(l.timestamp) >= startOfYear).length,
      wallet: {
        pending,
        paid: paidCurrentCycle,
        cumulative: totalCumulativePaid
      }
    };
  }, [logs]);

  if (!session && !loading) return <Login onLoginSuccess={() => supabaseService.getSession().then(setSession)} />;

  if (loading && logs.length === 0) {
    return (
      <div className="min-h-screen bg-[#020617] flex flex-col items-center justify-center p-6 text-center">
        <LogCashLogo size={60} />
        <p className="text-slate-500 font-game font-bold uppercase tracking-[0.3em] text-[10px] animate-pulse mt-4">Conectando ao Terminal...</p>
      </div>
    );
  }

  const formatBRL = (val: number) => new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(val);

  const popupTheme = {
    ENTRADA: { bg: 'from-emerald-600 to-emerald-950', border: 'border-emerald-400/40', text: 'text-emerald-400', ring: 'border-emerald-500', label: 'Entrada' },
    SAIDA: { bg: 'from-blue-600 to-blue-950', border: 'border-blue-400/40', text: 'text-blue-400', ring: 'border-blue-500', label: 'Saída' },
    DEVOLUCAO: { bg: 'from-orange-600 to-orange-950', border: 'border-orange-400/40', text: 'text-orange-400', ring: 'border-orange-500', label: 'Retorno' },
    SETTLE: { bg: 'from-indigo-600 to-indigo-950', border: 'border-indigo-400/40', text: 'text-indigo-400', ring: 'border-emerald-400', label: 'Recebido' }
  }[bulkActionType];

  return (
    <div className="min-h-screen bg-[#020617] text-slate-200 selection:bg-emerald-500/30 flex flex-col overflow-x-hidden relative">
      <header className="bg-slate-900/80 backdrop-blur-xl border-b border-white/5 px-4 md:px-8 sticky top-0 z-40 pt-safe transition-all h-20">
        <div className="max-w-5xl mx-auto flex justify-between items-center h-full">
          <div className="flex items-center gap-3">
            <LogCashLogo size={36} />
            <div>
              <h1 className="text-xl font-game font-black tracking-[0.1em] text-white leading-none">LOG<span className="text-emerald-400">CASH</span></h1>
              <p className="text-[8px] text-slate-500 font-bold uppercase tracking-widest mt-1">{isSyncing ? 'Sincronizando...' : 'Online'}</p>
            </div>
          </div>

          <div className="flex items-center gap-2">
            <button 
              onClick={() => { setShowSettings(true); setSettingsView('menu'); }} 
              className="p-3 bg-white/5 rounded-2xl border border-white/10 active:scale-95 transition-all hover:bg-white/10 flex items-center gap-2"
            >
              <Settings size={20} className="text-slate-400" />
              <span className="hidden sm:block text-[10px] font-black text-slate-400 uppercase tracking-widest">Painel</span>
            </button>
          </div>
        </div>
      </header>

      <main className="flex-1 max-w-5xl mx-auto w-full p-4 md:p-8 space-y-8 pb-28 md:pb-12 transition-all">
        {activeTab === 'dash' ? (
          <div className="animate-in fade-in duration-500">
            <div className="mb-8">
              <h2 className="text-3xl md:text-5xl font-game font-black text-white uppercase tracking-tight leading-tight">Olá, {userName.split(' ')[0]}</h2>
              <p className="text-[10px] md:text-xs text-slate-500 font-bold uppercase tracking-[0.4em] mt-2">Visão Geral da Operação</p>
            </div>

            <div className="grid grid-cols-1 lg:grid-cols-5 gap-6 mb-10">
              <div className="lg:col-span-3">
                <DashboardCards today={counts.today} week={counts.week} year={counts.year} />
              </div>
              <div className="lg:col-span-2">
                <WalletCard 
                  pendingAmount={counts.wallet.pending} 
                  paidAmount={counts.wallet.paid} 
                  totalCumulativePaid={counts.wallet.cumulative} 
                  onSettle={() => setShowWalletConfirm(true)}
                />
              </div>
            </div>

            <section className="space-y-4 mb-10">
              <div className="flex items-center justify-between px-1">
                <h2 className="text-slate-500 font-game font-bold text-[10px] uppercase tracking-[0.5em]">Lançamento de Pacotes</h2>
                <div className="h-px flex-1 bg-white/5 mx-4 hidden sm:block"></div>
              </div>
              <ActionButtons onAction={(type) => setActionToConfirm(type)} />
            </section>

            <section className="grid grid-cols-2 gap-4 mb-10">
              <button onClick={() => setBulkModal({ isOpen: true, type: 'ENTRADA' })} className="bg-slate-900/40 border border-white/5 p-6 rounded-3xl flex flex-col items-start gap-4 active:scale-95 hover:bg-white/[0.03] transition-all">
                <div className="p-3 bg-emerald-600/10 text-emerald-400 rounded-2xl border border-emerald-500/20"><ListPlus size={24} /></div>
                <div className="text-left"><p className="font-game font-black text-white text-sm uppercase tracking-widest">Lote Entrada</p><p className="text-[8px] text-slate-500 uppercase font-bold mt-1">Check-in Base</p></div>
              </button>
              <button onClick={() => setBulkModal({ isOpen: true, type: 'SAIDA' })} className="bg-slate-900/40 border border-white/5 p-6 rounded-3xl flex flex-col items-start gap-4 active:scale-95 hover:bg-white/[0.03] transition-all">
                <div className="p-3 bg-blue-600/10 text-blue-400 rounded-2xl border border-blue-500/20"><Send size={24} /></div>
                <div className="text-left"><p className="font-game font-black text-white text-sm uppercase tracking-widest">Lote Saída</p><p className="text-[8px] text-slate-500 uppercase font-bold mt-1">Entrega Final</p></div>
              </button>
            </section>

            <section className="bg-slate-900/50 p-6 md:p-10 rounded-[3rem] border border-white/5 relative overflow-hidden group text-center">
              <div className="flex flex-col items-center gap-4 mb-6">
                <div className="p-4 bg-emerald-500/10 rounded-full border border-emerald-500/20"><FileText size={32} className="text-emerald-400" /></div>
                <h3 className="font-game font-black text-white uppercase tracking-[0.2em] text-lg">Exportar Extrato Detalhado</h3>
              </div>
              <button 
                onClick={() => generatePDF(logs, userName)}
                className="w-full bg-emerald-600 hover:bg-emerald-500 py-5 rounded-[1.5rem] flex items-center justify-center gap-3 font-game font-black text-white active:scale-95 text-xs uppercase tracking-[0.4em] transition-all shadow-2xl shadow-emerald-900/30 border border-emerald-400/20"
              >
                <Download size={22} /> Gerar PDF Completo
              </button>
            </section>
          </div>
        ) : (
          <div className="animate-in fade-in duration-500">
            <DailyStatsTable logs={logs} />
          </div>
        )}
      </main>

      <nav className="fixed bottom-0 left-0 right-0 glass-card border-t border-white/10 md:hidden z-50">
        <div className="flex justify-around items-center h-20 max-w-lg mx-auto">
          <button onClick={() => setActiveTab('dash')} className={`flex flex-col items-center justify-center w-full h-full gap-1 transition-all ${activeTab === 'dash' ? 'text-emerald-400 scale-110' : 'text-slate-600'}`}>
            <LayoutDashboard size={24} strokeWidth={activeTab === 'dash' ? 2.5 : 2} /><span className="text-[9px] font-black uppercase tracking-[0.2em]">Dash</span>
          </button>
          <button onClick={() => setActiveTab('stats')} className={`flex flex-col items-center justify-center w-full h-full gap-1 transition-all ${activeTab === 'stats' ? 'text-emerald-400 scale-110' : 'text-slate-600'}`}>
            <TableIcon size={24} strokeWidth={activeTab === 'stats' ? 2.5 : 2} /><span className="text-[9px] font-black uppercase tracking-[0.2em]">Fluxo</span>
          </button>
        </div>
        <div className="h-safe bg-slate-950"></div>
      </nav>

      {/* MODAL DE CONFIRMAÇÃO DE AÇÃO EM LOTE (BULK) */}
      {bulkActionPending && (
        <div className="fixed inset-0 z-[650] flex items-center justify-center p-6 bg-black/95 backdrop-blur-2xl">
          <div className="w-full max-w-md glass-deep rounded-[3.5rem] p-10 border border-white/20 animate-pop-burst text-center relative overflow-hidden">
            <div className={`absolute top-0 inset-x-0 h-2 bg-gradient-to-r ${bulkActionPending.type === 'SAIDA' ? 'from-blue-600 via-white/40 to-blue-600' : 'from-emerald-600 via-white/40 to-emerald-600'}`}></div>

            <div className={`w-28 h-28 mx-auto bg-white/5 rounded-[2.5rem] flex items-center justify-center mb-8 border border-white/10 animate-float-bounce ${
              bulkActionPending.type === 'ENTRADA' ? 'text-emerald-400 shadow-[0_0_50px_rgba(52,211,153,0.2)]' : 'text-blue-400 shadow-[0_0_50px_rgba(59,130,246,0.2)]'
            }`}>
              <Package size={54} strokeWidth={1.5} />
            </div>

            <h3 className="text-3xl font-game font-black text-white uppercase tracking-tighter mb-2 leading-none">
              Confirmar Lote?
            </h3>

            <div className="flex flex-col items-center gap-2 mb-10">
              <p className="text-[11px] text-slate-400 font-bold uppercase tracking-[0.3em]">
                Você está registrando:
              </p>
              <div className={`px-6 py-2 rounded-2xl border text-2xl font-game font-black tracking-widest ${
                bulkActionPending.type === 'ENTRADA' ? 'bg-emerald-500/10 border-emerald-500/20 text-emerald-400' : 'bg-blue-500/10 border-blue-500/20 text-blue-400'
              }`}>
                {bulkActionPending.quantity} UNIDADES
              </div>
              {bulkActionPending.type === 'SAIDA' && (
                <div className="text-emerald-400 font-game font-black text-xl tracking-widest mt-2">
                   + {formatBRL(bulkActionPending.quantity * VALOR_POR_PACOTE)}
                </div>
              )}
            </div>

            <div className="space-y-4">
              <button 
                disabled={isExecuting}
                onClick={executeBulkAction}
                className={`w-full py-5 rounded-2xl font-game font-black text-sm uppercase tracking-[0.4em] shadow-2xl transition-all active:scale-95 text-white btn-confirm-impact flex items-center justify-center gap-3 shine-container overflow-hidden ${
                  bulkActionPending.type === 'ENTRADA' ? 'bg-emerald-600 shadow-emerald-900/40' : 'bg-blue-600 shadow-blue-900/40'
                }`}
              >
                <div className="shine-overlay"></div>
                {isExecuting ? <div className="w-5 h-5 border-2 border-white/30 border-t-white rounded-full animate-spin"></div> : 'Confirmar Lote Agora'}
              </button>
              <button 
                disabled={isExecuting}
                onClick={() => setBulkActionPending(null)}
                className="w-full py-4 bg-white/5 hover:bg-white/10 text-slate-500 font-bold uppercase text-[10px] tracking-widest rounded-xl transition-all"
              >
                Voltar e Ajustar
              </button>
            </div>
          </div>
        </div>
      )}

      {/* POPUP DE CONFIRMAÇÃO DE AÇÃO MANUAL (Single) */}
      {actionToConfirm && (
        <div className="fixed inset-0 z-[600] flex items-center justify-center p-6 bg-black/95 backdrop-blur-xl">
          <div className="w-full max-w-sm glass-deep rounded-[3.5rem] p-10 border border-white/20 animate-pop-burst text-center relative overflow-hidden">
            <div className="absolute top-0 inset-x-0 h-1.5 bg-gradient-to-r from-transparent via-white/20 to-transparent"></div>

            <div className={`w-24 h-24 mx-auto bg-white/5 rounded-3xl flex items-center justify-center mb-8 border border-white/10 animate-float-bounce ${
              actionToConfirm === 'ENTRADA' ? 'text-emerald-400 shadow-[0_0_40px_rgba(52,211,153,0.15)]' : 
              actionToConfirm === 'SAIDA' ? 'text-blue-400 shadow-[0_0_40px_rgba(59,130,246,0.15)]' : 'text-orange-400 shadow-[0_0_40px_rgba(249,115,22,0.15)]'
            }`}>
              {actionToConfirm === 'ENTRADA' && <ArrowDownLeft size={48} strokeWidth={3} />}
              {actionToConfirm === 'SAIDA' && <ArrowUpRight size={48} strokeWidth={3} />}
              {actionToConfirm === 'DEVOLUCAO' && <RotateCcw size={48} strokeWidth={3} />}
            </div>

            <h3 className="text-3xl font-game font-black text-white uppercase tracking-tighter mb-4 leading-none">
              Confirmar {actionToConfirm === 'ENTRADA' ? 'Entrada' : actionToConfirm === 'SAIDA' ? 'Saída' : 'Retorno'}?
            </h3>

            <p className="text-[10px] text-slate-500 font-bold uppercase tracking-[0.4em] mb-10 leading-relaxed px-4 opacity-80">
              Registrar Unidade Logística
            </p>

            <div className="space-y-4">
              <button 
                disabled={isExecuting}
                onClick={() => executeAction(actionToConfirm)}
                className={`w-full py-5 rounded-2xl font-game font-black text-sm uppercase tracking-[0.4em] shadow-2xl transition-all active:scale-95 text-white btn-confirm-impact flex items-center justify-center gap-3 shine-container overflow-hidden ${
                  actionToConfirm === 'ENTRADA' ? 'bg-emerald-600 shadow-emerald-900/40' : 
                  actionToConfirm === 'SAIDA' ? 'bg-blue-600 shadow-blue-900/40' : 'bg-orange-600 shadow-orange-900/40'
                }`}
              >
                <div className="shine-overlay"></div>
                {isExecuting ? <div className="w-5 h-5 border-2 border-white/30 border-t-white rounded-full animate-spin"></div> : 'Confirmar Registro'}
              </button>
              <button 
                disabled={isExecuting}
                onClick={() => setActionToConfirm(null)}
                className="w-full py-4 bg-white/5 hover:bg-white/10 text-slate-500 font-bold uppercase text-[10px] tracking-widest rounded-xl transition-all disabled:opacity-30"
              >
                Cancelar Ação
              </button>
            </div>
          </div>
        </div>
      )}

      {/* POPUP SUCESSO HYPER-INTERATIVO (Resultado Final) */}
      {showSuccessPopup && (
        <div 
          onClick={closeSuccessPopup}
          className="fixed inset-0 z-[700] flex items-center justify-center p-6 cursor-pointer overflow-hidden bg-black/50 backdrop-blur-sm"
        >
          <div className={`w-full max-w-sm glass-deep bg-gradient-to-b ${popupTheme.bg} ${popupTheme.border} border-2 rounded-[3.5rem] p-12 flex flex-col items-center text-center ${isClosingSuccess ? 'animate-pop-minimize' : 'animate-pop-burst'} relative transition-all`}>

            <div className="absolute inset-0 flex items-center justify-center pointer-events-none opacity-50">
               <Sparkles size={180} className={`${popupTheme.text} animate-pulse`} strokeWidth={0.5} />
            </div>

            <div className="relative mb-10 z-10 flex items-center justify-center">
              <div className={`absolute w-32 h-32 border-4 ${popupTheme.ring} rounded-full animate-ring-pulse`}></div>
              <div className={`w-28 h-28 bg-white/10 backdrop-blur-3xl border border-white/30 rounded-full flex items-center justify-center shadow-2xl animate-float-bounce`}>
                {bulkActionType === 'ENTRADA' && <ArrowDownLeft size={50} className="text-white" strokeWidth={3} />}
                {bulkActionType === 'SAIDA' && <ArrowUpRight size={50} className="text-white" strokeWidth={3} />}
                {bulkActionType === 'DEVOLUCAO' && <RotateCcw size={50} className="text-white" strokeWidth={3} />}
                {bulkActionType === 'SETTLE' && <Check size={64} className="text-white" strokeWidth={4} />}
              </div>
            </div>

            <h4 className="text-3xl md:text-4xl font-game font-black text-white uppercase tracking-tighter leading-none mb-4 drop-shadow-2xl z-10">
              {popupTheme.label.toUpperCase()} REGISTRADO!
            </h4>

            <div className="w-full h-px bg-white/20 mb-8 z-10"></div>

            <div className="space-y-4 z-10 w-full">
              {bulkActionType === 'SETTLE' ? (
                <div className="px-8 py-4 bg-white/10 rounded-3xl border border-white/20 shadow-inner shine-container overflow-hidden">
                  <div className="shine-overlay"></div>
                  <span className="text-4xl md:text-5xl font-game font-black text-white tracking-tighter block drop-shadow-lg">
                    {formatBRL(lastSettleValue)}
                  </span>
                </div>
              ) : (
                <div className="flex flex-col items-center">
                   <div className="px-8 py-3 bg-white/10 rounded-2xl border border-white/20 mb-5 shine-container overflow-hidden">
                      <div className="shine-overlay"></div>
                      <span className="text-3xl font-game font-black text-white tracking-widest uppercase">
                        {bulkCount} {bulkCount === 1 ? 'UNIDADE' : 'UNIDADES'}
                      </span>
                   </div>
                   {bulkActionType === 'SAIDA' && (
                     <div className="flex items-center gap-2 text-emerald-400 font-game font-black text-4xl tracking-widest drop-shadow-[0_0_20px_rgba(52,211,153,0.7)]">
                        <Zap size={28} fill="currentColor" />
                        +{formatBRL(bulkCount * VALOR_POR_PACOTE)}
                     </div>
                   )}
                </div>
              )}

              <p className="text-[10px] text-white/60 font-game font-bold uppercase tracking-[0.7em] pt-6 opacity-90 leading-relaxed">
                Toque para Minimizar
              </p>
            </div>

            <div className="absolute bottom-6 left-16 right-16 h-1 bg-white/20 rounded-full overflow-hidden">
               <div className="h-full bg-white animate-timer"></div>
            </div>
          </div>
        </div>
      )}

      {/* Modal Ajustes */}
      {showSettings && (
        <div className="fixed inset-0 z-[100] flex items-end md:items-center justify-center bg-black/90 backdrop-blur-md p-0 md:p-4">
          <div className="bg-slate-900 w-full max-w-lg rounded-t-[3rem] md:rounded-[3rem] border-t md:border border-white/10 overflow-hidden animate-in slide-in-from-bottom-full duration-500">
             <div className="px-8 py-6 border-b border-white/5 flex justify-between items-center">
              <h3 className="font-game font-black text-white uppercase tracking-[0.2em] text-sm">Painel de Ajustes</h3>
              <button onClick={() => { setShowSettings(false); setConfirmReset(false); }} className="p-3 bg-white/5 rounded-full text-slate-500"><X size={20} /></button>
             </div>
             <div className="p-8 md:p-12 space-y-8">
                {confirmReset ? (
                   <div className="text-center space-y-8 animate-in zoom-in-95">
                      <div className="w-20 h-20 bg-red-500/10 rounded-full flex items-center justify-center mx-auto border border-red-500/20 text-red-500"><AlertCircle size={40} /></div>
                      <p className="font-game font-black text-white uppercase tracking-widest text-lg">Resetar Terminal?</p>
                      <div className="flex flex-col gap-4">
                        <button onClick={handleResetData} className="w-full py-5 bg-red-600 hover:bg-red-500 text-white rounded-2xl font-game font-black uppercase tracking-[0.3em] shadow-2xl shadow-red-900/40 transition-all">Apagar Tudo</button>
                        <button onClick={() => setConfirmReset(false)} className="text-slate-500 uppercase text-[10px] font-black hover:text-white transition-colors">Voltar</button>
                      </div>
                   </div>
                ) : (
                  <div className="space-y-6">
                    <div className="space-y-4">
                       <label className="text-[10px] font-black text-slate-600 uppercase tracking-[0.4em] ml-1">Assinatura Logística</label>
                       <div className="relative group">
                        <User className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-600 group-focus-within:text-emerald-400 transition-colors" size={18} />
                        <input 
                          type="text" 
                          value={userName} 
                          onChange={(e) => setUserName(e.target.value)} 
                          className="w-full bg-black/40 border border-white/10 focus:border-emerald-500/50 rounded-2xl pl-12 pr-4 py-5 text-sm font-bold text-white focus:outline-none transition-all" 
                        />
                       </div>
                    </div>

                    <div className="pt-4 flex flex-col gap-3">
                      <button 
                        onClick={handleLogout}
                        className="w-full p-6 bg-slate-800/50 border border-white/5 text-slate-400 rounded-3xl flex items-center justify-between font-game font-black uppercase tracking-widest text-xs active:scale-95 transition-all hover:bg-red-500/10 hover:text-red-500"
                      >
                        Encerrar Sessão <LogOut size={20} />
                      </button>

                      <button onClick={() => setConfirmReset(true)} className="w-full p-6 bg-red-500/5 border border-red-500/10 text-red-500 rounded-3xl flex items-center justify-between font-game font-black uppercase tracking-widest text-xs active:scale-95 transition-all">
                        Limpar Banco <Trash2 size={20} />
                      </button>
                    </div>
                  </div>
                )}
             </div>
             <div className="h-safe bg-slate-900 pb-safe"></div>
          </div>
        </div>
      )}

      {/* Modal Confirmação Carteira */}
      {showWalletConfirm && (
        <div className="fixed inset-0 z-[110] flex items-center justify-center bg-black/95 backdrop-blur-xl p-6">
          <div className="bg-slate-900 border border-white/10 rounded-[3rem] w-full max-w-sm overflow-hidden animate-in zoom-in-95 duration-400">
            <div className="p-10 flex flex-col items-center text-center">
              <div className="w-20 h-20 bg-emerald-500/10 rounded-full flex items-center justify-center mb-8 border border-emerald-500/20 shadow-[0_0_30px_rgba(16,185,129,0.2)]">
                <Wallet className="text-emerald-400" size={36} />
              </div>
              <h3 className="text-3xl font-game font-black text-white uppercase tracking-tighter mb-3 leading-none">Confirmar Saldo?</h3>
              <p className="text-[10px] text-slate-500 font-bold uppercase tracking-widest leading-relaxed mb-10">
                Você liquidará o valor de <span className="text-emerald-400 font-black">{formatBRL(counts.wallet.pending)}</span> pendentes.
              </p>
              <div className="w-full space-y-4">
                <button onClick={handleSettleWallet} className="w-full py-5 bg-emerald-600 hover:bg-emerald-500 text-white rounded-2xl font-game font-black text-sm uppercase tracking-[0.3em] active:scale-95 transition-all shadow-2xl shadow-emerald-900/40">Confirmar Recebimento</button>
                <button onClick={() => setShowWalletConfirm(false)} className="text-slate-500 font-bold uppercase text-[10px] tracking-widest hover:text-white transition-colors">Voltar</button>
              </div>
            </div>
          </div>
        </div>
      )}

      <BulkActionModal 
        isOpen={bulkModal.isOpen} 
        type={bulkModal.type} 
        title={bulkModal.type === 'SAIDA' ? 'Saída em Massa' : 'Entrada em Massa'} 
        onClose={() => setBulkModal({ ...bulkModal, isOpen: false })} 
        onConfirm={handlePrepareBulk} 
      />
    </div>
  );
};

export default App;

import React, { useState, useEffect, useMemo } from 'react';
import { Truck, Zap, FileText, Download, LayoutDashboard, Send, Table as TableIcon, ListPlus, LogOut, Layers, Settings, Trash2, AlertCircle, User, Sliders, ChevronRight, X, CheckCircle2, Check, Wallet, AlertTriangle, ArrowDownLeft, ArrowUpRight, RotateCcw, Sparkles, Package, LogIn, Database } from 'lucide-react';
import DashboardCards from './components/DashboardCards';
import ActionButtons from './components/ActionButtons';
import DailyStatsTable from './components/DailyStatsTable';
import BulkActionModal from './components/BulkActionModal';
import WalletCard from './components/WalletCard';
import Login from './components/Login';
import { LogCashLogo } from './components/Logo';
import { LogEntry, LogActionType } from './types';
import { supabaseService } from './services/supabaseService';
import { generatePDF } from './services/pdfService';
import { SUPABASE_CACHE_KEY, VALOR_POR_PACOTE } from './constants';

type SystemActionType = LogActionType | 'EXPORT_PDF' | 'LOGOUT' | 'RESET_SYSTEM' | 'SETTLE_WALLET';

const App: React.FC = () => {
  const [session, setSession] = useState<any>(null);
  const [logs, setLogs] = useState<LogEntry[]>(() => {
    const cached = localStorage.getItem(SUPABASE_CACHE_KEY);
    return cached ? JSON.parse(cached) : [];
  });
  const [loading, setLoading] = useState(true);
  const [isSyncing, setIsSyncing] = useState(false);
  const [showToast, setShowToast] = useState(false);
  const [toastMsg, setToastMsg] = useState('');

  // Estados de Pop-up de Sucesso
  const [showSuccessPopup, setShowSuccessPopup] = useState(false);
  const [isClosingSuccess, setIsClosingSuccess] = useState(false);
  const [bulkCount, setBulkCount] = useState(0);
  const [lastSettleValue, setLastSettleValue] = useState(0);
  const [successType, setSuccessType] = useState<SystemActionType>('ENTRADA');

  // Estado Unificado de Confirmação
  const [confirmingAction, setConfirmingAction] = useState<SystemActionType | null>(null);
  const [bulkActionPending, setBulkActionPending] = useState<{ type: 'ENTRADA' | 'SAIDA'; quantity: number } | null>(null);
  const [isExecuting, setIsExecuting] = useState(false);

  const [userName, setUserName] = useState(() => localStorage.getItem('logcash_user_name') || 'Operador Logístico');
  const [activeTab, setActiveTab] = useState<'dash' | 'stats'>('dash');
  const [showSettings, setShowSettings] = useState(false);

  const [bulkModal, setBulkModal] = useState<{ isOpen: boolean; type: 'ENTRADA' | 'SAIDA' }>({
    isOpen: false,
    type: 'ENTRADA'
  });

  useEffect(() => {
    supabaseService.getSession().then(session => {
      setSession(session);
      if (!session) setLoading(false);
    });
  }, []);

  useEffect(() => {
    if (!session) return;
    setIsSyncing(true);
    const unsubscribe = supabaseService.subscribeToLogs((updatedLogs, supabaseError) => {
      if (!supabaseError) {
        setLogs(updatedLogs);
        localStorage.setItem(SUPABASE_CACHE_KEY, JSON.stringify(updatedLogs));
      }
      setLoading(false);
      setIsSyncing(false);
    });
    return () => unsubscribe();
  }, [session]);

  useEffect(() => {
    localStorage.setItem('logcash_user_name', userName);
  }, [userName]);

  const triggerSuccess = (type: SystemActionType, count: number = 1) => {
    setSuccessType(type);
    setBulkCount(count);
    setConfirmingAction(null);
    setBulkActionPending(null);
    setShowSettings(false);

    setTimeout(() => {
      setShowSuccessPopup(true);
      setTimeout(closeSuccessPopup, 2400);
    }, 100);
  };

  const closeSuccessPopup = () => {
    if (isClosingSuccess) return;
    setIsClosingSuccess(true);
    setTimeout(() => {
      setShowSuccessPopup(false);
      setIsClosingSuccess(false);
    }, 400);
  };

  const handleGlobalConfirm = async () => {
    if (isExecuting || !confirmingAction) return;
    setIsExecuting(true);

    try {
      switch (confirmingAction) {
        case 'ENTRADA':
        case 'SAIDA':
        case 'DEVOLUCAO':
          await supabaseService.saveLog({
            type: confirmingAction as LogActionType,
            timestamp: new Date().toISOString(),
            value: confirmingAction === 'SAIDA' ? VALOR_POR_PACOTE : 0
          });
          triggerSuccess(confirmingAction);
          break;

        case 'SETTLE_WALLET':
          const currentPending = counts.wallet.pending;
          setLastSettleValue(currentPending);
          await supabaseService.markAllAsPaid();
          triggerSuccess('SETTLE_WALLET');
          break;

        case 'EXPORT_PDF':
          generatePDF(logs, userName);
          triggerSuccess('EXPORT_PDF');
          break;

        case 'LOGOUT':
          await supabaseService.signOut();
          localStorage.removeItem(SUPABASE_CACHE_KEY);
          setSession(null);
          setLogs([]);
          setConfirmingAction(null);
          setShowSettings(false);
          break;

        case 'RESET_SYSTEM':
          await supabaseService.deleteAllLogs();
          setLogs([]);
          localStorage.removeItem(SUPABASE_CACHE_KEY);
          setUserName('Operador Logístico');
          localStorage.removeItem('logcash_user_name');
          triggerSuccess('RESET_SYSTEM');
          break;
      }
    } catch (err) {
      setToastMsg('Erro na operação.');
      setShowToast(true);
      setTimeout(() => setShowToast(false), 2000);
    } finally {
      setIsExecuting(false);
    }
  };

  const executeBulkAction = async () => {
    if (!bulkActionPending || isExecuting) return;
    setIsExecuting(true);

    const { type, quantity } = bulkActionPending;
    const newEntries = Array.from({ length: quantity }).map(() => ({
      type: type as LogActionType,
      timestamp: new Date().toISOString(),
      value: type === 'SAIDA' ? VALOR_POR_PACOTE : 0
    }));

    try {
      await supabaseService.saveBulkLogs(newEntries);
      triggerSuccess(type, quantity);
    } catch (err) {
      setToastMsg('Falha no lote.');
      setShowToast(true);
      setTimeout(() => setShowToast(false), 2000);
    } finally {
      setIsExecuting(false);
    }
  };

  const counts = useMemo(() => {
    const todayStr = new Date().toDateString();
    const now = new Date();
    const startOfWeek = new Date(now);
    startOfWeek.setDate(now.getDate() - now.getDay());
    startOfWeek.setHours(0, 0, 0, 0);
    const startOfYear = new Date(now.getFullYear(), 0, 1);

    const deliveredLogs = logs.filter(l => l.type === 'SAIDA');
    const pending = deliveredLogs.filter(l => !l.isPaid).length * VALOR_POR_PACOTE;
    const paidCurrentCycle = deliveredLogs.filter(l => l.isPaid && new Date(l.timestamp) >= startOfWeek).length * VALOR_POR_PACOTE;
    const totalCumulativePaid = deliveredLogs.filter(l => l.isPaid).length * VALOR_POR_PACOTE;

    return {
      today: logs.filter(l => l.type === 'SAIDA' && new Date(l.timestamp).toDateString() === todayStr).length,
      week: logs.filter(l => l.type === 'SAIDA' && new Date(l.timestamp) >= startOfWeek).length,
      year: logs.filter(l => l.type === 'SAIDA' && new Date(l.timestamp) >= startOfYear).length,
      wallet: {
        pending,
        paid: paidCurrentCycle,
        cumulative: totalCumulativePaid
      }
    };
  }, [logs]);

  if (!session && !loading) return <Login onLoginSuccess={() => supabaseService.getSession().then(setSession)} />;

  if (loading && logs.length === 0) {
    return (
      <div className="min-h-screen bg-[#020617] flex flex-col items-center justify-center p-6 text-center">
        <LogCashLogo size={60} />
        <p className="text-slate-500 font-game font-bold uppercase tracking-[0.3em] text-[10px] animate-pulse mt-4">Conectando Terminal...</p>
      </div>
    );
  }

  const formatBRL = (val: number) => new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(val);

  const getPopupStyles = (type: SystemActionType) => {
    switch (type) {
      case 'ENTRADA': return { bg: 'from-emerald-600 to-emerald-950', border: 'border-emerald-400/40', text: 'text-emerald-400', label: 'Entrada Registrada' };
      case 'SAIDA': return { bg: 'from-blue-600 to-blue-950', border: 'border-blue-400/40', text: 'text-blue-400', label: 'Entrega Concluída' };
      case 'DEVOLUCAO': return { bg: 'from-orange-600 to-orange-950', border: 'border-orange-400/40', text: 'text-orange-400', label: 'Retorno Processado' };
      case 'SETTLE_WALLET': return { bg: 'from-indigo-600 to-indigo-950', border: 'border-indigo-400/40', text: 'text-indigo-400', label: 'Pagamento Liquidado' };
      case 'EXPORT_PDF': return { bg: 'from-slate-700 to-slate-900', border: 'border-white/20', text: 'text-white', label: 'Extrato Gerado' };
      case 'RESET_SYSTEM': return { bg: 'from-red-600 to-red-950', border: 'border-red-400/40', text: 'text-red-400', label: 'Sistema Resetado' };
      default: return { bg: 'from-slate-700 to-slate-900', border: 'border-white/20', text: 'text-white', label: 'Sucesso' };
    }
  };

  const currentTheme = getPopupStyles(successType);

  return (
    <div className="min-h-screen bg-[#020617] text-slate-200 selection:bg-emerald-500/30 flex flex-col overflow-x-hidden relative">
      <header className="bg-slate-900/80 backdrop-blur-xl border-b border-white/5 px-4 md:px-8 sticky top-0 z-40 pt-safe transition-all h-20">
        <div className="max-w-5xl mx-auto flex justify-between items-center h-full">
          <div className="flex items-center gap-3">
            <LogCashLogo size={36} />
            <div>
              <h1 className="text-xl font-game font-black tracking-[0.1em] text-white leading-none">LOG<span className="text-emerald-400">CASH</span></h1>
              <p className="text-[8px] text-slate-500 font-bold uppercase tracking-widest mt-1">{isSyncing ? 'Sincronizando...' : 'Conectado'}</p>
            </div>
          </div>
          <button onClick={() => setShowSettings(true)} className="p-3 bg-white/5 rounded-2xl border border-white/10 active:scale-95 transition-all hover:bg-white/10 flex items-center gap-2">
            <Settings size={20} className="text-slate-400" />
            <span className="hidden sm:block text-[10px] font-black text-slate-400 uppercase tracking-widest">Ajustes</span>
          </button>
        </div>
      </header>

      <main className="flex-1 max-w-5xl mx-auto w-full p-4 md:p-8 space-y-8 pb-28 md:pb-12 transition-all">
        {activeTab === 'dash' ? (
          <div className="animate-in fade-in duration-500">
            <div className="mb-8">
              <h2 className="text-3xl md:text-5xl font-game font-black text-white uppercase tracking-tight leading-tight">Olá, {userName.split(' ')[0]}</h2>
              <p className="text-[10px] md:text-xs text-slate-500 font-bold uppercase tracking-[0.4em] mt-2">Dashboard Operacional</p>
            </div>

            <div className="grid grid-cols-1 lg:grid-cols-5 gap-6 mb-10">
              <div className="lg:col-span-3"><DashboardCards today={counts.today} week={counts.week} year={counts.year} /></div>
              <div className="lg:col-span-2"><WalletCard pendingAmount={counts.wallet.pending} paidAmount={counts.wallet.paid} totalCumulativePaid={counts.wallet.cumulative} onSettle={() => setConfirmingAction('SETTLE_WALLET')} /></div>
            </div>

            <section className="space-y-4 mb-10">
              <ActionButtons onAction={(type) => setConfirmingAction(type)} />
            </section>

            <section className="grid grid-cols-2 gap-4 mb-10">
              <button onClick={() => setBulkModal({ isOpen: true, type: 'ENTRADA' })} className="bg-slate-900/40 border border-white/5 p-6 rounded-3xl flex flex-col items-start gap-4 active:scale-95 hover:bg-white/[0.03] transition-all">
                <div className="p-3 bg-emerald-600/10 text-emerald-400 rounded-2xl border border-emerald-500/20"><ListPlus size={24} /></div>
                <div className="text-left"><p className="font-game font-black text-white text-sm uppercase tracking-widest">Lote Entrada</p><p className="text-[8px] text-slate-500 uppercase font-bold mt-1">Multi-Checkin</p></div>
              </button>
              <button onClick={() => setBulkModal({ isOpen: true, type: 'SAIDA' })} className="bg-slate-900/40 border border-white/5 p-6 rounded-3xl flex flex-col items-start gap-4 active:scale-95 hover:bg-white/[0.03] transition-all">
                <div className="p-3 bg-blue-600/10 text-blue-400 rounded-2xl border border-blue-500/20"><Send size={24} /></div>
                <div className="text-left"><p className="font-game font-black text-white text-sm uppercase tracking-widest">Lote Saída</p><p className="text-[8px] text-slate-500 uppercase font-bold mt-1">Multi-Entrega</p></div>
              </button>
            </section>

            <section className="bg-slate-900/50 p-6 md:p-10 rounded-[3rem] border border-white/5 relative overflow-hidden group text-center">
              <div className="flex flex-col items-center gap-4 mb-6">
                <div className="p-4 bg-emerald-500/10 rounded-full border border-emerald-500/20"><FileText size={32} className="text-emerald-400" /></div>
                <h3 className="font-game font-black text-white uppercase tracking-[0.2em] text-lg">Relatórios</h3>
              </div>
              <button onClick={() => setConfirmingAction('EXPORT_PDF')} className="w-full bg-emerald-600 hover:bg-emerald-500 py-5 rounded-[1.5rem] flex items-center justify-center gap-3 font-game font-black text-white active:scale-95 text-xs uppercase tracking-[0.4em] transition-all shadow-2xl shadow-emerald-900/30 border border-emerald-400/20">
                <Download size={22} /> Gerar PDF Completo
              </button>
            </section>
          </div>
        ) : (
          <div className="animate-in fade-in duration-500"><DailyStatsTable logs={logs} /></div>
        )}
      </main>

      <nav className="fixed bottom-0 left-0 right-0 glass-card border-t border-white/10 md:hidden z-50">
        <div className="flex justify-around items-center h-20 max-w-lg mx-auto">
          <button onClick={() => setActiveTab('dash')} className={`flex flex-col items-center justify-center w-full h-full gap-1 transition-all ${activeTab === 'dash' ? 'text-emerald-400 scale-110' : 'text-slate-600'}`}>
            <LayoutDashboard size={24} strokeWidth={activeTab === 'dash' ? 2.5 : 2} /><span className="text-[9px] font-black uppercase tracking-[0.2em]">Dash</span>
          </button>
          <button onClick={() => setActiveTab('stats')} className={`flex flex-col items-center justify-center w-full h-full gap-1 transition-all ${activeTab === 'stats' ? 'text-emerald-400 scale-110' : 'text-slate-600'}`}>
            <TableIcon size={24} strokeWidth={activeTab === 'stats' ? 2.5 : 2} /><span className="text-[9px] font-black uppercase tracking-[0.2em]">Fluxo</span>
          </button>
        </div>
        <div className="h-safe bg-slate-950"></div>
      </nav>

      {/* MODAL DE CONFIRMAÇÃO UNIFICADO (Pop-up Gamificado) */}
      {confirmingAction && (
        <div className="fixed inset-0 z-[600] flex items-center justify-center p-6 bg-black/95 backdrop-blur-2xl">
          <div className="w-full max-w-sm glass-deep rounded-[3.5rem] p-10 border border-white/20 animate-pop-burst text-center relative overflow-hidden">
            <div className="absolute top-0 inset-x-0 h-1.5 bg-gradient-to-r from-transparent via-white/20 to-transparent"></div>

            <div className={`w-24 h-24 mx-auto bg-white/5 rounded-3xl flex items-center justify-center mb-8 border border-white/10 animate-float-bounce ${
              confirmingAction === 'ENTRADA' ? 'text-emerald-400 shadow-[0_0_40px_rgba(52,211,153,0.15)]' : 
              confirmingAction === 'SAIDA' ? 'text-blue-400 shadow-[0_0_40px_rgba(59,130,246,0.15)]' : 
              confirmingAction === 'RESET_SYSTEM' || confirmingAction === 'LOGOUT' ? 'text-red-400 shadow-[0_0_40px_rgba(239,68,68,0.15)]' :
              confirmingAction === 'SETTLE_WALLET' ? 'text-indigo-400 shadow-[0_0_40px_rgba(99,102,241,0.15)]' : 'text-orange-400'
            }`}>
              {confirmingAction === 'ENTRADA' && <ArrowDownLeft size={48} strokeWidth={3} />}
              {confirmingAction === 'SAIDA' && <ArrowUpRight size={48} strokeWidth={3} />}
              {confirmingAction === 'DEVOLUCAO' && <RotateCcw size={48} strokeWidth={3} />}
              {confirmingAction === 'EXPORT_PDF' && <FileText size={48} strokeWidth={2} />}
              {confirmingAction === 'LOGOUT' && <LogOut size={48} strokeWidth={2} />}
              {confirmingAction === 'RESET_SYSTEM' && <Database size={48} strokeWidth={2} />}
              {confirmingAction === 'SETTLE_WALLET' && <Wallet size={48} strokeWidth={2} />}
            </div>

            <h3 className="text-3xl font-game font-black text-white uppercase tracking-tighter mb-4 leading-none">
              {confirmingAction === 'ENTRADA' ? 'Confirmar Entrada?' : 
               confirmingAction === 'SAIDA' ? 'Confirmar Saída?' : 
               confirmingAction === 'DEVOLUCAO' ? 'Confirmar Retorno?' :
               confirmingAction === 'EXPORT_PDF' ? 'Gerar Extrato?' :
               confirmingAction === 'LOGOUT' ? 'Encerrar Sessão?' :
               confirmingAction === 'SETTLE_WALLET' ? 'Receber Saldo?' :
               'Confirmar Reset?'}
            </h3>

            <p className="text-[10px] text-slate-500 font-bold uppercase tracking-[0.4em] mb-10 leading-relaxed px-4 opacity-80">
              {confirmingAction === 'SETTLE_WALLET' ? `Você liquidará ${formatBRL(counts.wallet.pending)}` : 'Validação de Segurança Necessária'}
            </p>

            <div className="space-y-4">
              <button disabled={isExecuting} onClick={handleGlobalConfirm} className={`w-full py-5 rounded-2xl font-game font-black text-sm uppercase tracking-[0.4em] shadow-2xl transition-all active:scale-95 text-white btn-confirm-impact flex items-center justify-center gap-3 shine-container overflow-hidden ${
                confirmingAction === 'RESET_SYSTEM' || confirmingAction === 'LOGOUT' ? 'bg-red-600 shadow-red-900/40' : 'bg-emerald-600 shadow-emerald-900/40'
              }`}>
                <div className="shine-overlay"></div>
                {isExecuting ? <div className="w-5 h-5 border-2 border-white/30 border-t-white rounded-full animate-spin"></div> : 'Confirmar Ação'}
              </button>
              <button disabled={isExecuting} onClick={() => setConfirmingAction(null)} className="w-full py-4 bg-white/5 hover:bg-white/10 text-slate-500 font-bold uppercase text-[10px] tracking-widest rounded-xl transition-all">Cancelar</button>
            </div>
          </div>
        </div>
      )}

      {/* MODAL LOTE (BULK) - INTEGRADO */}
      {bulkActionPending && (
        <div className="fixed inset-0 z-[650] flex items-center justify-center p-6 bg-black/95 backdrop-blur-2xl">
          <div className="w-full max-w-md glass-deep rounded-[3.5rem] p-10 border border-white/20 animate-pop-burst text-center relative overflow-hidden">
             <div className={`absolute top-0 inset-x-0 h-2 bg-gradient-to-r ${bulkActionPending.type === 'SAIDA' ? 'from-blue-600 via-white/40 to-blue-600' : 'from-emerald-600 via-white/40 to-emerald-600'}`}></div>
             <div className={`w-28 h-28 mx-auto bg-white/5 rounded-[2.5rem] flex items-center justify-center mb-8 border border-white/10 animate-float-bounce ${bulkActionPending.type === 'ENTRADA' ? 'text-emerald-400 shadow-[0_0_50px_rgba(52,211,153,0.2)]' : 'text-blue-400 shadow-[0_0_50px_rgba(59,130,246,0.2)]'}`}>
               <Package size={54} strokeWidth={1.5} />
             </div>
             <h3 className="text-3xl font-game font-black text-white uppercase tracking-tighter mb-2 leading-none">Confirmar Lote?</h3>
             <div className="flex flex-col items-center gap-2 mb-10">
               <div className={`px-6 py-2 rounded-2xl border text-2xl font-game font-black tracking-widest ${bulkActionPending.type === 'ENTRADA' ? 'bg-emerald-500/10 border-emerald-500/20 text-emerald-400' : 'bg-blue-500/10 border-blue-500/20 text-blue-400'}`}>{bulkActionPending.quantity} UNIDADES</div>
               {bulkActionPending.type === 'SAIDA' && <div className="text-emerald-400 font-game font-black text-xl tracking-widest mt-2">+ {formatBRL(bulkActionPending.quantity * VALOR_POR_PACOTE)}</div>}
             </div>
             <div className="space-y-4">
               <button disabled={isExecuting} onClick={executeBulkAction} className={`w-full py-5 rounded-2xl font-game font-black text-sm uppercase tracking-[0.4em] shadow-2xl transition-all active:scale-95 text-white flex items-center justify-center gap-3 shine-container overflow-hidden ${bulkActionPending.type === 'ENTRADA' ? 'bg-emerald-600 shadow-emerald-900/40' : 'bg-blue-600 shadow-blue-900/40'}`}>
                 <div className="shine-overlay"></div>
                 {isExecuting ? <div className="w-5 h-5 border-2 border-white/30 border-t-white rounded-full animate-spin"></div> : 'Confirmar Lote'}
               </button>
               <button disabled={isExecuting} onClick={() => setBulkActionPending(null)} className="w-full py-4 bg-white/5 text-slate-500 font-bold uppercase text-[10px] tracking-widest rounded-xl">Voltar</button>
             </div>
          </div>
        </div>
      )}

      {/* POPUP SUCESSO UNIFICADO (Minimiza ao Toque) */}
      {showSuccessPopup && (
        <div onClick={closeSuccessPopup} className="fixed inset-0 z-[700] flex items-center justify-center p-6 cursor-pointer overflow-hidden bg-black/50 backdrop-blur-sm">
          <div className={`w-full max-w-sm glass-deep bg-gradient-to-b ${currentTheme.bg} ${currentTheme.border} border-2 rounded-[3.5rem] p-12 flex flex-col items-center text-center ${isClosingSuccess ? 'animate-pop-minimize' : 'animate-pop-burst'} relative transition-all`}>
            <div className="absolute inset-0 flex items-center justify-center pointer-events-none opacity-50"><Sparkles size={180} className={`${currentTheme.text} animate-pulse`} strokeWidth={0.5} /></div>
            <div className="relative mb-10 z-10 flex items-center justify-center">
              <div className={`absolute w-32 h-32 border-4 border-white/40 rounded-full animate-ring-pulse`}></div>
              <div className={`w-28 h-28 bg-white/10 backdrop-blur-3xl border border-white/30 rounded-full flex items-center justify-center shadow-2xl animate-float-bounce`}>
                <Check size={ successType === 'SETTLE_WALLET' ? 64 : 50 } className="text-white" strokeWidth={4} />
              </div>
            </div>
            <h4 className="text-3xl font-game font-black text-white uppercase tracking-tighter leading-none mb-4 drop-shadow-2xl z-10">{currentTheme.label}</h4>
            <div className="w-full h-px bg-white/20 mb-8 z-10"></div>
            <div className="space-y-4 z-10 w-full">
              {successType === 'SETTLE_WALLET' ? <div className="px-8 py-4 bg-white/10 rounded-3xl border border-white/20 shadow-inner"><span className="text-4xl font-game font-black text-white">{formatBRL(lastSettleValue)}</span></div> : 
               (successType === 'ENTRADA' || successType === 'SAIDA' || successType === 'DEVOLUCAO') && <div className="px-8 py-3 bg-white/10 rounded-2xl border border-white/20 text-3xl font-game font-black text-white">{bulkCount} UNID.</div>}
              <p className="text-[10px] text-white/60 font-game font-bold uppercase tracking-[0.7em] pt-6 opacity-90 leading-relaxed italic">Cloud Sync Complete</p>
            </div>
            <div className="absolute bottom-6 left-16 right-16 h-1 bg-white/20 rounded-full overflow-hidden"><div className="h-full bg-white animate-timer"></div></div>
          </div>
        </div>
      )}

      {/* PAINEL DE AJUSTES */}
      {showSettings && (
        <div className="fixed inset-0 z-[100] flex items-end md:items-center justify-center bg-black/90 backdrop-blur-md p-0 md:p-4">
          <div className="bg-slate-900 w-full max-w-lg rounded-t-[3rem] md:rounded-[3rem] border-t md:border border-white/10 overflow-hidden animate-in slide-in-from-bottom-full duration-500">
             <div className="px-8 py-6 border-b border-white/5 flex justify-between items-center"><h3 className="font-game font-black text-white uppercase tracking-[0.2em] text-sm">Configurações</h3><button onClick={() => setShowSettings(false)} className="p-3 bg-white/5 rounded-full text-slate-500"><X size={20} /></button></div>
             <div className="p-8 md:p-12 space-y-8">
                <div className="space-y-4"><label className="text-[10px] font-black text-slate-600 uppercase tracking-[0.4em] ml-1">Assinatura Logística</label><div className="relative group"><User className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-600" size={18} /><input type="text" value={userName} onChange={(e) => setUserName(e.target.value)} className="w-full bg-black/40 border border-white/10 rounded-2xl pl-12 pr-4 py-5 text-sm font-bold text-white focus:outline-none focus:border-emerald-500/50 transition-all" /></div></div>
                <div className="pt-4 flex flex-col gap-3">
                  <button onClick={() => setConfirmingAction('LOGOUT')} className="w-full p-6 bg-slate-800/50 border border-white/5 text-slate-400 rounded-3xl flex items-center justify-between font-game font-black uppercase tracking-widest text-xs active:scale-95 transition-all hover:text-red-500 hover:bg-red-500/5">Encerrar Sessão <LogOut size={20} /></button>
                  <button onClick={() => setConfirmingAction('RESET_SYSTEM')} className="w-full p-6 bg-red-500/5 border border-red-500/10 text-red-500 rounded-3xl flex items-center justify-between font-game font-black uppercase tracking-widest text-xs active:scale-95 transition-all">Resetar Banco <Database size={20} /></button>
                </div>
             </div>
             <div className="h-safe bg-slate-900 pb-safe"></div>
          </div>
        </div>
      )}

      <BulkActionModal isOpen={bulkModal.isOpen} type={bulkModal.type} title={bulkModal.type === 'SAIDA' ? 'Saída em Massa' : 'Entrada em Massa'} onClose={() => setBulkModal({ ...bulkModal, isOpen: false })} onConfirm={(q) => setBulkActionPending({ type: bulkModal.type, quantity: q })} />
    </div>
  );
};

export default App;

