import { supabase } from "../supabaseConfig";
import { LogEntry } from "../types";

const TABLE_NAME = "logs";

// Utilitário para limpar campos undefined antes de enviar ao Supabase
const cleanPayload = (payload: any) => {
  return JSON.parse(JSON.stringify(payload));
};

export const supabaseService = {
  // --- AUTH METHODS ---
  signUp: async (email: string, pass: string) => {
    const { data, error } = await supabase.auth.signUp({ email, password: pass });
    if (error) throw error;
    return data;
  },

  signIn: async (email: string, pass: string) => {
    const { data, error } = await supabase.auth.signInWithPassword({ email, password: pass });
    if (error) throw error;
    return data;
  },

  signOut: async () => {
    const { error } = await supabase.auth.signOut();
    if (error) throw error;
  },

  getSession: async () => {
    const { data: { session } } = await supabase.auth.getSession();
    return session;
  },

  // --- LOG METHODS (COM ISOLAMENTO ESTRITO) ---
  subscribeToLogs: (callback: (logs: LogEntry[], error?: any) => void) => {
    let channel: any = null;

    const fetchAndSubscribe = async () => {
      const { data: { user } } = await supabase.auth.getUser();

      // Se não houver usuário, retorna vazio imediatamente para evitar vazamento
      if (!user) {
        callback([], null);
        return;
      }

      // Função interna para buscar dados com filtro estrito
      const fetchData = async () => {
        try {
          const { data, error } = await supabase
            .from(TABLE_NAME)
            .select("*")
            .eq('user_id', user.id) // FILTRO OBRIGATÓRIO
            .order("timestamp", { ascending: false });

          if (error) {
            console.error("Erro ao buscar logs (Isolamento Ativo):", error.message);
            // Em caso de erro, retorna vazio. NUNCA retorna todos os dados.
            callback([], error);
          } else {
            // Dupla verificação no cliente para garantir que nenhum dado vazou do banco
            const isolatedData = (data as LogEntry[]).filter(log => log.user_id === user.id);
            callback(isolatedData);
          }
        } catch (err) {
          console.error("Erro crítico no fetch:", err);
          callback([], err);
        }
      };

      // 1. Busca inicial
      await fetchData();

      // 2. Configura Realtime com filtro de usuário
      channel = supabase
        .channel(`user_updates_${user.id}`) // Canal único por usuário
        .on(
          "postgres_changes",
          { 
            event: "*", 
            schema: "public", 
            table: TABLE_NAME,
            filter: `user_id=eq.${user.id}` // Escuta apenas eventos deste usuário
          },
          () => {
            fetchData();
          }
        )
        .subscribe();
    };

    fetchAndSubscribe();

    return () => {
      if (channel) supabase.removeChannel(channel);
    };
  },

  // Inserção Segura
  saveLog: async (entry: Omit<LogEntry, 'id'>) => {
    const { data: { user } } = await supabase.auth.getUser();
    if (!user) throw new Error("Usuário desconectado. Operação abortada para segurança.");

    const payload = { 
      type: entry.type,
      timestamp: entry.timestamp,
      value: entry.value,
      user_id: user.id, // Vínculo obrigatório
      isPaid: entry.type === 'SAIDA' ? false : undefined
    };

    // Removemos o try/catch com fallback. Se falhar, deve retornar erro para o usuário saber.
    const { error } = await supabase.from(TABLE_NAME).insert([cleanPayload(payload)]);

    if (error) {
      console.error("Erro ao salvar log:", error);
      throw error;
    }
  },

  saveBulkLogs: async (entries: Omit<LogEntry, 'id'>[]) => {
    const { data: { user } } = await supabase.auth.getUser();
    if (!user) throw new Error("Usuário desconectado.");

    const payloads = entries.map(e => ({
      type: e.type,
      timestamp: e.timestamp,
      value: e.value,
      user_id: user.id,
      isPaid: e.type === 'SAIDA' ? false : undefined
    }));

    const { error } = await supabase.from(TABLE_NAME).insert(cleanPayload(payloads));
    if (error) throw error;
  },

  markAllAsPaid: async () => {
    const { data: { user } } = await supabase.auth.getUser();
    if (!user) return;

    // Garante que só atualiza registros do próprio usuário
    const { error } = await supabase
      .from(TABLE_NAME)
      .update({ isPaid: true })
      .eq('user_id', user.id)
      .eq('isPaid', false)
      .eq('type', 'SAIDA');

    if (error) throw error;
  },

  deleteAllLogs: async () => {
    const { data: { user } } = await supabase.auth.getUser();
    if (!user) return;

    // Garante que só deleta registros do próprio usuário
    const { error } = await supabase
        .from(TABLE_NAME)
        .delete()
        .eq('user_id', user.id);

    if (error) throw error;
  }
};

import { supabase } from "../supabaseConfig";
import { LogEntry } from "../types";

const TABLE_NAME = "logs";

// Utilitário para limpar campos undefined antes de enviar ao Supabase
const cleanPayload = (payload: any) => {
  return JSON.parse(JSON.stringify(payload));
};

export const supabaseService = {
  // --- AUTH METHODS ---
  signUp: async (email: string, pass: string) => {
    const { data, error } = await supabase.auth.signUp({ email, password: pass });
    if (error) throw error;
    return data;
  },

  signIn: async (email: string, pass: string) => {
    const { data, error } = await supabase.auth.signInWithPassword({ email, password: pass });
    if (error) throw error;
    return data;
  },

  signOut: async () => {
    const { error } = await supabase.auth.signOut();
    if (error) throw error;
  },

  getSession: async () => {
    const { data: { session } } = await supabase.auth.getSession();
    return session;
  },

  // --- LOG METHODS (COM ISOLAMENTO HÍBRIDO) ---
  subscribeToLogs: (callback: (logs: LogEntry[], error?: any) => void) => {
    let channel: any = null;

    const fetchAndSubscribe = async () => {
      const { data: { user } } = await supabase.auth.getUser();

      // Se não houver usuário, retorna vazio imediatamente
      if (!user) {
        callback([], null);
        return;
      }

      // Função interna para buscar dados
      const fetchData = async () => {
        try {
          const { data, error } = await supabase
            .from(TABLE_NAME)
            .select("*")
            .order("timestamp", { ascending: false });

          if (error) {
            console.error("Erro ao buscar logs:", error.message);
            callback([], error);
          } else {
            // FILTRO HÍBRIDO: Aceita dados do usuário OU dados legados (sem user_id)
            // Isso previne que a tela fique vazia caso o insert falhe no modo seguro e caia no fallback
            const isolatedData = (data as LogEntry[]).filter(log => 
              log.user_id === user.id || !log.user_id
            );
            callback(isolatedData);
          }
        } catch (err) {
          console.error("Erro crítico no fetch:", err);
          callback([], err);
        }
      };

      // 1. Busca inicial
      await fetchData();

      // 2. Configura Realtime
      // Nota: No modo híbrido, escutamos tudo e filtramos no client para garantir compatibilidade
      channel = supabase
        .channel(`public_logs_feed`)
        .on(
          "postgres_changes",
          { 
            event: "*", 
            schema: "public", 
            table: TABLE_NAME
          },
          () => {
            fetchData();
          }
        )
        .subscribe();
    };

    fetchAndSubscribe();

    return () => {
      if (channel) supabase.removeChannel(channel);
    };
  },

  // Inserção com FALLBACK (Tenta Seguro -> Tenta Legado)
  saveLog: async (entry: Omit<LogEntry, 'id'>) => {
    const { data: { user } } = await supabase.auth.getUser();
    if (!user) throw new Error("Usuário desconectado.");

    const payload = { 
      type: entry.type,
      timestamp: entry.timestamp,
      value: entry.value,
      user_id: user.id, // Tentativa 1: Com ID
      isPaid: entry.type === 'SAIDA' ? false : undefined
    };

    // 1. Tenta salvar com user_id
    const { error } = await supabase.from(TABLE_NAME).insert([cleanPayload(payload)]);

    if (error) {
      console.warn("Erro no insert seguro (possível falta de coluna user_id). Tentando modo legado...", error.message);

      // 2. Fallback: Remove user_id e tenta de novo
      const legacyPayload = { ...payload };
      delete (legacyPayload as any).user_id;

      const { error: legacyError } = await supabase.from(TABLE_NAME).insert([cleanPayload(legacyPayload)]);

      if (legacyError) {
        // Se ambos falharem, lança o erro original (mais provável ser a causa real se não for coluna) ou o legado
        console.error("Falha total no salvamento:", legacyError);
        throw legacyError;
      }
    }
  },

  saveBulkLogs: async (entries: Omit<LogEntry, 'id'>[]) => {
    const { data: { user } } = await supabase.auth.getUser();
    if (!user) throw new Error("Usuário desconectado.");

    const payloads = entries.map(e => ({
      type: e.type,
      timestamp: e.timestamp,
      value: e.value,
      user_id: user.id,
      isPaid: e.type === 'SAIDA' ? false : undefined
    }));

    // 1. Tenta salvar com user_id
    const { error } = await supabase.from(TABLE_NAME).insert(cleanPayload(payloads));

    if (error) {
       console.warn("Erro no insert em lote seguro. Tentando modo legado...", error.message);

       // 2. Fallback
       const legacyPayloads = payloads.map(p => {
         const copy = { ...p };
         delete (copy as any).user_id;
         return copy;
       });

       const { error: legacyError } = await supabase.from(TABLE_NAME).insert(cleanPayload(legacyPayloads));
       if (legacyError) throw legacyError;
    }
  },

  markAllAsPaid: async () => {
    const { data: { user } } = await supabase.auth.getUser();
    if (!user) return;

    // Tenta marcar apenas os do usuário
    const { error } = await supabase
      .from(TABLE_NAME)
      .update({ isPaid: true })
      .eq('user_id', user.id)
      .eq('isPaid', false)
      .eq('type', 'SAIDA');

    // Se não afetou linhas ou deu erro (ex: coluna user_id nao existe), 
    // não tentamos marcar "todos" globalmente por segurança financeira.
    // Apenas ignoramos se for erro de coluna inexistente para não travar a UI.
    if (error && !error.message.includes("column")) throw error;
  },

  deleteAllLogs: async () => {
    const { data: { user } } = await supabase.auth.getUser();
    if (!user) return;

    // Tenta deletar pelo ID
    const { error } = await supabase
        .from(TABLE_NAME)
        .delete()
        .eq('user_id', user.id);

    if (error) {
      // Se falhar (ex: coluna user_id não existe), não deletamos tudo para não apagar dados de outros.
      console.error("Erro ao deletar logs:", error.message);
      throw error;
    }
  }
};

import React, { useState, useEffect, useMemo } from 'react';
import { Truck, Zap, FileText, Download, LayoutDashboard, Send, Table as TableIcon, ListPlus, LogOut, Layers, Settings, Trash2, AlertCircle, User, Sliders, ChevronRight, X, CheckCircle2, Check, Wallet, AlertTriangle, ArrowDownLeft, ArrowUpRight, RotateCcw, Sparkles, Package, LogIn, Database, Map, MapPin } from 'lucide-react';
import DashboardCards from './components/DashboardCards';
import ActionButtons from './components/ActionButtons';
import DailyStatsTable from './components/DailyStatsTable';
import DailyRouteHistory from './components/DailyRouteHistory';
import BulkActionModal from './components/BulkActionModal';
import WalletCard from './components/WalletCard';
import Login from './components/Login';
import { LogCashLogo } from './components/Logo';
import { LogEntry, LogActionType } from './types';
import { supabaseService } from './services/supabaseService';
import { generatePDF } from './services/pdfService';
import { VALOR_POR_PACOTE } from './constants';

type SystemActionType = LogActionType | 'EXPORT_PDF' | 'LOGOUT' | 'RESET_SYSTEM' | 'SETTLE_WALLET';

const App: React.FC = () => {
  const [session, setSession] = useState<any>(null);
  const [logs, setLogs] = useState<LogEntry[]>([]); 
  const [loading, setLoading] = useState(true);
  const [isSyncing, setIsSyncing] = useState(false);

  // Feedback Visual
  const [showToast, setShowToast] = useState(false);
  const [toastMsg, setToastMsg] = useState('');

  // Estados de Pop-up de Sucesso
  const [showSuccessPopup, setShowSuccessPopup] = useState(false);
  const [isClosingSuccess, setIsClosingSuccess] = useState(false);
  const [bulkCount, setBulkCount] = useState(0);
  const [lastSettleValue, setLastSettleValue] = useState(0);
  const [successType, setSuccessType] = useState<SystemActionType>('ENTRADA');

  // Estado Unificado de Confirmação
  const [confirmingAction, setConfirmingAction] = useState<SystemActionType | null>(null);
  const [bulkActionPending, setBulkActionPending] = useState<{ type: 'ENTRADA' | 'SAIDA'; quantity: number } | null>(null);

  // Controle de Execução (Bloqueio de duplo clique)
  const [isExecuting, setIsExecuting] = useState(false);

  const [userName, setUserName] = useState(() => localStorage.getItem('logcash_user_name') || 'Operador Logístico');
  const [activeTab, setActiveTab] = useState<'dash' | 'stats' | 'route'>('dash');
  const [showSettings, setShowSettings] = useState(false);

  const [bulkModal, setBulkModal] = useState<{ isOpen: boolean; type: 'ENTRADA' | 'SAIDA' }>({
    isOpen: false,
    type: 'ENTRADA'
  });

  // 1. Verifica Sessão
  useEffect(() => {
    supabaseService.getSession().then(session => {
      setSession(session);
      if (!session) setLoading(false);
    });
  }, []);

  // 2. Sincronização
  useEffect(() => {
    if (!session?.user) {
      setLogs([]); 
      return;
    }

    const userId = session.user.id;
    const userCacheKey = `logcash_cache_${userId}`;

    // Cache Inicial (Melhora percepção de velocidade)
    try {
      const cached = localStorage.getItem(userCacheKey);
      if (cached) setLogs(JSON.parse(cached));
    } catch (e) { console.error(e); }

    setIsSyncing(true);

    const unsubscribe = supabaseService.subscribeToLogs((updatedLogs, supabaseError) => {
      if (!supabaseError) {
        setLogs(updatedLogs);
        localStorage.setItem(userCacheKey, JSON.stringify(updatedLogs));
      }
      setLoading(false);
      setIsSyncing(false);
    });

    return () => unsubscribe();
  }, [session]);

  useEffect(() => {
    localStorage.setItem('logcash_user_name', userName);
  }, [userName]);

  // Função auxiliar para mostrar Toast de Erro
  const showError = (msg: string) => {
    setToastMsg(msg);
    setShowToast(true);
    setTimeout(() => setShowToast(false), 4000);
  };

  const triggerSuccess = (type: SystemActionType, count: number = 1) => {
    setSuccessType(type);
    setBulkCount(count);
    setConfirmingAction(null);
    setBulkActionPending(null);
    setShowSettings(false);

    setTimeout(() => {
      setShowSuccessPopup(true);
      setTimeout(closeSuccessPopup, 2400); // Popup fecha sozinho
    }, 100);
  };

  const closeSuccessPopup = () => {
    if (isClosingSuccess) return;
    setIsClosingSuccess(true);
    setTimeout(() => {
      setShowSuccessPopup(false);
      setIsClosingSuccess(false);
    }, 400);
  };

  const handleGlobalConfirm = async () => {
    if (isExecuting || !confirmingAction) return;

    const actionToExecute = confirmingAction; 
    setIsExecuting(true);

    // --- OPTIMISTIC UI: Preparação ---
    const previousLogs = [...logs]; // Backup para rollback
    const tempId = `temp-${Date.now()}`;
    const timestamp = new Date().toISOString();

    try {
      switch (actionToExecute) {
        case 'ENTRADA':
        case 'SAIDA':
        case 'DEVOLUCAO':
          // 1. Atualização Otimista
          const newLog: LogEntry = {
            id: tempId,
            type: actionToExecute as LogActionType,
            timestamp,
            value: actionToExecute === 'SAIDA' ? VALOR_POR_PACOTE : 0,
            isPaid: false,
            user_id: session?.user?.id
          };
          setLogs(prev => [newLog, ...prev]);
          triggerSuccess(actionToExecute); // Feedback visual instantâneo

          // 2. Envio Real
          await supabaseService.saveLog({
            type: actionToExecute as LogActionType,
            timestamp,
            value: actionToExecute === 'SAIDA' ? VALOR_POR_PACOTE : 0
          });
          // Se der certo, o Realtime atualizará o log com o ID real depois
          break;

        case 'SETTLE_WALLET':
          const currentPending = counts.wallet.pending;
          setLastSettleValue(currentPending);

          // Otimista
          setLogs(prev => prev.map(l => (l.type === 'SAIDA' && !l.isPaid) ? { ...l, isPaid: true } : l));
          triggerSuccess('SETTLE_WALLET');

          // Real
          await supabaseService.markAllAsPaid();
          break;

        case 'EXPORT_PDF':
          generatePDF(logs, userName);
          triggerSuccess('EXPORT_PDF');
          break;

        case 'LOGOUT':
          const userId = session?.user?.id;
          await supabaseService.signOut();
          if (userId) localStorage.removeItem(`logcash_cache_${userId}`);
          setSession(null);
          setLogs([]);
          setConfirmingAction(null);
          setShowSettings(false);
          break;

        case 'RESET_SYSTEM':
          setLogs([]); // Otimista
          triggerSuccess('RESET_SYSTEM');

          await supabaseService.deleteAllLogs();
          if (session?.user?.id) localStorage.removeItem(`logcash_cache_${session.user.id}`);
          setUserName('Operador Logístico');
          localStorage.removeItem('logcash_user_name');
          break;
      }
    } catch (err: any) {
      console.error("Erro na ação:", err);
      // ROLLBACK em caso de erro
      if (['ENTRADA', 'SAIDA', 'DEVOLUCAO', 'SETTLE_WALLET', 'RESET_SYSTEM'].includes(actionToExecute)) {
        setLogs(previousLogs); 
        // Exibe a mensagem real do erro para facilitar diagnóstico (ex: coluna faltando)
        showError(err.message || "Erro de sincronização. Ação revertida.");
      } else {
        showError(err.message || 'Erro na operação.');
      }
    } finally {
      setIsExecuting(false);
    }
  };

  const executeBulkAction = async () => {
    if (!bulkActionPending || isExecuting) return;

    const pending = bulkActionPending;
    setIsExecuting(true);

    const { type, quantity } = pending;
    const previousLogs = [...logs];
    const timestamp = new Date().toISOString();

    try {
      // 1. Otimista
      const newEntriesOptimistic: LogEntry[] = Array.from({ length: quantity }).map((_, i) => ({
        id: `temp-bulk-${Date.now()}-${i}`,
        type: type as LogActionType,
        timestamp,
        value: type === 'SAIDA' ? VALOR_POR_PACOTE : 0,
        isPaid: false,
        user_id: session?.user?.id
      }));

      setLogs(prev => [...newEntriesOptimistic, ...prev]);
      triggerSuccess(type, quantity);

      // 2. Real
      const payload = newEntriesOptimistic.map(e => ({
        type: e.type,
        timestamp: e.timestamp,
        value: e.value
      }));

      await supabaseService.saveBulkLogs(payload);

    } catch (err: any) {
      console.error("Erro no lote:", err);
      setLogs(previousLogs); // Rollback
      showError(err.message || "Falha ao salvar lote. Tente novamente.");
    } finally {
      setIsExecuting(false);
    }
  };

  const counts = useMemo(() => {
    const todayStr = new Date().toDateString();
    const now = new Date();
    const startOfWeek = new Date(now);
    startOfWeek.setDate(now.getDate() - now.getDay());
    startOfWeek.setHours(0, 0, 0, 0);
    const startOfMonth = new Date(now.getFullYear(), now.getMonth(), 1);
    const startOfYear = new Date(now.getFullYear(), 0, 1);

    const deliveredLogs = logs.filter(l => l.type === 'SAIDA');
    const todayLogs = logs.filter(l => new Date(l.timestamp).toDateString() === todayStr);

    const pending = deliveredLogs.filter(l => !l.isPaid).length * VALOR_POR_PACOTE;
    const paidCurrentCycle = deliveredLogs.filter(l => l.isPaid && new Date(l.timestamp) >= startOfMonth).length * VALOR_POR_PACOTE;
    const totalCumulativePaid = deliveredLogs.filter(l => l.isPaid).length * VALOR_POR_PACOTE;

    return {
      today: todayLogs.filter(l => l.type === 'SAIDA').length,
      todayEntrada: todayLogs.filter(l => l.type === 'ENTRADA').length,
      todaySaida: todayLogs.filter(l => l.type === 'SAIDA').length,
      todayDevolucao: todayLogs.filter(l => l.type === 'DEVOLUCAO').length,
      week: logs.filter(l => l.type === 'SAIDA' && new Date(l.timestamp) >= startOfWeek).length,
      year: logs.filter(l => l.type === 'SAIDA' && new Date(l.timestamp) >= startOfYear).length,
      wallet: {
        pending,
        paid: paidCurrentCycle,
        cumulative: totalCumulativePaid
      }
    };
  }, [logs]);

  if (!session && !loading) return <Login onLoginSuccess={() => supabaseService.getSession().then(setSession)} />;

  if (loading && logs.length === 0) {
    return (
      <div className="min-h-screen bg-[#020617] flex flex-col items-center justify-center p-6 text-center">
        <LogCashLogo size={60} />
        <p className="text-slate-500 font-game font-bold uppercase tracking-[0.3em] text-[10px] animate-pulse mt-4">Conectando Terminal...</p>
      </div>
    );
  }

  const formatBRL = (val: number) => new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(val);

  const getPopupStyles = (type: SystemActionType) => {
    switch (type) {
      case 'ENTRADA': return { bg: 'from-emerald-600 to-emerald-950', border: 'border-emerald-400/40', text: 'text-emerald-400', label: 'Entrada Registrada' };
      case 'SAIDA': return { bg: 'from-blue-600 to-blue-950', border: 'border-blue-400/40', text: 'text-blue-400', label: 'Entrega Concluída' };
      case 'DEVOLUCAO': return { bg: 'from-orange-600 to-orange-950', border: 'border-orange-400/40', text: 'text-orange-400', label: 'Retorno Processado' };
      case 'SETTLE_WALLET': return { bg: 'from-indigo-600 to-indigo-950', border: 'border-indigo-400/40', text: 'text-indigo-400', label: 'Pagamento Liquidado' };
      case 'EXPORT_PDF': return { bg: 'from-slate-700 to-slate-900', border: 'border-white/20', text: 'text-white', label: 'Extrato Gerado' };
      case 'RESET_SYSTEM': return { bg: 'from-red-600 to-red-950', border: 'border-red-400/40', text: 'text-red-400', label: 'Sistema Resetado' };
      default: return { bg: 'from-slate-700 to-slate-900', border: 'border-white/20', text: 'text-white', label: 'Sucesso' };
    }
  };

  const currentTheme = getPopupStyles(successType);

  return (
    <div className="min-h-screen bg-[#020617] text-slate-200 selection:bg-emerald-500/30 flex flex-col overflow-x-hidden relative">
      <header className="bg-slate-900/80 backdrop-blur-xl border-b border-white/5 px-4 md:px-8 sticky top-0 z-40 pt-safe transition-all h-20">
        <div className="max-w-5xl mx-auto flex justify-between items-center h-full">
          <div className="flex items-center gap-3">
            <LogCashLogo size={36} />
            <div>
              <h1 className="text-xl font-game font-black tracking-[0.1em] text-white leading-none">LOG<span className="text-emerald-400">CASH</span></h1>
              <p className="text-[8px] text-slate-500 font-bold uppercase tracking-widest mt-1">{isSyncing ? 'Sincronizando...' : 'Conectado'}</p>
            </div>
          </div>
          <button onClick={() => setShowSettings(true)} className="p-3 bg-white/5 rounded-2xl border border-white/10 active:scale-95 transition-all hover:bg-white/10 flex items-center gap-2">
            <Settings size={20} className="text-slate-400" />
            <span className="hidden sm:block text-[10px] font-black text-slate-400 uppercase tracking-widest">Ajustes</span>
          </button>
        </div>
      </header>

      {showToast && (
        <div className="fixed top-24 left-1/2 -translate-x-1/2 z-[1000] animate-in slide-in-from-top-4 duration-300">
          <div className="bg-red-600 text-white px-6 py-3 rounded-full font-game font-black text-[10px] uppercase tracking-widest shadow-2xl border border-red-400/30 whitespace-nowrap">
            {toastMsg}
          </div>
        </div>
      )}

      <main className="flex-1 max-w-5xl mx-auto w-full p-4 md:p-8 space-y-8 pb-28 md:pb-12 transition-all">
        {activeTab === 'dash' ? (
          <div className="animate-in fade-in duration-500">
            <div className="mb-8">
              <h2 className="text-3xl md:text-5xl font-game font-black text-white uppercase tracking-tight leading-tight">Olá, {userName.split(' ')[0]}</h2>
              <p className="text-[10px] md:text-xs text-slate-500 font-bold uppercase tracking-[0.4em] mt-2">Dashboard Operacional</p>
            </div>

            <div className="grid grid-cols-1 lg:grid-cols-5 gap-6 mb-10">
              <div className="lg:col-span-3"><DashboardCards today={counts.today} week={counts.week} year={counts.year} /></div>
              <div className="lg:col-span-2">
                <WalletCard 
                  pendingAmount={counts.wallet.pending} 
                  paidAmount={counts.wallet.paid} 
                  totalCumulativePaid={counts.wallet.cumulative} 
                  onSettle={() => setConfirmingAction('SETTLE_WALLET')} 
                  logs={logs}
                />
              </div>
            </div>

            <section className="space-y-4 mb-10">
              <ActionButtons 
                onAction={(type) => setConfirmingAction(type)} 
                todayCounts={{
                  ENTRADA: counts.todayEntrada,
                  SAIDA: counts.todaySaida,
                  DEVOLUCAO: counts.todayDevolucao
                }}
              />
              {/* Botão de Atalho para Rota */}
              <button 
                onClick={() => setActiveTab('route')}
                className="w-full mt-4 p-4 rounded-2xl border border-white/5 bg-gradient-to-r from-slate-900 to-slate-800 flex items-center justify-between group hover:border-blue-500/30 transition-all active:scale-95"
              >
                <div className="flex items-center gap-3">
                  <div className="p-2 bg-blue-500/10 rounded-lg text-blue-400 group-hover:bg-blue-500 group-hover:text-white transition-colors">
                    <MapPin size={20} />
                  </div>
                  <div className="text-left">
                    <p className="font-game font-black text-white text-sm uppercase tracking-wider">Rota de Hoje</p>
                    <p className="text-[8px] text-slate-500 font-bold uppercase tracking-widest">Ver Detalhes</p>
                  </div>
                </div>
                <ChevronRight size={18} className="text-slate-600 group-hover:text-white group-hover:translate-x-1 transition-all" />
              </button>
            </section>

            <section className="grid grid-cols-2 gap-4 mb-10">
              <button onClick={() => setBulkModal({ isOpen: true, type: 'ENTRADA' })} className="bg-slate-900/40 border border-white/5 p-6 rounded-3xl flex flex-col items-start gap-4 active:scale-95 hover:bg-white/[0.03] transition-all">
                <div className="p-3 bg-emerald-600/10 text-emerald-400 rounded-2xl border border-emerald-500/20"><ListPlus size={24} /></div>
                <div className="text-left"><p className="font-game font-black text-white text-sm uppercase tracking-widest">Lote Entrada</p><p className="text-[8px] text-slate-500 uppercase font-bold mt-1">Multi-Checkin</p></div>
              </button>
              <button onClick={() => setBulkModal({ isOpen: true, type: 'SAIDA' })} className="bg-slate-900/40 border border-white/5 p-6 rounded-3xl flex flex-col items-start gap-4 active:scale-95 hover:bg-white/[0.03] transition-all">
                <div className="p-3 bg-blue-600/10 text-blue-400 rounded-2xl border border-blue-500/20"><Send size={24} /></div>
                <div className="text-left"><p className="font-game font-black text-white text-sm uppercase tracking-widest">Lote Saída</p><p className="text-[8px] text-slate-500 uppercase font-bold mt-1">Multi-Entrega</p></div>
              </button>
            </section>

            <section className="bg-slate-900/50 p-6 md:p-10 rounded-[3rem] border border-white/5 relative overflow-hidden group text-center">
              <div className="flex flex-col items-center gap-4 mb-6">
                <div className="p-4 bg-emerald-500/10 rounded-full border border-emerald-500/20"><FileText size={32} className="text-emerald-400" /></div>
                <h3 className="font-game font-black text-white uppercase tracking-[0.2em] text-lg">Relatórios</h3>
              </div>
              <button onClick={() => setConfirmingAction('EXPORT_PDF')} className="w-full bg-emerald-600 hover:bg-emerald-500 py-5 rounded-[1.5rem] flex items-center justify-center gap-3 font-game font-black text-white active:scale-95 text-xs uppercase tracking-[0.4em] transition-all shadow-2xl shadow-emerald-900/30 border border-emerald-400/20">
                <Download size={22} /> Gerar PDF Completo
              </button>
            </section>
          </div>
        ) : activeTab === 'stats' ? (
          <div className="animate-in fade-in duration-500"><DailyStatsTable logs={logs} /></div>
        ) : (
          <div className="animate-in fade-in duration-500"><DailyRouteHistory logs={logs} /></div>
        )}
      </main>

      <nav className="fixed bottom-0 left-0 right-0 glass-card border-t border-white/10 md:hidden z-50">
        <div className="flex justify-around items-center h-20 max-w-lg mx-auto">
          <button onClick={() => setActiveTab('dash')} className={`flex flex-col items-center justify-center w-full h-full gap-1 transition-all ${activeTab === 'dash' ? 'text-emerald-400 scale-110' : 'text-slate-600'}`}>
            <LayoutDashboard size={24} strokeWidth={activeTab === 'dash' ? 2.5 : 2} /><span className="text-[9px] font-black uppercase tracking-[0.2em]">Dash</span>
          </button>

          <button onClick={() => setActiveTab('route')} className={`flex flex-col items-center justify-center w-full h-full gap-1 transition-all ${activeTab === 'route' ? 'text-blue-400 scale-110' : 'text-slate-600'}`}>
            <Map size={24} strokeWidth={activeTab === 'route' ? 2.5 : 2} /><span className="text-[9px] font-black uppercase tracking-[0.2em]">Rota</span>
          </button>

          <button onClick={() => setActiveTab('stats')} className={`flex flex-col items-center justify-center w-full h-full gap-1 transition-all ${activeTab === 'stats' ? 'text-emerald-400 scale-110' : 'text-slate-600'}`}>
            <TableIcon size={24} strokeWidth={activeTab === 'stats' ? 2.5 : 2} /><span className="text-[9px] font-black uppercase tracking-[0.2em]">Fluxo</span>
          </button>
        </div>
        <div className="h-safe bg-slate-950"></div>
      </nav>

      {/* MODAL DE CONFIRMAÇÃO UNIFICADO (Single Action) */}
      {confirmingAction && (
        <div className="fixed inset-0 z-[600] flex items-center justify-center p-6 bg-black/95 backdrop-blur-2xl">
          <div className="w-full max-w-sm glass-deep rounded-[3.5rem] p-10 border border-white/20 animate-pop-burst text-center relative overflow-hidden">
            <div className="absolute top-0 inset-x-0 h-1.5 bg-gradient-to-r from-transparent via-white/20 to-transparent"></div>

            <div className={`w-24 h-24 mx-auto bg-white/5 rounded-3xl flex items-center justify-center mb-8 border border-white/10 animate-float-bounce ${
              confirmingAction === 'ENTRADA' ? 'text-emerald-400 shadow-[0_0_40px_rgba(52,211,153,0.15)]' : 
              confirmingAction === 'SAIDA' ? 'text-blue-400 shadow-[0_0_40px_rgba(59,130,246,0.15)]' : 
              confirmingAction === 'RESET_SYSTEM' || confirmingAction === 'LOGOUT' ? 'text-red-400 shadow-[0_0_40px_rgba(239,68,68,0.15)]' :
              confirmingAction === 'SETTLE_WALLET' ? 'text-indigo-400 shadow-[0_0_40px_rgba(99,102,241,0.15)]' : 'text-orange-400'
            }`}>
              {confirmingAction === 'ENTRADA' && <ArrowDownLeft size={48} strokeWidth={3} />}
              {confirmingAction === 'SAIDA' && <ArrowUpRight size={48} strokeWidth={3} />}
              {confirmingAction === 'DEVOLUCAO' && <RotateCcw size={48} strokeWidth={3} />}
              {confirmingAction === 'EXPORT_PDF' && <FileText size={48} strokeWidth={2} />}
              {confirmingAction === 'LOGOUT' && <LogOut size={48} strokeWidth={2} />}
              {confirmingAction === 'RESET_SYSTEM' && <Database size={48} strokeWidth={2} />}
              {confirmingAction === 'SETTLE_WALLET' && <Wallet size={48} strokeWidth={2} />}
            </div>

            <h3 className="text-3xl font-game font-black text-white uppercase tracking-tighter mb-4 leading-none">
              {confirmingAction === 'ENTRADA' ? 'Confirmar Entrada?' : 
               confirmingAction === 'SAIDA' ? 'Confirmar Saída?' : 
               confirmingAction === 'DEVOLUCAO' ? 'Confirmar Retorno?' :
               confirmingAction === 'EXPORT_PDF' ? 'Gerar Extrato?' :
               confirmingAction === 'LOGOUT' ? 'Encerrar Sessão?' :
               confirmingAction === 'SETTLE_WALLET' ? 'Receber Saldo?' :
               'Confirmar Reset?'}
            </h3>

            <p className="text-[10px] text-slate-500 font-bold uppercase tracking-[0.4em] mb-10 leading-relaxed px-4 opacity-80">
              {confirmingAction === 'SETTLE_WALLET' ? `Você liquidará ${formatBRL(counts.wallet.pending)}` : 'Validação de Segurança Necessária'}
            </p>

            <div className="space-y-4">
              <button 
                disabled={isExecuting} 
                onClick={handleGlobalConfirm} 
                className={`w-full py-5 rounded-2xl font-game font-black text-sm uppercase tracking-[0.4em] shadow-2xl transition-all active:scale-95 text-white btn-confirm-impact flex items-center justify-center gap-3 shine-container overflow-hidden ${
                  confirmingAction === 'RESET_SYSTEM' || confirmingAction === 'LOGOUT' ? 'bg-red-600 shadow-red-900/40' : 'bg-emerald-600 shadow-emerald-900/40'
                }`}
              >
                <div className="shine-overlay"></div>
                {isExecuting ? <div className="w-5 h-5 border-2 border-white/30 border-t-white rounded-full animate-spin"></div> : 'Confirmar Ação'}
              </button>
              <button 
                disabled={isExecuting} 
                onClick={() => setConfirmingAction(null)} 
                className="w-full py-4 bg-white/5 hover:bg-white/10 text-slate-500 font-bold uppercase text-[10px] tracking-widest rounded-xl transition-all"
              >
                Cancelar
              </button>
            </div>
          </div>
        </div>
      )}

      {/* MODAL LOTE (Bulk Confirmation) */}
      {bulkActionPending && (
        <div className="fixed inset-0 z-[650] flex items-center justify-center p-6 bg-black/95 backdrop-blur-2xl">
          <div className="w-full max-w-md glass-deep rounded-[3.5rem] p-10 border border-white/20 animate-pop-burst text-center relative overflow-hidden">
             <div className={`absolute top-0 inset-x-0 h-2 bg-gradient-to-r ${bulkActionPending.type === 'SAIDA' ? 'from-blue-600 via-white/40 to-blue-600' : 'from-emerald-600 via-white/40 to-emerald-600'}`}></div>
             <div className={`w-28 h-28 mx-auto bg-white/5 rounded-[2.5rem] flex items-center justify-center mb-8 border border-white/10 animate-float-bounce ${bulkActionPending.type === 'ENTRADA' ? 'text-emerald-400 shadow-[0_0_50px_rgba(52,211,153,0.2)]' : 'text-blue-400 shadow-[0_0_50px_rgba(59,130,246,0.2)]'}`}>
               <Package size={54} strokeWidth={1.5} />
             </div>
             <h3 className="text-3xl font-game font-black text-white uppercase tracking-tighter mb-2 leading-none">Confirmar Lote?</h3>
             <div className="flex flex-col items-center gap-2 mb-10">
               <div className={`px-6 py-2 rounded-2xl border text-2xl font-game font-black tracking-widest ${bulkActionPending.type === 'ENTRADA' ? 'bg-emerald-500/10 border-emerald-500/20 text-emerald-400' : 'bg-blue-500/10 border-blue-500/20 text-blue-400'}`}>{bulkActionPending.quantity} UNIDADES</div>
               {bulkActionPending.type === 'SAIDA' && <div className="text-emerald-400 font-game font-black text-xl tracking-widest mt-2">+ {formatBRL(bulkActionPending.quantity * VALOR_POR_PACOTE)}</div>}
             </div>
             <div className="space-y-4">
               <button 
                disabled={isExecuting} 
                onClick={executeBulkAction} 
                className={`w-full py-5 rounded-2xl font-game font-black text-sm uppercase tracking-[0.4em] shadow-2xl transition-all active:scale-95 text-white flex items-center justify-center gap-3 shine-container overflow-hidden ${bulkActionPending.type === 'ENTRADA' ? 'bg-emerald-600 shadow-emerald-900/40' : 'bg-blue-600 shadow-blue-900/40'}`}
              >
                 <div className="shine-overlay"></div>
                 {isExecuting ? <div className="w-5 h-5 border-2 border-white/30 border-t-white rounded-full animate-spin"></div> : 'Confirmar Lote'}
               </button>
               <button 
                disabled={isExecuting} 
                onClick={() => setBulkActionPending(null)} 
                className="w-full py-4 bg-white/5 text-slate-500 font-bold uppercase text-[10px] tracking-widest rounded-xl transition-all"
              >
                Voltar
              </button>
             </div>
          </div>
        </div>
      )}

      {/* POPUP SUCESSO UNIFICADO */}
      {showSuccessPopup && (
        <div onClick={closeSuccessPopup} className="fixed inset-0 z-[700] flex items-center justify-center p-6 cursor-pointer overflow-hidden bg-black/50 backdrop-blur-sm">
          <div className={`w-full max-w-sm glass-deep bg-gradient-to-b ${currentTheme.bg} ${currentTheme.border} border-2 rounded-[3.5rem] p-12 flex flex-col items-center text-center ${isClosingSuccess ? 'animate-pop-minimize' : 'animate-pop-burst'} relative transition-all`}>
            <div className="absolute inset-0 flex items-center justify-center pointer-events-none opacity-50"><Sparkles size={180} className={`${currentTheme.text} animate-pulse`} strokeWidth={0.5} /></div>
            <div className="relative mb-10 z-10 flex items-center justify-center">
              <div className={`absolute w-32 h-32 border-4 border-white/40 rounded-full animate-ring-pulse`}></div>
              <div className={`w-28 h-28 bg-white/10 backdrop-blur-3xl border border-white/30 rounded-full flex items-center justify-center shadow-2xl animate-float-bounce`}>
                <Check size={ successType === 'SETTLE_WALLET' ? 64 : 50 } className="text-white" strokeWidth={4} />
              </div>
            </div>
            <h4 className="text-3xl font-game font-black text-white uppercase tracking-tighter leading-none mb-4 drop-shadow-2xl z-10">{currentTheme.label}</h4>
            <div className="w-full h-px bg-white/20 mb-8 z-10"></div>
            <div className="space-y-4 z-10 w-full">
              {successType === 'SETTLE_WALLET' ? <div className="px-8 py-4 bg-white/10 rounded-3xl border border-white/20 shadow-inner"><span className="text-4xl font-game font-black text-white">{formatBRL(lastSettleValue)}</span></div> : 
               (successType === 'ENTRADA' || successType === 'SAIDA' || successType === 'DEVOLUCAO') && <div className="px-8 py-3 bg-white/10 rounded-2xl border border-white/20 text-3xl font-game font-black text-white">{bulkCount} UNID.</div>}
              <p className="text-[10px] text-white/60 font-game font-bold uppercase tracking-[0.7em] pt-6 opacity-90 leading-relaxed italic">Cloud Sync Complete</p>
            </div>
            <div className="absolute bottom-6 left-16 right-16 h-1 bg-white/20 rounded-full overflow-hidden"><div className="h-full bg-white animate-timer"></div></div>
          </div>
        </div>
      )}

      {/* PAINEL DE AJUSTES */}
      {showSettings && (
        <div className="fixed inset-0 z-[100] flex items-end md:items-center justify-center bg-black/90 backdrop-blur-md p-0 md:p-4">
          <div className="bg-slate-900 w-full max-w-lg rounded-t-[3rem] md:rounded-[3rem] border-t md:border border-white/10 overflow-hidden animate-in slide-in-from-bottom-full duration-500">
             <div className="px-8 py-6 border-b border-white/5 flex justify-between items-center"><h3 className="font-game font-black text-white uppercase tracking-[0.2em] text-sm">Configurações</h3><button onClick={() => setShowSettings(false)} className="p-3 bg-white/5 rounded-full text-slate-500 active:scale-90 transition-all"><X size={20} /></button></div>
             <div className="p-8 md:p-12 space-y-8">
                <div className="space-y-4"><label className="text-[10px] font-black text-slate-600 uppercase tracking-[0.4em] ml-1">Assinatura Logística</label><div className="relative group"><User className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-600" size={18} /><input type="text" value={userName} onChange={(e) => setUserName(e.target.value)} className="w-full bg-black/40 border border-white/10 rounded-2xl pl-12 pr-4 py-5 text-sm font-bold text-white focus:outline-none focus:border-emerald-500/50 transition-all" /></div></div>
                <div className="pt-4 flex flex-col gap-3">
                  <button onClick={() => setConfirmingAction('LOGOUT')} className="w-full p-6 bg-slate-800/50 border border-white/5 text-slate-400 rounded-3xl flex items-center justify-between font-game font-black uppercase tracking-widest text-xs active:scale-95 transition-all hover:text-red-500 hover:bg-red-500/5">Encerrar Sessão <LogOut size={20} /></button>
                  <button onClick={() => setConfirmingAction('RESET_SYSTEM')} className="w-full p-6 bg-red-500/5 border border-red-500/10 text-red-500 rounded-3xl flex items-center justify-between font-game font-black uppercase tracking-widest text-xs active:scale-95 transition-all">Resetar Banco <Database size={20} /></button>
                </div>
             </div>
             <div className="h-safe bg-slate-900 pb-safe"></div>
          </div>
        </div>
      )}

      <BulkActionModal 
        isOpen={bulkModal.isOpen} 
        type={bulkModal.type} 
        title={bulkModal.type === 'SAIDA' ? 'Saída em Massa' : 'Entrada em Massa'} 
        onClose={() => setBulkModal({ ...bulkModal, isOpen: false })} 
        onConfirm={(q) => {
          setBulkModal({ ...bulkModal, isOpen: false });
          setBulkActionPending({ type: bulkModal.type, quantity: q });
        }} 
      />
    </div>
  );
};

export default App;

import React, { useState, useEffect, useMemo } from 'react';
import { Truck, Zap, FileText, Download, LayoutDashboard, Send, Table as TableIcon, ListPlus, LogOut, Layers, Settings, Trash2, AlertCircle, User, Sliders, ChevronRight, X, CheckCircle2, Check, Wallet, AlertTriangle, ArrowDownLeft, ArrowUpRight, RotateCcw, Sparkles, Package, LogIn, Database, Map, MapPin, Eraser } from 'lucide-react';
import DashboardCards from './components/DashboardCards';
import ActionButtons from './components/ActionButtons';
import DailyStatsTable from './components/DailyStatsTable';
import DailyRouteHistory from './components/DailyRouteHistory';
import BulkActionModal from './components/BulkActionModal';
import WalletCard from './components/WalletCard';
import Login from './components/Login';
import { LogCashLogo } from './components/Logo';
import { LogEntry, LogActionType } from './types';
import { supabaseService } from './services/supabaseService';
import { generatePDF } from './services/pdfService';
import { VALOR_POR_PACOTE } from './constants';

type SystemActionType = LogActionType | 'EXPORT_PDF' | 'LOGOUT' | 'RESET_SYSTEM' | 'SETTLE_WALLET' | 'CLEAR_CACHE';

const App: React.FC = () => {
  const [session, setSession] = useState<any>(null);
  const [logs, setLogs] = useState<LogEntry[]>([]); 
  const [loading, setLoading] = useState(true);
  const [isSyncing, setIsSyncing] = useState(false);

  // Feedback Visual
  const [showToast, setShowToast] = useState(false);
  const [toastMsg, setToastMsg] = useState('');

  // Estados de Pop-up de Sucesso
  const [showSuccessPopup, setShowSuccessPopup] = useState(false);
  const [isClosingSuccess, setIsClosingSuccess] = useState(false);
  const [bulkCount, setBulkCount] = useState(0);
  const [lastSettleValue, setLastSettleValue] = useState(0);
  const [successType, setSuccessType] = useState<SystemActionType>('ENTRADA');

  // Estado Unificado de Confirmação
  const [confirmingAction, setConfirmingAction] = useState<SystemActionType | null>(null);
  const [bulkActionPending, setBulkActionPending] = useState<{ type: 'ENTRADA' | 'SAIDA'; quantity: number } | null>(null);

  // Controle de Execução (Bloqueio de duplo clique)
  const [isExecuting, setIsExecuting] = useState(false);

  const [userName, setUserName] = useState(() => localStorage.getItem('logcash_user_name') || 'Operador Logístico');
  const [activeTab, setActiveTab] = useState<'dash' | 'stats' | 'route'>('dash');
  const [showSettings, setShowSettings] = useState(false);

  const [bulkModal, setBulkModal] = useState<{ isOpen: boolean; type: 'ENTRADA' | 'SAIDA' }>({
    isOpen: false,
    type: 'ENTRADA'
  });

  // 1. Verifica Sessão
  useEffect(() => {
    supabaseService.getSession().then(session => {
      setSession(session);
      if (!session) setLoading(false);
    });
  }, []);

  // 2. Sincronização
  useEffect(() => {
    if (!session?.user) {
      setLogs([]); 
      return;
    }

    const userId = session.user.id;
    const userCacheKey = `logcash_cache_${userId}`;

    // Cache Inicial (Melhora percepção de velocidade)
    try {
      const cached = localStorage.getItem(userCacheKey);
      if (cached) setLogs(JSON.parse(cached));
    } catch (e) { console.error(e); }

    setIsSyncing(true);

    const unsubscribe = supabaseService.subscribeToLogs((updatedLogs, supabaseError) => {
      if (!supabaseError) {
        setLogs(updatedLogs);
        localStorage.setItem(userCacheKey, JSON.stringify(updatedLogs));
      }
      setLoading(false);
      setIsSyncing(false);
    });

    return () => unsubscribe();
  }, [session]);

  useEffect(() => {
    localStorage.setItem('logcash_user_name', userName);
  }, [userName]);

  // Função auxiliar para mostrar Toast de Erro
  const showError = (msg: string) => {
    setToastMsg(msg);
    setShowToast(true);
    setTimeout(() => setShowToast(false), 4000);
  };

  const triggerSuccess = (type: SystemActionType, count: number = 1) => {
    setSuccessType(type);
    setBulkCount(count);
    setConfirmingAction(null);
    setBulkActionPending(null);
    setShowSettings(false);

    setTimeout(() => {
      setShowSuccessPopup(true);
      setTimeout(closeSuccessPopup, 2400); // Popup fecha sozinho
    }, 100);
  };

  const closeSuccessPopup = () => {
    if (isClosingSuccess) return;
    setIsClosingSuccess(true);
    setTimeout(() => {
      setShowSuccessPopup(false);
      setIsClosingSuccess(false);
    }, 400);
  };

  const handleGlobalConfirm = async () => {
    if (isExecuting || !confirmingAction) return;

    const actionToExecute = confirmingAction; 
    setIsExecuting(true);

    // --- OPTIMISTIC UI: Preparação ---
    const previousLogs = [...logs]; // Backup para rollback
    const tempId = `temp-${Date.now()}`;
    const timestamp = new Date().toISOString();

    try {
      switch (actionToExecute) {
        case 'ENTRADA':
        case 'SAIDA':
        case 'DEVOLUCAO':
          // 1. Atualização Otimista
          const newLog: LogEntry = {
            id: tempId,
            type: actionToExecute as LogActionType,
            timestamp,
            value: actionToExecute === 'SAIDA' ? VALOR_POR_PACOTE : 0,
            isPaid: false,
            user_id: session?.user?.id
          };
          setLogs(prev => [newLog, ...prev]);
          triggerSuccess(actionToExecute); // Feedback visual instantâneo

          // 2. Envio Real
          await supabaseService.saveLog({
            type: actionToExecute as LogActionType,
            timestamp,
            value: actionToExecute === 'SAIDA' ? VALOR_POR_PACOTE : 0
          });
          // Se der certo, o Realtime atualizará o log com o ID real depois
          break;

        case 'SETTLE_WALLET':
          const currentPending = counts.wallet.pending;
          setLastSettleValue(currentPending);

          // Otimista
          setLogs(prev => prev.map(l => (l.type === 'SAIDA' && !l.isPaid) ? { ...l, isPaid: true } : l));
          triggerSuccess('SETTLE_WALLET');

          // Real
          await supabaseService.markAllAsPaid();
          break;

        case 'EXPORT_PDF':
          generatePDF(logs, userName);
          triggerSuccess('EXPORT_PDF');
          break;

        case 'LOGOUT':
          const userId = session?.user?.id;
          await supabaseService.signOut();
          if (userId) localStorage.removeItem(`logcash_cache_${userId}`);
          setSession(null);
          setLogs([]);
          setConfirmingAction(null);
          setShowSettings(false);
          break;

        case 'CLEAR_CACHE':
          if (session?.user?.id) {
            localStorage.removeItem(`logcash_cache_${session.user.id}`);
          }
          localStorage.removeItem('logcash_user_name');
          localStorage.removeItem('logcash_saved_email'); // Opcional: remove email salvo do login

          triggerSuccess('CLEAR_CACHE');

          // Recarrega a página após 1.5s para forçar estado limpo
          setTimeout(() => {
            window.location.reload();
          }, 1500);
          break;

        case 'RESET_SYSTEM':
          setLogs([]); // Otimista
          triggerSuccess('RESET_SYSTEM');

          await supabaseService.deleteAllLogs();
          if (session?.user?.id) localStorage.removeItem(`logcash_cache_${session.user.id}`);
          setUserName('Operador Logístico');
          localStorage.removeItem('logcash_user_name');
          break;
      }
    } catch (err: any) {
      console.error("Erro na ação:", err);
      // ROLLBACK em caso de erro
      if (['ENTRADA', 'SAIDA', 'DEVOLUCAO', 'SETTLE_WALLET', 'RESET_SYSTEM'].includes(actionToExecute)) {
        setLogs(previousLogs); 
        // Exibe a mensagem real do erro para facilitar diagnóstico (ex: coluna faltando)
        showError(err.message || "Erro de sincronização. Ação revertida.");
      } else {
        showError(err.message || 'Erro na operação.');
      }
    } finally {
      setIsExecuting(false);
    }
  };

  const executeBulkAction = async () => {
    if (!bulkActionPending || isExecuting) return;

    const pending = bulkActionPending;
    setIsExecuting(true);

    const { type, quantity } = pending;
    const previousLogs = [...logs];
    const timestamp = new Date().toISOString();

    try {
      // 1. Otimista
      const newEntriesOptimistic: LogEntry[] = Array.from({ length: quantity }).map((_, i) => ({
        id: `temp-bulk-${Date.now()}-${i}`,
        type: type as LogActionType,
        timestamp,
        value: type === 'SAIDA' ? VALOR_POR_PACOTE : 0,
        isPaid: false,
        user_id: session?.user?.id
      }));

      setLogs(prev => [...newEntriesOptimistic, ...prev]);
      triggerSuccess(type, quantity);

      // 2. Real
      const payload = newEntriesOptimistic.map(e => ({
        type: e.type,
        timestamp: e.timestamp,
        value: e.value
      }));

      await supabaseService.saveBulkLogs(payload);

    } catch (err: any) {
      console.error("Erro no lote:", err);
      setLogs(previousLogs); // Rollback
      showError(err.message || "Falha ao salvar lote. Tente novamente.");
    } finally {
      setIsExecuting(false);
    }
  };

  const counts = useMemo(() => {
    const todayStr = new Date().toDateString();
    const now = new Date();
    const startOfWeek = new Date(now);
    startOfWeek.setDate(now.getDate() - now.getDay());
    startOfWeek.setHours(0, 0, 0, 0);
    const startOfMonth = new Date(now.getFullYear(), now.getMonth(), 1);
    const startOfYear = new Date(now.getFullYear(), 0, 1);

    const deliveredLogs = logs.filter(l => l.type === 'SAIDA');
    const todayLogs = logs.filter(l => new Date(l.timestamp).toDateString() === todayStr);

    const pending = deliveredLogs.filter(l => !l.isPaid).length * VALOR_POR_PACOTE;
    const paidCurrentCycle = deliveredLogs.filter(l => l.isPaid && new Date(l.timestamp) >= startOfMonth).length * VALOR_POR_PACOTE;
    const totalCumulativePaid = deliveredLogs.filter(l => l.isPaid).length * VALOR_POR_PACOTE;

    return {
      today: todayLogs.filter(l => l.type === 'SAIDA').length,
      todayEntrada: todayLogs.filter(l => l.type === 'ENTRADA').length,
      todaySaida: todayLogs.filter(l => l.type === 'SAIDA').length,
      todayDevolucao: todayLogs.filter(l => l.type === 'DEVOLUCAO').length,
      week: logs.filter(l => l.type === 'SAIDA' && new Date(l.timestamp) >= startOfWeek).length,
      year: logs.filter(l => l.type === 'SAIDA' && new Date(l.timestamp) >= startOfYear).length,
      wallet: {
        pending,
        paid: paidCurrentCycle,
        cumulative: totalCumulativePaid
      }
    };
  }, [logs]);

  if (!session && !loading) return <Login onLoginSuccess={() => supabaseService.getSession().then(setSession)} />;

  if (loading && logs.length === 0) {
    return (
      <div className="min-h-screen bg-[#020617] flex flex-col items-center justify-center p-6 text-center">
        <LogCashLogo size={60} />
        <p className="text-slate-500 font-game font-bold uppercase tracking-[0.3em] text-[10px] animate-pulse mt-4">Conectando Terminal...</p>
      </div>
    );
  }

  const formatBRL = (val: number) => new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(val);

  const getPopupStyles = (type: SystemActionType) => {
    switch (type) {
      case 'ENTRADA': return { bg: 'from-emerald-600 to-emerald-950', border: 'border-emerald-400/40', text: 'text-emerald-400', label: 'Entrada Registrada' };
      case 'SAIDA': return { bg: 'from-blue-600 to-blue-950', border: 'border-blue-400/40', text: 'text-blue-400', label: 'Entrega Concluída' };
      case 'DEVOLUCAO': return { bg: 'from-orange-600 to-orange-950', border: 'border-orange-400/40', text: 'text-orange-400', label: 'Retorno Processado' };
      case 'SETTLE_WALLET': return { bg: 'from-indigo-600 to-indigo-950', border: 'border-indigo-400/40', text: 'text-indigo-400', label: 'Pagamento Liquidado' };
      case 'EXPORT_PDF': return { bg: 'from-slate-700 to-slate-900', border: 'border-white/20', text: 'text-white', label: 'Extrato Gerado' };
      case 'RESET_SYSTEM': return { bg: 'from-red-600 to-red-950', border: 'border-red-400/40', text: 'text-red-400', label: 'Sistema Resetado' };
      case 'CLEAR_CACHE': return { bg: 'from-amber-500 to-amber-900', border: 'border-amber-400/40', text: 'text-amber-400', label: 'Cache Limpo' };
      default: return { bg: 'from-slate-700 to-slate-900', border: 'border-white/20', text: 'text-white', label: 'Sucesso' };
    }
  };

  const currentTheme = getPopupStyles(successType);

  return (
    <div className="min-h-screen bg-[#020617] text-slate-200 selection:bg-emerald-500/30 flex flex-col overflow-x-hidden relative">
      <header className="bg-slate-900/80 backdrop-blur-xl border-b border-white/5 px-4 md:px-8 sticky top-0 z-40 pt-safe transition-all h-20">
        <div className="max-w-5xl mx-auto flex justify-between items-center h-full">
          <div className="flex items-center gap-3">
            <LogCashLogo size={36} />
            <div>
              <h1 className="text-xl font-game font-black tracking-[0.1em] text-white leading-none">LOG<span className="text-emerald-400">CASH</span></h1>
              <p className="text-[8px] text-slate-500 font-bold uppercase tracking-widest mt-1">{isSyncing ? 'Sincronizando...' : 'Conectado'}</p>
            </div>
          </div>
          <button onClick={() => setShowSettings(true)} className="p-3 bg-white/5 rounded-2xl border border-white/10 active:scale-95 transition-all hover:bg-white/10 flex items-center gap-2">
            <Settings size={20} className="text-slate-400" />
            <span className="hidden sm:block text-[10px] font-black text-slate-400 uppercase tracking-widest">Ajustes</span>
          </button>
        </div>
      </header>

      {showToast && (
        <div className="fixed top-24 left-1/2 -translate-x-1/2 z-[1000] animate-in slide-in-from-top-4 duration-300">
          <div className="bg-red-600 text-white px-6 py-3 rounded-full font-game font-black text-[10px] uppercase tracking-widest shadow-2xl border border-red-400/30 whitespace-nowrap">
            {toastMsg}
          </div>
        </div>
      )}

      <main className="flex-1 max-w-5xl mx-auto w-full p-4 md:p-8 space-y-8 pb-28 md:pb-12 transition-all">
        {activeTab === 'dash' ? (
          <div className="animate-in fade-in duration-500">
            <div className="mb-8">
              <h2 className="text-3xl md:text-5xl font-game font-black text-white uppercase tracking-tight leading-tight">Olá, {userName.split(' ')[0]}</h2>
              <p className="text-[10px] md:text-xs text-slate-500 font-bold uppercase tracking-[0.4em] mt-2">Dashboard Operacional</p>
            </div>

            <div className="grid grid-cols-1 lg:grid-cols-5 gap-6 mb-10">
              <div className="lg:col-span-3"><DashboardCards today={counts.today} week={counts.week} year={counts.year} /></div>
              <div className="lg:col-span-2">
                <WalletCard 
                  pendingAmount={counts.wallet.pending} 
                  paidAmount={counts.wallet.paid} 
                  totalCumulativePaid={counts.wallet.cumulative} 
                  onSettle={() => setConfirmingAction('SETTLE_WALLET')} 
                  logs={logs}
                />
              </div>
            </div>

            <section className="space-y-4 mb-10">
              <ActionButtons 
                onAction={(type) => setConfirmingAction(type)} 
                todayCounts={{
                  ENTRADA: counts.todayEntrada,
                  SAIDA: counts.todaySaida,
                  DEVOLUCAO: counts.todayDevolucao
                }}
              />
              {/* Botão de Atalho para Rota */}
              <button 
                onClick={() => setActiveTab('route')}
                className="w-full mt-4 p-4 rounded-2xl border border-white/5 bg-gradient-to-r from-slate-900 to-slate-800 flex items-center justify-between group hover:border-blue-500/30 transition-all active:scale-95"
              >
                <div className="flex items-center gap-3">
                  <div className="p-2 bg-blue-500/10 rounded-lg text-blue-400 group-hover:bg-blue-500 group-hover:text-white transition-colors">
                    <MapPin size={20} />
