        onClose={() => setBulkModal({ ...bulkModal, isOpen: false })} 
        onConfirm={(q) => {
          setBulkModal({ ...bulkModal, isOpen: false });
          setBulkActionPending({ type: bulkModal.type, quantity: q });
        }} 
      />
    </div>
  );
};

export default App;

import { supabase } from "../supabaseConfig";
import { LogEntry } from "../types";

const TABLE_NAME = "logs";

// Utilitário para limpar campos undefined antes de enviar ao Supabase
const cleanPayload = (payload: any) => {
  return JSON.parse(JSON.stringify(payload));
};

// Utilitário para tratar erros de rede
const handleSupabaseError = (error: any) => {
  if (error?.message?.includes('Failed to fetch') || error?.message?.includes('NetworkError')) {
    throw new Error('Sem conexão com a internet. Verifique sua rede.');
  }
  throw error;
};

export const supabaseService = {
  // --- AUTH METHODS ---
  signUp: async (email: string, pass: string) => {
    const { data, error } = await supabase.auth.signUp({ email, password: pass });
    if (error) handleSupabaseError(error);
    return data;
  },

  signIn: async (email: string, pass: string) => {
    const { data, error } = await supabase.auth.signInWithPassword({ email, password: pass });
    if (error) handleSupabaseError(error);
    return data;
  },

  signOut: async () => {
    const { error } = await supabase.auth.signOut();
    if (error) handleSupabaseError(error);
  },

  getSession: async () => {
    try {
      const { data: { session }, error } = await supabase.auth.getSession();
      if (error) throw error;
      return session;
    } catch (err) {
      console.error("Erro ao obter sessão:", err);
      return null;
    }
  },

  // --- LOG METHODS (COM ISOLAMENTO HÍBRIDO) ---
  subscribeToLogs: (callback: (logs: LogEntry[], error?: any) => void) => {
    let channel: any = null;

    const fetchAndSubscribe = async () => {
      try {
        // Tenta pegar o usuário do cache local (getSession) em vez de validar na rede (getUser)
        const { data: { session }, error: authError } = await supabase.auth.getSession();

        if (authError) {
           console.warn("Erro de sessão ao subscrever:", authError.message);
           callback([], authError);
           return;
        }

        const user = session?.user;

        // Se não houver usuário, retorna vazio imediatamente
        if (!user) {
          callback([], null);
          return;
        }

        // Função interna para buscar dados
        const fetchData = async () => {
          try {
            const { data, error } = await supabase
              .from(TABLE_NAME)
              .select("*")
              .order("timestamp", { ascending: false });

            if (error) {
              console.error("Erro ao buscar logs:", error.message);
              // Se for erro de fetch na busca, passamos o erro mas não quebramos a app
              callback([], error);
            } else {
              // FILTRO HÍBRIDO: Aceita dados do usuário OU dados legados (sem user_id)
              const isolatedData = (data as LogEntry[]).filter(log => 
                log.user_id === user.id || !log.user_id
              );
              callback(isolatedData);
            }
          } catch (err: any) {
            console.error("Erro crítico no fetch:", err);
            // Se for erro de rede, apenas avisa, não limpa os logs se não quiser
            callback([], err);
          }
        };

        // 1. Busca inicial
        await fetchData();

        // 2. Configura Realtime
        channel = supabase
          .channel(`public_logs_feed`)
          .on(
            "postgres_changes",
            { 
              event: "*", 
              schema: "public", 
              table: TABLE_NAME
            },
            () => {
              fetchData();
            }
          )
          .subscribe((status) => {
             if (status === 'CHANNEL_ERROR') {
               console.warn("Erro no canal Realtime (provável desconexão).");
             }
          });
      } catch (err) {
        console.error("Erro fatal no subscribeToLogs:", err);
        callback([], err);
      }
    };

    fetchAndSubscribe();

    return () => {
      if (channel) supabase.removeChannel(channel);
    };
  },

  // Inserção com FALLBACK (Tenta Seguro -> Tenta Legado)
  saveLog: async (entry: Omit<LogEntry, 'id'>) => {
    // Usa getSession para evitar falha de rede na verificação de auth
    const { data: { session } } = await supabase.auth.getSession();
    const user = session?.user;

    if (!user) throw new Error("Usuário desconectado.");

    const payload = { 
      type: entry.type,
      timestamp: entry.timestamp,
      value: entry.value,
      user_id: user.id, // Tentativa 1: Com ID
      isPaid: entry.type === 'SAIDA' ? false : undefined
    };

    // 1. Tenta salvar com user_id
    const { error } = await supabase.from(TABLE_NAME).insert([cleanPayload(payload)]);

    if (error) {
      if (error.message.includes('Failed to fetch')) {
         throw new Error('Sem conexão com a internet.');
      }

      console.warn("Erro no insert seguro. Tentando modo legado...", error.message);

      // 2. Fallback: Remove user_id e tenta de novo
      const legacyPayload = { ...payload };
      delete (legacyPayload as any).user_id;

      const { error: legacyError } = await supabase.from(TABLE_NAME).insert([cleanPayload(legacyPayload)]);

      if (legacyError) handleSupabaseError(legacyError);
    }
  },

  saveBulkLogs: async (entries: Omit<LogEntry, 'id'>[]) => {
    const { data: { session } } = await supabase.auth.getSession();
    const user = session?.user;

    if (!user) throw new Error("Usuário desconectado.");

    const payloads = entries.map(e => ({
      type: e.type,
      timestamp: e.timestamp,
      value: e.value,
      user_id: user.id,
      isPaid: e.type === 'SAIDA' ? false : undefined
    }));

    // 1. Tenta salvar com user_id
    const { error } = await supabase.from(TABLE_NAME).insert(cleanPayload(payloads));

    if (error) {
       if (error.message.includes('Failed to fetch')) {
         throw new Error('Sem conexão com a internet.');
       }
       console.warn("Erro no insert em lote seguro. Tentando modo legado...", error.message);

       // 2. Fallback
       const legacyPayloads = payloads.map(p => {
         const copy = { ...p };
         delete (copy as any).user_id;
         return copy;
       });

       const { error: legacyError } = await supabase.from(TABLE_NAME).insert(cleanPayload(legacyPayloads));
       if (legacyError) handleSupabaseError(legacyError);
    }
  },

  markAllAsPaid: async () => {
    const { data: { session } } = await supabase.auth.getSession();
    const user = session?.user;
    if (!user) return;

    // Tenta marcar apenas os do usuário
    const { error } = await supabase
      .from(TABLE_NAME)
      .update({ isPaid: true })
      .eq('user_id', user.id)
      .eq('isPaid', false)
      .eq('type', 'SAIDA');

    if (error && !error.message.includes("column")) handleSupabaseError(error);
  },

  deleteAllLogs: async () => {
    const { data: { session } } = await supabase.auth.getSession();
    const user = session?.user;
    if (!user) return;

    // Tenta deletar pelo ID
    const { error } = await supabase
        .from(TABLE_NAME)
        .delete()
        .eq('user_id', user.id);

    if (error) handleSupabaseError(error);
  }
};

import React, { useState } from 'react';
import { Wallet, CheckCircle, Clock, X, Package, Calendar, History, ArrowUpRight, ChevronRight, TrendingUp } from 'lucide-react';
import { VALOR_POR_PACOTE } from '../constants';
import { LogEntry } from '../types';

interface WalletCardProps {
  pendingAmount: number;
  paidAmount: number;
  totalCumulativePaid: number;
  onSettle: () => void;
  logs: LogEntry[];
}

const WalletCard: React.FC<WalletCardProps> = ({ pendingAmount, paidAmount, totalCumulativePaid, onSettle, logs }) => {
  const [detailModal, setDetailModal] = useState<{
    isOpen: boolean;
    title: string;
    description: string;
    count: number;
    icon: React.ReactNode;
    color: string;
    logs: LogEntry[];
    type: 'pending' | 'paid' | 'total';
  } | null>(null);

  const format = (val: number) => 
    new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(val);

  const openDetail = (type: 'pending' | 'paid' | 'total') => {
    const now = new Date();
    const startOfMonth = new Date(now.getFullYear(), now.getMonth(), 1);

    let filteredLogs: LogEntry[] = [];
    let title = '';
    let description = '';
    let icon = null;
    let color = '';

    switch (type) {
      case 'pending':
        filteredLogs = logs.filter(l => l.type === 'SAIDA' && !l.isPaid).sort((a, b) => new Date(a.timestamp).getTime() - new Date(b.timestamp).getTime());
        title = 'Saldo Pendente';
        description = 'Valores de entregas realizadas que ainda não foram liquidados para sua conta.';
        icon = <Clock size={32} />;
        color = 'text-orange-400';
        break;
      case 'paid':
        filteredLogs = logs.filter(l => l.type === 'SAIDA' && l.isPaid && new Date(l.timestamp) >= startOfMonth).sort((a, b) => new Date(b.timestamp).getTime() - new Date(a.timestamp).getTime());
        title = 'Pagos no Ciclo';
        description = 'Lista de entregas já confirmadas e pagas durante o mês atual.';
        icon = <CheckCircle size={32} />;
        color = 'text-emerald-400';
        break;
      case 'total':
        filteredLogs = logs.filter(l => l.type === 'SAIDA' && l.isPaid).sort((a, b) => new Date(b.timestamp).getTime() - new Date(a.timestamp).getTime());
        title = 'Histórico Total';
        description = 'Toda a sua produtividade acumulada desde o primeiro registro no sistema.';
        icon = <History size={32} />;
        color = 'text-blue-400';
        break;
    }

